import React, { Suspense, lazy } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { CartProvider } from './contexts/CartContext';
import { EditorProvider } from './contexts/EditorContext';
import { ToastProvider } from './contexts/ToastContext';
import { VisualEditorProvider } from './pages/Tienda/contexts/VisualEditorContext';
import { LayoutProvider } from './contexts/LayoutContext';
import { WishlistProvider } from './contexts/WishlistContext';
import AdminNotifications from './pages/admin/AdminNotifications/AdminNotifications';
import AdminRoute from './components/AdminRoute/AdminRoute';
import RouteTracker from './components/analytics/RouteTracker';
import ReferralTracker from './components/analytics/ReferralTracker';
import ErrorBoundary from './components/common/ErrorBoundary/ErrorBoundary';
import PageLoading from './components/common/PageLoading/PageLoading';
import AppPrefetcher from './components/common/AppPrefetcher/AppPrefetcher';
import NavProgressBar from './components/common/NavProgressBar/NavProgressBar';
import CustomFontsInjector from './components/common/CustomFontsInjector/CustomFontsInjector';
import './App.css';

// ── Páginas principales y Layout Crítico (Carga Inmediata para evitar efecto Waterfall de Suspense) ──
import TiendaPage from './pages/Tienda/TiendaPage';
import LegacyTiendaPage from './pages/LegacyTienda/LegacyTiendaPage';
import Header from './components/common/Header';
import Footer from './components/common/Footer';
import WordlePage from './pages/Tienda/WordlePage';
import BottomNav from './components/common/BottomNav';
import WhatsAppButton from './components/common/WhatsAppButton';
import FirebaseWarning from './components/common/FirebaseWarning';
import KapiPet from './components/common/KapiPet/KapiPet';
import AdminBar from './components/common/AdminBar/AdminBar';
import VisualEditorPanel from './pages/Tienda/admin/VisualEditorPanel';
import DeepLinkHandler from './components/common/DeepLinkHandler';


// ── Páginas secundarias — lazy para no bloquear ──────────
const ProductPage = lazy(() => import('./pages/ProductPage'));
const PersonalizarPage = lazy(() => import('./pages/PersonalizarPage'));
const CartPage = lazy(() => import('./pages/CartPage'));
const LoginPage = lazy(() => import('./pages/LoginPage'));
const RegisterPage = lazy(() => import('./pages/RegisterPage'));
const CompleteProfilePage = lazy(() => import('./pages/CompleteProfilePage'));
const ResetPasswordPage = lazy(() => import('./pages/ResetPasswordPage'));
const PoliticasPrivacidadPage = lazy(() => import('./pages/PoliticasPrivacidadPage'));
const TerminosCondicionesPage = lazy(() => import('./pages/TerminosCondicionesPage'));
const DynamicLandingPage = lazy(() => import('./pages/Tienda/DynamicLandingPage'));
const SubscriptionSurveyPage = lazy(() => import('./pages/SubscriptionSurveyPage'));
const SubscriptionLandingPage = lazy(() => import('./pages/SubscriptionLandingPage'));
const NuevosUsuariosPage = lazy(() => import('./pages/NuevosUsuariosPage'));
const MinijuegosPage = lazy(() => import('./pages/Minijuegos/MinijuegosPage'));
const RuletaPage = lazy(() => import('./pages/Minijuegos/RuletaPage'));
const GiftExperiencePage = lazy(() => import('./pages/GiftExperiencePage'));

// ── Admin Layout ─────────────────────────────────────────────────────────────
const AdminLayout = lazy(() => import('./components/AdminLayout/AdminLayout'));

// ── Secciones pesadas — lazy ─────────────────────────────────────────────────
const EditorPage = lazy(() => import('./pages/EditorPage'));
const CheckoutPage = lazy(() => import('./pages/CheckoutPage'));
const AdminDashboard = lazy(() => import('./pages/AdminDashboard'));

// ── Admin pages ───────────────────────────────────────────────────────────────
const AdminProductos = lazy(() => import('./pages/Tienda/admin/AdminProductos'));
const AdminInventario = lazy(() => import('./pages/Tienda/admin/AdminInventario'));
const AdminMockups = lazy(() => import('./pages/Tienda/admin/AdminMockups'));
const AdminReferidos = lazy(() => import('./pages/admin/AdminReferidos'));
const AdminProductoFormV2 = lazy(() => import('./pages/Tienda/admin/AdminProductoFormV2'));
const AdminCategorias = lazy(() => import('./pages/admin/AdminCategorias'));
const AdminColecciones = lazy(() => import('./pages/admin/AdminColecciones'));

const AdminWhatsApp = lazy(() => import('./pages/admin/AdminWhatsApp'));
const AdminPagos = lazy(() => import('./pages/admin/AdminPagos'));
const AdminDestacados = lazy(() => import('./pages/admin/AdminDestacados'));
const AdminCliparts = lazy(() => import('./pages/admin/AdminCliparts'));
const AdminMascota = lazy(() => import('./pages/admin/AdminMascota'));
const AdminBackups = lazy(() => import('./pages/admin/AdminBackups'));
const AdminConfiguracion = lazy(() => import('./pages/admin/AdminConfiguracion'));
const AdminCrearCuentasPedidos = lazy(() => import('./pages/admin/AdminCrearCuentasPedidos'));
const AdminRetos = lazy(() => import('./pages/admin/AdminRetos'));
const AdminUsuariosAnalyticsPage = lazy(() => import('./pages/admin/AdminUsuariosAnalyticsPage'));
const AdminWordlePage = lazy(() => import('./pages/admin/AdminWordlePage'));
const AdminMarcas = lazy(() => import('./pages/admin/AdminMarcas'));
const AdminLandingPages = lazy(() => import('./pages/Tienda/admin/AdminLandingPages'));
const AdminThemes = lazy(() => import('./pages/Tienda/admin/AdminThemes'));
const AdminStoreEditor = lazy(() => import('./pages/Tienda/admin/AdminStoreEditor'));
const AdminRuletaPage = lazy(() => import('./pages/admin/AdminRuletaPage'));
const AdminEncuestas = lazy(() => import('./pages/admin/AdminEncuestas'));
const AdminFechasImportantesPage = lazy(() => import('./pages/admin/AdminFechasImportantesPage'));

const AppRedirect = lazy(() => import('./pages/AppRedirect'));

// ── Cuenta ────────────────────────────────────────────────────────────────────
const CuentaLayout = lazy(() => import('./pages/CuentaLayout'));
const PerfilPage = lazy(() => import('./pages/cuenta/PerfilPage'));
const CuentaPedidosPage = lazy(() => import('./pages/cuenta/CuentaPedidosPage'));
const MisCreacionesPage = lazy(() => import('./pages/cuenta/MisCreacionesPage'));
const CuentaReferidosPage = lazy(() => import('./pages/cuenta/CuentaReferidosPage'));
const CuentaFechasImportantesPage = lazy(() => import('./pages/cuenta/CuentaFechasImportantesPage'));
const CatalogReward = lazy(() => import('./pages/cuenta/CatalogReward'));
const WishlistPrivatePage = lazy(() => import('./pages/cuenta/WishlistPage'));
const WishlistPublicPage = lazy(() => import('./pages/WishlistPublic/WishlistPublic'));

// ── QueryClient optimizado ────────────────────────────────────────────────────
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      refetchOnWindowFocus: false,
      refetchOnMount: false,
      refetchOnReconnect: false,
      retry: 2,
      staleTime: 60 * 60 * 1000,   // 1 hour in memory
      gcTime: 24 * 60 * 60 * 1000, // 24 hours
      networkMode: 'offlineFirst', // Return cached data even offline
    },
  },
});

// ── Restricted route config for maintenance ─────────────────────────────────────
const RestrictedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  if (loading) return null;
  const isYorh = user?.email?.toLowerCase() === 'yorh001@gmail.com';
  if (isYorh) return children;
  return <Navigate to="/cuenta" replace />;
};

const GlobalLayout = ({ children }) => {
  const location = useLocation();
  const isIndependentRoute = location.pathname.startsWith('/regalos-con-amor');

  if (isIndependentRoute) {
    return (
      <div className="App independent-app">
        <main style={{ width: '100%', minHeight: '100vh', padding: 0, margin: 0 }}>
          {children}
        </main>
      </div>
    );
  }

  return (
    <div className="App">
      <NavProgressBar />
      <RouteTracker />
      <ReferralTracker />
      <AdminBar />
      <VisualEditorPanel />
      <Header />
      <main id="main-content-area">
        {children}
      </main>
      <Footer />
      <BottomNav />
      <div className="floating-action-stack">
        <WhatsAppButton />
        <KapiPet />
      </div>

      <FirebaseWarning />
    </div>
  );
};

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <CustomFontsInjector />
      {/* Prefetch silencioso en background cuando el navegador está libre */}
      <AppPrefetcher />
      <ToastProvider>
        <AuthProvider>
          <WishlistProvider>
            <VisualEditorProvider>
              <CartProvider>
                <LayoutProvider>
                  <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
                  <DeepLinkHandler />
                <GlobalLayout>
                  <ErrorBoundary>
                    <Suspense fallback={<PageLoading />}>
                      <Routes>
                        {/* Tienda abierta para todos */}
                        <Route path="/" element={<TiendaPage />} />
                        <Route path="/tienda" element={<LegacyTiendaPage />} />
                        <Route path="/encuesta-suscripcion" element={
                          <Suspense fallback={<PageLoading />}>
                            <SubscriptionSurveyPage />
                          </Suspense>
                        } />
                        <Route path="/suscripciones" element={
                          <Suspense fallback={<PageLoading />}>
                            <SubscriptionLandingPage />
                          </Suspense>
                        } />
                        <Route path="/producto/:id" element={<ProductPage />} />
                        <Route path="/personalizar" element={<PersonalizarPage />} />
                        <Route path="/editor/:id" element={<EditorPage />} />
                        <Route path="/carrito" element={<CartPage />} />
                        <Route path="/checkout" element={<CheckoutPage />} />
                        <Route path="/wishlist/:userCode" element={<WishlistPublicPage />} />
                        <Route path="/app" element={<AppRedirect />} />
                        <Route path="/descargar" element={<AppRedirect />} />

                        <Route path="/pedidos" element={<Navigate to="/cuenta/pedidos" replace />} />

                        <Route path="/cuenta" element={<CuentaLayout />}>
                          <Route index element={<Navigate to="/cuenta/pedidos" replace />} />
                          <Route path="perfil" element={<PerfilPage />} />
                          <Route path="pedidos" element={<CuentaPedidosPage />} />
                          <Route path="creaciones" element={<MisCreacionesPage />} />
                          <Route path="referidos" element={<CuentaReferidosPage />} />
                          <Route path="fechas-importantes" element={<CuentaFechasImportantesPage />} />
                          <Route path="catalogo" element={<CatalogReward />} />
                          <Route path="wishlist" element={<WishlistPrivatePage />} />
                        </Route>

                        <Route path="/admin" element={<AdminRoute />}>
                          <Route element={<AdminLayout />}>
                            <Route index element={<AdminDashboard />} />
                            <Route path="productos" element={<AdminProductos />} />
                            <Route path="inventario" element={<AdminInventario />} />
                            <Route path="mockups" element={<AdminMockups />} />
                            <Route path="productos/nuevo" element={<AdminProductoFormV2 />} />
                            <Route path="productos/:id" element={<AdminProductoFormV2 />} />
                            <Route path="categorias" element={<AdminCategorias />} />
                            <Route path="colecciones" element={<AdminColecciones />} />

                            <Route path="whatsapp" element={<AdminWhatsApp />} />
                            <Route path="referidos" element={<AdminReferidos />} />
                            <Route path="pagos" element={<AdminPagos />} />
                            <Route path="retos" element={<AdminRetos />} />
                            <Route path="destacados" element={<AdminDestacados />} />
                            <Route path="zonas" element={<Navigate to="/admin" replace />} />
                            <Route path="cliparts" element={<AdminCliparts />} />
                            <Route path="mascota" element={<AdminMascota />} />
                            <Route path="crear-cuentas-pedidos" element={<AdminCrearCuentasPedidos />} />
                            <Route path="usuarios-analytics" element={<AdminUsuariosAnalyticsPage />} />
                            <Route path="wordle" element={<AdminWordlePage />} />
                            <Route path="notificaciones" element={<AdminNotifications />} />
                            <Route path="marcas" element={<AdminMarcas />} />
                            <Route path="landing-pages" element={<AdminLandingPages />} />
                            <Route path="temas" element={<AdminThemes />} />
                            <Route path="store-editor" element={<AdminStoreEditor />} />
                            <Route path="ruleta" element={<AdminRuletaPage />} />
                            <Route path="backups" element={<AdminBackups />} />
                            <Route path="configuracion" element={<AdminConfiguracion />} />
                            <Route path="encuestas" element={<AdminEncuestas />} />
                            <Route path="fechas-importantes" element={<AdminFechasImportantesPage />} />
                          </Route>
                        </Route>

                        <Route path="/login" element={<LoginPage />} />
                        <Route path="/registro" element={<RegisterPage />} />
                        <Route path="/completar-perfil" element={<CompleteProfilePage />} />
                        <Route path="/palabra-del-dia" element={<WordlePage />} />
                        <Route path="/minijuegos" element={<MinijuegosPage />} />
                        <Route path="/ruleta" element={<RuletaPage />} />
                        <Route path="/recuperar-contrasena" element={<ResetPasswordPage />} />
                        <Route path="/politicas-privacidad" element={<PoliticasPrivacidadPage />} />
                        <Route path="/terminos-y-condiciones" element={<TerminosCondicionesPage />} />
                        <Route path="/regalos-con-amor" element={<NuevosUsuariosPage />} />
                        <Route path="/nuevos-usuarios" element={<Navigate to="/regalos-con-amor" replace />} />
                        <Route path="/regalo/:orderId" element={<GiftExperiencePage />} />
                        
                        {/* Dynamic Landing Pages Interceptor */}
                        <Route path="/:slug" element={<DynamicLandingPage />} />
                        
                        <Route path="*" element={<Navigate to="/cuenta" replace />} />
                      </Routes>
                    </Suspense>
                  </ErrorBoundary>
                </GlobalLayout>
                </Router>
                </LayoutProvider>
              </CartProvider>
            </VisualEditorProvider>
          </WishlistProvider>
        </AuthProvider>
      </ToastProvider>
    </QueryClientProvider>
  );
}

export default App;
// Force dev server update

import React from 'react';
import { Navigate, Outlet } from 'react-router-dom';
import { Capacitor } from '@capacitor/core';
import { useAuth } from '../../contexts/AuthContext';

/**
 * Ruta protegida: solo usuarios con rol admin (o email yorh001@gmail.com) pueden acceder.
 * Si no hay usuario → redirige a login. Si no es admin → redirige a inicio.
 */
const AdminRoute = () => {
  const { user, loading, isAdmin } = useAuth();

  if (loading) {
    return (
      <div style={{ padding: '2rem', textAlign: 'center' }}>
        <span>Verificando acceso...</span>
      </div>
    );
  }

  if (!user && !isAdmin) {
    return <Navigate to="/login" replace />;
  }

  if (!isAdmin) {
    return <Navigate to="/" replace />;
  }

  return <Outlet />;
};

export default AdminRoute;

import React, { useState } from 'react';
import ImageGallery from '../ImageGallery';
import Timeline from '../Timeline';
import DetalleEtapaModal from '../Timeline/DetalleEtapaModal';
import Modal from '../common/Modal';
import HistorialPagos from './HistorialPagos';
import { useQuery } from '@tanstack/react-query';
import { getMessage } from '../../services/messages';
import { getEtapaBadgeLabel, ETAPAS_TIMELINE, estadoToKey, getQueueStage } from '../../utils/constants';
import { useAuth } from '../../contexts/AuthContext';
import { showFlyingCoins } from '../../utils/animations';
import { ChevronDown, ChevronUp, CheckCircle2, AlertTriangle, User, MapPin, Building, Flag, AlertCircle, ShoppingCart } from 'lucide-react';
import { listFilesInFolder } from '../../services/firebase/storage';
import styles from './PedidoCard.module.css';

const DEUDA_IMPRESION_MENSAJE = 'STOP... TIENES UNA DEUDA PENDIENTE, POR FAVOR REALIZA TU PAGO PARA QUE TU PEDIDO PUEDA CONTINUAR AVANZANDO';

const PedidoCard = ({ pedido, onImageClick, brandsMap }) => {
  const { userProfile, claimMonedas } = useAuth();
  const [isExpanded, setIsExpanded] = useState(false);
  const [etapaModal, setEtapaModal] = useState(null);
  const [showDeudaImpresionModal, setShowDeudaImpresionModal] = useState(false);
  const [showPagoModal, setShowPagoModal] = useState(false);
  const [showHistorialModal, setShowHistorialModal] = useState(false);
  const [showBoletaModal, setShowBoletaModal] = useState(false);
  const [boletas, setBoletas] = useState([]);
  const [loadingBoletas, setLoadingBoletas] = useState(false);
  const [boletaError, setBoletaError] = useState(null);
  const [claimingCoins, setClaimingCoins] = useState(false);
  const [boletasEnvio, setBoletasEnvio] = useState(null);
  const [loadingBoletasEnvio, setLoadingBoletasEnvio] = useState(false);

  const completedEstados = ['finalizado', 'entregado', 'completado'];
  const isCompleted = completedEstados.includes(estadoToKey(pedido.estadoGeneral));
  const reclamadas = userProfile?.monedasReclamadas || [];
  const canClaimCoins = isCompleted && !reclamadas.includes(pedido.id);

  const handleClaimCoins = async (e) => {
    e.stopPropagation();
    if (claimingCoins) return;
    setClaimingCoins(true);
    try {
      const rect = e.target.getBoundingClientRect();
      const x = rect.left + rect.width / 2;
      const y = rect.top;
      const res = await claimMonedas(pedido.id, 10);
      if (!res.error) showFlyingCoins(x, y);
    } finally {
      setClaimingCoins(false);
    }
  };

  const { data: configPagos } = useQuery({
    queryKey: ['user-pagos-config'],
    queryFn: async () => {
      const [yapeNum, yapeName, plinNum, plinName, waPagos, waFallback, waText] = await Promise.all([
        getMessage('yape_number'), getMessage('yape_name'), getMessage('plin_number'), getMessage('plin_name'), 
        getMessage('whatsapp_number_pagos'), getMessage('whatsapp_number_cuenta'), getMessage('whatsapp_text_pagos')
      ]);
      return {
        yape_number: yapeNum.data?.trim() || '',
        yape_name: yapeName.data?.trim() || '',
        plin_number: plinNum.data?.trim() || '',
        plin_name: plinName.data?.trim() || '',
        whatsapp_pagos: waPagos.data?.trim() || waFallback.data?.trim() || '',
        whatsapp_pagos_text: waText.data || 'Hola, quiero pagar mi saldo pendiente del pedido *#{id}*. Adjunto mi comprobante por S/ *{monto}*.',
      };
    },
    enabled: !!pedido.conDeuda,
  });

  const getMarcaLogoPath = (marcaName) => {
    if (!marcaName || typeof marcaName !== 'string') return '/logo-wala.svg';
    const targetName = marcaName.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim();
    if (brandsMap && brandsMap.has(targetName)) return brandsMap.get(targetName);
    return '/logo-wala.svg';
  };

  const handleDeudaClick = (e) => {
    e.stopPropagation();
    if (pedido.conDeuda) setShowPagoModal(true);
  };

  const enviarComprobanteWA = () => {
    if (!configPagos?.whatsapp_pagos) return;
    const cleanNum = configPagos.whatsapp_pagos.replace(/[^\d\+]/g, '');
    const num = cleanNum.startsWith('+') ? cleanNum : `+51${cleanNum}`;
    let baseText = configPagos.whatsapp_pagos_text;
    baseText = baseText.replace('{id}', pedido.id).replace('{monto}', pedido.montoDeuda ?? '0.00');
    const link = `https://wa.me/${num.replace('+', '')}?text=${encodeURIComponent(baseText)}`;
    window.open(link, '_blank');
  };

  const handleVerBoleta = async (e) => {
    e.stopPropagation();
    setShowBoletaModal(true);
    if (boletas.length === 0) {
      setLoadingBoletas(true);
      setBoletaError(null);
      const { urls, error } = await listFilesInFolder(`00${pedido.id}`);
      setLoadingBoletas(false);
      if (error) {
        setBoletaError(error);
      } else {
        setBoletas(urls);
      }
    }
  };

  const toggleExpanded = () => {
    const nextExpanded = !isExpanded;
    setIsExpanded(nextExpanded);
    if (nextExpanded && estadoToKey(pedido.estadoGeneral) === 'impresion' && pedido.conDeuda) {
      setShowDeudaImpresionModal(true);
    }
    if (nextExpanded && boletasEnvio === null) {
      fetchBoletasEnvio();
    }
  };

  const fetchBoletasEnvio = async () => {
    setLoadingBoletasEnvio(true);

    // 1. Priorizar lectura rápida desde Firestore (según boletas_envio_storage.md)
    if (pedido.reparto?.boletasEnvio && Array.isArray(pedido.reparto.boletasEnvio) && pedido.reparto.boletasEnvio.length > 0) {
      const urlsFromFirestore = pedido.reparto.boletasEnvio.map(b => b.url || b);
      setBoletasEnvio(urlsFromFirestore);
      setLoadingBoletasEnvio(false);
      return;
    }

    // 2. Fallback: buscar en Storage directamente (para compatibilidad con datos legacy)
    let { urls, error } = await listFilesInFolder(`boletas_envio/00${pedido.id}`);
    if (error || urls.length === 0) {
      const fallback = await listFilesInFolder(`boletas_envio/${pedido.id}`);
      urls = fallback.urls || [];
    }
    setBoletasEnvio(urls);
    setLoadingBoletasEnvio(false);
  };

  const badgeLabel = getEtapaBadgeLabel(pedido.estadoGeneral);
  
  const getBadgeColor = (estadoKey) => {
    switch(estadoKey) {
       case 'finalizado': return '#10b981'; // emerald-500
       case 'reparto': case 'impresion': return '#3b82f6'; // blue-500
       case 'preparacion': case 'preparación': return '#eab308'; // yellow-500
       case 'estampado': return '#f97316'; // orange-500
       case 'empaquetado': return '#14b8a6'; // teal-500
       case 'anulado': return '#ef4444'; // red-500
       default: return '#8b5cf6'; // violet-500 (pendiente/diseno)
    }
  };
  const badgeBg = getBadgeColor(estadoToKey(pedido.estadoGeneral));

  const notes = pedido.detallesEtapas?.compra?.observación || pedido.observacion || '';



  return (
    <div className={styles.card}>
      {/* 1. Header (Siempre visible) */}
      <div className={styles.cardHeader} onClick={toggleExpanded}>
        <div className={styles.headerLeft}>
          <div className={styles.marcaBadgeContainer} title={pedido.marca ? `Marca: ${pedido.marca}` : 'Marca: Walá'}>
            <div className={styles.marcaBadge}>
              <img 
                src={getMarcaLogoPath(pedido.marca)} 
                alt={pedido.marca || 'Walá'} 
                className={styles.marcaLogoImg}
                onError={(e) => { e.target.onerror = null; e.target.src = '/logo-wala.svg'; }}
              />
            </div>
          </div>
          <div className={styles.headerTitleGroup}>
            <span className={styles.headerTitle}>Pedido: #{pedido.id}</span>
            {pedido.numeroColaDisplay != null && pedido.numeroColaDisplay !== '' && getQueueStage(pedido.estadoGeneral) && (
              <span className={styles.colaBadge}>🎟️ {pedido.numeroColaDisplay}</span>
            )}
          </div>
        </div>
        
        <div className={styles.headerRight}>
          <div className={styles.badgesScrollable}>
            {canClaimCoins && (
              <button 
                type="button" 
                className={`${styles.reclamarChip} ${claimingCoins ? styles.claiming : ''}`}
                onClick={handleClaimCoins}
                title="Ganar 10 monedas"
              >
               🪙 Reclamar
              </button>
            )}
            {isCompleted && !canClaimCoins && <span className={styles.canjeadoChip}>🪙 Reclamado</span>}
            
            <span className={pedido.conDeuda ? styles.deudaChipCon : styles.deudaChipSin}>
              {pedido.conDeuda ? 'DEUDA' : 'SIN DEUDA'}
            </span>

            <span className={styles.badge} style={{ backgroundColor: badgeBg }}>
              {badgeLabel}
            </span>
          </div>
          {isExpanded ? <ChevronUp size={20} className={styles.iconoChevron} /> : <ChevronDown size={20} className={styles.iconoChevron} />}
        </div>
      </div>

      {/* 2. Body (Desplegable) */}
      <div className={`${styles.cardBody} ${isExpanded ? styles.expanded : ''}`}>
        
        {/* SECCIÓN D: TIMELINE */}
        <div className={styles.sectionTitle} style={{ marginTop: 0 }}><Flag size={16} /> Etapa del Pedido</div>
        <Timeline
          fechas={pedido.fechas}
          fechaCompra={pedido.fechaCompra}
          pedido={pedido}
          onEtapaClick={(key) => setEtapaModal(key)}
        />

        {/* SECCIÓN C: GALERÍA */}
        <div className={styles.sectionDivider} />
        <div className={styles.sectionTitle}><Building size={16} /> Galería de Diseños</div>
        <ImageGallery 
          images={pedido.imageURLs} 
          onImageClick={(index) => onImageClick(pedido.imageURLs, index)}
        />

        {/* SECCIÓN A: INFORMACIÓN */}
        <div className={styles.sectionDivider} />
