          onClose={() => setEtapaModal(null)}
        >
          <DetalleEtapaModal etapaKey={etapaModal} pedido={pedido} />
        </Modal>
      )}

      <Modal
        isOpen={showDeudaImpresionModal}
        title="Aviso de impresión"
        onClose={() => setShowDeudaImpresionModal(false)}
