        <p style={{ color: '#ef4444', fontWeight: 700 }}>{DEUDA_IMPRESION_MENSAJE}</p>
        <div style={{ marginTop: '1rem', textAlign: 'center' }}>
          <button className={styles.waBoton} onClick={() => {
            setShowDeudaImpresionModal(false);
            setShowPagoModal(true);
          }}>
            Ver Detalles de Pago
          </button>
        </div>
      </Modal>

      <Modal
        isOpen={showHistorialModal}
        title={`Historial de Pagos`}
        onClose={() => setShowHistorialModal(false)}
      >
        <HistorialPagos pedido={pedido} />
      </Modal>

      <Modal
        isOpen={showPagoModal}
        title="Pagar Saldo Pendiente"
        onClose={() => setShowPagoModal(false)}
      >
        <div className={styles.modalPagoInner}>
          <p style={{ textAlign: 'center', fontSize: '1.2rem', marginBottom: '1.5rem', fontWeight: 'bold' }}>
            Monto a cancelar: <span style={{ color: '#ea580c' }}>S/ {pedido.montoDeuda ?? '0.00'}</span>
          </p>

          {!configPagos ? (
            <p style={{ textAlign: 'center', fontSize: '0.9rem', color: '#666' }}>Cargando información de pago...</p>
          ) : (
            <div className={styles.opcionesPago}>
              {configPagos.yape_number && (
                <div className={styles.metodoPago}>
                  <img src="https://i.imgur.com/gK1NpxI.png" alt="Yape" style={{ width: 60 }} />
                  <div>
                    <strong style={{ fontSize: '1.15rem', color: '#333' }}>{configPagos.yape_number}</strong>
                    {configPagos.yape_name && <p style={{ fontSize: '0.85rem', color: '#555', margin: 0 }}>{configPagos.yape_name}</p>}
                  </div>
                </div>
              )}
              {configPagos.plin_number && (
                <div className={styles.metodoPago}>
                  <img src="https://i.imgur.com/K1R9Ifn.png" alt="Plin" style={{ width: 60 }} />
                  <div>
                    <strong style={{ fontSize: '1.15rem', color: '#333' }}>{configPagos.plin_number}</strong>
                    {configPagos.plin_name && <p style={{ fontSize: '0.85rem', color: '#555', margin: 0 }}>{configPagos.plin_name}</p>}
                  </div>
                </div>
              )}

              {(!configPagos.yape_number && !configPagos.plin_number) && (
                <p style={{ textAlign: 'center', color: '#888', fontSize: '0.9rem' }}>Las cuentas de pago no están configuradas temporalmente.</p>
              )}

              <div style={{ marginTop: '1.5rem' }}>
                <p style={{ fontSize: '0.85rem', color: '#666', marginBottom: '0.5rem', textAlign: 'center' }}>
                  Una vez realizado el depósito, por favor envíanos la captura:
                </p>
                <button 
                  className={styles.waBoton}
                  onClick={enviarComprobanteWA}
                  disabled={!configPagos.whatsapp_pagos}
                  style={!configPagos.whatsapp_pagos ? { opacity: 0.5, cursor: 'not-allowed' } : {}}
                >
                   🚀 Enviar comprobante por WhatsApp
                </button>
              </div>
            </div>
          )}
        </div>
      </Modal>

      <Modal
        isOpen={showBoletaModal}
        title={`Boleta del Pedido #${pedido.id}`}
        onClose={() => setShowBoletaModal(false)}
      >
        <div style={{ padding: '1rem', textAlign: 'center' }}>
          {loadingBoletas ? (
            <p style={{ color: '#666' }}>Buscando boletas...</p>
          ) : boletaError ? (
            <p style={{ color: '#ef4444' }}>Error al cargar boletas.</p>
          ) : boletas.length === 0 ? (
            <div style={{ color: '#666', padding: '2rem 0' }}>
              <span style={{ fontSize: '3rem', opacity: 0.2, margin: '0 auto 1rem', display: 'block' }}>📄</span>
              <p>Aún no hay boletas adjuntas a este pedido.</p>
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
              {boletas.map((url, index) => (
                <div key={index} style={{ border: '1px solid #e2e8f0', borderRadius: '8px', overflow: 'hidden' }}>
                  <img src={url} alt={`Boleta ${index + 1}`} style={{ width: '100%', height: 'auto', display: 'block' }} />
                </div>
              ))}
            </div>
          )}
        </div>
      </Modal>
    </div>
  );
};

export default PedidoCard;

import React from 'react';
import { ETAPAS_TIMELINE, estadoToKey, getQueueStage } from '../../utils/constants';
import { toDirectImageUrl, toThumbnailImageUrl } from '../../utils/imageUrl';
import styles from './DetalleEtapaModal.module.css';

const TITULOS_ETAPA = Object.fromEntries(
  ETAPAS_TIMELINE.map((e) => [e.key, e.nombre])
);

/** Convierte productos (array u objeto del ERP) a texto legible, sin JSON crudo. */
function formatProductosParaModal(productos) {
  if (productos == null) return null;
  if (typeof productos === 'string') return productos;
  if (Array.isArray(productos)) {
    const lineas = productos.map((p) => {
      if (p == null) return '';
      if (typeof p === 'string') return p;
      if (typeof p === 'object') {
        const cant = p.cantidad ?? p.cant;
        const nombre = p.producto ?? p.nombre ?? p.productoId ?? '';
        if (cant != null && nombre) return `${cant} × ${nombre}`;
        if (nombre) return nombre;
        return Object.entries(p)
          .filter(([, v]) => v != null && v !== '')
          .map(([k, v]) => `${k}: ${v}`)
          .join(', ');
      }
      return String(p);
    });
    return lineas.filter(Boolean).join(' · ') || null;
  }
  if (typeof productos === 'object') {
    const cant = productos.cantidad ?? productos.cant;
    const nombre = productos.producto ?? productos.nombre ?? productos.productoId;
    if (cant != null && nombre) return `${cant} × ${nombre}`;
    if (nombre) return String(nombre);
    return Object.entries(productos)
      .filter(([, v]) => v != null && v !== '')
      .map(([k, v]) => `${k}: ${v}`)
      .join(', ');
  }
  return null;
}

function Fila({ label, value }) {
  const display = value != null && value !== '' ? String(value) : 'Pendiente';
  return (
    <div className={styles.fila}>
      <dt className={styles.label}>{label}</dt>
      <dd className={styles.valor}>{display}</dd>
    </div>
  );
}

function Seccion({ titulo, children }) {
  if (!children) return null;
  return (
    <section className={styles.seccion}>
      <h4 className={styles.seccionTitulo}>{titulo}</h4>
      {children}
    </section>
  );
}

function DesignImageWithFallback({ url, index }) {
  const handleError = (e) => {
    const target = e.target;
    if (target.dataset.fallbackTried) return;
    target.dataset.fallbackTried = '1';
    const fallback = toThumbnailImageUrl(url);
    if (fallback && fallback !== target.src) target.src = fallback;
  };
  return (
    <a href={url} target="_blank" rel="noopener noreferrer" className={styles.imgLink}>
      <img
        src={toDirectImageUrl(url)}
        alt={`Diseño ${index + 1}`}
        className={styles.miniImg}
        loading="lazy"
        onError={handleError}
      />
    </a>
  );
}

export default function DetalleEtapaModal({ etapaKey, pedido }) {
  const detalles = pedido?.detallesEtapas ?? {};
  const d = detalles[etapaKey] ?? {};

  const currentKey = getQueueStage(pedido?.estadoGeneral);
  const showQueue = currentKey === etapaKey && pedido?.numeroColaDisplay != null && pedido?.numeroColaDisplay !== '';
  
  const queueBadge = showQueue ? (
    <div className={styles.colaContainer}>
      <span className={styles.colaBadge}>
        🎟️ COLA: {pedido.numeroColaDisplay}
      </span>
    </div>
  ) : null;

  if (etapaKey === 'compra') {
    const compra = d;
    const productosRaw = compra.productos;
    const prendas = compra.prendas ?? pedido?.tallas;
    const productosTexto = formatProductosParaModal(productosRaw);
    return (
      <div className={styles.wrapper}>
        <Seccion titulo="Fecha y hora">
          <Fila label="Fecha de compra" value={compra.fecha ?? pedido?.fechaCompra} />
        </Seccion>
        <Seccion titulo="Productos y tallas">
          <Fila label="Prendas / descripción" value={prendas} />
          <Fila label="Productos" value={productosTexto} />
          <Fila label="Cantidad" value={compra.cantidad} />
        </Seccion>
        <Seccion titulo="Venta">
          <Fila label="Vendedor" value={compra.vendedor} />
          <Fila label="Canal de venta" value={compra.canalVenta} />
          <Fila label="Monto total" value={compra.montoTotal != null ? `S/ ${compra.montoTotal}` : pedido?.montoTotal != null ? `S/ ${pedido.montoTotal}` : null} />
          <Fila label="Adelanto" value={compra.montoAdelanto != null ? `S/ ${compra.montoAdelanto}` : pedido?.montoAdelantado != null ? `S/ ${pedido.montoAdelantado}` : null} />
          <Fila label="Observación" value={compra.observación} />
        </Seccion>
      </div>
    );
  }

  if (etapaKey === 'diseno') {
    const rawUrls = d.urlImagen != null ? (Array.isArray(d.urlImagen) ? d.urlImagen : [d.urlImagen]) : (pedido?.imageURLs ?? []);
    const urls = rawUrls
      .flatMap((u) => (u != null ? String(u).trim().split(/\s+/).map((p) => p.trim()).filter(Boolean) : []))
      .filter((u) => u.length > 0);
    return (
      <div className={styles.wrapper}>
        {queueBadge}
        <Seccion titulo="Fechas">
          <Fila label="Entrada a diseño" value={d.fechaEntrada} />
          <Fila label="Salida de diseño" value={d.fechaSalida} />
        </Seccion>
        <Fila label="Diseñador asignado" value={d.diseñadorAsignado} />
        {urls.length > 0 && (
          <Seccion titulo="Imágenes">
            <div className={styles.galeria}>
              {urls.map((url, i) => (
                <DesignImageWithFallback key={i} url={url} index={i} />
              ))}
            </div>
          </Seccion>
        )}
      </div>
    );
  }

  if (etapaKey === 'impresion') {
    return (
      <div className={styles.wrapper}>
        <Seccion titulo="Fechas">
          <Fila label="Entrada" value={d.fechaEntrada} />
          <Fila label="Salida" value={d.fechaSalida} />
        </Seccion>
        <Fila label="Estado" value={d.estado} />
        <Fila label="Primer pago" value={d.pago1} />
        <Fila label="Segundo pago" value={d.pago2} />
        <Fila label="Monto pendiente" value={d.montoPendiente != null ? `S/ ${d.montoPendiente}` : null} />
      </div>
    );
  }

  if (['preparacion', 'estampado', 'empaquetado'].includes(etapaKey)) {
    return (
      <div className={styles.wrapper}>
        {queueBadge}
        <Fila label="Operador" value={d.operador} />
        <Seccion titulo="Fechas">
          <Fila label="Entrada" value={d.fechaEntrada} />
          <Fila label="Salida" value={d.fechaSalida} />
        </Seccion>
      </div>
    );
  }

  if (etapaKey === 'reparto') {
    return (
      <div className={styles.wrapper}>
        <Fila label="Repartidor" value={d.repartidor} />
        <Seccion titulo="Fechas">
          <Fila label="Entrada" value={d.fechaEntrada} />
          <Fila label="Salida" value={d.fechaSalida} />
          <Fila label="Finalizado" value={d.fechaFinalizado} />
        </Seccion>
      </div>
    );
  }

  if (etapaKey === 'finalizado') {
    return (
      <div className={styles.wrapper}>
        <Seccion titulo="Cierre">
          <Fila label="Fecha" value={d.fecha} />
        </Seccion>
        <p className={styles.mensaje}>Pedido finalizado.</p>
      </div>
    );
  }

  return (
    <div className={styles.wrapper}>
      <p className={styles.mensaje}>No hay detalles para esta etapa.</p>
    </div>
  );
}

export { TITULOS_ETAPA };

import React, { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getCuestionariosTemplates, createCuestionarioTemplate, updateCuestionarioTemplate } from '../../../services/cuestionarios';
import Button from '../../common/Button';
import AdminCuestionarioTemplateModal from '../AdminCuestionarioTemplateModal/AdminCuestionarioTemplateModal';
import styles from './AdminButtonModal.module.css';

function AdminButtonModal({ isOpen, onClose, onInsert, defaultNumber, initialData }) {
  const [buttonType, setButtonType] = useState('whatsapp');
  const [text, setText] = useState('Contactar por WhatsApp');
  const [url, setUrl] = useState('');
  const [selectedTemplate, setSelectedTemplate] = useState('');
  
  const [templateModalOpen, setTemplateModalOpen] = useState(false);
  const [editingTemplate, setEditingTemplate] = useState(null);

  const queryClient = useQueryClient();
  const { data: templatesRaw, isLoading } = useQuery({
    queryKey: ['cuestionario-templates'],
    queryFn: async () => {
      const res = await getCuestionariosTemplates();
      return res.data || [];
    },
    enabled: isOpen
  });
  const templates = templatesRaw || [];

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setButtonType(initialData.type || 'whatsapp');
        setText(initialData.text || 'Contactar por WhatsApp');
        if (initialData.type === 'cuestionario') {
          setSelectedTemplate(initialData.url.replace('cuestionario://', ''));
          setUrl('');
        } else {
          setUrl(initialData.url || '');
          setSelectedTemplate('');
        }
      } else {
        setButtonType('whatsapp');
        setText('Contactar por WhatsApp');
        
        const numClean = (defaultNumber || '').replace(/[\s\-\(\)]/g, '');
        const formatNum = numClean.startsWith('+') ? numClean.replace('+','') : '51'+numClean;
        setUrl(`https://wa.me/${formatNum}?text=Hola,%20quiero%20más%20información`);
        setSelectedTemplate('');
      }
    }
  }, [isOpen, defaultNumber, initialData]);

  const handleTypeChange = (newType) => {
    setButtonType(newType);
    if (newType === 'whatsapp') {
      setText('Contactar por WhatsApp');
      const numClean = (defaultNumber || '').replace(/[\s\-\(\)]/g, '');
      const formatNum = numClean.startsWith('+') ? numClean.replace('+','') : '51'+numClean;
      setUrl(`https://wa.me/${formatNum}?text=Hola,%20quiero%20más%20información`);
    } else if (newType === 'cuestionario') {
      setText('PAGA EN CASA');
      setUrl('');
      if (templates.length > 0) setSelectedTemplate(templates[0].id);
    } else {
      setText('Ver más detalles');
      setUrl('https://');
    }
  };

  const handleSaveTemplate = async (templateData) => {
    if (templateData.id) {
      await updateCuestionarioTemplate(templateData.id, templateData);
    } else {
      await createCuestionarioTemplate(templateData);
    }
    queryClient.invalidateQueries(['cuestionario-templates']);
    setTemplateModalOpen(false);
  };

  if (!isOpen) return null;

  const handleInsert = (e) => {
    e.preventDefault();
    if (buttonType === 'cuestionario') {
      if (!selectedTemplate) {
        alert('Por favor selecciona o crea una plantilla de cuestionario.');
        return;
      }
      if (!text) {
        alert('Por favor ingresa el texto del botón.');
        return;
      }
      onInsert({ type: buttonType, text, url: `cuestionario://${selectedTemplate}` });
      return;
    }

    if (!text || !url) {
      alert('Por favor completa todos los campos.');
      return;
    }
    onInsert({ type: buttonType, text, url });
  };

  return (
    <>
      <div className={styles.overlay} style={{ zIndex: templateModalOpen ? 10 : 10000 }}>
        <div className={styles.modal}>
          <div className={styles.header}>
            <h3 className={styles.title}>{initialData ? 'Editar Botón Personalizado' : 'Insertar Botón Personalizado'}</h3>
            <button type="button" className={styles.closeBtn} onClick={onClose}>&times;</button>
          </div>
          
          <form onSubmit={handleInsert} className={styles.form}>
            <div className={styles.field}>
              <label className={styles.label}>Tipo de Botón</label>
              <div className={styles.typeSelector}>
                <button 
                  type="button"
                  className={`${styles.typeBtn} ${buttonType === 'whatsapp' ? styles.activeWsp : ''}`}
                  onClick={() => handleTypeChange('whatsapp')}
                >
                  WhatsApp
                </button>
                <button 
                  type="button"
                  className={`${styles.typeBtn} ${buttonType === 'normal' ? styles.activeNormal : ''}`}
                  onClick={() => handleTypeChange('normal')}
                >
                  Enlace Normal
                </button>
                <button 
                  type="button"
                  className={`${styles.typeBtn} ${buttonType === 'cuestionario' ? styles.activeCuestionario : ''}`}
                  onClick={() => handleTypeChange('cuestionario')}
                >
                  Cuestionario
                </button>
              </div>
            </div>

            <div className={styles.field}>
              <label className={styles.label}>Texto del Botón</label>
              <input 
                type="text" 
                className={styles.input} 
                value={text} 
                onChange={e => setText(e.target.value)} 
                placeholder="Ej: Contactar"
                required
              />
            </div>

            {buttonType === 'cuestionario' ? (
               <div className={styles.field}>
                 <label className={styles.label}>Plantilla del Cuestionario</label>
                 <div style={{ display: 'flex', gap: '8px' }}>
                    <select 
                      className={styles.input} 
                      value={selectedTemplate} 
                      onChange={e => setSelectedTemplate(e.target.value)}
                      style={{ flex: 1 }}
                    >
                      <option value="">Selecciona una plantilla...</option>
                      {templates.map(t => (
                        <option key={t.id} value={t.id}>{t.name}</option>
                      ))}
                    </select>
                    <Button 
                      type="button" 
                      variant="outline" 
                      onClick={() => {
                        const templateToEdit = templates.find(t => t.id === selectedTemplate);
                        setEditingTemplate(templateToEdit || null);
                        setTemplateModalOpen(true);
                      }}
                    >
                       {selectedTemplate ? 'Editar' : '+ Nuevo'}
                    </Button>
                 </div>
               </div>
            ) : (
              <div className={styles.field}>
                <label className={styles.label}>Enlace (URL)</label>
                <input 
                  type="url" 
                  className={styles.input} 
                  value={url} 
                  onChange={e => setUrl(e.target.value)} 
                  placeholder="https://..."
                  required={buttonType !== 'cuestionario'}
                />
                {buttonType === 'whatsapp' && (
                  <p className={styles.hint}>Se usó tu número configurado por defecto. Puedes editar el mensaje en el enlace.</p>
                )}
              </div>
            )}

            <div className={styles.footer}>
              <Button variant="outline" type="button" onClick={onClose}>Cancelar</Button>
              <Button variant="primary" type="submit">Insertar Botón</Button>
            </div>
          </form>
        </div>
      </div>
      
      <AdminCuestionarioTemplateModal 
        isOpen={templateModalOpen}
        onClose={() => setTemplateModalOpen(false)}
        onSave={handleSaveTemplate}
        initialData={editingTemplate}
      />
    </>
  );
}

export default AdminButtonModal;

import React, { useState, forwardRef, useImperativeHandle } from 'react';
import { useQuery } from '@tanstack/react-query';
import { getProduct } from '../../../services/products';
import UnifiedComboEditor from '../UnifiedComboEditor/UnifiedComboEditor';
import { toDirectImageUrl, ensureSingleImageUrl } from '../../../utils/imageUrl';
import styles from './ComboEditor.module.css';

const ComboEditor = forwardRef(({
  comboItems = [],
  comboLayout = { orientation: 'horizontal', spacing: 20 },
  onItemsChange,
  comboItemCustomization,
  onComboItemCustomizationChange,
  onCaptureDefaultThumbnail,
  onColorChange,
  triggerCaptureRef
}, ref) => {
  useImperativeHandle(ref, () => ({}), []);

  if (comboItems.length === 0) {
    return (
      <div className={styles.empty}>
        <p>No hay productos en el combo. Añade productos desde la configuración del combo.</p>
      </div>
    );
  }

  return (
    <div className={styles.comboEditor}>
      <UnifiedComboEditor
        canEditZones={true}
        comboItems={comboItems}
        comboLayout={comboLayout}
        comboItemCustomization={comboItemCustomization}
        onComboItemCustomizationChange={onComboItemCustomizationChange}
        onCaptureDefaultThumbnail={onCaptureDefaultThumbnail}
        onColorChange={onColorChange}
        triggerCaptureRef={triggerCaptureRef}
      />
    </div>
  );
});

ComboEditor.displayName = 'ComboEditor';

const ComboPreview = forwardRef(({ comboItems, comboLayout }, ref) => {
  const [previewImages, setPreviewImages] = useState({});
  const previewRef = React.useRef(null);

  React.useImperativeHandle(ref, () => ({
    getPreviewElement: () => previewRef.current
  }), []);

  React.useEffect(() => {
    comboItems.forEach(async (item, index) => {
      try {
        const { data: product } = await getProduct(item.productId);
        if (product) {
          const view = product.customizationViews?.find((v) => v.id === item.viewId) || product.customizationViews?.[0];
          const displayColor = item.variantMapping?.color || '';
          const rawUrl = view?.imagesByColor?.[displayColor] || view?.imagesByColor?.default || product.images?.[0] || '';
          const imageUrl = ensureSingleImageUrl(rawUrl) ? toDirectImageUrl(ensureSingleImageUrl(rawUrl)) : '';
          const cacheKey = `${item.productId}-${index}-${displayColor}`;
          if (imageUrl) {
            setPreviewImages((prev) => ({ ...prev, [cacheKey]: imageUrl }));
          }
        }
      } catch (error) {
        console.error(`Error loading preview for product ${item.productId}:`, error);
      }
    });
  }, [comboItems]);

  const isHorizontal = comboLayout.orientation === 'horizontal';

  return (
    <div
      ref={previewRef}
      className={styles.preview}
      style={{
        flexDirection: isHorizontal ? 'row' : 'column',
        gap: `${comboLayout.spacing || 20}px`
      }}
    >
      {comboItems.map((item, index) => {
        const cacheKey = `${item.productId}-${index}-${item.variantMapping?.color || ''}`;
        const imageUrl = previewImages[cacheKey];
        if (!imageUrl) {
          return (
            <div key={`${item.productId}-${index}`} className={styles.previewPlaceholder}>
              Cargando...
            </div>
          );
        }
        return (
          <div
            key={`${item.productId}-${index}`}
            className={styles.previewItem}
            style={{
              transform: `scale(${item.scale || 1})`,
              flex: isHorizontal ? '0 0 auto' : '1 1 auto'
            }}
          >
            <img src={imageUrl} alt={`Producto ${index + 1}`} className={styles.previewImage} loading="lazy" />
          </div>
        );
      })}
    </div>
  );
});

ComboPreview.displayName = 'ComboPreview';

export { ComboPreview };
export default ComboEditor;

import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { getProduct } from '../../../services/products';
import { toDirectImageUrl, ensureSingleImageUrl } from '../../../utils/imageUrl';
import Button from '../../common/Button';
import styles from './ComboItemsManager.module.css';

const ComboItemsManager = ({ comboItems = [], onItemsChange, onAddItem }) => {
  const [editingIndex, setEditingIndex] = useState(null);
  const [scaleInputs, setScaleInputs] = useState({});

  const handleRemoveItem = (index) => {
    const newItems = comboItems.filter((_, i) => i !== index);
    onItemsChange(newItems);
  };

  const handleMoveUp = (index) => {
    if (index === 0) return;
    const newItems = [...comboItems];
    [newItems[index - 1], newItems[index]] = [newItems[index], newItems[index - 1]];
    newItems[index - 1].position = index - 1;
    newItems[index].position = index;
    onItemsChange(newItems);
  };

  const handleMoveDown = (index) => {
    if (index === comboItems.length - 1) return;
    const newItems = [...comboItems];
    [newItems[index], newItems[index + 1]] = [newItems[index + 1], newItems[index]];
    newItems[index].position = index;
    newItems[index + 1].position = index + 1;
    onItemsChange(newItems);
  };

  const handleScaleChange = (index, value) => {
    const numValue = parseFloat(value);
    if (isNaN(numValue) || numValue <= 0) return;
    const newItems = [...comboItems];
    newItems[index] = { ...newItems[index], scale: numValue };
    onItemsChange(newItems);
  };

  const handleDisplayColorChange = (index, color) => {
    const newItems = [...comboItems];
    newItems[index] = {
      ...newItems[index],
      variantMapping: {
        ...(newItems[index].variantMapping || {}),
        color: color || undefined
      }
    };
    onItemsChange(newItems);
  };

  const handleAllowedColorsChange = (index, allowedColors) => {
    const newItems = [...comboItems];
    const currentMapping = newItems[index].variantMapping || {};

    // Si la lista cambia, aseguramos que el color principal esté dentro de los permitidos
    let newMainColor = currentMapping.color;
    if (allowedColors.length > 0 && (!newMainColor || !allowedColors.includes(newMainColor))) {
      newMainColor = allowedColors[0];
    } else if (allowedColors.length === 0) {
      newMainColor = undefined;
    }

    newItems[index] = {
      ...newItems[index],
      variantMapping: {
        ...currentMapping,
        color: newMainColor,
        allowedColors: allowedColors.length > 0 ? allowedColors : undefined
      }
    };
    onItemsChange(newItems);
  };

  return (
    <div className={styles.manager}>
      <div className={styles.header}>
        <h4 className={styles.title}>Productos del Combo</h4>
        <Button type="button" variant="secondary" onClick={onAddItem}>
          + Añadir Producto
        </Button>
      </div>

      {comboItems.length === 0 ? (
        <div className={styles.empty}>
          <p>No hay productos en el combo. Haz clic en "Añadir Producto" para comenzar.</p>
        </div>
      ) : (
        <div className={styles.itemsList}>
          {comboItems.map((item, index) => (
            <ComboItemCard
              key={`${item.productId}-${item.viewId}-${index}`}
              item={item}
              index={index}
              onRemove={() => handleRemoveItem(index)}
              onMoveUp={index > 0 ? () => handleMoveUp(index) : null}
              onMoveDown={index < comboItems.length - 1 ? () => handleMoveDown(index) : null}
              onScaleChange={(value) => handleScaleChange(index, value)}
              onDisplayColorChange={(color) => handleDisplayColorChange(index, color)}
              onAllowedColorsChange={(colors) => handleAllowedColorsChange(index, colors)}
              scale={item.scale || 1}
            />
          ))}
        </div>
      )}
    </div>
  );
};

const ComboItemCard = ({
  item, index, onRemove, onMoveUp, onMoveDown, onScaleChange, onDisplayColorChange, onAllowedColorsChange, scale
}) => {
  const { data: product, isLoading } = useQuery({
    queryKey: ['product', item.productId],
    queryFn: async () => {
      const { data, error } = await getProduct(item.productId);
      if (error) throw new Error(error);
      return data;
    },
    enabled: !!item.productId
  });

  const view = product?.customizationViews?.find(v => v.id === item.viewId) || product?.customizationViews?.[0];
  const availableVariants = Array.isArray(product?.variants) ? product.variants : [];
  const availableColors = !availableVariants.length && product?.variants?.colors ? product.variants.colors : [];
  const variantOptions = availableVariants.length > 0 ? availableVariants : availableColors.map((c) => ({ id: c, name: c }));

  const displayColor = item.variantMapping?.color || '';
  const matchedVariant = availableVariants.find(v => v.name === displayColor);
  const viewImageRaw = matchedVariant?.imageUrl || view?.imagesByColor?.[displayColor] || product?.mainImage || view?.imagesByColor?.default || product?.images?.[0] || '';
  const viewImage = ensureSingleImageUrl(viewImageRaw) ? toDirectImageUrl(ensureSingleImageUrl(viewImageRaw)) : '';
  const productName = product?.name || 'Cargando...';

  return (
    <div className={styles.itemCard}>
      <div className={styles.itemHeader}>
        <span className={styles.itemNumber}>#{index + 1}</span>
        <div className={styles.itemActions}>
          {onMoveUp && (
            <button type="button" className={styles.actionBtn} onClick={onMoveUp} title="Mover arriba">
              ↑
            </button>
          )}
          {onMoveDown && (
            <button type="button" className={styles.actionBtn} onClick={onMoveDown} title="Mover abajo">
              ↓
            </button>
          )}
          <button type="button" className={styles.actionBtn} onClick={onRemove} title="Eliminar">
            ×
          </button>
        </div>
      </div>

      <div className={styles.itemContent}>
        {isLoading ? (
          <div className={styles.loading}>Cargando producto...</div>
        ) : (
          <>
            <div className={styles.itemThumbnail}>
              {viewImage && (
                <img
                  src={viewImage}
                  alt={productName}
                  className={styles.thumbnail}
                  loading="lazy"
                />
              )}
            </div>
            <div className={styles.itemInfo}>
              <div className={styles.itemName}>{productName}</div>
              <div className={styles.itemMeta}>
                Vista: {view?.name || 'Por defecto'}
              </div>
              {variantOptions.length > 0 && (
                <div className={styles.variantContainer}>
                  <div className={styles.colorControl}>
                    <label className={styles.fieldLabel}>Variante Principal:</label>
                    <select
                      value={displayColor}
                      onChange={(e) => onDisplayColorChange(e.target.value)}
                      className={styles.colorSelect}
                    >
                      <option value="">{availableVariants.length > 0 ? 'Sin variante...' : 'Por defecto'}</option>
                      {(item.variantMapping?.allowedColors || variantOptions.map(o => o.name)).map((name) => (
                        <option key={name} value={name}>{name}</option>
                      ))}
                    </select>
                  </div>

                  <div className={styles.allowedColorsControl}>
                    <label className={styles.fieldLabel}>Variantes Permitidas:</label>
                    <div className={styles.allowedGrid}>
                      {variantOptions.map((opt) => {
                        const isAllowed = (item.variantMapping?.allowedColors || []).includes(opt.name);
                        const order = (item.variantMapping?.allowedColors || []).indexOf(opt.name) + 1;

                        return (
                          <label
                            key={opt.id}
                            className={`${styles.allowedOption} ${isAllowed ? styles.allowedOptionActive : ''}`}
                            title={isAllowed ? `Orden en el editor: ${order}` : 'Habilitar variante'}
                          >
                            <input
                              type="checkbox"
                              checked={isAllowed}
                              onChange={(e) => {
                                const current = item.variantMapping?.allowedColors || [];
                                if (e.target.checked) {
                                  onAllowedColorsChange([...current, opt.name]);
                                } else {
                                  onAllowedColorsChange(current.filter(c => c !== opt.name));
                                }
                              }}
                              className={styles.allowedCheckbox}
                            />
                            <span className={styles.allowedName}>{opt.name || opt.id}</span>
                            {isAllowed && <span className={styles.allowedOrder}>{order}</span>}
                          </label>
                        );
                      })}
                    </div>
                  </div>
                </div>
              )}
              <div className={styles.scaleControl}>
                <label className={styles.scaleLabel}>
                  Escala:
                  <input
                    type="number"
                    min="0.1"
                    max="2"
                    step="0.1"
                    value={scale}
                    onChange={(e) => onScaleChange(e.target.value)}
                    className={styles.scaleInput}
                  />
                </label>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default ComboItemsManager;

