            const copied = JSON.parse(copiedRaw);
            const newZone = {
              ...copied,
              id: createZoneId(),
              x: Math.max(0, Math.min(100 - (copied.width || 0), copied.x + 5)),
              y: Math.max(0, Math.min(100 - (copied.height || 0), copied.y + 5))
            };
