            setSelectedZoneId(newZone.id);
            if (copied.rotation !== undefined) setRotation(prev => ({ ...prev, [newZone.id]: copied.rotation }));
            if (copied.skew) setSkew(prev => ({ ...prev, [newZone.id]: copied.skew }));
