            ...skew,
            [zoneId]: {
              skewX: updates.skewX !== undefined ? updates.skewX : (skew[zoneId]?.skewX || z.skewX || 0),
              skewY: updates.skewY !== undefined ? updates.skewY : (skew[zoneId]?.skewY || z.skewY || 0)
            }
          };
