       const submitEvidence = httpsCallable(functions, 'submitChallengeEvidence');
       await submitEvidence({
         evidenceUrl,
         challengeId: activeWeeklyChallenge.challengeId,
         evidenceType: 'link'
       });
       alert('¡Evidencia enviada! Será revisada pronto.');
       setEvidenceUrl('');
