                    setActivePrintAreaId(viewIdToUse, area.id);
                    safeRenderAll(lc);
                  }
                });
                safeRenderAll(lc);
              }
            });
            // Crear un rectángulo temporal mientras se carga
            newZone = new fabric.Rect({
              left: pa.x,
              top: pa.y,
              width: pa.width,
              height: pa.height,
              fill: fillColor,
              stroke: strokeColor,
              strokeWidth: strokeWidth,
              strokeDashArray: strokeDashArray,
              selectable: false,
              evented: showZones,
              hoverCursor: 'pointer',
              printAreaId: area.id,
              visible: showZones,
              objectCaching: false,
              strokeUniform: true,
              originX: 'left',
              originY: 'top'
            });
          } else {
            newZone = new fabric.Rect({
              left: pa.x,
              top: pa.y,
              width: pa.width,
              height: pa.height,
              fill: fillColor,
              stroke: strokeColor,
              strokeWidth: strokeWidth,
              strokeDashArray: strokeDashArray,
              selectable: false,
              evented: showZones,
              hoverCursor: 'pointer',
              printAreaId: area.id,
              visible: showZones,
              objectCaching: false,
              strokeUniform: true,
              originX: 'left',
              originY: 'top'
            });
          }
          lc.add(newZone);
          newZone.sendToBack();
          newZone.on('mousedown', (e) => {
            if (e.e && !e.e.ctrlKey && !e.e.metaKey) {
              setActivePrintAreaId(viewIdToUse, area.id);
              safeRenderAll(lc);
            }
          });
        }
      });
      safeRenderAll(lc);

      // Sincronizar layers: actualizar objetos existentes in situ para no perder selección ni modo edición
      const activeArea = activePrintAreaId
        ? printAreasToRender.find(a => a.id === activePrintAreaId)
        : null;
      const areaToUse = activeArea || printAreasToRender[0];
      const defaultPa = {
        x: (imageDimensions.padding || 0) + (imageDimensions.width * (areaToUse.x || 0)) / 100,
        y: (imageDimensions.padding || 0) + (imageDimensions.height * (areaToUse.y || 0)) / 100,
        width: (imageDimensions.width * (areaToUse.width || 40)) / 100,
        height: (imageDimensions.height * (areaToUse.height || 40)) / 100,
      };
      const defaultLeft = defaultPa.x + defaultPa.width / 2 - 50;
      const defaultTop = defaultPa.y + defaultPa.height / 2 - 25;

      const layerIds = new Set(layers.map((l) => l.id));
      const existingObjects = lc.getObjects().filter((o) => o.customId && !o.printAreaId && !o._isTintOverlay);

      // Eliminar solo los objetos cuya capa ya no existe
      existingObjects.forEach((obj) => {
        if (!layerIds.has(obj.customId)) {
          // Eliminar también el overlay de tinte si existe
          if (obj._tintOverlay) {
            try { lc.remove(obj._tintOverlay); } catch (_) { }
            obj._tintOverlay = null;
          }
          lc.remove(obj);
          if (editingTextId === obj.customId) {
            setEditingTextId(null);
            editingTextObjRef.current = null;
          }
        }
      });

      layers.forEach((rawLayer) => {
        const layer = { ...rawLayer };
        const dW = imageDimensions.width;
        const dH = imageDimensions.height;
        // Si el layer viene de otra vista (ej. con "Copiar a todos") y el tamaño original de 
        // la prenda es distinto, adaptamos coordenadas exactas proporcionalmente
        if (layer.baseW && dW && layer.baseW !== dW && layer.x != null) {
          const rX = dW / layer.baseW;
          const rY = dH / (layer.baseH || layer.baseW);
          layer.x = layer.x * rX;
          if (layer.y != null) layer.y = layer.y * rY;
          layer.scaleX = (layer.scaleX ?? 1) * rX;
          layer.scaleY = (layer.scaleY ?? 1) * rY;
        }

        const existing = lc.getObjects().find((o) => o.customId === layer.id);

        if (layer.type === 'text') {
          if (existing && (existing.type === 'i-text' || existing.type === 'text')) {
            // Actualizar in situ para no deseleccionar ni salir de edición
            const isEditing = existing.isEditing === true;
            const isGrouped = existing.group && existing.group.type === 'activeSelection';
            existing.set({
              ...(isEditing ? {} : { text: layer.text || 'Texto' }),
              fontSize: layer.fontSize || 40,
              fill: layer.color || '#000000',
              fontFamily: layer.fontFamily || 'Arial',
              fontWeight: layer.fontWeight || FONT_WEIGHT_NORMAL,
              fontStyle: layer.fontStyle || FONT_STYLE_NORMAL,
              textAlign: layer.textAlign || 'left',
              ...(isGrouped ? {} : {
                left: layer.x ?? defaultPa.x + 20,
                top: layer.y ?? defaultPa.y + 20,
                scaleX: layer.scaleX ?? 1,
                scaleY: layer.scaleY ?? 1,
                angle: layer.angle || 0,
                flipX: layer.flipX || false,
                flipY: layer.flipY || false,
              }),
              editable: !(typeof window !== 'undefined' && window.innerWidth <= 768)
            });
            existing.setCoords();
            safeRequestRenderAll(lc);
          } else {
            const TextClass = fabric.IText || fabric.Text;
            // Use saved position if it exists; only fall back to default for brand-new layers
            const initLeft = layer.x != null ? layer.x : defaultLeft;
            const initTop = layer.y != null ? layer.y : defaultTop;
            const text = new TextClass(layer.text || 'Texto', {
              left: initLeft,
              top: initTop,
              fontSize: layer.fontSize || 40,
              fill: layer.color || '#000000',
              fontFamily: layer.fontFamily || 'Arial',
              fontWeight: layer.fontWeight || FONT_WEIGHT_NORMAL,
              fontStyle: layer.fontStyle || FONT_STYLE_NORMAL,
              textAlign: layer.textAlign || 'left',
              scaleX: layer.scaleX ?? 1,
              scaleY: layer.scaleY ?? 1,
              angle: layer.angle || 0,
              flipX: layer.flipX || false,
              flipY: layer.flipY || false,
              customId: layer.id,
              editable: !(typeof window !== 'undefined' && window.innerWidth <= 768) // Previene que se abra el SO keyboard nativo en móvil
            });
            lc.add(text);
            // Only call updateLayer for truly new layers (no saved x,y)
            if (rawLayer.x == null || rawLayer.y == null) {
              updateLayer(viewIdToUse, layer.id, { x: initLeft, y: initTop, baseW: imageDimensions.width, baseH: imageDimensions.height });
            }
            if (text.isEditing !== undefined) {
              text.on('editing:entered', () => {
                setEditingTextId(layer.id);
                editingTextObjRef.current = text;
              });
              text.on('editing:exited', () => {
                updateLayer(viewIdToUse, layer.id, {
                  text: text.text,
                  fontSize: text.fontSize,
                  fontFamily: text.fontFamily || 'Arial',
                  fontWeight: text.fontWeight || FONT_WEIGHT_NORMAL,
                  fontStyle: text.fontStyle || FONT_STYLE_NORMAL,
                  color: text.fill,
                  textAlign: text.textAlign || 'left',
                  x: text.left,
                  y: text.top,
                  scaleX: text.scaleX,
                  scaleY: text.scaleY,
                  angle: text.angle,
                  baseW: imageDimensionsRef.current.width,
                  baseH: imageDimensionsRef.current.height,
                });
                setEditingTextId(null);
                editingTextObjRef.current = null;
              });
            }
          }
        } else if (layer.type === 'image' && layer.src) {
          const rawUrl = ensureSingleImageUrl(layer.src);
          const imageUrl = toDirectImageUrl(rawUrl);

          if (!imageUrl) return;
          const applyTintFilter = (fabricImg) => {
            if (!fabricImg) return;

            // Si la capa tiene color, sobreescribimos el método _render 
            // para dibujarla en un canvas virtual y aplicar source-atop sin requerir CORS
            if (layer.tintColor) {
              if (!fabricImg._originalRender) {
                fabricImg._originalRender = fabricImg._render.bind(fabricImg);
              }
              fabricImg.tintColor = layer.tintColor;
              fabricImg.tintOpacity = layer.tintOpacity ?? 1;

              fabricImg._render = function (ctx) {
                if (!this.tintColor || !this._element) {
                  this._originalRender(ctx);
                  return;
                }
                const w = this.width;
                const h = this.height;
                const offCanvas = document.createElement('canvas');
                offCanvas.width = w;
                offCanvas.height = h;
                const offCtx = offCanvas.getContext('2d');

                // 1. Dibujar imagen original
                offCtx.drawImage(this._element, 0, 0, w, h);
                // 2. Aplicar color encima de los pixeles no transparentes
                offCtx.globalCompositeOperation = 'source-atop';
                offCtx.fillStyle = this.tintColor;
                offCtx.globalAlpha = this.tintOpacity ?? 1;
                offCtx.fillRect(0, 0, w, h);

                // 3. Llevar al lienzo de FabricJS
                ctx.drawImage(offCanvas, -w / 2, -h / 2, w, h);
              };
            } else {
              // Limpiar tinte restaurando render original y eliminando estado
              if (fabricImg._originalRender) {
                fabricImg._render = fabricImg._originalRender;
                fabricImg._originalRender = undefined;
              }
              fabricImg.tintColor = null;
              fabricImg.tintOpacity = null;
            }
          };

          if (existing && existing.type === 'image') {
            const lastSrc = lastImageSrcByLayerIdRef.current[layer.id];
            if (lastSrc !== layer.src) {
              existing.setSrc(imageUrl, () => {
                const el = existing._element ?? existing.getElement?.();
                const hasValid = el && typeof el.naturalWidth === 'number' && el.naturalWidth > 0;
                const isGrouped = existing.group && existing.group.type === 'activeSelection';
                if (!isGrouped) {
                  existing.set({
                    left: layer.x ?? defaultPa.x + 20,
                    top: layer.y ?? defaultPa.y + 20,
                    scaleX: layer.scaleX ?? 1,
                    scaleY: layer.scaleY ?? 1,
                    angle: layer.angle || 0,
                    flipX: layer.flipX || false,
                    flipY: layer.flipY || false,
                  });
                }
                if (hasValid) {
                  if (layer.maskShape === 'circle') {
                    existing.clipPath = new fabric.Circle({
                      radius: Math.min(existing.width, existing.height) / 2,
                      originX: 'center',
                      originY: 'center',
                    });
                  } else if (layer.maskShape === 'square') {
                    existing.clipPath = new fabric.Rect({
                      width: existing.width,
                      height: existing.height,
                      originX: 'center',
                      originY: 'center',
                    });
                  } else {
                    existing.clipPath = null;
                  }
                }
                applyTintFilter(existing);
                existing.setCoords();
                safeRenderAll(lc);
              });
              lastImageSrcByLayerIdRef.current = { ...lastImageSrcByLayerIdRef.current, [layer.id]: layer.src };
            } else {
              const isGrouped = existing.group && existing.group.type === 'activeSelection';
              if (!isGrouped) {
                existing.set({
                  left: layer.x ?? defaultPa.x + 20,
                  top: layer.y ?? defaultPa.y + 20,
                  scaleX: layer.scaleX ?? 1,
                  scaleY: layer.scaleY ?? 1,
                  angle: layer.angle || 0,
                  flipX: layer.flipX || false,
                  flipY: layer.flipY || false,
                });
              }
              applyTintFilter(existing);
              existing.setCoords();
            }
          } else {
            const tempLayerId = layer.id;
            if (loadingImageIdsRef.current.has(tempLayerId)) return;
            loadingImageIdsRef.current.add(tempLayerId);

            fabric.Image.fromURL(imageUrl, (img) => {
              loadingImageIdsRef.current.delete(tempLayerId);
              if (!img) return;

              const el = img._element ?? img.getElement?.();
              const hasValidElement = el && typeof el.naturalWidth === 'number' && el.naturalWidth > 0;
              const hasDimensions = typeof img.width === 'number' && typeof img.height === 'number' && img.width > 0 && img.height > 0;
              if (!hasValidElement && !hasDimensions) return;
              
              // Evitar redibujar si en este milisegundo ya se instanció de alguna forma síncrona/cacheada
              if (lc.getObjects().some(o => o.customId === tempLayerId)) return;

              // Obtener estado mas actualizado para sortear la condición de carrera
              const _latestLayer = (layersByViewRef.current[viewIdToUse] || []).find(l => l.id === tempLayerId) || rawLayer;
              const safeLayer = { ..._latestLayer };
              const currentW = imageDimensionsRef.current.width;
              const currentH = imageDimensionsRef.current.height;

              if (safeLayer.baseW && currentW && safeLayer.baseW !== currentW && safeLayer.x != null) {
                  const rX = currentW / safeLayer.baseW;
                  const rY = currentH / (safeLayer.baseH || safeLayer.baseW);
                  safeLayer.x = safeLayer.x * rX;
                  if (safeLayer.y != null) safeLayer.y = safeLayer.y * rY;
                  safeLayer.scaleX = (safeLayer.scaleX ?? 1) * rX;
                  safeLayer.scaleY = (safeLayer.scaleY ?? 1) * rY;
              }

              const initLeft = safeLayer.x != null ? safeLayer.x : defaultLeft;
              const initTop = safeLayer.y != null ? safeLayer.y : defaultTop;
              img.set({
                left: initLeft,
                top: initTop,
                scaleX: safeLayer.scaleX ?? 1,
                scaleY: safeLayer.scaleY ?? 1,
                angle: safeLayer.angle || 0,
                flipX: safeLayer.flipX || false,
                flipY: safeLayer.flipY || false,
                customId: safeLayer.id,
              });
              if (_latestLayer.x == null || _latestLayer.y == null) {
                updateLayer(viewIdToUse, safeLayer.id, { x: initLeft, y: initTop, baseW: currentW, baseH: currentH });
              }
              if (safeLayer.maskShape === 'circle') {
                const clipPath = new fabric.Circle({
                  radius: Math.min(img.width, img.height) / 2,
                  originX: 'center',
                  originY: 'center',
                });
                img.clipPath = clipPath;
              } else if (safeLayer.maskShape === 'square') {
                const clipPath = new fabric.Rect({
                  width: img.width,
                  height: img.height,
                  originX: 'center',
                  originY: 'center',
                });
                img.clipPath = clipPath;
              }
              lc.add(img);
              applyTintFilter(img);
              lastImageSrcByLayerIdRef.current = { ...lastImageSrcByLayerIdRef.current, [safeLayer.id]: safeLayer.src };
              safeRenderAll(lc);
            });
          }
        } else if (layer.type === 'shape') {
          if (existing && (existing.type === 'rect' || existing.type === 'circle' || existing.type === 'triangle')) {
            const isGrouped = existing.group && existing.group.type === 'activeSelection';
            existing.set({
              fill: layer.fill || '#000000',
              stroke: layer.stroke || null,
              ...(isGrouped ? {} : {
                left: layer.x ?? defaultPa.x + 20,
                top: layer.y ?? defaultPa.y + 20,
                scaleX: layer.scaleX ?? 1,
                scaleY: layer.scaleY ?? 1,
                angle: layer.angle || 0,
                flipX: layer.flipX || false,
                flipY: layer.flipY || false,
              })
            });
            existing.setCoords();
          } else {
            // Use saved position if it exists; only fall back to default for brand-new layers
            const initLeft = layer.x != null ? layer.x : defaultLeft;
            const initTop = layer.y != null ? layer.y : defaultTop;
            const opts = {
              left: initLeft,
              top: initTop,
              fill: layer.fill || '#000000',
              stroke: layer.stroke || null,
              scaleX: layer.scaleX ?? 1,
              scaleY: layer.scaleY ?? 1,
              angle: layer.angle || 0,
              flipX: layer.flipX || false,
              flipY: layer.flipY || false,
              customId: layer.id,
            };
            let obj;
            if (layer.shapeType === 'circle') {
              obj = new fabric.Circle({ radius: layer.radius ?? 40, ...opts });
            } else if (layer.shapeType === 'rectangle') {
              obj = new fabric.Rect({ width: layer.width ?? 80, height: layer.height ?? 60, ...opts });
            } else if (layer.shapeType === 'triangle') {
              obj = new fabric.Triangle({ width: 60, height: 60, ...opts });
            } else {
              obj = new fabric.Rect({ width: 80, height: 60, ...opts });
            }
            lc.add(obj);
            // Only persist position for truly new layers (no saved x,y)
            if (rawLayer.x == null || rawLayer.y == null) {
              updateLayer(viewIdToUse, layer.id, { x: initLeft, y: initTop, baseW: imageDimensions.width, baseH: imageDimensions.height });
            }
          }
        }
      });

      // Asegurar el orden de apilamiento correcto (Z-order)
      layers.forEach((layer) => {
        const obj = lc.getObjects().find((o) => o.customId === layer.id);
        if (obj) {
          obj.bringToFront();
          // El overlay de tinte también debe estar encima de la imagen
          if (obj._tintOverlay) obj._tintOverlay.bringToFront();
        }
      });

      safeRenderAll(lc);

      if (pendingActiveLayerIdRef.current) {
        const obj = lc.getObjects().find((o) => o.customId === pendingActiveLayerIdRef.current);
        if (obj) lc.setActiveObject(obj);
        safeRequestRenderAll(lc);
        pendingActiveLayerIdRef.current = null;
      }
    } catch (err) {
      console.warn('EditorCanvas: error syncing layers', err);
    }
  }, [canvas, layers, printAreas, imageDimensions.width, imageDimensions.height, activePrintAreaId, viewIdToUse, updateLayer, editingTextId, setActivePrintAreaId]);

  const getEditingTextObject = () => {
    if (!canvas || !editingTextId) return null;
    return canvas.getObjects().find(o => o.customId === editingTextId) || editingTextObjRef.current;
  };

  useEffect(() => {
    if (!editingTextId || !containerRef.current) {
      setToolbarRect(null);
      return;
    }
    const updateRect = () => {
      if (containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        setToolbarRect({ top: rect.top, left: rect.left, width: rect.width });
      }
    };
    updateRect();
    window.addEventListener('resize', updateRect);
    window.addEventListener('scroll', updateRect, true);
    return () => {
      window.removeEventListener('resize', updateRect);
      window.removeEventListener('scroll', updateRect, true);
    };
  }, [editingTextId]);

  // Sincronizar valor del input de tamaño cuando se abre el editor de texto
  useEffect(() => {
    if (editingTextId && canvas) {
      const obj = canvas.getObjects().find(o => o.customId === editingTextId) || editingTextObjRef.current;
      setInlineFontSizeInput(String(obj?.fontSize ?? 40));
    }
  }, [editingTextId, canvas]);

  const editingLayer = editingTextId ? layers.find((l) => l.id === editingTextId) : null;
  const inlineToolbarContent = editingTextId && canvas && toolbarRect && (
    <div
      className={styles.inlineTextToolbar}
      style={{
        position: 'fixed',
        top: Math.max(8, toolbarRect.top - 52),
        left: toolbarRect.left + toolbarRect.width / 2,
        transform: 'translate(-50%, 0)',
      }}
    >
      <div className={styles.inlineToolbarGroup}>
        <span className={styles.inlineToolbarLabel}>Alinear:</span>
        {[
          { value: 'left', title: 'Izquierda', svg: <path d="M0 2h20v1.5H0V2zm0 5h14v1.5H0V7zm0 5h20v1.5H0V12z" /> },
          { value: 'center', title: 'Centro', svg: <path d="M3 2h14v1.5H3V2zm1 5h12v1.5H4V7zm3 5h6v1.5H7V12z" /> },
          { value: 'right', title: 'Derecha', svg: <path d="M0 2h20v1.5H0V2zm6 5h14v1.5H6V7zM0 12h20v1.5H0V12z" /> }
        ].map(({ value, title, svg }) => {
          const currentAlign = getEditingTextObject()?.textAlign || 'left';
          const isActive = currentAlign === value;
          return (
            <button
              key={value}
              type="button"
              className={`${styles.inlineToolbarBtn} ${isActive ? styles.inlineToolbarBtnActive : ''}`}
              title={title}
              onClick={() => {
                const obj = getEditingTextObject();
                if (obj) {
                  obj.set('textAlign', value);
                  updateLayer(viewIdToUse, editingTextId, { textAlign: value });
                  safeRequestRenderAll(canvas);
                }
              }}
            >
              <svg width="18" height="14" viewBox="0 0 20 16" fill="currentColor" aria-hidden>
                {svg}
              </svg>
            </button>
          );
        })}
      </div>
      <div className={styles.inlineToolbarGroup}>
        <span className={styles.inlineToolbarLabel}>Color:</span>
        <input
          type="color"
          value={editingLayer?.color ?? getEditingTextObject()?.fill ?? '#000000'}
          onChange={(e) => {
            const obj = getEditingTextObject();
            const val = e.target.value;
            if (obj) {
              obj.set('fill', val);
              updateLayer(viewIdToUse, editingTextId, { color: val });
              safeRequestRenderAll(canvas);
            }
          }}
          className={styles.inlineColorInput}
        />
      </div>
      <div className={styles.inlineToolbarGroup}>
        <span className={styles.inlineToolbarLabel}>Estilo:</span>
        <button
          type="button"
          title="Negrita"
          className={`${styles.inlineToolbarBtn} ${(editingLayer?.fontWeight ?? getEditingTextObject()?.fontWeight ?? FONT_WEIGHT_NORMAL) === FONT_WEIGHT_BOLD ? styles.inlineToolbarBtnActive : ''}`}
          onClick={() => {
            const obj = getEditingTextObject();
            if (!obj) return;
            const next = (obj.fontWeight || FONT_WEIGHT_NORMAL) === FONT_WEIGHT_BOLD ? FONT_WEIGHT_NORMAL : FONT_WEIGHT_BOLD;
            obj.set('fontWeight', next);
            updateLayer(viewIdToUse, editingTextId, { fontWeight: next });
            safeRequestRenderAll(canvas);
          }}
        >
          <strong>B</strong>
        </button>
        <button
          type="button"
          title="Cursiva"
          className={`${styles.inlineToolbarBtn} ${(editingLayer?.fontStyle ?? getEditingTextObject()?.fontStyle ?? FONT_STYLE_NORMAL) === FONT_STYLE_ITALIC ? styles.inlineToolbarBtnActive : ''}`}
          onClick={() => {
            const obj = getEditingTextObject();
            if (!obj) return;
            const next = (obj.fontStyle || FONT_STYLE_NORMAL) === FONT_STYLE_ITALIC ? FONT_STYLE_NORMAL : FONT_STYLE_ITALIC;
            obj.set('fontStyle', next);
            updateLayer(viewIdToUse, editingTextId, { fontStyle: next });
            safeRequestRenderAll(canvas);
          }}
        >
          <em>I</em>
        </button>
      </div>
      <div className={styles.inlineToolbarGroup}>
        <span className={styles.inlineToolbarLabel}>Fuente:</span>
        <select
          value={editingLayer?.fontFamily ?? getEditingTextObject()?.fontFamily ?? 'Arial'}
          onChange={(e) => {
            const obj = getEditingTextObject();
            const val = e.target.value;
            if (obj) {
              obj.set('fontFamily', val);
              updateLayer(viewIdToUse, editingTextId, { fontFamily: val });
              safeRequestRenderAll(canvas);
            }
          }}
          className={styles.inlineFontSelect}
        >
          {EDITOR_FONTS.map((f) => (
            <option key={f} value={f}>{f}</option>
          ))}
        </select>
      </div>
      <div className={styles.inlineToolbarGroup}>
        <span className={styles.inlineToolbarLabel}>Tamaño:</span>
        <input
          type="number"
          min={8}
          max={200}
          value={inlineFontSizeInput}
          onChange={(e) => {
            setInlineFontSizeInput(e.target.value);
            const v = parseInt(e.target.value, 10);
            if (Number.isNaN(v)) return;
            const val = Math.max(8, Math.min(200, v));
            const obj = getEditingTextObject();
            if (obj) {
              obj.set('fontSize', val);
              updateLayer(viewIdToUse, editingTextId, { fontSize: val });
              safeRequestRenderAll(canvas);
            }
          }}
          onBlur={() => {
            const obj = getEditingTextObject();
            if (obj) setInlineFontSizeInput(String(obj.fontSize ?? 40));
          }}
          className={styles.inlineFontSizeInput}
        />
      </div>
    </div>
  );

  const { totalW = imageDimensions.width, totalH = imageDimensions.height, padding = 0 } = imageDimensions;
  const scaledW = Math.round(totalW * canvasScale);
  const scaledH = Math.round(totalH * canvasScale);

  const innerContent = (
    <div
      className={styles.canvasWrapper}
      style={{
        width: scaledW,
        height: scaledH,
        position: 'relative',
        overflow: 'hidden', /* Oculto estrictamente para no deformar el responsive móvil */
        borderRadius: '8px'
      }}
    >
      {/* Contenedor Único Escalado: Sincroniza imagen y canvas al 100% */}
      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: totalW,
          height: totalH,
          transform: `scale(${canvasScale})`,
          transformOrigin: 'top left',
          zIndex: 1,
        }}
      >
        {productImageDisplayUrl && (
          <img
            src={productImageDisplayUrl}
            alt=""
            className={styles.fallbackProductImage}
            style={{
              position: 'absolute',
              top: padding,
              left: padding,
              width: imageDimensions.width,
              height: imageDimensions.height,
              objectFit: 'contain',
              zIndex: 0,
              pointerEvents: 'none',
              display: 'block'
            }}
          />
        )}
        {/* Stable wrapper to prevent Fabric.js DOM manipulation from crashing React */}
        <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', zIndex: 1 }}>
          <canvas ref={canvasRef} className={styles.canvas} />
        </div>
      </div>
    </div>
  );

  return (
    <>
      <div ref={containerRef} className={styles.canvasContainer}>
        {/* Imagen de referencia CSS invisible: usa max-width:100% igual que PrintAreasEditor.
            Su offsetWidth se usa para calcular canvasScale, garantizando tamaños idénticos en ambas pestañas. */}
        {productImageDisplayUrl && (
          <img
            ref={cssImgRef}
            src={productImageDisplayUrl}
            alt=""
            aria-hidden="true"
            onLoad={() => { if (updateScaleRef.current) updateScaleRef.current(); }}
            style={{
              display: 'block',
              width: 'auto',
              maxWidth: '100%',
              height: 'auto',
              maxHeight: '100%',
              objectFit: 'contain',
              opacity: 0,
              pointerEvents: 'none',
              position: 'absolute',
              top: 0,
              left: 0,
              zIndex: -1,
            }}
          />
        )}
        {innerContent}
      </div>
      {viewId === activeViewId && inlineToolbarContent && createPortal(inlineToolbarContent, document.body)}
    </>
  );
};

export default EditorCanvas;

import React, { useState, useRef, useCallback } from 'react';
import { useEditor } from '../../../contexts/EditorContext';
import { toDirectImageUrl, ensureSingleImageUrl } from '../../../utils/imageUrl';
import { makeColorTransparent } from '../../../utils/imageBackgroundRemoval';
import { uploadFromDataUrl } from '../../../services/firebase/storage';
import { useAuth } from '../../../contexts/AuthContext';
import styles from './ImageProperties.module.css';

const MASK_OPTIONS = [
  { value: '', label: 'Ninguna' },
  { value: 'circle', label: 'Circular' },
  { value: 'square', label: 'Cuadrado' },
];

const ImageProperties = ({ layerId }) => {
  const { layers, updateLayer, canvas, product } = useEditor();
  const { user, isAdmin } = useAuth();
  const layer = layers.find((l) => l.id === layerId);
  const [cropOpen, setCropOpen] = useState(false);
  const [cropData, setCropData] = useState(null);
  const imgRef = useRef(null);
  const cropOverlayRef = useRef(null);
  const [removeBgColor, setRemoveBgColor] = useState('#FFFFFF');
  const [removeBgTolerance, setRemoveBgTolerance] = useState(25);
  const [removeBgApplying, setRemoveBgApplying] = useState(false);
  const [removeBgError, setRemoveBgError] = useState(null);

  const handleCropApply = useCallback(() => {
    if (!layer?.src || !imgRef.current || !cropData) return;
    const img = imgRef.current;
    const naturalW = img.naturalWidth || img.width;
    const naturalH = img.naturalHeight || img.height;
    const x = Math.round(cropData.x * naturalW);
    const y = Math.round(cropData.y * naturalH);
    const w = Math.round(cropData.w * naturalW);
    const h = Math.round(cropData.h * naturalH);

    const canvas = document.createElement('canvas');
    canvas.width = w;
    canvas.height = h;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(img, x, y, w, h, 0, 0, w, h);
    const dataUrl = canvas.toDataURL('image/png');
    // Actualizar pantalla inmediatamente con base64 para que sea rápido
    updateLayer(layerId, { src: dataUrl });
    setCropOpen(false);

    // Subir a Storage silenciosamente para no exceder limite de 1MB en Firestore al guardar el diseño
    const uploadEditedImage = async () => {
      const userId = user?.uid || 'anonymous';
      const path = isAdmin && product?.id
        ? `products/${product.id}/designs/${Date.now()}_crop.png`
        : `designs/${userId}/${Date.now()}_crop.png`;
      const { url, error } = await uploadFromDataUrl(dataUrl, path);
      if (url && !error) {
        updateLayer(layerId, { src: url });
      }
    };
    uploadEditedImage();
  }, [layer?.src, layerId, cropData, updateLayer, user, isAdmin, product]);

  const handleRemoveBackground = useCallback(async () => {
    const srcStr = layer ? ensureSingleImageUrl(layer.src) : '';
    if (!srcStr || removeBgApplying) return;
    setRemoveBgError(null);
    setRemoveBgApplying(true);
    try {
      let imageSource = toDirectImageUrl(srcStr);
      if (canvas && layerId) {
        const obj = canvas.getObjects().find((o) => o.customId === layerId);
        if (obj && obj.type === 'image' && typeof obj.toDataURL === 'function') {
          try {
            imageSource = obj.toDataURL({ format: 'png' });
          } catch (_) { }
        }
      }
      const dataUrl = await makeColorTransparent(
        imageSource,
        removeBgColor,
        removeBgTolerance,
        1200
      );

      // Mostrar rápidamente base64
      updateLayer(layerId, { src: dataUrl });

      // Subir asíncronamente a Storage para evitar límite de Firebase Firestore (1MB)
      const uploadEditedImage = async () => {
        const userId = user?.uid || 'anonymous';
        const path = isAdmin && product?.id
          ? `products/${product.id}/designs/${Date.now()}_nobg.png`
          : `designs/${userId}/${Date.now()}_nobg.png`;
        const { url, error } = await uploadFromDataUrl(dataUrl, path);
        if (url && !error) {
          updateLayer(layerId, { src: url });
        }
      };
      uploadEditedImage();
    } catch (err) {
      setRemoveBgError(err?.message || 'No se pudo quitar el fondo');
    } finally {
      setRemoveBgApplying(false);
    }
  }, [layer, layerId, removeBgColor, removeBgTolerance, updateLayer, removeBgApplying, canvas]);

  if (!layer || layer.type !== 'image') return null;

  const imageUrlForLayer = toDirectImageUrl(ensureSingleImageUrl(layer.src));
  const canEditImage = Boolean(imageUrlForLayer);

  const handleMaskChange = (e) => {
    const value = e.target.value;
    updateLayer(layerId, { maskShape: value || undefined });
  };

  const handleCropStart = () => {
    setCropOpen(true);
    setCropData({ x: 0.1, y: 0.1, w: 0.8, h: 0.8 });
  };

  const handleTintColorChange = (e) => {
    const val = e.target.value;
    if (!val) {
      updateLayer(layerId, { tintColor: undefined, tintOpacity: undefined });
      return;
    }
    updateLayer(layerId, {
      tintColor: val,
      tintOpacity: layer.tintOpacity ?? 1, // 1.0 por defecto para color sólido (ideal para cliparts)
    });
  };

  const handleTintOpacityChange = (e) => {
    const val = Number(e.target.value) / 100;
    updateLayer(layerId, { tintOpacity: val });
  };

  const clearTint = () => {
    updateLayer(layerId, { tintColor: undefined, tintOpacity: undefined });
  };

  return (
    <div className={styles.wrapper}>
      <div className={styles.field}>
        <label>Máscara de forma:</label>
        <select value={layer.maskShape || ''} onChange={handleMaskChange} className={styles.select}>
          {MASK_OPTIONS.map((opt) => (
            <option key={opt.value || 'none'} value={opt.value}>
              {opt.label}
            </option>
          ))}
        </select>
      </div>
      <div className={styles.field}>
        <button type="button" className={styles.cropButton} onClick={handleCropStart} disabled={!canEditImage}>
          Recortar imagen
        </button>
      </div>

      <div className={styles.section}>
        <h4 className={styles.sectionTitle}>Quitar fondo</h4>
        <p className={styles.hint}>Elige el color del fondo a eliminar (p. ej. blanco) y la tolerancia.</p>
        {!canEditImage && <p className={styles.errorText}>Esta imagen no tiene una URL válida para editar.</p>}
        <div className={styles.field}>
          <label>Color a quitar:</label>
          <input
            type="color"
            value={removeBgColor}
            onChange={(e) => setRemoveBgColor(e.target.value)}
            className={styles.colorInput}
            disabled={!canEditImage}
          />
          <span className={styles.colorHex}>{removeBgColor}</span>
        </div>
        <div className={styles.field}>
          <label>Tolerancia: {removeBgTolerance}%</label>
          <input
            type="range"
            min="0"
            max="100"
            value={removeBgTolerance}
            onChange={(e) => setRemoveBgTolerance(Number(e.target.value))}
            className={styles.range}
            disabled={!canEditImage}
          />
        </div>
        {removeBgError && <p className={styles.errorText}>{removeBgError}</p>}
        <button
          type="button"
          className={styles.cropButton}
          onClick={handleRemoveBackground}
          disabled={removeBgApplying || !canEditImage}
        >
          {removeBgApplying ? 'Aplicando...' : 'Aplicar quitar fondo'}
        </button>
      </div>

      <div className={styles.section}>
        <h4 className={styles.sectionTitle}>Color (Cliparts e Imágenes)</h4>
        <p className={styles.hint}>Reemplaza el color de un clipart/dibujo o aplica un tinte a las fotos.</p>
        <div className={styles.field}>
          <label>Color a aplicar:</label>
          <div className={styles.tintRow}>
            <input
              type="color"
              value={layer.tintColor || '#000000'}
              onChange={handleTintColorChange}
              className={styles.colorInput}
            />
            <span className={styles.colorHex}>{layer.tintColor ? layer.tintColor : 'Original'}</span>
            {!layer.tintColor && (
              <button
                type="button"
                className={styles.cropButton}
                onClick={() => updateLayer(layerId, { tintColor: '#000000', tintOpacity: 1 })}
                style={{ padding: '0.4rem', marginLeft: 'auto', minHeight: 'auto' }}
              >
                Colorear
              </button>
            )}
          </div>
        </div>
        {layer.tintColor && (
          <div className={styles.field}>
            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.75rem' }}>
              <button
                type="button"
                className={styles.cropButton}
                onClick={() => updateLayer(layerId, { tintOpacity: 1 })}
                style={{ flex: 1, padding: '0.4rem', fontSize: '12px', minHeight: 'auto', background: layer.tintOpacity === 1 ? '#eee' : 'transparent', color: '#333', borderColor: layer.tintOpacity === 1 ? '#333' : '#ccc' }}
              >
                Color sólido
              </button>
              <button
                type="button"
                className={styles.cropButton}
                onClick={() => updateLayer(layerId, { tintOpacity: 0.5 })}
                style={{ flex: 1, padding: '0.4rem', fontSize: '12px', minHeight: 'auto', background: layer.tintOpacity !== 1 ? '#eee' : 'transparent', color: '#333', borderColor: layer.tintOpacity !== 1 ? '#333' : '#ccc' }}
              >
                Tinte suave
              </button>
              <button
                type="button"
                className={styles.cropButton}
                onClick={clearTint}
                style={{ flex: 1, padding: '0.4rem', fontSize: '12px', minHeight: 'auto', background: '#fff0f0', color: '#b4171e', borderColor: '#ffcccc' }}
              >
                Quitar
              </button>
            </div>
            <label>Opacidad / Mezcla: {Math.round((layer.tintOpacity ?? 1) * 100)}%</label>
            <input
              type="range"
              min="0"
              max="100"
              value={(layer.tintOpacity ?? 1) * 100}
              onChange={handleTintOpacityChange}
              className={styles.range}
            />
          </div>
        )}
      </div>

      {cropOpen && imageUrlForLayer && (
        <div className={styles.modalBackdrop} onClick={() => setCropOpen(false)}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <h4>Recortar</h4>
            <p className={styles.hint}>Ajusta el área. La imagen se recortará al aplicar.</p>
            <div className={styles.cropPreview}>
              <img
                ref={imgRef}
                src={imageUrlForLayer}
                alt=""
                crossOrigin="anonymous"
                onLoad={() => setCropData((d) => d || { x: 0.1, y: 0.1, w: 0.8, h: 0.8 })}
              />
              {cropData && (
                <div
                  ref={cropOverlayRef}
                  className={styles.cropOverlay}
                  style={{
                    left: `${cropData.x * 100}%`,
                    top: `${cropData.y * 100}%`,
                    width: `${cropData.w * 100}%`,
                    height: `${cropData.h * 100}%`,
                  }}
                />
              )}
            </div>
            <div className={styles.cropControls}>
              <label>X: <input type="range" min="0" max="100" value={(cropData?.x ?? 0) * 100} onChange={(e) => setCropData((d) => ({ ...d, x: Number(e.target.value) / 100 }))} /></label>
              <label>Y: <input type="range" min="0" max="100" value={(cropData?.y ?? 0) * 100} onChange={(e) => setCropData((d) => ({ ...d, y: Number(e.target.value) / 100 }))} /></label>
              <label>Ancho: <input type="range" min="10" max="100" value={(cropData?.w ?? 0.8) * 100} onChange={(e) => setCropData((d) => ({ ...d, w: Number(e.target.value) / 100 }))} /></label>
              <label>Alto: <input type="range" min="10" max="100" value={(cropData?.h ?? 0.8) * 100} onChange={(e) => setCropData((d) => ({ ...d, h: Number(e.target.value) / 100 }))} /></label>
            </div>
            <div className={styles.modalActions}>
              <button type="button" className={styles.btnSecondary} onClick={() => setCropOpen(false)}>
                Cancelar
              </button>
              <button type="button" className={styles.btnPrimary} onClick={handleCropApply}>
                Aplicar recorte
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ImageProperties;

import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import { useEditor } from '../../../contexts/EditorContext';
import { useDesignClipboard } from '../../../contexts/DesignClipboardContext';
import styles from './MobileFloatingTools.module.css';

const MobileFloatingTools = () => {
  const {
    handleUndo, handleRedo, canUndo, canRedo,
    selectedLayer, layersByView, activeViewId,
    addLayer
  } = useEditor();

  const { globalClipboard, copyLayers } = useDesignClipboard();
  const [isOpen, setIsOpen] = useState(false);

  const layers = layersByView[activeViewId] || [];
  const hasSelection = !!selectedLayer;
  const canPaste = globalClipboard && globalClipboard.length > 0;

  const onCopy = () => {
    if (!hasSelection) return;
    const layerData = layers.find(l => l.id === selectedLayer);
    if (layerData) {
      copyLayers([layerData]);
      setIsOpen(false);
    }
  };

  const onPaste = () => {
    if (!canPaste) return;
    globalClipboard.forEach(layer => {
      // Un pequeño offset para que no quede exactamente encima
      const newLayer = { ...layer, x: (layer.x || 10) + 15, y: (layer.y || 10) + 15 };
      addLayer(undefined, newLayer);
    });
    setIsOpen(false);
  };

  const onDuplicate = () => {
    if (!hasSelection) return;
    const layerData = layers.find(l => l.id === selectedLayer);
    if (layerData) {
      // Copia superficial ignorando el ID
      const { id, ...rest } = layerData;
      const newLayer = { ...rest, x: (rest.x || 10) + 15, y: (rest.y || 10) + 15 };
      addLayer(undefined, newLayer);
    }
    setIsOpen(false);
  };

  return (
    <div className={styles.container}>
      <button
        className={`${styles.fab} ${isOpen ? styles.fabActive : ''}`}
        onClick={() => setIsOpen(!isOpen)}
        title="Herramientas"
      >
        {isOpen ? (
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
        ) : (
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
        )}
      </button>

      <div className={`${styles.menu} ${isOpen ? styles.open : ''}`}>
        <button
          onClick={handleUndo}
          disabled={!canUndo}
          className={styles.toolBtn}
          title="Deshacer"
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
        </button>
        <button
          onClick={handleRedo}
          disabled={!canRedo}
          className={styles.toolBtn}
          title="Rehacer"
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 10h-10a8 8 0 00-8 8v2M21 10l-6 6m6-6l-6-6" /></svg>
        </button>

        <div className={styles.divider} />

        <button
          onClick={onCopy}
          disabled={!hasSelection}
          className={styles.toolBtn}
          title="Copiar (Requiere selección)"
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7v8a2 2 0 002 2h6M8 7V5a2 2 0 012-2h4.586a1 1 0 01.707.293l4.414 4.414a1 1 0 01.293.707V15a2 2 0 01-2 2h-2M8 7H6a2 2 0 00-2 2v10a2 2 0 002 2h8a2 2 0 002-2v-2" /></svg>
        </button>
        <button
          onClick={onPaste}
          disabled={!canPaste}
          className={styles.toolBtn}
          title="Pegar"
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
        </button>
        <button
          onClick={onDuplicate}
          disabled={!hasSelection}
          className={styles.toolBtn}
          title="Duplicar (Requiere selección)"
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
        </button>
      </div>
    </div>
  );
};

export default MobileFloatingTools;

import React, { createContext, useContext, useState, useEffect, startTransition } from 'react';
import { onAuthChange } from '../services/firebase/auth';
import { getFunctions, httpsCallable } from 'firebase/functions';
import { getDocument, updateDocument, setDocument } from '../services/firebase/firestore';
import { getAdminRoleByEmail, setAdminRole } from '../services/adminRoles';
import { getStartOfWeek, formatIsoDate } from '../services/firebase/ruleta';
import { LEGACY_USERS_COLLECTION, PORTAL_USERS_COLLECTION } from '../constants/userCollections';
import { doc, onSnapshot } from 'firebase/firestore';
import { db } from '../services/firebase/config';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth debe usarse dentro de AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [userProfile, setUserProfile] = useState(null);
  const [adminPermissions, setAdminPermissions] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeWeeklyChallenge, setActiveWeeklyChallenge] = useState(null);

  useEffect(() => {
    if (!db) return;
    const unsub = onSnapshot(doc(db, 'globals', 'activeChallenge'), (snapshot) => {
      if (snapshot.exists()) {
        setActiveWeeklyChallenge(snapshot.data());
      } else {
        setActiveWeeklyChallenge(null);
      }
    });
    return () => unsub();
  }, []);

  useEffect(() => {
    const unsubscribe = onAuthChange(async (firebaseUser) => {
      if (firebaseUser) {
        setUser(firebaseUser);
        const { data: portalDoc } = await getDocument(PORTAL_USERS_COLLECTION, firebaseUser.uid);
        
        let profileData = null;
        if (portalDoc) {
          profileData = portalDoc;
        } else {
          // Intentar obtener de legacy users si no existe en portal
          const { data: legacyDoc } = await getDocument(LEGACY_USERS_COLLECTION, firebaseUser.uid);
          profileData = legacyDoc || {
            email: firebaseUser.email,
            role: 'client'
          };
        }

        // Generar referralCode si no tiene
        if (!profileData.referralCode) {
          const newCode = 'KS-' + Math.random().toString(36).substring(2, 8).toUpperCase();
          profileData.referralCode = newCode;
          // Guardar en Firestore asíncronamente
          setDocument(PORTAL_USERS_COLLECTION, firebaseUser.uid, { referralCode: newCode });
        }

        // Fetch admin permissions if user exists
        if (firebaseUser.email) {
          const roleData = await getAdminRoleByEmail(firebaseUser.email);
          // Hardcode de super admins iniciales por si no están en DB
          if (!roleData && (firebaseUser.email === 'yorh001@gmail.com' || firebaseUser.email === 'heyeru24@gmail.com')) {
            const defaultSuperAdmin = { 
              permissions: ['superadmin'] 
            };
            setAdminPermissions(defaultSuperAdmin.permissions);
            // Auto-guardarlos en la db para que ya aparezcan en la configuración
            await setAdminRole(firebaseUser.email, { name: profileData.name || 'Admin', permissions: ['superadmin'] });
          } else {
            setAdminPermissions(roleData ? roleData.permissions || [] : []);
          }
        }

        // Update lastAppOpen if not updated today
        const todayStr = new Date().toISOString().split('T')[0];
        if (profileData.lastAppOpen !== todayStr) {
          profileData.lastAppOpen = todayStr;
          setDocument(PORTAL_USERS_COLLECTION, firebaseUser.uid, { lastAppOpen: todayStr });
        }

        setUserProfile(profileData);
      } else {
        setUser(null);
        setUserProfile(null);
        setAdminPermissions(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const updateUserProfile = React.useCallback(async (updates) => {
    if (!user) return { error: 'Usuario no autenticado' };

    const { error } = await setDocument(PORTAL_USERS_COLLECTION, user.uid, updates);
    if (error && error.includes('Firebase no está configurado')) {
      // En modo desarrollo, actualizar solo localmente
      setUserProfile(prev => ({ ...prev, ...updates }));
      return { error: null };
    }
    if (!error) {
      setUserProfile(prev => ({ ...prev, ...updates }));
    }
    return { error };
  }, [user]);

  const linkDNI = React.useCallback(async (dni, phone) => {
    return await updateUserProfile({ dni, phone });
  }, [updateUserProfile]);

  const calculateActiveCoins = React.useCallback(() => {
    if (!userProfile || !userProfile.monedasActivas) return userProfile?.monedas || 0;
    const now = new Date().toISOString();
    return userProfile.monedasActivas.reduce((acc, batch) => {
      if (batch.expiresAt > now) return acc + batch.amount;
      return acc;
    }, 0);
  }, [userProfile]);

  // Migración automática de monedas antiguas
  React.useEffect(() => {
    if (userProfile && userProfile.monedas > 0 && !userProfile.legacyCoinsMigrated) {
      const migrateCoins = async () => {
        const expDate = new Date();
        expDate.setDate(expDate.getDate() + 31); // TTL de 31 días para las antiguas
        
        const legacyBatch = {
          amount: userProfile.monedas,
          expiresAt: expDate.toISOString(),
          reason: 'Migración de monedas antiguas (TTL 31 días)'
        };
        
        try {
          await updateUserProfile({
            legacyCoinsMigrated: true,
            monedasActivas: [...(userProfile.monedasActivas || []), legacyBatch]
          });
        } catch (err) {
          console.error("Error migrating legacy coins:", err);
        }
      };
      
      migrateCoins();
    }
  }, [userProfile, updateUserProfile]);

  const earnMainCoins = React.useCallback(async (amount, reason = 'Bono', ttlDays = 90) => {
    if (!userProfile) return { error: 'No profile' };
    
    const now = new Date();
    const expirationDate = new Date(now);
    expirationDate.setDate(expirationDate.getDate() + ttlDays);
    expirationDate.setHours(23, 59, 59, 999);
    const expiresAtIso = expirationDate.toISOString();

    let monedasActivas = [...(userProfile.monedasActivas || [])];
    const existingBatchIndex = monedasActivas.findIndex(b => b.expiresAt === expiresAtIso);
    
    if (existingBatchIndex >= 0) {
      monedasActivas[existingBatchIndex] = {
        ...monedasActivas[existingBatchIndex],
        amount: monedasActivas[existingBatchIndex].amount + amount
      };
    } else {
      monedasActivas.push({
        amount,
        expiresAt: expiresAtIso,
        reason,
        createdAt: now.toISOString()
      });
    }

    const currentGlobal = userProfile.monedas || 0;
    return await updateUserProfile({
      monedas: currentGlobal + amount,
      monedasActivas
    });
  }, [userProfile, updateUserProfile]);

  const claimMonedas = React.useCallback(async (pedidoId, amount = 10) => {
    if (!userProfile) return { error: 'No profile' };
    const reclamadas = userProfile.monedasReclamadas || [];
    if (reclamadas.includes(pedidoId)) return { error: 'Ya reclamado' };
    
    try {
      const { error } = await earnMainCoins(amount, "pedido_" + pedidoId, 90);
      if (error) throw new Error(error);
      
      const nuevasReclamadas = [...reclamadas, pedidoId];
      await updateUserProfile({
        monedasReclamadas: nuevasReclamadas
      });
      
      return { error: null, data: { success: true } };
    } catch (error) {
      console.error("Error al reclamar monedas:", error);
      return { error: error.message || 'Error al procesar el reclamo' };
    }
  }, [userProfile, earnMainCoins, updateUserProfile]);

  const spendMonedas = React.useCallback(async (amount) => {
    if (!userProfile) return { error: 'No profile' };
    
    let activeCoins = calculateActiveCoins();
    if (activeCoins < amount) return { error: 'Monedas insuficientes' };

    let remainingToSpend = amount;
    const now = new Date().toISOString();
    
    // Clonar y filtrar solo los que no han expirado, ordenados por fecha de expiración (FIFO)
    let monedasActivas = [...(userProfile.monedasActivas || [])];
    
    // Ordenar: los que expiran antes van primero
    monedasActivas.sort((a, b) => a.expiresAt.localeCompare(b.expiresAt));

    for (let i = 0; i < monedasActivas.length; i++) {
      let batch = monedasActivas[i];
      if (batch.expiresAt > now && batch.amount > 0) {
        if (batch.amount >= remainingToSpend) {
          monedasActivas[i] = { ...batch, amount: batch.amount - remainingToSpend };
          remainingToSpend = 0;
          break;
        } else {
          remainingToSpend -= batch.amount;
          monedasActivas[i] = { ...batch, amount: 0 };
        }
      }
    }

    // Filtrar los que quedaron en 0 o expiraron para limpiar la DB (opcional, pero buena práctica)
    monedasActivas = monedasActivas.filter(b => b.amount > 0 && b.expiresAt > now);

    const currentMonedas = userProfile.monedas || 0;
    return await updateUserProfile({
      monedas: Math.max(0, currentMonedas - amount),
      monedasActivas
    });
  }, [userProfile, calculateActiveCoins, updateUserProfile]);

  const freezeMonedas = React.useCallback(async (amount, pseudoOrderId) => {
    if (!userProfile) return { error: 'No profile' };
    const activeCoins = calculateActiveCoins();
    if (activeCoins < amount) return { error: 'Monedas insuficientes' };
    
    const monedasEnEspera = userProfile.monedasEnEspera || 0;
    const historyEspera = userProfile.historialMonedasEspera || [];
    
    const spendRes = await spendMonedas(amount);
    if (spendRes.error) return spendRes;
    
    return await updateUserProfile({
      monedasEnEspera: monedasEnEspera + amount,
      historialMonedasEspera: [
        ...historyEspera,
        {
          orderId: pseudoOrderId,
          amount: amount,
          status: 'pending',
          date: new Date().toISOString()
        }
      ]
    });
  }, [userProfile, calculateActiveCoins, spendMonedas, updateUserProfile]);

  const processChallengeEvent = React.useCallback(async (actionType, count = 1) => {
    if (!userProfile || !activeWeeklyChallenge) return;
    
    // Si el tipo de evento coincide
    if (activeWeeklyChallenge.actionType === actionType) {
      const challengeId = activeWeeklyChallenge.challengeId;
      const currentProgress = userProfile.weeklyChallengeProgress || {};
      
      // Si ya lo completó o es de otro challenge, reseteamos/ignoramos
      if (currentProgress.challengeId !== challengeId) {
         currentProgress.challengeId = challengeId;
         currentProgress.progress = 0;
         currentProgress.completed = false;
      }
      
      if (currentProgress.completed) return; // Ya lo completó
      
      const newProgress = Math.min((currentProgress.progress || 0) + count, activeWeeklyChallenge.goal);
      const isNowCompleted = newProgress >= activeWeeklyChallenge.goal;
      
      let updates = {
         weeklyChallengeProgress: {
            challengeId,
            progress: newProgress,
            completed: isNowCompleted
         }
      };

      // Si se acaba de completar, acreditamos
      if (isNowCompleted) {
         if (activeWeeklyChallenge.rewardType === 'kapi_double_3d') {
             updates.activeMultiplier = 'kapi_double_3d';
             updates.multiplierExpiresAt = new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString();
         }
         window.dispatchEvent(new CustomEvent('weekly-challenge-completed'));
      }
      
      await updateUserProfile(updates);

      // Si es "main", acreditamos aparte para asegurar consistencia
      if (isNowCompleted && activeWeeklyChallenge.rewardType === 'main') {
          await earnMainCoins(activeWeeklyChallenge.rewardCoins, 'Reto Semanal Completado', 90);
      }
    }
  }, [userProfile, activeWeeklyChallenge, updateUserProfile, earnMainCoins]);

  const feedKapi = React.useCallback(async () => {
    if (!userProfile) return { error: 'No profile' };
    
    const todayStr = new Date().toISOString().split('T')[0];
    if (userProfile.lastKapiClaimDate === todayStr) {
      return { error: 'Ya alimentaste a Kapi hoy' };
    }
    
    const currentKapiCoins = userProfile.kapiCoins || 0;
    if (currentKapiCoins >= 31) {
      return { error: 'Límite de Kapi Coins mensual alcanzado' };
    }

    const currentHappiness = userProfile.kapiHappiness || 0;

    // Calcular racha semanal para la ruleta
    const currentWeekStart = formatIsoDate(getStartOfWeek());
    let weeklyData = userProfile.weeklyClaimsData || { weekStart: currentWeekStart, daysClaimed: [] };
    
    if (weeklyData.weekStart !== currentWeekStart) {
      // Nueva semana
      weeklyData = { weekStart: currentWeekStart, daysClaimed: [todayStr] };
    } else {
      // Misma semana
      if (!weeklyData.daysClaimed.includes(todayStr)) {
        weeklyData.daysClaimed.push(todayStr);
      }
    }

    let coinsToAdd = 1;
    if (userProfile.activeMultiplier === 'kapi_double_3d') {
      if (userProfile.multiplierExpiresAt && new Date(userProfile.multiplierExpiresAt) > new Date()) {
         coinsToAdd = 2;
      }
    }

    return await updateUserProfile({
      kapiCoins: currentKapiCoins + coinsToAdd,
      lastKapiClaimDate: todayStr,
      kapiHappiness: Math.min(100, currentHappiness + 10),
      weeklyClaimsData: weeklyData
    });
  }, [userProfile, updateUserProfile]);

  const validateDatesStreak = React.useCallback(async (completedOrders) => {
    if (!userProfile) return { error: 'No profile' };
    
    // CompletedOrders should be an array of orders. 
    // We check how many unique special dates this user has covered.
    const coveredDates = completedOrders
      .filter(o => o.fechaEspecial || o.motivoRegalo)
      .map(o => o.fechaEspecial || o.motivoRegalo);
      
    const uniqueDates = [...new Set(coveredDates)];
    const hasReceivedBonus = userProfile.streakBonusReceived === true;
    
    // Streak: 3 fechas cubiertas = 25 bonus 90 días
    if (uniqueDates.length >= 3 && !hasReceivedBonus) {
      await earnMainCoins(25, 'Streak 3 fechas cubiertas', 90);
      return await updateUserProfile({ streakBonusReceived: true });
    }
    
    return { status: 'no_action' };
  }, [userProfile, earnMainCoins, updateUserProfile]);

  const profileIncomplete = !!user && !!userProfile && (!userProfile.dni || !userProfile.phone);

  const isLegacyAdmin = userProfile?.role === 'admin' || user?.email === 'yorh001@gmail.com' || user?.email === 'heyeru24@gmail.com' || localStorage.getItem('adminWalaPro') === 'true';
  const effectiveAdminPermissions = (adminPermissions && adminPermissions.length > 0) ? adminPermissions : (isLegacyAdmin ? ['superadmin'] : []);
  
  const isAdmin = isLegacyAdmin || effectiveAdminPermissions.length > 0;

  const value = React.useMemo(() => ({
    user,
    userProfile,
    adminPermissions: effectiveAdminPermissions,
    loading,
    updateUserProfile,
    linkDNI,
    claimMonedas,
    spendMonedas,
    freezeMonedas,
    earnMainCoins,
    feedKapi,
    validateDatesStreak,
    processChallengeEvent,
    activeWeeklyChallenge,
    activeMainCoins: calculateActiveCoins(),
    isAuthenticated: !!user,
    isAdmin,
    profileIncomplete,
  }), [user, userProfile, effectiveAdminPermissions, loading, updateUserProfile, linkDNI, claimMonedas, spendMonedas, freezeMonedas, earnMainCoins, feedKapi, validateDatesStreak, processChallengeEvent, activeWeeklyChallenge, calculateActiveCoins, profileIncomplete, isAdmin]);

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

import React, { createContext, useContext, useState, useCallback, useMemo, useRef, useEffect } from 'react';

const EditorContext = createContext();

const DEFAULT_VIEW_ID = 'default';

export const useEditor = () => {
  const context = useContext(EditorContext);
  if (!context) {
    throw new Error('useEditor debe usarse dentro de EditorProvider');
  }
  return context;
};

export const EditorProvider = ({ children }) => {
  const [layersByView, setLayersByView] = useState({});
  const [activeViewId, setActiveViewId] = useState(DEFAULT_VIEW_ID);
  const [selectedLayer, setSelectedLayer] = useState(null);
  const [canvas, setCanvas] = useState(null);
  const [product, setProduct] = useState(null);
  const [variant, setVariant] = useState({ size: '', color: '' });
  const [price, setPrice] = useState(0);
  const [activePrintAreaIdByView, setActivePrintAreaIdByView] = useState({});
  const [canvasDimensions, setCanvasDimensions] = useState({ width: 500, height: 600 });
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [clipboardLayers, setClipboardLayers] = useState([]);
  const [activeComboItem, setActiveComboItem] = useState(0);
  const [comboVariantSelections, setComboVariantSelections] = useState({});
  const [composedComboImage, setComposedComboImage] = useState(null);
  const layersByViewRef = useRef(layersByView);
  useEffect(() => { layersByViewRef.current = layersByView; }, [layersByView]);

  const layers = useMemo(
    () => (layersByView[activeViewId] ?? []),
    [layersByView, activeViewId]
  );

  const pushToHistory = useCallback((stateBeforeAction) => {
    setUndoStack((prev) => {
      // Keep only the last 10 distinct states
      const next = [...prev, JSON.parse(JSON.stringify(stateBeforeAction))];
      const maxHistory = 10;
      return next.length > maxHistory ? next.slice(-maxHistory) : next;
    });
    setRedoStack([]);
  }, []);

  const addLayer = useCallback((viewIdOrLayer, layerArg) => {
    const isLegacyCall = layerArg === undefined && viewIdOrLayer && typeof viewIdOrLayer === 'object' && viewIdOrLayer.type;
    const vId = isLegacyCall ? activeViewId : (viewIdOrLayer ?? activeViewId);
    const layer = isLegacyCall ? viewIdOrLayer : layerArg;

    pushToHistory(layersByViewRef.current);

    const newId = `layer_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    const newLayer = {
      id: newId,
      type: layer.type,
      ...layer,
    };

    setLayersByView((prev) => {
      const current = prev[vId] ?? [];
      return {
        ...prev,
        [vId]: [...current, { ...newLayer, zIndex: current.length }]
      };
    });
    return newId;
  }, [activeViewId, pushToHistory]);

  const updateLayer = useCallback((viewIdOrLayerId, layerIdOrUpdates, updatesArg) => {
    const isLegacyCall = updatesArg === undefined && typeof viewIdOrLayerId === 'string' && layerIdOrUpdates && typeof layerIdOrUpdates === 'object';
    const vId = isLegacyCall ? activeViewId : (viewIdOrLayerId ?? activeViewId);
    const layerId = isLegacyCall ? viewIdOrLayerId : layerIdOrUpdates;
    const updates = isLegacyCall ? layerIdOrUpdates : updatesArg;
    setLayersByView((prev) => ({
      ...prev,
      [vId]: (prev[vId] ?? []).map((layer) =>
        layer.id === layerId ? { ...layer, ...updates } : layer
      )
    }));
  }, [activeViewId]);

  const removeLayer = useCallback((viewIdOrLayerId, layerIdArg) => {
    const isLegacyCall = layerIdArg === undefined;
    const vId = isLegacyCall ? activeViewId : (viewIdOrLayerId ?? activeViewId);
    const layerId = isLegacyCall ? viewIdOrLayerId : layerIdArg;
    pushToHistory(layersByViewRef.current);
    setLayersByView((prev) => ({
      ...prev,
      [vId]: (prev[vId] ?? []).filter((layer) => layer.id !== layerId)
    }));
    setSelectedLayer((current) => (current === layerId ? null : current));
  }, [activeViewId, pushToHistory]);

  const transferLayer = useCallback((layerId, fromViewId, toViewId) => {
    setLayersByView((prev) => {
      const fromList = prev[fromViewId] ?? [];
      const layer = fromList.find((l) => l.id === layerId);
      if (!layer) return prev;

      const newFromList = fromList.filter((l) => l.id !== layerId);
      const toList = prev[toViewId] ?? [];
      const newLayer = { ...layer, zIndex: toList.length };

      return {
        ...prev,
        [fromViewId]: newFromList,
        [toViewId]: [...toList, newLayer]
      };
    });
    setSelectedLayer(null);
  }, []);

  const reorderLayers = useCallback((viewIdOrFromIndex, toIndexOrToIndex, toIndexArg) => {
    const isLegacyCall = toIndexArg === undefined;
    const vId = isLegacyCall ? activeViewId : (viewIdOrFromIndex ?? activeViewId);
    const fromIndex = isLegacyCall ? viewIdOrFromIndex : toIndexOrToIndex;
    const toIndex = isLegacyCall ? toIndexOrToIndex : toIndexArg;
    pushToHistory(layersByViewRef.current);
    setLayersByView((prev) => {
      const list = prev[vId] ?? [];
      const newList = [...list];
      const [moved] = newList.splice(fromIndex, 1);
      newList.splice(toIndex, 0, moved);
      return {
        ...prev,
        [vId]: newList.map((layer, index) => ({ ...layer, zIndex: index }))
      };
    });
  }, [activeViewId, pushToHistory]);

  const setLayersForView = useCallback((viewId, newLayers) => {
    setLayersByView((prev) => ({ ...prev, [viewId]: newLayers ?? [] }));
  }, []);

  const clearLayers = useCallback((viewId) => {
    const vId = viewId ?? activeViewId;
    setLayersByView((prev) => ({ ...prev, [vId]: [] }));
    setSelectedLayer(null);
  }, [activeViewId]);

  // ---- NEW: Undo / Redo / Clear All ----
  const undo = useCallback(() => {
    setUndoStack((prevUndo) => {
      if (prevUndo.length === 0) return prevUndo;
      const previousState = prevUndo[prevUndo.length - 1];
      setRedoStack((prevRedo) => [...prevRedo, JSON.parse(JSON.stringify(layersByViewRef.current))]);
      setLayersByView(previousState);
      return prevUndo.slice(0, -1);
    });
  }, []);

  const redo = useCallback(() => {
    setRedoStack((prevRedo) => {
      if (prevRedo.length === 0) return prevRedo;
      const nextState = prevRedo[prevRedo.length - 1];
      setUndoStack((prevUndo) => [...prevUndo, JSON.parse(JSON.stringify(layersByViewRef.current))]);
      setLayersByView(nextState);
      return prevRedo.slice(0, -1);
    });
  }, []);

  const clearAll = useCallback(() => {
    setLayersByView({});
    setUndoStack([]);
    setRedoStack([]);
    setSelectedLayer(null);
  }, []);

  const setLayersByViewFromDesign = useCallback((nextLayersByView) => {
    if (nextLayersByView && typeof nextLayersByView === 'object') {
      setLayersByView(nextLayersByView);
    }
  }, []);

  const calculatePrice = useCallback(() => {
    if (!product) return 0;
    let basePrice = product.basePrice || product.price || 0;
    let customizationPrice = 0;
    Object.values(layersByView).forEach((viewLayers) => {
      (viewLayers || []).forEach((layer) => {
        if (layer.type === 'text') customizationPrice += 5;
        else if (layer.type === 'image' || layer.type === 'shape') customizationPrice += 10;
      });
    });
    const finalPrice = basePrice + customizationPrice;
    setPrice(finalPrice);
    return finalPrice;
  }, [product, layersByView]);

  const activePrintAreaId = useMemo(
    () => activePrintAreaIdByView[activeViewId] || null,
    [activePrintAreaIdByView, activeViewId]
  );

  /** Posición por defecto (x, y en píxeles del canvas) para nuevos elementos: centro de la zona de impresión activa */
  const getDefaultPositionInPrintArea = useCallback(() => {
    const view = product?.customizationViews?.find((v) => v.id === activeViewId) || product?.customizationViews?.[0];
    const areas = view?.printAreas || [];
    const area = activePrintAreaId ? areas.find((a) => a.id === activePrintAreaId) : areas[0];
    const w = canvasDimensions?.width ?? 500;
    const h = canvasDimensions?.height ?? 600;
    if (!area || !w) return { x: 100, y: 100 };
    const left = (w * (area.x || 10)) / 100;
    const top = (h * (area.y || 10)) / 100;
    const zoneW = (w * (area.width || 80)) / 100;
    const zoneH = (h * (area.height || 80)) / 100;
    return { x: Math.round(left + zoneW / 2 - 50), y: Math.round(top + zoneH / 2 - 25) };
  }, [product?.customizationViews, activeViewId, activePrintAreaId, canvasDimensions]);

  const setActivePrintAreaId = useCallback((viewIdOrAreaId, areaIdArg) => {
    const isLegacyCall = areaIdArg === undefined;
    const vId = isLegacyCall ? activeViewId : (viewIdOrAreaId ?? activeViewId);
    const areaId = isLegacyCall ? viewIdOrAreaId : areaIdArg;
    setActivePrintAreaIdByView((prev) => ({
      ...prev,
      [vId]: areaId
    }));
  }, [activeViewId]);

  const clearActivePrintAreaId = useCallback((viewId) => {
    const vId = viewId ?? activeViewId;
    setActivePrintAreaIdByView((prev) => {
      const next = { ...prev };
      delete next[vId];
      return next;
    });
  }, [activeViewId]);

  const handleUndo = useCallback(() => {
    setUndoStack((prev) => {
      if (prev.length === 0) return prev;
      const previousState = prev[prev.length - 1];
      setLayersByView(JSON.parse(JSON.stringify(previousState)));
      setRedoStack((redo) => [...redo, JSON.parse(JSON.stringify(layersByViewRef.current))]);
      return prev.slice(0, -1);
    });
  }, []);

  const handleRedo = useCallback(() => {
    setRedoStack((prev) => {
      if (prev.length === 0) return prev;
      const nextState = prev[prev.length - 1];
      setLayersByView(JSON.parse(JSON.stringify(nextState)));
      setUndoStack((undo) => [...undo, JSON.parse(JSON.stringify(layersByViewRef.current))]);
      return prev.slice(0, -1);
    });
  }, []);

  const canUndo = undoStack.length > 0;
  const canRedo = redoStack.length > 0;

  const updateComboVariant = useCallback((itemIndex, variant) => {
    setComboVariantSelections((prev) => ({
      ...prev,
      [itemIndex]: variant
    }));
  }, []);

  const regenerateComboImage = useCallback(() => {
    // Esta función se implementará cuando se integre con useComboImageComposer
    // Por ahora, se maneja en ComboUserEditor
  }, []);

  const value = useMemo(() => ({
    layers,
    layersByView,
    setLayersByView,
    setLayersForView,
    setLayersByViewFromDesign,
    activeViewId,
    setActiveViewId,
    selectedLayer,
    setSelectedLayer,
    canvas,
    setCanvas,
    product,
    variant,
    setProduct,
    setVariant,
    price,
    addLayer,
    transferLayer,
    updateLayer,
    removeLayer,
    reorderLayers,
    clearLayers,
    calculatePrice,
    activePrintAreaId,
    setActivePrintAreaId,
    clearActivePrintAreaId,
    activePrintAreaIdByView,
    canvasDimensions,
    setCanvasDimensions,
    getDefaultPositionInPrintArea,
    pushToHistory,
    handleUndo,
    handleRedo,
    canUndo,
    canRedo,
    clipboardLayers,
    setClipboardLayers,
    activeComboItem,
    setActiveComboItem,
    comboVariantSelections,
    updateComboVariant,
    composedComboImage,
    setComposedComboImage,
    regenerateComboImage,
    // expose clearAll for resetting design
    clearAll,
  }), [
    layers,
    layersByView,
    activeViewId,
    selectedLayer,
    canvas,
    product,
    variant,
    price,
    addLayer,
    transferLayer,
    updateLayer,
    removeLayer,
    reorderLayers,
    clearLayers,
    calculatePrice,
    setLayersForView,
    setLayersByViewFromDesign,
    activePrintAreaId,
    setActivePrintAreaId,
    clearActivePrintAreaId,
    activePrintAreaIdByView,
    canvasDimensions,
    getDefaultPositionInPrintArea,
    pushToHistory,
    handleUndo,
    handleRedo,
    canUndo,
    canRedo,
    clipboardLayers,
    setClipboardLayers,
    activeComboItem,
    setActiveComboItem,
    comboVariantSelections,
    updateComboVariant,
    composedComboImage,
    setComposedComboImage,
    regenerateComboImage,
    clearAll
  ]);

  return <EditorContext.Provider value={value}>{children}</EditorContext.Provider>;
};

import { useQuery, useQueryClient } from '@tanstack/react-query';
import { getProducts, getProduct, searchProducts, getProductsByCategory } from '../services/products';

export const useProducts = (filters = [], orderBy = null) => {
  return useQuery({
    queryKey: ['products', filters, orderBy],
    queryFn: async () => {
      const { data, error } = await getProducts(filters, orderBy);
      if (error) throw new Error(error);
      return data;
    },
    staleTime: 1000 * 60 * 5, // 5 minutes (reduced from 1h for better freshness)
    gcTime: 1000 * 60 * 60 * 24 // 24 hours
  });
};

export const useProduct = (productId) => {
  const queryClient = useQueryClient();

  return useQuery({
    queryKey: ['product', productId],
    queryFn: async () => {
      const { data, error } = await getProduct(productId);
      if (error) throw new Error(error);

      // Sincronizar agresivamente el producto fresco en TODAS las cachés
      // para evitar que el usuario vuelva a ver el "diseño viejo" al retroceder o recargar.
      try {
        const updater = (old) => {
          if (!Array.isArray(old)) return old;
          return old.map(p => p.id === productId ? data : p);
        };
        queryClient.setQueriesData({ queryKey: ['products'] }, updater);
        queryClient.setQueriesData({ queryKey: ['allProducts'] }, updater);
        
        try {
          const cached = localStorage.getItem('conamor_products_cache');
          if (cached) {
            const parsed = JSON.parse(cached);
            localStorage.setItem('conamor_products_cache', JSON.stringify(updater(parsed)));
          }
        } catch(e) {}
      } catch(e) {}

      return data;
    },
    initialData: () => {
      // Intenta obtener los datos iniciales de la caché general de productos 
      // (Tienda o destacados) para mostrar inmediatamente y evitar el loading.
      const queries = queryClient.getQueriesData({ queryKey: ['products'] });
      const allQueries = queryClient.getQueriesData({ queryKey: ['allProducts'] });
      
      for (const [key, data] of [...queries, ...allQueries]) {
        if (Array.isArray(data)) {
          const found = data.find(p => p.id === productId);
          if (found) return found;
        }
      }
      return undefined;
    },
    staleTime: 0, // Always fetch newest data in background
    gcTime: 1000 * 60 * 60 * 24, // 24 hours
    enabled: !!productId
  });
};

