);

const validationSchema = Yup.object({
  customerName: Yup.string().required('Nombre requerido'),
  dni: Yup.string().required('DNI requerido'),
  phone: Yup.string().required('Teléfono requerido'),
  address: Yup.string().required('Dirección requerida'),
  district: Yup.string().required('Distrito requerido'),
  city: Yup.string().required('Ciudad requerida'),
  email: Yup.string().email('Email inválido').required('Email requerido'),
  isGiftMode: Yup.boolean(),
  giftRecipientName: Yup.string().when('isGiftMode', {
    is: true,
    then: () => Yup.string().required('Nombre del destinatario requerido')
  }),
  giftMessage: Yup.string().when('isGiftMode', {
    is: true,
    then: () => Yup.string().max(200, 'Máximo 200 caracteres').required('Mensaje requerido')
  }),
  giftSticker: Yup.string()
});

const CheckoutPage = () => {
  const navigate = useNavigate();
  const { items, getTotalPrice, clearCart } = useCart();
  const { user, userProfile, updateUserProfile, freezeMonedas, activeMainCoins } = useAuth();
  const toast = useGlobalToast();

  const [processing, setProcessing] = useState(false);
  const [useCoinsToggle, setUseCoinsToggle] = useState(false);
  
  const subtotal = getTotalPrice();
  const monedasCount = activeMainCoins || 0;
  
  // Calcular límite de monedas (50% del subtotal como máximo)
  const maxCoinsAllowed = Math.floor(subtotal / 2);
  const availableCoins = Math.min(monedasCount, maxCoinsAllowed);
  const canUseCoins = monedasCount > 0 && availableCoins > 0;
  
  // Calcular descuentos
  const discount = (canUseCoins && useCoinsToggle) ? availableCoins : 0;
  
  const subtotalWithDiscount = Math.max(0, subtotal - discount);
  const shipping = subtotalWithDiscount > 100 ? 0 : 15;
  const total = subtotalWithDiscount + shipping;
  
  const handleToggleCoins = () => {
    setUseCoinsToggle(!useCoinsToggle);
  };
  
  // Config WhatsApp

  const { data: whatsappConfig } = useQuery({
    queryKey: ['whatsapp-config-tienda'],
    queryFn: async () => {
      try {
        const tiendaNum = await getMessage('whatsapp_number_tienda');
        const fallbackNum = await getMessage('whatsapp_number');
        const textTienda = await getMessage('whatsapp_text_tienda');

        let num = tiendaNum.data?.trim() || fallbackNum.data?.trim() || '';
        let cleanText = textTienda.data || 'Solicitud de Pedido\n\nHola! Vengo de la tienda virtual y quiero confirmar mi pedido con código {id}.';

        let clean = num.replace(/[\s\-\(\)\+]/g, '');
        if (clean && !clean.startsWith('51') && clean.length <= 9) {
          clean = `51${clean}`;
        }
        return {
          number: clean || '51999999999',
          customText: cleanText
        };
      } catch (e) {
        return {
          number: '51999999999',
          customText: 'Solicitud de Pedido\n\nHola! Vengo de la tienda virtual y quiero confirmar mi pedido con código {id}.'
        };
      }
    }
  });

  const guestSavedInfo = JSON.parse(localStorage.getItem('checkout_customer_info') || '{}');

  const formik = useFormik({
    enableReinitialize: true,
    initialValues: {
      customerName: userProfile?.displayName || user?.displayName || guestSavedInfo.customerName || '',
      dni: userProfile?.dni || guestSavedInfo.dni || '',
      phone: userProfile?.phone || guestSavedInfo.phone || '',
      address: guestSavedInfo.address || '',
      district: guestSavedInfo.district || '',
      city: guestSavedInfo.city || 'Lima',
      email: user?.email || guestSavedInfo.email || '',
      isGiftMode: false,
      giftRecipientName: '',
      giftMessage: '',
      giftSticker: 'kapi-love'
    },
    validationSchema,
    onSubmit: async (values) => {

      setProcessing(true);

      try {
        const pseudoOrderId = `PD-${Date.now().toString(36).toUpperCase()}`;

        // ── Separar nombre en partes (nombre / apellidos) ─────────────────
        const nameParts = values.customerName.trim().split(/\s+/);
        const clienteNombre = nameParts[0] || values.customerName;
        const clienteApellidos = nameParts.length > 1 ? nameParts.slice(1).join(' ') : '';

        // ── Construir string de prendas (resumen de ítems del carrito) ─────
        const prendasStr = items
          .map((item) => {
            if (item.isComboProduct) {
              // Para combos: listar cada sub-producto con su talla y color
              const comboVariantSelections = item.comboVariantSelections || {};
              const comboItemCustomization = item.customization?.comboItemCustomization || [];
              const subResumen = (item.comboItems || []).map((subItem, subIdx) => {
                const varSel = comboVariantSelections[subIdx] || comboItemCustomization[subIdx]?.variant || {};
                const talla = varSel.size ? `(${varSel.size})` : '';
                const color = varSel.color ? `/${varSel.color}` : '';
                const nombre = subItem.productName || subItem.name || `Producto ${subIdx + 1}`;
                return `${nombre}${color} ${talla}`;
              }).join(' + ');
              return `[COMBO] ${item.productName}: ${subResumen} x${item.quantity}`;
            }
            const talla = item.variant?.size ? `(${item.variant.size})` : '';
            const color = item.variant?.color ? `/${item.variant.color}` : '';
            return `${item.productName}${color} ${talla} x${item.quantity}`.trim();
          })
          .join(' - ');

        // ── Construir mapa de productos (estructura ERP: productos) ────────
        // Para combos: incluye sub-productos, tallas, colores y diseños por vista (frente/espalda)
        const productosMap = {};
        items.forEach((item, idx) => {
          const precioItem = item.customization?.finalPrice || item.price || 0;
          const subtotalItem = precioItem * (item.quantity || 1);

          if (item.isComboProduct) {
            // ── Extraer datos por sub-producto del combo ──────────────────
            const comboVariantSelections = item.comboVariantSelections || {};
            const comboItemCustomization = item.customization?.comboItemCustomization || [];
            // Datos completos del sub-producto cargados desde Firestore (contiene nombre, imágenes, vistas)
            const comboSubProductsData = item.comboSubProductsData || {};

            const subProductos = {};
            (item.comboItems || []).forEach((subItem, subIdx) => {
              const varSel =
                comboVariantSelections[subIdx] ||
                comboItemCustomization[subIdx]?.variant ||
                {};
              const colorKey = varSel.color || 'default';
              const colorKeyLower = colorKey.trim().toLowerCase();
              const itemLayers = comboItemCustomization[subIdx]?.layersByView || {};
              // Datos completos del sub-producto (si se agregó desde la página del producto)
              const subProductData = comboSubProductsData[subIdx] || comboSubProductsData[String(subIdx)];

              // Nombre real del sub-producto (desde datos cargados o fallback al config del admin)
              const productName =
                subProductData?.name ||
                subItem.productName ||
                subItem.name ||
                `Producto ${subIdx + 1}`;

              // Clasificar capas del editor: frente vs espalda
              const frenteKey = `combo-view-${subIdx}-${colorKey}`;
              const espaldaKey = `combo-view-${subIdx}-${colorKey}-back`;

              const extraerInfoCapas = (layers) => {
                if (!Array.isArray(layers) || layers.length === 0) return null;
                return {
                  cantidadCapas: layers.length,
                  imagenes: layers
                    .filter((l) => l.type === 'image' && l.src)
                    .map((l) => l.src),
                  textos: layers
                    .filter((l) => l.type === 'text' && l.text)
                    .map((l) => l.text),
                };
              };

              const frenteLayers = itemLayers[frenteKey];
              const espaldaLayers = itemLayers[espaldaKey];
              const tieneDiseno = !!(frenteLayers?.length || espaldaLayers?.length);

              // Renders pre-generados por el editor (imagen renderizada con diseño + producto)
              // Estructura: item.customization.comboItemRenderedPreviews[subIdx] = { frente, espalda }
              const renderedPreviews = item.customization?.comboItemRenderedPreviews?.[subIdx] || null;

              // Si no hay capas del editor, extraer imágenes base del producto por color seleccionado
              let disenoFrenteData = null;
              let disenoEspaldaData = null;

              if (tieneDiseno) {
                // Usuario usó el editor: preferir el render visual final sobre los srcs de capas crudas
                const frenteImgRender = renderedPreviews?.frente || null;
                const espaldaImgRender = renderedPreviews?.espalda || null;

                if (frenteLayers?.length > 0) {
                  const capasInfo = extraerInfoCapas(frenteLayers);
                  disenoFrenteData = {
                    ...capasInfo,
                    // Si hay render visual, lo ponemos como primera imagen (la más importante para el ERP)
                    imagenes: frenteImgRender
                      ? [frenteImgRender, ...capasInfo.imagenes]
                      : capasInfo.imagenes,
                  };
                }
                if (espaldaLayers?.length > 0) {
                  const capasInfo = extraerInfoCapas(espaldaLayers);
                  disenoEspaldaData = {
                    ...capasInfo,
                    imagenes: espaldaImgRender
                      ? [espaldaImgRender, ...capasInfo.imagenes]
                      : capasInfo.imagenes,
                  };
                }
              } else if (subProductData) {
                // Buscar la vista frontal del sub-producto (por viewId del admin o la primera disponible)
                const frontView =
                  subProductData.customizationViews?.find((v) => v.id === subItem.viewId) ||
                  subProductData.customizationViews?.[0];

                if (frontView) {
                  // Matching de color case-insensitive (igual que hace el editor)
                  const imgsByColor = frontView.imagesByColor || {};
                  const matchedFrontKey = Object.keys(imgsByColor).find(
                    (k) => k.trim().toLowerCase() === colorKeyLower
                  );
                  const frontImgUrl =
                    (matchedFrontKey && imgsByColor[matchedFrontKey]) ||
                    imgsByColor.default ||
                    subProductData.variants?.find(
                      (v) => v.name?.trim().toLowerCase() === colorKeyLower
                    )?.imageUrl ||
                    subProductData.mainImage ||
                    '';

                  if (frontImgUrl) {
                    disenoFrenteData = {
                      cantidadCapas: 0,
                      imagenes: [frontImgUrl],
                      textos: [],
                      esImagenBase: true, // distingue imagen de producto vs diseño del cliente
                    };
                  }

                  // Vista de espalda (si el producto tiene backSide)
                  if (frontView.hasBackSide && frontView.backSide) {
                    const backImgsByColor = frontView.backSide.imagesByColor || {};
                    const matchedBackKey = Object.keys(backImgsByColor).find(
                      (k) => k.trim().toLowerCase() === colorKeyLower
                    );
                    const backImgUrl =
                      (matchedBackKey && backImgsByColor[matchedBackKey]) ||
                      backImgsByColor.default ||
                      '';

                    if (backImgUrl) {
                      disenoEspaldaData = {
                        cantidadCapas: 0,
                        imagenes: [backImgUrl],
                        textos: [],
                        esImagenBase: true,
                      };
                    }
                  }
                }
              }

              subProductos[`subItem_${subIdx}`] = {
                productoId: subItem.productId || subItem.id || '',
                producto: productName,
                talla: varSel.size || '',
                color: colorKey !== 'default' ? colorKey : '',
                personalizado: tieneDiseno,
                ...(disenoFrenteData && { disenoFrente: disenoFrenteData }),
                ...(disenoEspaldaData && { disenoEspalda: disenoEspaldaData }),
              };
            });

            productosMap[`item_${idx}`] = {
              productoId: item.productId || '',
              producto: item.productName || '',
              cantidad: item.quantity || 1,
              precio: precioItem,
              subtotal: subtotalItem,
              esCombo: true,
              personalizado: !!(item.customization?.comboItemCustomization?.some(
                (c) => c?.layersByView && Object.values(c.layersByView).some((l) => l?.length > 0)
              )),
              urlImagenPersonalizada: item.customization?.imageURL || '',
              designId: item.customization?.designId || '',
              subProductos,
            };
          } else {
            // ── Producto simple ───────────────────────────────────────────
            productosMap[`item_${idx}`] = {
              productoId: item.productId || '',
              producto: item.productName || '',
              cantidad: item.quantity || 1,
              talla: item.variant?.size || '',
              color: item.variant?.color || '',
              precio: precioItem,
              subtotal: subtotalItem,
              personalizado: !!(item.customization?.layersByView
                ? Object.values(item.customization.layersByView).some((l) => l?.length > 0)
                : item.customization?.imageURL),
              textoPersonalizado: item.customization?.text || '',
              urlImagenPersonalizada: item.customization?.imageURL || '',
              designId: item.customization?.designId || '',
            };
          }
        });

        // ── Payload completo con campos del ERP ───────────────────────────
        const webOrderPayload = {
          // ─ Número de referencia ─
          numeroPedido: pseudoOrderId,

          // ─ Datos del cliente (campos ERP oficiales) ─
          clienteNombre,
          clienteApellidos,
          clienteNombreCompleto: values.customerName,
          clienteNumeroDocumento: values.dni,
          clienteTipoDocumento: 'DNI',
          clienteContacto: values.phone,
          clienteContactoSecundario: '',
          clienteCorreo: values.email,
          clienteDepartamento: values.city,
          clienteDistrito: values.district,
          clienteProvincia: values.city === 'Lima' || values.city === 'Callao' ? 'No' : 'Sí',

          // ─ Datos de envío ─
          envioNombres: clienteNombre,
          envioApellidos: clienteApellidos,
          envioContacto: values.phone,
          envioNumeroDocumento: values.dni,
          envioTipoDocumento: 'DNI',
          envioDireccion: values.address,
          envioDistrito: values.district,
          envioDepartamento: values.city,
          envioProvincia: values.city === 'Lima' || values.city === 'Callao' ? 'No' : 'Sí',

          // ─ Canal, origen y flag web ─
          canalVenta: 'Portal Web',
          web: true,
          activador: 'portal_web',
          vendedor: 'Portal Web',
          whatsappOrigen: '',

          // ─ Montos ─
          montoTotal: total,
          montoAdelanto: 0,
          montoPendiente: total,
          ...(discount > 0 && { descuentoMonedas: discount }),
          ...(discount > 0 && { monedasEnEspera: discount }),

          // ─ Estado inicial ─
          estadoGeneral: 'Nuevo',
          status: 'Nuevo',

          // ─ Prendas y productos ─
          prendas: prendasStr,
          cantidad: items.reduce((acc, i) => acc + (i.quantity || 1), 0),
          productos: productosMap,
          lineaProducto: '',
          añadidos: [],

          // ─ Flags de tipo de pedido ─
          esPersonalizado: items.some(
            (i) => !!(i.customization?.text || i.customization?.imageURL)
          ),
          esMostacero: false,
          esPrioridad: false,
          importado: false,

          // ─ Imágenes de diseños personalizados (Mapeo completo galería) ─
          imageURLs: items
            .flatMap((i) => {
              const urls = [];
              if (i.customization?.imageURL) urls.push(i.customization.imageURL);
              if (i.isComboProduct && productosMap) {
                const itemMap = Object.values(productosMap).find((pm) => pm.productoId === i.productId);
                if (itemMap?.subProductos) {
                  Object.values(itemMap.subProductos).forEach((sub) => {
                    if (sub.disenoFrente?.imagenes) urls.push(...sub.disenoFrente.imagenes);
                    if (sub.disenoEspalda?.imagenes) urls.push(...sub.disenoEspalda.imagenes);
                  });
                }
              }
              return urls;
            })
            .filter(Boolean),

          // ─ Sub-maps de etapas (vacíos, se completan en el ERP al aprobar) ─
          impresion: {
            estado: 'Pendiente',
            pago1: null,
            pago2: null,
            montoPendiente: total,
          },
          diseño: {
            diseñadorAsignado: null,
            urlImagen: null,
            fechaEntrada: null,
            fechaSalida: null,
          },
          preparación: {
            estado: null,
            operador: null,
            fechaEntrada: null,
            fechaSalida: null,
          },
          estampado: {
            estado: null,
            operador: null,
            fechaEntrada: null,
            fechaSalida: null,
          },
          empaquetado: {
            estado: null,
            operador: null,
            fechaEntrada: null,
            fechaSalida: null,
          },
          reparto: {
            estado: null,
            repartidor: null,
            fechaEntrada: null,
            fechaSalida: null,
            fechaFinalizado: null,
          },

          // ─ Otros campos ERP ─
          agenciaEnvio: '',
          observación: '',
          historialModificaciones: [],
          tiempos: {},
          fechaEnvio: null,

          // ─ Referencia del usuario autenticado (si aplica) ─
          ...(user?.uid && { userId: user.uid }),
          portalPseudoOrderId: pseudoOrderId,
          ...(values.isGiftMode && {
            giftDetails: {
              isGift: true,
              recipientName: values.giftRecipientName,
              message: values.giftMessage,
              sticker: values.giftSticker
            }
          }),
        };

        // ── 1. Guardar en pedidos_web (colección separada, para validación previa) ──
        let webOrderId = null;
        try {
          const { id, error: webErr } = await createWebOrder(webOrderPayload);
          if (webErr) {
            console.warn('No se pudo guardar en pedidos_web:', webErr);
          } else {
            webOrderId = id;
          }
        } catch (erpErr) {
          console.warn('Error al conectar con ERP Firebase:', erpErr);
        }

        // ── 1.5 Procesar Regalos de Wishlist ──────────────────────────────
        try {
          const wishlistGifts = items.filter(item => item.isWishlistGift && item.wishlistUserCode);
          for (const gift of wishlistGifts) {
            await markItemAsGifted(gift.wishlistUserCode, gift.productId, values.customerName);
          }
        } catch (giftErr) {
          console.warn('Error al marcar regalos de wishlist:', giftErr);
        }

        // ── 2. Procesar referidos ─────────────────────────────────────────
        let referralTag = '';
        try {
          const rawRef = localStorage.getItem('wala_referral');
          if (rawRef) {
            const refData = JSON.parse(rawRef);
            const now = Date.now();
            if (now - refData.timestamp < 36 * 60 * 60 * 1000) {
              referralTag = `\n_Referido por: ${refData.referrerCode}_`;
              await linkPurchaseToReferral(refData.referralId, pseudoOrderId, subtotal);
            }
          }
        } catch (e) {
          console.warn('No se pudo procesar cookie de referido:', e);
        }

        // ── 3. Armar mensaje de WhatsApp ──────────────────────────────────
        let message = `SOLICITUD DE NUEVO PEDIDO (${pseudoOrderId})\n\n`;
        message += `Datos del Cliente:\n`;
        message += `Nombre: ${values.customerName}\n`;
        message += `DNI: ${values.dni}\n`;
        message += `Teléfono: ${values.phone}\n`;
        message += `Email: ${values.email}\n`;
        message += `Dirección: ${values.address}, ${values.district}, ${values.city}\n\n`;

        if (values.isGiftMode) {
          message += `🎁 *MODO REGALO ACTIVO*\n`;
          message += `   Para: ${values.giftRecipientName}\n`;
          message += `   Mensaje: "${values.giftMessage}"\n\n`;
        }

        message += `Detalle de Compra:\n`;
        items.forEach((item, index) => {
          message += `${index + 1}. ${item.productName}\n`;
          message += `   Cantidad: ${item.quantity}\n`;
          if (item.variant && item.variant.size) {
            message += `   Talla/Modelo: ${item.variant.size}\n`;
          }
          if (item.customization && item.customization.text) {
            message += `   Texto: ${item.customization.text}\n`;
          }
          const price = item.customization?.finalPrice || item.price;
          message += `   Subtotal: S/ ${(price * item.quantity).toFixed(2)}\n`;
          message += `   Link: ${window.location.origin}/producto/${item.productId}\n\n`;
        });

        message += `Resumen de Pago:\n`;
        message += `Producto(s): S/ ${subtotal.toFixed(2)}\n`;
        if (discount > 0) {
          message += `Descuento (Monedas): - S/ ${discount.toFixed(2)}\n`;
        }
        message += `Envío: ${shipping === 0 ? 'Gratis' : `S/ ${shipping.toFixed(2)}`}\n`;
        message += `TOTAL A PAGAR: S/ ${total.toFixed(2)}\n\n`;

        message += whatsappConfig?.customText?.replace('{id}', pseudoOrderId) || `Solicitud de Pedido\n\nHola! Vengo de la tienda virtual y quiero confirmar mi pedido con código ${pseudoOrderId}.`;
        if (referralTag) message += referralTag;

        const waLink = `https://wa.me/${whatsappConfig?.number}?text=${encodeURIComponent(message)}`;

        // ── 4. Guardar en localStorage (pendiente de confirmación) ─────────
        const currentCart = JSON.parse(localStorage.getItem('shopping_cart') || '[]');
        const updatedCart = currentCart.map((item) => ({
          ...item,
          status: 'pending_confirmation',
          pseudoOrderId,
          ...(webOrderId && { webOrderId }),
        }));
        localStorage.setItem('shopping_cart', JSON.stringify(updatedCart));

        const savedInfo = {
          customerName: values.customerName,
          dni: values.dni,
          phone: values.phone,
          address: values.address,
          district: values.district,
          city: values.city,
          email: values.email,
        };
        localStorage.setItem('checkout_customer_info', JSON.stringify(savedInfo));

        // ── 5. Congelar monedas en estado de "espera" ─────────────────────
        if (discount > 0 && freezeMonedas) {
          // Congela de la cantidad "monedas" a "monedasEnEspera"
          await freezeMonedas(discount, pseudoOrderId);
        }

        // ── 6. Auto-actualizar perfil del usuario ─────────────────────────
        if (user && updateUserProfile) {
          const updates = {};
          if (!userProfile?.dni || userProfile.dni !== values.dni) updates.dni = values.dni;
          if (!userProfile?.phone || userProfile.phone !== values.phone) updates.phone = values.phone;
          if (!userProfile?.displayName || userProfile.displayName !== values.customerName) updates.displayName = values.customerName;
          if (Object.keys(updates).length > 0) {
            updateUserProfile(updates).catch((err) =>
              console.error('Error auto-updating profile from checkout:', err)
            );
          }
        }

        // ── 7. Abrir WhatsApp ─────────────────────────────────────────────
        toast.success('¡Redirigiendo a WhatsApp para finalizar tu pedido!');
        window.open(waLink, '_blank');
        navigate('/carrito');
      } catch (error) {
        console.error('Error al generar pedido:', error);
        toast.error('Error al procesar el pedido. Inténtalo de nuevo.');
      } finally {
        setProcessing(false);
      }
    }
  });

  if (items.length === 0) {
    return (
      <div className={styles.empty}>
        <h2>Tu carrito está vacío</h2>
        <Button onClick={() => navigate('/tienda')}>Ir a la Tienda</Button>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <h1>Checkout</h1>

      <div className={styles.layout}>
        <div className={styles.formContainer}>
          <form onSubmit={formik.handleSubmit} className={styles.form}>
            <h2>Detalles de Envío</h2>

            <div className={styles.field}>
              <label>Nombre Completo *</label>
              <input
                type="text"
                name="customerName"
                value={formik.values.customerName}
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                placeholder="Ej: Juan Pérez"
              />
              {formik.touched.customerName && formik.errors.customerName && (
                <span className={styles.error}>{formik.errors.customerName}</span>
              )}
            </div>

            <div className={styles.row}>
              <div className={styles.field}>
                <label>DNI *</label>
                <input
                  type="text"
                  name="dni"
                  value={formik.values.dni}
                  onChange={formik.handleChange}
                  onBlur={formik.handleBlur}
                  placeholder="Documento de Identidad"
                />
                {formik.touched.dni && formik.errors.dni && (
                  <span className={styles.error}>{formik.errors.dni}</span>
                )}
              </div>
              <div className={styles.field}>
                <label>Teléfono *</label>
                <input
                  type="tel"
                  name="phone"
                  value={formik.values.phone}
                  onChange={formik.handleChange}
                  onBlur={formik.handleBlur}
                  placeholder="Celular"
                />
                {formik.touched.phone && formik.errors.phone && (
                  <span className={styles.error}>{formik.errors.phone}</span>
                )}
              </div>
            </div>

            <div className={styles.field}>
              <label>Email *</label>
              <input
                type="email"
                name="email"
                value={formik.values.email}
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                placeholder="correo@ejemplo.com"
              />
              {formik.touched.email && formik.errors.email && (
                <span className={styles.error}>{formik.errors.email}</span>
              )}
            </div>

            <div className={styles.row}>
              <div className={styles.field}>
                <label>Ciudad / Región *</label>
                <select
                  name="city"
                  value={formik.values.city}
                  onChange={formik.handleChange}
                  onBlur={formik.handleBlur}
                  className={styles.selectInput}
                  style={{ padding: '0.8rem 1rem', border: '2px solid var(--gris-borde)', borderRadius: 'var(--radio-pequeno)', fontSize: '1rem', background: 'white' }}
                >
                  <option value="Lima">Lima Metropolitana</option>
                  <option value="Callao">Callao</option>
                  <option value="Provincias">Otras Provincias</option>
                </select>
                {formik.touched.city && formik.errors.city && (
                  <span className={styles.error}>{formik.errors.city}</span>
                )}
              </div>
              <div className={styles.field}>
                <label>Distrito *</label>
                <input
                  type="text"
                  name="district"
                  value={formik.values.district}
                  onChange={formik.handleChange}
                  onBlur={formik.handleBlur}
                  placeholder="Ej: Miraflores"
                />
                {formik.touched.district && formik.errors.district && (
                  <span className={styles.error}>{formik.errors.district}</span>
                )}
              </div>
            </div>

            <div className={styles.field}>
              <label>Dirección exacta *</label>
              <input
                type="text"
                name="address"
                value={formik.values.address}
                onChange={formik.handleChange}
                onBlur={formik.handleBlur}
                placeholder="Avenida, Calle, Nro, Dpto, Referencia"
              />
              {formik.touched.address && formik.errors.address && (
                <span className={styles.error}>{formik.errors.address}</span>
              )}
            </div>

            <div className={styles.giftModeContainer}>
              <div className={styles.giftModeToggle}>
                <label>
                  <input
                    type="checkbox"
                    name="isGiftMode"
                    checked={formik.values.isGiftMode}
                    onChange={formik.handleChange}
                  />
                  🎁 Activar Modo Regalo (Gratis)
                </label>
                <p>Incluye una experiencia digital inmersiva para el destinatario.</p>
              </div>

              {formik.values.isGiftMode && (
                <div className={styles.giftModeFields}>
                  <div className={styles.field}>
                    <label>Nombre del destinatario *</label>
                    <input
                      type="text"
                      name="giftRecipientName"
                      value={formik.values.giftRecipientName}
                      onChange={formik.handleChange}
                      onBlur={formik.handleBlur}
                      placeholder="Ej: María"
                    />
                    {formik.touched.giftRecipientName && formik.errors.giftRecipientName && (
                      <span className={styles.error}>{formik.errors.giftRecipientName}</span>
                    )}
                  </div>

                  <div className={styles.field}>
                    <label>Mensaje (Máx 200 caracteres) *</label>
                    <textarea
                      name="giftMessage"
                      value={formik.values.giftMessage}
                      onChange={formik.handleChange}
                      onBlur={formik.handleBlur}
                      maxLength="200"
                      placeholder="Escribe un mensaje especial..."
                      rows="3"
                    ></textarea>
                    {formik.touched.giftMessage && formik.errors.giftMessage && (
                      <span className={styles.error}>{formik.errors.giftMessage}</span>
                    )}
                  </div>

                  <div className={styles.field}>
                    <label>Sticker de Kapi</label>
                    <div className={styles.stickerSelection}>
                      <label className={formik.values.giftSticker === 'kapi-love' ? styles.stickerSelected : ''}>
                        <input type="radio" name="giftSticker" value="kapi-love" checked={formik.values.giftSticker === 'kapi-love'} onChange={formik.handleChange} />
                        😍 Amor
                      </label>
                      <label className={formik.values.giftSticker === 'kapi-party' ? styles.stickerSelected : ''}>
                        <input type="radio" name="giftSticker" value="kapi-party" checked={formik.values.giftSticker === 'kapi-party'} onChange={formik.handleChange} />
                        🎉 Fiesta
                      </label>
                      <label className={formik.values.giftSticker === 'kapi-smile' ? styles.stickerSelected : ''}>
                        <input type="radio" name="giftSticker" value="kapi-smile" checked={formik.values.giftSticker === 'kapi-smile'} onChange={formik.handleChange} />
                        😊 Feliz
                      </label>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className={styles.buttonGroup}>
              <Button type="button" variant="outline" onClick={() => navigate('/carrito')} disabled={processing} fullWidth>
                Volver al carrito
              </Button>
              <Button type="submit" variant="primary" disabled={processing} fullWidth>
                {processing ? 'Generando...' : 'Confirmar y Enviar por WhatsApp'}
              </Button>
            </div>
          </form>
        </div>

        <div className={styles.summary}>
          <h2>Resumen del Pedido</h2>
          <div className={styles.items}>
            {items.map(item => (
              <div key={item.id} className={styles.summaryItem}>
                <span>{item.productName} x{item.quantity}</span>
                <span>S/ {(item.customization?.finalPrice || item.price * item.quantity).toFixed(2)}</span>
              </div>
            ))}
          </div>
          <div className={styles.totals}>
              <div className={styles.totalRow}>
                <span>Subtotal:</span>
                <span>S/ {subtotal.toFixed(2)}</span>
              </div>
              {canUseCoins && (
                <div style={{ marginTop: '1rem', marginBottom: '1rem', background: 'linear-gradient(145deg, #fffbeb, #fef3c7)', padding: '1.25rem', borderRadius: '12px', border: '1px solid #fcd34d', boxShadow: '0 4px 15px rgba(245, 158, 11, 0.1)' }}>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <KapiSolCoinMini />
                        <label style={{ fontWeight: 700, fontSize: '15px', color: '#92400e', margin: 0, lineHeight: 1 }}>
                          Tienes {monedasCount} monedas = S/{monedasCount.toFixed(2)}
                        </label>
                      </div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <span style={{ fontSize: '14px', fontWeight: 'bold', color: '#b45309' }}>¿Aplicar?</span>
                        <input 
                          type="checkbox" 
                          checked={useCoinsToggle} 
                          onChange={handleToggleCoins}
                          style={{ width: '20px', height: '20px', cursor: 'pointer', accentColor: '#e11d48' }}
                        />
                      </div>
                    </div>
                    <p style={{ fontSize: '0.8rem', color: '#b45309', margin: '0', fontWeight: 500 }}>
                      Se aplicará automáticamente el descuento máximo permitido ({availableCoins} monedas = S/{availableCoins.toFixed(2)}).
                    </p>
                  </div>
                </div>
              )}
              {discount > 0 && (
                <div className={styles.totalRow} style={{ color: '#d97706', fontWeight: 600, fontSize: '1.05rem', margin: '0.5rem 0', padding: '0.5rem', background: '#fffbeb', borderRadius: '8px' }}>
                  <span style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <KapiSolCoinMini /> Ahorro Monedas:
                  </span>
                  <span>-S/ {discount.toFixed(2)}</span>
                </div>
              )}
              <div className={styles.totalRow}>
                <span>Envío:</span>
              <span>{shipping === 0 ? 'Gratis' : `S/ ${shipping.toFixed(2)}`}</span>
            </div>
            <div className={styles.totalRow + ' ' + styles.finalTotal}>
              <span>Total a Pagar:</span>
              <span>S/ {total.toFixed(2)}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CheckoutPage;

import React, { useEffect, useState, useMemo, useRef, useCallback } from 'react';
import { useParams, useSearchParams, useNavigate } from 'react-router-dom';
import { useProduct } from '../hooks/useProducts';
import { useEditor, EditorProvider } from '../contexts/EditorContext';
import { useCart } from '../contexts/CartContext';
import { useAuth } from '../contexts/AuthContext';
import { DesignClipboardProvider } from '../contexts/DesignClipboardContext';
import { getDesignById, saveDesign, getDesignsByUser } from '../services/designs';
import { isComboProduct } from '../utils/comboProductUtils';
import { generateFullUserComboCartPreview, generatePerItemSidePreviews } from '../utils/comboImageComposer';
import AdminViewEditor from '../components/admin/AdminViewEditor/AdminViewEditor';
import UnifiedComboEditor from '../components/admin/UnifiedComboEditor/UnifiedComboEditor';
import ComboUserEditor from '../components/editor/ComboUserEditor/ComboUserEditor';
import Button from '../components/common/Button';
import Modal from '../components/common/Modal/Modal';
import DraggableContainer from '../components/common/DraggableContainer/DraggableContainer';
import { useImagePreloader } from '../components/common/OptimizedImage/OptimizedImage';
import styles from './EditorPage.module.css';

const DEFAULT_VIEW_ID = 'default';

const EditorPage = () => {
  const { id } = useParams();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const size = searchParams.get('size') || '';
  const color = searchParams.get('color') || '';
  const designId = searchParams.get('designId');

  const { data: product, isLoading } = useProduct(id);
  const {
    setProduct,
    setVariant,
    setActiveViewId,
    setLayersByViewFromDesign,
    setLayersForView,
    calculatePrice,
    price,
    layersByView,
    activeViewId,
    product: editorProduct,
    variant,
    setActivePrintAreaId
  } = useEditor();
  const { addToCart } = useCart();
  const { user } = useAuth();
  // Estado local de customización del combo para el USUARIO.
  // NUNCA modifica el producto original del administrador.
  // Al guardar, se crea un clon en "Mis creaciones" del usuario.
  const [userComboCustomization, setUserComboCustomization] = useState(null);
  const [savingDesign, setSavingDesign] = useState(false);
  const [designLoaded, setDesignLoaded] = useState(false);
  const [editorMounted, setEditorMounted] = useState(false);
  const [existingDesignPrompt, setExistingDesignPrompt] = useState(null);
  const [showExitModal, setShowExitModal] = useState(false);
  const [showSavePromptModal, setShowSavePromptModal] = useState(false);
  const [isEditingBackSide, setIsEditingBackSide] = useState(false);
  const bypassGuardsRef = useRef(false);
  const [savedHash, setSavedHash] = useState(null);
  const [showMobileSettingsModal, setShowMobileSettingsModal] = useState(false);

  const currentHash = useMemo(() => 
    JSON.stringify({ layersByView, userComboCustomization, variant }),
  [layersByView, userComboCustomization, variant]);

  // Precargar todas las imágenes del producto para navegación sin saltos (caché)
  const allProductUrls = useMemo(() => {
    if (!product) return [];
    const urls = new Set();
    const extract = (obj) => {
      if (!obj) return;
      if (typeof obj === 'string') {
        if (obj.startsWith('http') && (obj.includes('cloudinary') || obj.match(/\.(jpeg|jpg|webp|png|gif)$/i))) {
          urls.add(obj);
        }
      } else if (Array.isArray(obj)) {
        obj.forEach(extract);
      } else if (typeof obj === 'object') {
        Object.values(obj).forEach(extract);
      }
    };
    extract(product);
    return Array.from(urls);
  }, [product]);

  useImagePreloader(allProductUrls);

  useEffect(() => {
    if (designLoaded && savedHash === null) {
      setSavedHash(currentHash);
    }
  }, [designLoaded, currentHash, savedHash]);

  const handleComboLayersChange = useCallback((newLayers) => {
    setUserComboCustomization((prev) => {
      const base = prev || product?.comboItemCustomization || [];
      let changed = false;
      const next = base.map(x => ({ ...x })); // shallow clone to safely assign
      
      Object.entries(newLayers).forEach(([vId, layers]) => {
        const match = vId.match(/^combo-view-(\d+)-([^]+)$/);
        if (match) {
          const index = parseInt(match[1], 10);
          if (!next[index]) {
            next[index] = { layersByView: {} };
            changed = true;
          }
          if (!next[index].layersByView) {
            next[index].layersByView = {};
            changed = true;
          }
          if (next[index].layersByView[vId] !== layers) {
            next[index].layersByView = { ...next[index].layersByView, [vId]: layers };
            changed = true;
          }
        }
      });
      return changed ? next : prev;
    });
  }, [product?.comboItemCustomization]);

  const handleVariantChange = useCallback((idx, variant) => {
    setUserComboCustomization(prev => {
      const next = [...(prev || product?.comboItemCustomization || [])];
      if (!next[idx]) next[idx] = {};
      
      // Compare to avoid infinite loops if it hasn't actually changed
      if (next[idx].variant?.color === variant?.color && next[idx].variant?.size === variant?.size) {
        return prev;
      }
      
      next[idx] = { ...next[idx], variant };
      return next;
    });
  }, [product?.comboItemCustomization]);

  React.useEffect(() => {
    const t = setTimeout(() => setEditorMounted(true), 0);
    
    // Añadimos clase global para ocultar elementos invasivos en móvil (footer, nav bottom, etc.)
    document.body.classList.add('mobile-editor-active');
    
    return () => {
      clearTimeout(t);
      document.body.classList.remove('mobile-editor-active');
    };
  }, []);

  const isCombo = isComboProduct(product || {});

  const hasUnsavedLayers = useMemo(() => {
    let hasAnyLayer = false;
    if (isCombo) {
      if (Array.isArray(userComboCustomization)) {
        hasAnyLayer = userComboCustomization.some(item => 
          item.layersByView && Object.values(item.layersByView).some(arr => Array.isArray(arr) && arr.length > 0)
        );
      }
    } else {
      hasAnyLayer = Object.values(layersByView || {}).some((arr) => Array.isArray(arr) && arr.length > 0);
    }
    return hasAnyLayer && savedHash !== null && currentHash !== savedHash;
  }, [isCombo, userComboCustomization, layersByView, currentHash, savedHash]);

  useEffect(() => {
    if (!hasUnsavedLayers) return;

    // 1. Native Tab Closing Prevention
    const onBeforeUnload = (e) => {
      if (bypassGuardsRef.current) return;
      e.preventDefault();
      e.returnValue = ''; 
    };
    window.addEventListener('beforeunload', onBeforeUnload);

    // 2. Browser Back Button / History Interception
    // Push a dummy state so clicking back doesn't actually leave
    window.history.pushState(null, null, window.location.pathname);
    const handlePopState = (e) => {
      if (bypassGuardsRef.current) return;
      // Push it back immediately
      window.history.pushState(null, null, window.location.pathname);
      setShowExitModal(true);
    };
    window.addEventListener('popstate', handlePopState);

    // 3. React Router Link Interception (global click interception)
    const handleClick = (e) => {
      if (bypassGuardsRef.current) return;
      const anchor = e.target.closest('a');
      if (anchor && anchor.href) {
        // Ignorar descargas o modales locales reales
        if (anchor.target === '_blank' || anchor.hasAttribute('download')) return;
        
        // Verifica si la url de destino es distinta a la ruta actual (excluyendo query parameters si se desea, aquí excluiremos id)
        const currentOrigin = window.location.origin;
        if (anchor.href.startsWith(currentOrigin) && anchor.pathname !== window.location.pathname) {
          e.preventDefault();
          e.stopPropagation();
          setShowExitModal(true);
        }
      }
    };
    document.addEventListener('click', handleClick, true);

    return () => {
      window.removeEventListener('beforeunload', onBeforeUnload);
      window.removeEventListener('popstate', handlePopState);
      document.removeEventListener('click', handleClick, true);
    };
  }, [hasUnsavedLayers]);

  const handleReturn = () => {
    if (hasUnsavedLayers) {
      setShowExitModal(true);
    } else {
      bypassGuardsRef.current = true;
      navigate(`/producto/${product?.id || id}`);
    }
  };

  const handleResetDesign = () => {
    if (!window.confirm("¿Seguro que deseas restablecer el diseño al original? Se perderán todos tus cambios no guardados.")) return;
    const url = new URL(window.location.href);
    url.searchParams.delete('designId');
    window.location.href = url.toString();
  };

  const views = useMemo(
    () => (Array.isArray(product?.customizationViews) ? product.customizationViews : []),
    [product?.customizationViews]
  );
  const hasMultipleViews = views.length > 0;

  useEffect(() => {
    if (product) {
      setProduct(product);
      setVariant({ size: size || '', color: color || '' });
      const viewIdToSet = hasMultipleViews && views[0]?.id ? views[0].id : DEFAULT_VIEW_ID;
      setActiveViewId(viewIdToSet);

      const comboSelectionsParam = searchParams.get('comboSelections');
      if (isComboProduct(product) && comboSelectionsParam) {
        try {
          const parsed = JSON.parse(comboSelectionsParam);
          const baseCustomization = Array.isArray(product.comboItemCustomization) 
            ? product.comboItemCustomization 
            : Array((product.comboItems || []).length).fill({});
            
          const initialComboCust = baseCustomization.map((dbItem, index) => {
             const urlSel = parsed[index];
             if (urlSel) {
               return {
                 ...dbItem,
                 variant: { ...(dbItem.variant || {}), ...urlSel }
               };
             }
             return dbItem;
          });
          setUserComboCustomization(prev => prev || initialComboCust);
        } catch (e) {
          console.error("Error parsing comboSelections", e);
        }
      }

      // Inicializar zona activa: primera zona de la vista actual
      const currentView = views.find(v => v.id === viewIdToSet) || views[0] || null;
      if (currentView?.printAreas && Array.isArray(currentView.printAreas) && currentView.printAreas.length > 0) {
        setActivePrintAreaId(viewIdToSet, currentView.printAreas[0].id);
      }
    }
  }, [product, size, color, setProduct, setVariant, setActiveViewId, setActivePrintAreaId, hasMultipleViews, views]);

  useEffect(() => {
    if (!product || designLoaded) return;

    const loadEmptyDesign = () => {
      const currentViewId = hasMultipleViews && views.length > 0 ? views[0].id : DEFAULT_VIEW_ID;
      const currentView = hasMultipleViews ? views.find((v) => v.id === currentViewId) : null;
      const colorKey = product?.isClothing && variant?.color ? variant.color : 'default';
      const newLayersByView = {};

      if (!isComboProduct(product)) {
        if (currentView?.initialLayersByColor && typeof currentView.initialLayersByColor === 'object') {
          const layersForColor = currentView.initialLayersByColor[colorKey] || currentView.initialLayersByColor.default || [];
          if (Array.isArray(layersForColor) && layersForColor.length > 0) newLayersByView[currentViewId] = layersForColor;
        } else if (currentView?.initialLayers && Array.isArray(currentView.initialLayers) && currentView.initialLayers.length > 0) {
          newLayersByView[currentViewId] = currentView.initialLayers;
        } else if (!hasMultipleViews && product?.customizationViews?.[0]) {
          const firstView = product.customizationViews[0];
          if (firstView.initialLayersByColor && typeof firstView.initialLayersByColor === 'object') {
            const layersForColor = firstView.initialLayersByColor[colorKey] || firstView.initialLayersByColor.default || [];
            if (Array.isArray(layersForColor) && layersForColor.length > 0) newLayersByView[DEFAULT_VIEW_ID] = layersForColor;
          } else if (Array.isArray(firstView.initialLayers) && firstView.initialLayers.length > 0) {
            newLayersByView[DEFAULT_VIEW_ID] = firstView.initialLayers;
          }
        }
      }
      setLayersByViewFromDesign(newLayersByView);
      setDesignLoaded(true);
    };

    // Si hay designId explícito, cargamos ese
    if (designId && !existingDesignPrompt) {
      let cancelled = false;
      (async () => {
        const { data: design, error } = await getDesignById(designId);
        if (cancelled || error || !design) return;
        if (design.layersByView && typeof design.layersByView === 'object' && Object.keys(design.layersByView).length > 0) {
          setLayersByViewFromDesign(design.layersByView);
        } else if (design.layers && Array.isArray(design.layers) && design.layers.length > 0) {
          setLayersForView(product?.customizationViews?.[0]?.id ?? DEFAULT_VIEW_ID, design.layers);
        }
        if (design.variant && (design.variant.size || design.variant.color)) {
          setVariant(design.variant);
        }
        // Si es un combo del usuario, restaurar su customización personal
        if (design.isUserComboDesign && Array.isArray(design.comboItemCustomization)) {
          setUserComboCustomization(design.comboItemCustomization);
        }
        setDesignLoaded(true);
      })();
      return () => { cancelled = true; };
    }

    // Si no hay designId y el usuario está logueado, verificamos si existe uno guardado previamente
    if (!designId && user && existingDesignPrompt === null) {
      let cancelled = false;
      (async () => {
        const { data: designs } = await getDesignsByUser(user.uid);
        if (cancelled) return;
        
        const existing = (designs || [])
          .sort((a, b) => {
            const timeA = a.updatedAt?.toMillis ? a.updatedAt.toMillis() : (a.updatedAt || 0);
            const timeB = b.updatedAt?.toMillis ? b.updatedAt.toMillis() : (b.updatedAt || 0);
            return timeB - timeA;
          })
          .find(d => d.productId === product.id);

        if (existing) {
          setExistingDesignPrompt(existing);
        } else {
          loadEmptyDesign();
        }
      })();
      return () => { cancelled = true; };
    }

    if (!designId && (!user || existingDesignPrompt === false)) {
      loadEmptyDesign();
    }
  }, [product, designId, designLoaded, hasMultipleViews, views, variant, setLayersByViewFromDesign, setLayersForView, setVariant, user, existingDesignPrompt]);

  useEffect(() => {
    calculatePrice();
  }, [layersByView, calculatePrice]);



  const handleSaveDesign = async () => {
    if (!user) {
      setShowSavePromptModal(true);
      return;
    }
    if (!editorProduct) return;
    
    setSavingDesign(true);

    // Si es combo: incluir la customización del combo del usuario (no la del admin)
    const isComboSave = isComboProduct(editorProduct);
    const comboPayload = isComboSave ? {
      comboItemCustomization: userComboCustomization || editorProduct.comboItemCustomization || [],
      // Clonar la referencia del producto admin sin modificarla
      isUserComboDesign: true,
    } : {};

    const { id: savedId, error } = await saveDesign(user.uid, {
      designId: designId || undefined,
      productId: editorProduct.id,
      productName: editorProduct.name,
      layersByView,
      variant: variant || { size, color },
      ...comboPayload,
    });
    setSavingDesign(false);
    if (error) {
      alert('No se pudo guardar el diseño: ' + error);
      return;
    }
    if (!designId && savedId) {
      navigate(`/editor/${id}?designId=${savedId}${size ? '&size='+size : ''}${color ? '&color='+color : ''}`, { replace: true });
    }
    setSavedHash(currentHash);
    alert('✅ Diseño guardado en tus creaciones.');
  };

  const handleAddToCart = async () => {
    if (!product) return;
    
    // Simplificamos la detección de capas según si es Combo o Normal
    const isCombo = isComboProduct(product);
    let hasAnyLayer = false;
    
    if (isCombo) {
      if (userComboCustomization && Array.isArray(userComboCustomization)) {
        hasAnyLayer = userComboCustomization.some(c => 
          c.layersByView && Object.values(c.layersByView).some(arr => Array.isArray(arr) && arr.length > 0)
        );
      }
    } else {
      hasAnyLayer = Object.values(layersByView || {}).some((arr) => Array.isArray(arr) && arr.length > 0);
    }

    const variantToAdd = { size: variant?.size ?? size, color: variant?.color ?? color };

    if (!hasAnyLayer) {
      if (window.confirm('No has añadido ningún diseño a la personalización. ¿Deseas agregar al carrito sin personalizar?')) {
        addToCart(product, variantToAdd, null, 1);
        navigate('/carrito');
      }
      return;
    }

    // Si tiene diseño y NO está logueado, lo frenamos con el Nodal de Registro
    if (hasAnyLayer && !user) {
      setShowSavePromptModal(true);
      return;
    }

    // Si tiene diseño y SÍ está logueado, forzamos un Autoguardado silencioso antes de ir al carrito
    if (hasAnyLayer && user && hasUnsavedLayers) {
       // Guardamos silenciosamente (ya sabemos que es usuario)
       setSavingDesign(true);
       try {
         const isComboSave = isComboProduct(editorProduct || product);
         const comboPayload = isComboSave ? {
           comboItemCustomization: userComboCustomization || (editorProduct || product).comboItemCustomization || [],
           isUserComboDesign: true,
         } : {};

         await saveDesign(user.uid, {
           designId: designId || undefined,
           productId: (editorProduct || product).id,
           productName: (editorProduct || product).name,
           layersByView,
           variant: variant || { size, color },
           ...comboPayload,
         });
       } catch (e) {
         console.error("Autosave falló", e);
       }
       setSavingDesign(false);
    }

    // Si es combo, generamos en paralelo:
    // 1) Thumbnail unificado (preview del carrito/WhatsApp)
    // 2) Renders individuales por sub-producto/lado para el ERP (frente + espalda con diseño)
    let finalCustomizedImage = null;
    let comboItemRenderedPreviews = null; // [ { frente: dataUrl|null, espalda: dataUrl|null }, ... ]
    if (isCombo) {
      setSavingDesign(true); 
      try {
        [finalCustomizedImage, comboItemRenderedPreviews] = await Promise.all([
          generateFullUserComboCartPreview(product, userComboCustomization),
          generatePerItemSidePreviews(product, userComboCustomization),
        ]);
      } catch (e) {
        console.error("Error generando thumbnails para carrito", e);
      }
      setSavingDesign(false);
    }

    // Agregar al Carrito Final
    const customization = {
      layersByView,
      comboItemCustomization: isCombo ? userComboCustomization : null,
      // Renders individuales por sub-producto/lado (frente + espalda con diseño del cliente)
      comboItemRenderedPreviews: comboItemRenderedPreviews || null,
      variant: variant || { size, color },
      finalPrice: price,
      isComboDesign: isCombo,
      designId: designId, // Se pasa el ID si ya existía
      imageURL: finalCustomizedImage
    };
    
    addToCart(product, variantToAdd, customization, 1);
    
    // Ignorar bloqueadores nativos porque yendo al carrito es una acción deseada
    bypassGuardsRef.current = true;
    navigate('/carrito');
  };

  const PLACEHOLDER_IMAGE = 'https://via.placeholder.com/500x600';

  // Misma lógica que en AdminProductoForm: view.imagesByColor?.[currentColor] || view.imagesByColor?.default
  const colorKey = product?.isClothing && variant?.color ? variant.color : 'default';
  const currentView = hasMultipleViews ? views.find((v) => v.id === activeViewId) : views[0] || null;
  
  const productImage = (() => {
    if (!product) return null;

    const trim = (s) => (typeof s === 'string' ? s.trim() : '');
    const valid = (url) => url && trim(url).length > 0 ? trim(url) : null;
    const matchedVar = product?.variants?.find(v => v.name === colorKey);

    // 1) Imagen de la vista actual por color
    if (currentView?.imagesByColor && typeof currentView.imagesByColor === 'object') {
      const viewImage = currentView.imagesByColor[colorKey];
      const url = valid(viewImage);
      if (url) return url;
    }

    // 2) Imagen de la variante explícita
    const varUrl = valid(matchedVar?.imageUrl);
    if (varUrl) return varUrl;

    // 3) Imagen default
    if (currentView?.imagesByColor && typeof currentView.imagesByColor === 'object') {
      const viewDefault = currentView.imagesByColor.default;
      const url = valid(viewDefault);
      if (url) return url;
    }

    // 4) Otra vista del mismo producto (por si la actual no tiene imagen)
    if (Array.isArray(product.customizationViews)) {
      for (const v of product.customizationViews) {
        if (!v?.imagesByColor || typeof v.imagesByColor !== 'object') continue;
        const def = valid(v.imagesByColor.default);
        if (def) return def;
        const any = Object.values(v.imagesByColor).find((val) => valid(val));
        if (any) return trim(any);
      }
    }

    // 3) Imagen principal del producto
    if (Array.isArray(product?.images) && product.images.length > 0) {
      const url = valid(product.images[0]);
      if (url) return url;
    }

    return PLACEHOLDER_IMAGE;
  })();

  // Memoizar printAreas para evitar nueva referencia en cada render (evita bucle en EditorCanvas)
  const printAreas = useMemo(() => {
    const cv = hasMultipleViews ? views.find((v) => v.id === activeViewId) : views[0] || null;
    if (cv?.printAreas && Array.isArray(cv.printAreas) && cv.printAreas.length > 0) {
      return cv.printAreas;
    }
    if (cv?.printArea && typeof cv.printArea === 'object') {
      return [{
        id: 'default',
        shape: 'rectangle',
        x: cv.printArea.x || 10,
        y: cv.printArea.y || 10,
        width: cv.printArea.width || 80,
        height: cv.printArea.height || 80
      }];
    }
    return [{ id: 'default', shape: 'rectangle', x: 10, y: 10, width: 80, height: 80 }];
  }, [hasMultipleViews, views, activeViewId]);

  const hasBackSide = currentView?.hasBackSide && currentView?.backSide;
  const backSideView = currentView?.backSide || null;
  
  const backSideImage = useMemo(() => {
    if (!backSideView || !product) return null;
    const trim = (s) => (typeof s === 'string' ? s.trim() : '');
    const valid = (url) => url && trim(url).length > 0 ? trim(url) : null;
    
    if (backSideView.imagesByColor && typeof backSideView.imagesByColor === 'object') {
      const viewImage = backSideView.imagesByColor[colorKey];
      const url = valid(viewImage);
      if (url) return url;
      const viewDefault = backSideView.imagesByColor.default;
      const urlDefault = valid(viewDefault);
      if (urlDefault) return urlDefault;
    }
    return null;
  }, [backSideView, colorKey, product]);

  const backSidePrintAreas = useMemo(() => {
    if (!backSideView?.printAreas || !Array.isArray(backSideView.printAreas) || backSideView.printAreas.length === 0) {
      return [{ id: 'back_default', shape: 'rectangle', x: 10, y: 10, width: 80, height: 80 }];
    }
    return backSideView.printAreas;
  }, [backSideView]);

  const viewIdToUse = isEditingBackSide && backSideView ? backSideView.id : activeViewId;

  if (isLoading || (existingDesignPrompt && existingDesignPrompt !== false)) {
    if (existingDesignPrompt && existingDesignPrompt !== false) {
      return (
        <div className={styles.container}>
          <div className={styles.promptModal}>
            <h3>Continuar diseño</h3>
            <p>Hemos encontrado que previamente estabas personalizando este equipo. ¿Qué deseas hacer?</p>
            <div className={styles.promptActions}>
              <Button onClick={() => {
                // Forzamos la recarga completa del navegador actuando como "otra página"
                window.location.href = `/editor/${id}?designId=${existingDesignPrompt.id}${size ? '&size='+size : ''}${color ? '&color='+color : ''}`;
              }}>
                Continuar Editando
              </Button>
              <Button variant="outline" onClick={() => setExistingDesignPrompt(false)}>
                Ver Producto Original
              </Button>
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className={styles.container}>
        <div className={styles.loadingInline}>
          <span className={styles.loadingDot} />
          <span>Cargando producto...</span>
        </div>
      </div>
    );
  }

  if (!product) {
    return <div className={styles.container}>Producto no encontrado</div>;
  }

  const priceDisplay = typeof price === 'number' && !Number.isNaN(price) ? price.toFixed(2) : '0.00';

  const renderExitModal = () => (
    <Modal isOpen={showExitModal} onClose={() => setShowExitModal(false)} title="¿Salir sin guardar?">
      <div style={{ padding: '0 1rem', paddingBottom: 'calc(1.5rem + env(safe-area-inset-bottom, 24px))' }}>
        <p style={{ marginBottom: '1.5rem', color: '#4b5563', lineHeight: '1.5', fontSize: '0.9375rem', textAlign: 'center' }}>
          Tienes cambios sin guardar. Si sales ahora, perderás toda tu personalización.
        </p>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
          <Button variant="primary" onClick={() => setShowExitModal(false)}>
            No, seguir editando
          </Button>
          {user && (
            <Button variant="outline" onClick={async () => {
              setShowExitModal(false);
              bypassGuardsRef.current = true;
              await handleSaveDesign();
              // Retraso para que se guarde
              setTimeout(() => navigate(`/producto/${product?.id || id}`), 1000);
            }}>
              Guardar diseño y salir
            </Button>
          )}
          <button 
            type="button"
            onClick={() => { 
              setShowExitModal(false); 
              bypassGuardsRef.current = true; 
              navigate(`/producto/${product?.id || id}`); 
            }}
            style={{ 
              background: 'none', 
              border: 'none', 
              color: '#dc2626', 
              padding: '0.75rem', 
              fontWeight: 600, 
              cursor: 'pointer',
              marginTop: '0.5rem',
              fontSize: '0.9375rem'
            }}
          >
            Sí, salir sin guardar
          </button>
        </div>
      </div>
    </Modal>
  );

  const renderSavePromptModal = () => (
    <Modal isOpen={showSavePromptModal} onClose={() => setShowSavePromptModal(false)} title="¡Guarda tu progreso!">
      <div style={{ padding: '0 1rem', paddingBottom: 'calc(1.5rem + env(safe-area-inset-bottom, 24px))' }}>
        <p style={{ marginBottom: '1.5rem', color: '#4b5563', lineHeight: '1.5', fontSize: '0.9375rem', textAlign: 'center' }}>
          Tu diseño está quedando increíble. Guarda tu progreso para no perderlo y poder continuar en cualquier momento o dispositivo.
        </p>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
          <Button variant="primary" onClick={() => navigate('/login?redirect=' + encodeURIComponent(window.location.pathname + window.location.search))}>
            Iniciar Sesión
          </Button>
          <Button variant="outline" onClick={() => navigate('/registro?redirect=' + encodeURIComponent(window.location.pathname + window.location.search))}>
            Crear una Cuenta
          </Button>
          <button 
            type="button"
            onClick={() => setShowSavePromptModal(false)}
            style={{ 
              background: 'none', 
              border: 'none', 
              color: '#6b7280', 
              padding: '0.75rem', 
              fontWeight: 600, 
              cursor: 'pointer',
              marginTop: '0.5rem',
              fontSize: '0.9375rem'
            }}
          >
            Seguir editando sin guardar
          </button>
        </div>
      </div>
    </Modal>
  );

  // Si es combo, renderizar el editor de combos en vez del AdminViewEditor
  if (isCombo && editorMounted) {
    return (
      <div className={styles.container}>
        <ComboUserEditor
          comboProduct={product}
          comboItems={product.comboItems || []}
          userComboCustomization={userComboCustomization}
          comboLayout={product.comboLayout || { orientation: 'horizontal', spacing: 20 }}
          initialVariantSelections={userComboCustomization ? userComboCustomization.reduce((acc, item, idx) => {
            // Asegurar que capturemos la variante guardada, o rellenemos con la permitida/defecto del item
            if (item.variant) {
              acc[idx] = item.variant;
            } else if (product.comboItems?.[idx]) {
               const variantMap = product.comboItems[idx].variantMapping;
               acc[idx] = { color: variantMap?.color || 'default', size: variantMap?.size || '' };
            }
            return acc;
          }, {}) : {}}
          onVariantChange={handleVariantChange}
          onLayersChange={handleComboLayersChange}
          isDesignLoaded={designLoaded}
        />
        <div className={styles.resetDesignContainer}>
          <button 
             type="button" 
             className={styles.resetDesignBtn} 
             onClick={handleResetDesign}
          >
            <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"></path><path d="M3 3v5h5"></path></svg>
             Restablecer diseño original
          </button>
        </div>
        <div className={styles.actionsBar} aria-label="Acciones del editor">
          <Button variant="outline" onClick={handleReturn}>
            Volver
          </Button>
          <Button variant="outline" onClick={handleSaveDesign} disabled={savingDesign}>
            {savingDesign ? 'Guardando...' : 'Guardar'}
          </Button>
          <Button variant="primary" onClick={handleAddToCart} className={styles.btnPrimaryMobile}>
            Agregar al Carrito
          </Button>
        </div>
        {renderExitModal()}
        {renderSavePromptModal()}
      </div>
    );
  }

  const SingleProductControls = (
    <div className={styles.singleProductControlsWrapper}>
      {product.isClothing && (
        <div className={styles.variantBar}>
          {product.variants?.sizes?.length > 0 && (
            <div className={styles.variantGroup}>
              <span className={styles.variantLabel}>
                Talla:
                {product.variants.sizes.length > 5 && <span className={styles.scrollHint}>Deslizar <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"></path><path d="m12 5 7 7-7 7"></path></svg></span>}
              </span>
              <DraggableContainer className={styles.variantOptions} onPointerDown={(e) => e.stopPropagation()} onTouchStart={(e) => e.stopPropagation()} onClick={(e) => e.stopPropagation()}>
                {(product.variants.sizes || []).map((s) => (
                  <button
                    key={s}
                    type="button"
                    className={`${styles.variantBtn} ${variant?.size === s ? styles.variantBtnActive : ''}`}
                    onClick={() => setVariant((prev) => ({ ...prev, size: s }))}
                  >
                    {s}
                  </button>
                ))}
              </DraggableContainer>
            </div>
          )}
          {product.variants?.colors?.length > 0 && (
            <div className={styles.variantGroup}>
              <span className={styles.variantLabel}>
                Color:
                {product.variants.colors.length > 5 && <span className={styles.scrollHint}>Deslizar <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"></path><path d="m12 5 7 7-7 7"></path></svg></span>}
              </span>
              <DraggableContainer className={styles.variantOptions} onPointerDown={(e) => e.stopPropagation()} onTouchStart={(e) => e.stopPropagation()} onClick={(e) => e.stopPropagation()}>
                {(product.variants.colors || []).map((c) => (
                  <button
                    key={c}
                    type="button"
                    className={`${styles.variantBtn} ${styles.colorBtn} ${variant?.color === c ? styles.variantBtnActive : ''}`}
                    onClick={() => setVariant((prev) => ({ ...prev, color: c }))}
                    title={c}
                    style={{ backgroundColor: /^#|[a-fA-F0-9]{6}$/.test(c) ? c : undefined }}
                  >
                    {/^#|[a-fA-F0-9]{6}$/.test(c) ? '' : c.slice(0, 1)}
                  </button>
                ))}
              </DraggableContainer>
            </div>
          )}
        </div>
      )}

      <div className={styles.resetDesignContainer}>
        <button 
           type="button" 
           className={styles.resetDesignBtn} 
           onClick={handleResetDesign}
        >
          <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"></path><path d="M3 3v5h5"></path></svg>
          Restablecer diseño original
        </button>
      </div>

      {hasMultipleViews && (
        <div className={styles.viewTabs}>
          {views.map((v) => (
            <button
              key={v.id}
              type="button"
              className={`${styles.viewTab} ${activeViewId === v.id && !isEditingBackSide ? styles.viewTabActive : ''}`}
              onClick={() => {
                setActiveViewId(v.id);
                setIsEditingBackSide(false);
                // Inicializar zona activa al cambiar de vista
                if (v.printAreas && Array.isArray(v.printAreas) && v.printAreas.length > 0) {
                  setActivePrintAreaId(v.id, v.printAreas[0].id);
                }
              }}
            >
              {v.name}
            </button>
          ))}
          {hasBackSide && (
            <button
              type="button"
              className={`${styles.viewTab} ${isEditingBackSide ? styles.viewTabActive : ''}`}
              onClick={() => {
                setIsEditingBackSide(true);
                if (backSideView?.printAreas && Array.isArray(backSideView.printAreas) && backSideView.printAreas.length > 0) {
                  setActivePrintAreaId(backSideView.id, backSideView.printAreas[0].id);
                }
              }}
            >
              {backSideView?.name || 'Espalda'}
            </button>
          )}
        </div>
      )}
    </div>
  );

  return (
    <div className={styles.container}>

      {/* Botón exclusivo para móvil para abrir ajustes */}
      <div className={styles.showOnlyMobile}>
        <button className={styles.mobileSettingsBtn} onClick={() => setShowMobileSettingsModal(true)}>
          <svg viewBox="0 0 24 24" width="20" height="20" stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="3"></circle><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"></path></svg>
          Ajustes de Producto
        </button>
      </div>

      <div className={styles.desktopControls}>
        {SingleProductControls}
      </div>

      {showMobileSettingsModal && (
        <Modal 
          isOpen={showMobileSettingsModal} 
          onClose={() => setShowMobileSettingsModal(false)}
          title="Ajustes de Producto"
          position="center"
        >
          {SingleProductControls}
          <Button 
            variant="primary" 
            onClick={() => setShowMobileSettingsModal(false)}
            style={{ width: '100%', marginTop: '1rem' }}
          >
            Aceptar
          </Button>
        </Modal>
      )}

      {editorMounted && (isEditingBackSide ? backSideImage : productImage) ? (
        <AdminViewEditor
          viewId={viewIdToUse}
          productImage={isEditingBackSide ? backSideImage : productImage}
          printAreas={isEditingBackSide ? backSidePrintAreas : printAreas}
          initialLayersByColor={{
            [colorKey]: (layersByView?.[viewIdToUse]?.length > 0)
              ? layersByView[viewIdToUse]
              : (isEditingBackSide
                  ? backSideView?.initialLayersByColor?.[colorKey] || backSideView?.initialLayersByColor?.default
                  : currentView?.initialLayersByColor?.[colorKey] || currentView?.initialLayersByColor?.default) || []
          }}
          currentColor={colorKey}
          availableColors={product?.variants?.colors}
          onColorChange={(c) => setVariant((prev) => ({ ...prev, color: c }))}
          onLayersChange={(color, newLayers) => setLayersForView(viewIdToUse, newLayers)}
          designOnly
          noHeader
        />
      ) : editorMounted && !(isEditingBackSide ? backSideImage : productImage) ? (
        <div className={styles.loadingInline}>
          <span className={styles.loadingDot} />
          <span>Cargando imagen del producto...</span>
        </div>
      ) : (
        <div className={styles.loadingInline}>
          <span className={styles.loadingDot} />
          <span>Preparando editor...</span>
        </div>
      )}

      <div className={styles.actionsBar} aria-label="Acciones del editor">
        <Button variant="outline" onClick={handleReturn}>
          Volver
        </Button>
        <Button variant="outline" onClick={handleSaveDesign} disabled={savingDesign}>
          {savingDesign ? 'Guardando...' : 'Guardar'}
        </Button>
        <Button variant="primary" onClick={handleAddToCart} className={styles.btnPrimaryMobile}>
          Agregar al Carrito
        </Button>
      </div>

      {renderExitModal()}
      {renderSavePromptModal()}
    </div >
  );
};

export default function EditorPageWrapper(props) {
