  ];

  const handleNextReview = () => {
    if (!isTransitioning) return;
    setReviewsSlideIndex((prev) => prev + 1);
  };

  const handlePrevReview = () => {
    if (!isTransitioning) return;
    setReviewsSlideIndex((prev) => prev - 1);
  };

  // ARREGLO DE PARES DE IMÁGENES PARA EL BLOQUE VS (4 imágenes = 2 pares)
  const vsSlidesData = [
    { left: 'https://picsum.photos/400/400?random=10', right: 'https://picsum.photos/400/400?random=11' },
    { left: 'https://picsum.photos/400/400?random=12', right: 'https://picsum.photos/400/400?random=13' }
  ];

  const handleNextVsSlide = () => {
    setVsSlideIndex((prev) => (prev + 1) % vsSlidesData.length);
  };

  const handlePrevVsSlide = () => {
    setVsSlideIndex((prev) => (prev - 1 + vsSlidesData.length) % vsSlidesData.length);
  };

  // LÓGICA DEL CARRUSEL INFINITO FLUIDO (BLOQUE 9)
  React.useEffect(() => {
    let timeout;
    if (reviewsSlideIndex >= reviewsData.length * 2) {
      timeout = setTimeout(() => {
        setIsTransitioning(false);
        setReviewsSlideIndex(reviewsData.length + (reviewsSlideIndex - reviewsData.length * 2));
      }, 500);
    }
    else if (reviewsSlideIndex <= 0) {
      timeout = setTimeout(() => {
        setIsTransitioning(false);
        setReviewsSlideIndex(reviewsData.length + reviewsSlideIndex);
      }, 500);
    }
    else if (!isTransitioning) {
      timeout = setTimeout(() => {
        setIsTransitioning(true);
      }, 50);
    }
    return () => clearTimeout(timeout);
  }, [reviewsSlideIndex, isTransitioning, reviewsData.length]);

