const EVENT_TYPES = [
  { id: 'cumpleanos', label: 'Cumpleaños', needsDate: true },
  { id: 'aniversario', label: 'Aniversario', needsDate: true },
  { id: 'otro', label: 'Fecha Especial', needsDate: true }
];

const ROLES_MAP = {
  hijos: { label: 'Hijos', icon: <UserPlus size={32} />, singular: 'Hijo/a' },
  padres: { label: 'Padres', icon: <Users size={32} />, singular: 'Padre/Madre' },
  hermanos: { label: 'Hermanos', icon: <Users size={32} />, singular: 'Hermano/a' },
  sobrinos: { label: 'Sobrinos', icon: <Users size={32} />, singular: 'Sobrino/a' },
  primos: { label: 'Primos', icon: <Users size={32} />, singular: 'Primo/a' },
  amigos: { label: 'Amigos', icon: <UserPlus size={32} />, singular: 'Amigo/a' },
  otros: { label: 'Otros', icon: <UserCircle size={32} />, singular: 'Otra persona' }
};

const SubscriptionSurveyPage = () => {
  const { userProfile, updateUserProfile, loading: authLoading, earnMainCoins } = useAuth();
  const navigate = useNavigate();
  
  const [config, setConfig] = useState(DEFAULT_SURVEY_CONFIG);
  const [configLoading, setConfigLoading] = useState(true);
  
  // Flujo Principal
  const [currentStep, setCurrentStep] = useState(0); 
  const [saving, setSaving] = useState(false);
  const [animationDir, setAnimationDir] = useState('Right');
  
  const [basicAnswers, setBasicAnswers] = useState({});
  
  // Selección de Roles
  const [selectedRoles, setSelectedRoles] = useState({
    pareja: false,
    hijos: false,
    padres: false,
    hermanos: false,
    sobrinos: false,
    primos: false,
    amigos: false,
    otros: false
  });

  // Bucle de Roles (Hub and Spoke)
  const [rolesList, setRolesList] = useState([]);
  const [currentRoleIndex, setCurrentRoleIndex] = useState(0);
  
  const [isEditingRecipient, setIsEditingRecipient] = useState(false);
  const [tempRecipient, setTempRecipient] = useState(null);
  
  const [finalRecipients, setFinalRecipients] = useState([]);

  useEffect(() => {
    const fetchConfig = async () => {
      const { data } = await getSurveyConfig();
      if (data) setConfig({ ...DEFAULT_SURVEY_CONFIG, ...data });
      setConfigLoading(false);
    };
    fetchConfig();
  }, []);

  const handleSkip = async () => {
    try {
      await updateUserProfile({ lastSurveyPromptedAt: Date.now() });
    } catch (e) {
      console.error('Error saving skip timestamp:', e);
    }
    navigate('/', { replace: true });
  };

  const validateFields = (fieldsArray, answersObject) => {
    for (let field of fieldsArray) {
      if (field.required && !answersObject[field.id]) {
        alert(`Por favor completa el campo: ${field.label}`);
        return false;
      }
    }
    return true;
  };

  const createBlankRecipient = (roleKey, displayRole) => {
    return {
      id: Math.random().toString(36).substring(2, 9),
      roleKey,
      roleDisplay: displayRole,
      name: '',
      gender: '',
      events: [{ id: Math.random().toString(36).substring(2, 9), type: 'Cumpleaños', date: '' }],
      selectedCategories: [],
      categoryAnswers: {},
      familySet: false,
      familyAnswers: { q1: '', q2: '', q3: '' }
    };
  };

  const setupParejaIfNeeded = (recipientsList, currentRoles, index) => {
    if (currentRoles[index] === 'pareja') {
      const hasPareja = recipientsList.some(r => r.roleKey === 'pareja');
      if (!hasPareja) {
        setFinalRecipients(prev => [...prev, createBlankRecipient('pareja', 'Pareja')]);
      }
    }
  };

  const goToNextStep = () => {
    if (currentStep === 1 && !validateFields(config.basicDataPanel.fields, basicAnswers)) return;
    
    if (currentStep === 2) {
      const selectedKeys = Object.keys(ROLES_MAP).filter(key => selectedRoles[key]);
      if (selectedRoles.pareja) selectedKeys.unshift('pareja');
      
      if (selectedKeys.length === 0) {
        return alert('Por favor, selecciona al menos un rol o dale a Atrás/Omitir si no deseas regalar a nadie.');
      }

      setRolesList(selectedKeys);
      setCurrentRoleIndex(0);
      setIsEditingRecipient(false);
      setupParejaIfNeeded(finalRecipients, selectedKeys, 0);
    }

    setAnimationDir('Right');
    setCurrentStep(prev => prev + 1);
  };

  const goBack = () => {
    setAnimationDir('Left');
    setCurrentStep(prev => prev - 1);
  };

  const isRecipientComplete = (rec) => {
    if (!rec.name || rec.name.trim() === '') return false;
    if (!rec.gender || rec.gender.trim() === '') return false;
    
    for (const ev of rec.events) {
      const evTypeConfig = EVENT_TYPES.find(e => e.label === ev.type) || EVENT_TYPES.find(e => e.label === 'Otro Evento');
      if (evTypeConfig.needsDate && (!ev.date || ev.date.trim() === '')) {
        return false;
      }
    }
    
    return true;
  };

  const goToNextRoleGroup = () => {
    const currentRoleKey = rolesList[currentRoleIndex];
    const roleRecipients = finalRecipients.filter(r => r.roleKey === currentRoleKey);
    
    const hasIncompletes = roleRecipients.some(r => !isRecipientComplete(r));
    if (hasIncompletes) {
       return alert('Por favor completa todos los datos obligatorios (Nombre y Género) de todas las tarjetas antes de continuar.');
    }
    
    if (roleRecipients.length === 0 && currentRoleKey !== 'pareja') {
      const confirmSkip = window.confirm('No has agregado a nadie en este grupo. ¿Deseas continuar de todos modos?');
      if (!confirmSkip) return;
    }

    const nextIdx = currentRoleIndex + 1;
    if (nextIdx < rolesList.length) {
      setAnimationDir('Right');
      setCurrentRoleIndex(nextIdx);
      setIsEditingRecipient(false);
      setupParejaIfNeeded(finalRecipients, rolesList, nextIdx);
    } else {
      handleFinalSave();
    }
  };

  const handleAddNewCard = () => {
    const roleKey = rolesList[currentRoleIndex];
    const roleDisplay = ROLES_MAP[roleKey].singular;
    const newRecipient = createBlankRecipient(roleKey, roleDisplay);
    setFinalRecipients(prev => [...prev, newRecipient]);
  };

  const startEditingCard = (recipient) => {
    setTempRecipient(JSON.parse(JSON.stringify(recipient)));
    setAnimationDir('Right');
    setIsEditingRecipient(true);
  };

  const handleTempChange = (field, value) => {
    setTempRecipient(prev => ({ ...prev, [field]: value }));
  };

  const addEvent = () => {
    setTempRecipient(prev => ({
      ...prev,
      events: [...prev.events, { id: Math.random().toString(36).substring(2, 9), type: 'Fecha Especial', date: '', customName: '' }]
    }));
  };

  const updateEvent = (index, field, value) => {
    setTempRecipient(prev => {
      const newEvents = [...prev.events];
      newEvents[index][field] = value;
      
      if (field === 'type') {
        const evTypeConfig = EVENT_TYPES.find(e => e.label === value) || EVENT_TYPES.find(e => e.id === 'otro');
        if (evTypeConfig && !evTypeConfig.needsDate) {
          newEvents[index].date = '';
        }
      }
      return { ...prev, events: newEvents };
    });
  };

  const removeEvent = (index) => {
    setTempRecipient(prev => {
      const newEvents = [...prev.events];
      newEvents.splice(index, 1);
      return { ...prev, events: newEvents };
    });
  };

  const saveTempRecipient = () => {
    if (!tempRecipient.name || tempRecipient.name.trim() === '') {
       return alert('El nombre es obligatorio.');
    }
    if (!tempRecipient.gender || tempRecipient.gender.trim() === '') {
       return alert('El género es obligatorio.');
    }

    for (const ev of tempRecipient.events) {
      const evTypeConfig = EVENT_TYPES.find(e => e.label === ev.type) || EVENT_TYPES.find(e => e.id === 'otro');
      if (evTypeConfig.needsDate && (!ev.date || ev.date.trim() === '')) {
        return alert(`La fecha es obligatoria para el evento: ${ev.type}.`);
      }
      if (ev.type === 'Fecha Especial' && (!ev.customName || ev.customName.trim() === '')) {
        return alert('Por favor, indica qué se celebra en la Fecha Especial.');
      }
    }

    setFinalRecipients(prev => {
      const copy = [...prev];
      const existingIdx = copy.findIndex(r => r.id === tempRecipient.id);
      if (existingIdx >= 0) {
        copy[existingIdx] = tempRecipient;
      }
      return copy;
    });

    setAnimationDir('Left');
    setIsEditingRecipient(false);
  };

  const cancelTempRecipient = () => {
    setAnimationDir('Left');
    setIsEditingRecipient(false);
  };

  const handleFinalSave = async () => {
    setSaving(true);
    try {
      const validRecipients = finalRecipients.filter(r => isRecipientComplete(r));
      
      // Calcular monedas ganadas solo si es la primera vez que completa la encuesta
      let coinsEarned = 0;
      
      if (!userProfile.hasCompletedSurvey) {
        let totalFechas = 0;
        validRecipients.forEach(r => {
          totalFechas += r.events.length;
        });
        coinsEarned = totalFechas * 5;
      }
      
      await updateUserProfile({ 
        surveyBasicData: basicAnswers, 
        giftRoles: selectedRoles,
        giftRecipients: validRecipients, 
        hasCompletedSurvey: true
      });

      if (coinsEarned > 0) {
        await earnMainCoins(coinsEarned, 'Fechas registradas en encuesta', 90);
        window.dispatchEvent(new CustomEvent('coins-animation-start', { detail: { amount: coinsEarned } }));
      }

      setAnimationDir('Right');
      setCurrentStep(4);
    } catch (err) {
      alert('Hubo un error al guardar tus datos.');
    } finally {
      setSaving(false);
    }
  };

  if (authLoading || configLoading) return <div className={styles.surveyLayout}>Cargando...</div>;

  let progressPercent = 0;
  if (currentStep <= 2) {
    progressPercent = (currentStep / 4) * 100;
  } else if (currentStep === 3) {
    const subProgress = (currentRoleIndex / rolesList.length) * (100 / 4);
    progressPercent = (3 / 4) * 100 + subProgress;
  } else {
    progressPercent = 100;
  }

  const animationKey = currentStep === 3 ? `${rolesList[currentRoleIndex]}-${isEditingRecipient ? 'edit' : 'hub'}` : `main-${currentStep}`;
  const animationClass = animationDir === 'Right' ? styles.animateSlideInRight : styles.animateSlideInLeft;

  const currentRoleObj = rolesList[currentRoleIndex] === 'pareja' 
    ? { label: 'Pareja', icon: <Heart size={32} />, singular: 'Pareja' } 
    : ROLES_MAP[rolesList[currentRoleIndex]];

  return (
    <div className={styles.surveyLayout} style={{ '--survey-primary': config.design.primaryColor, backgroundColor: config.design.backgroundColor, color: config.design.textColor }}>
      
      <div className={styles.sideScene}></div>

      <div className={styles.centerColumn}>
        
        <div className={styles.progressBarContainer}>
          <div className={styles.progressBarLight}></div>
          <div className={styles.progressBarFill} style={{ width: `${progressPercent}%` }}></div>
        </div>

        <div key={animationKey} className={`${styles.card} ${animationClass}`}>
          
          {currentStep === 0 && (
            <>
              <div className={styles.headerIcon}><Gift size={40} color={config.design.primaryColor} /></div>
              <h1 className={styles.title}>{config.introPanel.title}</h1>
              <h2 className={styles.subtitle}>{config.introPanel.subtitle}</h2>
              
              <div style={{ backgroundColor: '#fffbeb', color: '#b45309', padding: '1rem', borderRadius: '12px', margin: '1.5rem 0', display: 'flex', alignItems: 'center', gap: '0.75rem', fontWeight: 'bold', border: '1px solid #fde68a', boxShadow: '0 4px 6px -1px rgba(251, 191, 36, 0.1)' }}>
                <span style={{ fontSize: '2rem', lineHeight: 1 }}>🪙</span>
                <span style={{ fontSize: '1rem', textAlign: 'left' }}>
                  ¡Gana 5 Kapicoins por cada fecha importante (Cumpleaños o Fecha Especial) que registres de tus seres queridos!
                </span>
              </div>

              <p className={styles.description}>{config.introPanel.description}</p>
              <div className={styles.actions} style={{ justifyContent: 'center' }}>
                <button type="button" onClick={handleSkip} className={styles.skipBtn}>{config.introPanel.skipButtonText}</button>
                <button type="button" onClick={goToNextStep} className={styles.saveBtn}>{config.introPanel.continueButtonText}</button>
              </div>
            </>
          )}

          {currentStep === 1 && (
            <>
              <div className={styles.headerIcon}><UserCircle size={40} color={config.design.primaryColor} /></div>
              <h1 className={styles.title}>{config.basicDataPanel.title}</h1>
              <h2 className={styles.subtitle}>{config.basicDataPanel.subtitle}</h2>
              <div className={styles.form}>
                {config.basicDataPanel.fields.map(f => (
                  <div key={f.id} className={styles.fieldGroup}>
                    <label>{f.label} {f.required && '*'}</label>
                    {f.type === 'text' && <input type="text" className={styles.input} value={basicAnswers[f.id] || ''} onChange={e => setBasicAnswers(p => ({...p, [f.id]: e.target.value}))} required={f.required} />}
                    {f.type === 'select' && (
                      <select className={styles.input} value={basicAnswers[f.id] || ''} onChange={e => setBasicAnswers(p => ({...p, [f.id]: e.target.value}))} required={f.required}>
                        <option value="">Seleccionar...</option>
                        {f.options?.map((opt, i) => <option key={i} value={opt}>{opt}</option>)}
                      </select>
                    )}
                  </div>
                ))}
              </div>
              <div className={styles.actions}>
                <button type="button" onClick={goBack} className={styles.skipBtn}>Atrás</button>
                <button type="button" onClick={goToNextStep} className={styles.saveBtn}>Continuar</button>
              </div>
            </>
          )}

          {currentStep === 2 && (
            <>
              <div className={styles.headerIcon}><Users size={40} color={config.design.primaryColor} /></div>
              <h1 className={styles.title}>¿A quiénes sueles regalar?</h1>
              <p className={styles.description}>Selecciona todos los perfiles a los que sueles hacer regalos (puedes elegir varios).</p>
              
              <div className={styles.groupsContainer}>
                <button 
                  className={`${styles.groupCard} ${selectedRoles.pareja ? styles.groupCardSelected : ''}`}
                  onClick={() => setSelectedRoles(p => ({...p, pareja: !p.pareja}))}
                >
                  <Heart size={32} /><h3>Pareja</h3>
                </button>
                {Object.keys(ROLES_MAP).map(roleKey => (
                  <button 
                    key={roleKey}
                    className={`${styles.groupCard} ${selectedRoles[roleKey] ? styles.groupCardSelected : ''}`}
                    onClick={() => setSelectedRoles(p => ({...p, [roleKey]: !p[roleKey]}))}
                  >
                    {ROLES_MAP[roleKey].icon}<h3>{ROLES_MAP[roleKey].label}</h3>
                  </button>
                ))}
              </div>

              <div className={styles.actions}>
                <button type="button" onClick={goBack} className={styles.skipBtn}>Atrás</button>
                <button type="button" onClick={goToNextStep} className={styles.saveBtn}>Continuar</button>
              </div>
            </>
          )}

          {currentStep === 3 && currentRoleObj && (
            <>
              {!isEditingRecipient ? (
                <>
                  <div className={styles.headerIcon}>{currentRoleObj.icon}</div>
                  <h1 className={styles.title}>{rolesList[currentRoleIndex] === 'pareja' ? 'Tu Pareja' : `Tus ${currentRoleObj.label}`}</h1>
                  <p className={styles.description}>Completa los datos de estas personas para poder guardarlas.</p>
                  
                  <div className={styles.form}>
                    <div className={styles.recipientsList}>
                      {finalRecipients.filter(r => r.roleKey === rolesList[currentRoleIndex]).map((rec, idx) => {
                        const isDone = isRecipientComplete(rec);
                        return (
                          <div key={rec.id} className={`${styles.recipientCard} ${isDone ? styles.cardComplete : styles.cardIncomplete}`} onClick={() => startEditingCard(rec)}>
                            <div className={styles.recipientInfo}>
                              <h3>{rec.name || `${rec.roleDisplay} (Sin Nombre)`}</h3>
                              {isDone ? (
                                <p style={{color: '#10b981'}}><CheckCircle size={14}/> Perfil Completado</p>
                              ) : (
                                <p style={{color: '#f59e0b'}}><AlertCircle size={14}/> Falta completar datos</p>
                              )}
                            </div>
                            <button type="button" className={isDone ? styles.hubEditBtn : styles.hubCompleteBtn} onClick={(e) => { e.stopPropagation(); startEditingCard(rec); }}>
                              {isDone ? 'Editar' : 'Completar Perfil'}
                            </button>
                            {rolesList[currentRoleIndex] !== 'pareja' && (
                              <button type="button" onClick={(e) => { e.stopPropagation(); setFinalRecipients(prev => prev.filter(p => p.id !== rec.id)); }} className={styles.removeBtn} style={{marginLeft:'0.5rem'}}>
                                <Trash2 size={20} />
                              </button>
                            )}
                          </div>
                        );
                      })}
                    </div>

                    {rolesList[currentRoleIndex] !== 'pareja' && (
                      <button type="button" onClick={handleAddNewCard} className={styles.addRecipientBtn}>
                        <Plus size={20} /> Añadir {currentRoleObj.singular}
                      </button>
                    )}
                  </div>

                  <div className={styles.actions}>
                    {currentRoleIndex === 0 ? (
                      <button type="button" onClick={() => setCurrentStep(2)} className={styles.skipBtn}>Atrás</button>
                    ) : (
                      <button type="button" onClick={() => {
                        setAnimationDir('Left');
                        setCurrentRoleIndex(prev => prev - 1);
                        setIsEditingRecipient(false);
                      }} className={styles.skipBtn}>Grupo Anterior</button>
                    )}
                    <button type="button" onClick={goToNextRoleGroup} className={styles.saveBtn} disabled={saving}>
                      {currentRoleIndex + 1 >= rolesList.length ? (saving ? 'Guardando...' : 'Terminar Encuesta') : 'Siguiente Grupo'}
                    </button>
                  </div>
                </>
              ) : (
                <>
                  <div className={styles.subFlowHeader}>
                    <button className={styles.backLinkBtn} onClick={cancelTempRecipient} style={{background:'none', border:'none', color:'#64748b', display:'flex', alignItems:'center', gap:'0.5rem', cursor:'pointer', marginBottom:'1rem', fontWeight:'600'}}>
                      <ArrowLeft size={16}/> Volver sin guardar
                    </button>
                    <h3>Datos de {tempRecipient.roleDisplay}</h3>
                  </div>
                  
                  <div className={styles.form}>
                    <div style={{ display: 'flex', gap: '1rem' }}>
                      <div className={styles.fieldGroup} style={{ flex: 2 }}>
                        <label>Nombre de la persona *</label>
                        <input type="text" className={styles.input} placeholder="Ej. Carlos" value={tempRecipient.name} onChange={e => handleTempChange('name', e.target.value)} />
                      </div>
                      <div className={styles.fieldGroup} style={{ flex: 1 }}>
                        <label>Género *</label>
                        <select className={styles.input} value={tempRecipient.gender || ''} onChange={e => handleTempChange('gender', e.target.value)} required>
                          <option value="">Seleccionar...</option>
                          <option value="Masculino">Masculino</option>
                          <option value="Femenino">Femenino</option>
                          <option value="Otro">Otro</option>
                        </select>
                      </div>
                    </div>
                    
                    <div className={styles.breakdownSection}>
                      <h3 className={styles.breakdownTitle} style={{fontSize:'1rem'}}>Fechas Importantes</h3>
                      
                      {tempRecipient.events.map((event, eventIdx) => {
                        const evTypeConfig = EVENT_TYPES.find(e => e.label === event.type) || EVENT_TYPES.find(e => e.id === 'otro');
                        
                        return (
                          <div key={event.id} style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem', alignItems: 'flex-start', background: eventIdx === 0 ? '#f8fafc' : 'transparent', padding: eventIdx === 0 ? '1rem' : '0', borderRadius: '8px', border: eventIdx === 0 ? '1px solid #e2e8f0' : 'none' }}>
                            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                              
                              {eventIdx === 0 ? (
                                <div style={{ fontWeight: 'bold', color: '#0f172a', padding: '0.5rem 0' }}>
                                  Cumpleaños *
                                </div>
                              ) : (
                                <select 
                                  className={styles.input} 
                                  value={event.type}
                                  onChange={e => updateEvent(eventIdx, 'type', e.target.value)}
                                >
                                  {EVENT_TYPES.filter(et => et.id !== 'cumpleanos').map(et => (
                                    <option key={et.id} value={et.label}>{et.label}</option>
                                  ))}
                                </select>
                              )}
                              
                              {event.type === 'Fecha Especial' && eventIdx > 0 && (
                                <input 
                                  type="text" 
                                  className={styles.input} 
                                  placeholder="¿Qué se celebra? (Ej. Bautizo, Graduación)" 
                                  value={event.customName || ''} 
                                  onChange={e => updateEvent(eventIdx, 'customName', e.target.value)}
                                  required={true}
                                />
                              )}

                              {evTypeConfig.needsDate && (
                                <input 
                                  type="date" 
                                  className={styles.input} 
                                  value={event.date} 
                                  onChange={e => updateEvent(eventIdx, 'date', e.target.value)} 
                                  required={true}
                                />
                              )}
                            </div>
                            
                            {eventIdx > 0 && (
                              <button type="button" onClick={() => removeEvent(eventIdx)} className={styles.removeBtn} style={{ marginTop: '0.2rem' }}>
                                <Trash2 size={20} />
                              </button>
                            )}
                          </div>
                        );
                      })}
                      
                      <button type="button" onClick={addEvent} className={styles.addBtn} style={{ background: 'transparent', color: config.design.primaryColor, border: `1px dashed ${config.design.primaryColor}`, padding: '0.5rem', borderRadius: '8px', width: '100%', cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '0.5rem', fontWeight: 'bold' }}>
                        <Plus size={18} /> Agregar otra fecha importante
                      </button>
                    </div>

                    {/* CONJUNTO FAMILIA (Hardcoded con lógica de género) */}
                    <div className={styles.breakdownSection} style={{ padding: '1rem' }}>
                      <button 
                        type="button"
                        className={`${styles.conjuntoBtn} ${tempRecipient.familySet ? styles.conjuntoBtnActive : ''}`}
                        onClick={() => handleTempChange('familySet', !tempRecipient.familySet)}
                      >
                        <span style={{flex: 1, textAlign: 'left', fontWeight: 'bold'}}>Conjunto Familia</span>
                        <div className={styles.toggleIndicator}>
                          <div className={styles.toggleCircle}></div>
                        </div>
                      </button>
                      
                      {tempRecipient.familySet && (
                        <div style={{ marginTop: '1rem' }}>
                          <div className={styles.fieldGroup}>
                            <label>¿Es para {tempRecipient.gender === 'Masculino' ? 'él' : tempRecipient.gender === 'Femenino' ? 'ella' : 'él o ella'}?</label>
                            <input 
                              type="text" 
                              className={styles.input} 
                              placeholder="Ej. Ropa, reloj..."
                              value={tempRecipient.familyAnswers?.q1 || ''} 
                              onChange={e => handleTempChange('familyAnswers', { ...tempRecipient.familyAnswers, q1: e.target.value })} 
                            />
                          </div>
                          <div className={styles.fieldGroup}>
                            <label>¿Es para ambos?</label>
                            <input 
                              type="text" 
                              className={styles.input} 
                              placeholder="Ej. Un viaje, cena..."
                              value={tempRecipient.familyAnswers?.q2 || ''} 
                              onChange={e => handleTempChange('familyAnswers', { ...tempRecipient.familyAnswers, q2: e.target.value })} 
                            />
                          </div>
                          <div className={styles.fieldGroup}>
                            <label>¿Es para más personas?</label>
                            <input 
                              type="text" 
                              className={styles.input} 
                              placeholder="Ej. Juego de mesa familiar..."
                              value={tempRecipient.familyAnswers?.q3 || ''} 
                              onChange={e => handleTempChange('familyAnswers', { ...tempRecipient.familyAnswers, q3: e.target.value })} 
                            />
                          </div>
                        </div>
                      )}
                    </div>

                    {/* CONJUNTOS DINÁMICOS DE FIREBASE */}
                    {config.brandsPanel?.categories?.map(cat => {
                      const isCatSelected = tempRecipient.selectedCategories?.includes(cat.id);
                      return (
                        <div key={cat.id} className={styles.breakdownSection} style={{ padding: '1rem' }}>
                          <button 
                            type="button"
                            className={`${styles.conjuntoBtn} ${isCatSelected ? styles.conjuntoBtnActive : ''}`}
                            onClick={() => {
                              const currentList = tempRecipient.selectedCategories || [];
                              const newList = !isCatSelected ? [...currentList, cat.id] : currentList.filter(id => id !== cat.id);
                              handleTempChange('selectedCategories', newList);
                            }}
                          >
                            <span style={{flex: 1, textAlign: 'left', fontWeight: 'bold'}}>Conjunto {cat.name}</span>
                            <div className={styles.toggleIndicator}>
                              <div className={styles.toggleCircle}></div>
                            </div>
                          </button>
                          
                          {isCatSelected && cat.fields?.map(field => {
                            const answerValue = tempRecipient.categoryAnswers?.[cat.id]?.[field.id] || '';
                            return (
                              <div key={field.id} className={styles.fieldGroup} style={{ marginTop: '1rem' }}>
                                <label>{field.label} {field.required && '*'}</label>
                                {field.type === 'text' && (
                                  <input 
                                    type="text" 
                                    className={styles.input} 
                                    value={answerValue} 
                                    onChange={e => {
                                      const currentAnswers = tempRecipient.categoryAnswers || {};
                                      handleTempChange('categoryAnswers', {
                                        ...currentAnswers,
                                        [cat.id]: { ...(currentAnswers[cat.id] || {}), [field.id]: e.target.value }
                                      });
                                    }} 
                                    required={field.required}
                                  />
                                )}
                                {field.type === 'select' && (
                                  <select 
                                    className={styles.input} 
                                    value={answerValue} 
                                    onChange={e => {
                                      const currentAnswers = tempRecipient.categoryAnswers || {};
                                      handleTempChange('categoryAnswers', {
                                        ...currentAnswers,
                                        [cat.id]: { ...(currentAnswers[cat.id] || {}), [field.id]: e.target.value }
                                      });
                                    }} 
                                    required={field.required}
                                  >
                                    <option value="">Seleccionar...</option>
                                    {field.options?.map((opt, i) => <option key={i} value={opt}>{opt}</option>)}
                                  </select>
                                )}
                              </div>
                            );
                          })}
                        </div>
                      );
                    })}

                  </div>

                  <div className={styles.actions}>
                    <button type="button" onClick={cancelTempRecipient} className={styles.skipBtn}>Cancelar</button>
                    <button type="button" onClick={saveTempRecipient} className={styles.saveBtn}>Guardar {tempRecipient.roleDisplay}</button>
                  </div>
                </>
              )}
            </>
          )}

          {currentStep === 4 && (
            <>
              <div className={styles.headerIcon}>
                <CheckCircle size={60} color={config.design.primaryColor} />
              </div>
              <h1 className={styles.title}>{config.completionPanel.title}</h1>
              <p className={styles.description}>{config.completionPanel.message}</p>
              
              <div style={{ background: '#f8fafc', padding: '1rem', borderRadius: '8px', border: '1px solid #e2e8f0', marginTop: '1rem', textAlign: 'left' }}>
                <p style={{ margin: 0, fontSize: '0.9rem', color: '#475569' }}>
                  <strong>💡 Tip:</strong> A partir de ahora puedes gestionar a tus personas importantes y agregar nuevas fechas yendo a tu Perfil y dándole a la pestaña <strong>"Fechas Importantes"</strong>.
                </p>
              </div>

              <div style={{ flex: 1 }}></div>
              <div className={styles.actions} style={{ justifyContent: 'center' }}>
                <button type="button" onClick={handleSkip} className={styles.saveBtn}>
                  {config.completionPanel.buttonText}
                </button>
              </div>
            </>
          )}

        </div>
      </div>

      <div className={styles.sideScene}></div>

    </div>
  );
};

export default SubscriptionSurveyPage;

import React, { useEffect, useState } from 'react';
import { useParams, Navigate } from 'react-router-dom';
import { getLandingPageBySlug } from './services/landingPages';
import { getThemeById } from './services/themes';
import { useLayoutContext } from '../../contexts/LayoutContext';
import { useVisualEditor } from './contexts/VisualEditorContext';
import TiendaPage from './TiendaPage';
import PageLoading from '../../components/common/PageLoading/PageLoading';
import { useAuth } from '../../contexts/AuthContext';

const DynamicLandingPage = () => {
  const { slug } = useParams();
  const { setHeaderVisible, setFooterVisible } = useLayoutContext();
  const { setActivePageId, storeConfigDraft } = useVisualEditor();
  const { isAuthenticated, loading: authLoading } = useAuth();
  
  const [loading, setLoading] = useState(true);
  const [landingPage, setLandingPage] = useState(null);
  const [themeContent, setThemeContent] = useState(null);

  useEffect(() => {
    let mounted = true;
    const fetchLandingPage = async () => {
      const page = await getLandingPageBySlug(slug);
      if (mounted) {
        if (page) {
          setLandingPage(page);
          setActivePageId(page.id);
          setHeaderVisible(!page.hideHeader);
          setFooterVisible(!page.hideFooter);
          
          if (page.themeId) {
            const theme = await getThemeById(page.themeId);
            if (theme && theme.cssContent) {
              setThemeContent(theme.cssContent);
            }
          }
        }
        setLoading(false);
      }
    };

    fetchLandingPage();

    return () => {
      mounted = false;
      // Restaurar visibilidad por defecto al salir de la landing page
      setHeaderVisible(true);
      setFooterVisible(true);
      setActivePageId('home');
    };
  }, [slug, setHeaderVisible, setFooterVisible, setActivePageId]);

  if (loading || authLoading) return <PageLoading />;

  if (!landingPage) {
    // Redirigir a inicio si está logueado, o a login si no
    return isAuthenticated ? <Navigate to="/" replace /> : <Navigate to="/login" replace />;
  }

  return (
    <div className={`landing-page-wrapper ${landingPage.hideHeader ? 'no-header' : ''}`} id="landing-theme-wrapper">
      {themeContent && (
        <style dangerouslySetInnerHTML={{ __html: themeContent }} />
      )}
      {/* 
        TiendaPage internamente usa la ruta para definir el pageId,
        así que ya renderizará las secciones correctas para esta landing.
      */}
      <TiendaPage />
    </div>
  );
};

export default DynamicLandingPage;

import React, { useState, useMemo } from 'react';
import { Plus } from 'lucide-react';
import { useSearchParams, useLocation } from 'react-router-dom';
import { useQuery, keepPreviousData } from '@tanstack/react-query';
import ProductGrid from './components/ProductGrid';
import VisualCategoryNav from './components/VisualCategoryNav/VisualCategoryNav';
import ProductSearch from './components/ProductSearch';
import CollectionCarousel from './components/CollectionCarousel';
import AnnouncementBar from './components/AnnouncementBar';
import HeroCarousel from './components/HeroCarousel';
import FlashSales from './components/FlashSales';
import SidebarCatalogLayout from './components/SidebarCatalogLayout';
import BrandMarquee from './components/BrandMarquee/BrandMarquee';
import BestSellersRow from './components/BestSellersRow/BestSellersRow';
import Testimonials from './components/Testimonials';
import MapLocation from './components/MapLocation';
import TrustBadges from './components/TrustBadges/TrustBadges';
import TextBlock from './components/TextBlock/TextBlock';
import ImageBlock from './components/ImageBlock/ImageBlock';
import HeaderBlock from './components/HeaderBlock/HeaderBlock';
import {
  getProducts,
  getCategories,
  searchProducts,
  getProductsByCategory,
  getFeaturedProducts,
  getCachedProducts,
  getCachedCategories,
  getCachedFeaturedProducts
} from '../../services/products';
import { getMessage } from '../../services/messages';
import { getStorefrontConfig } from './services/storefront';
import { getDocument } from '../../services/firebase/firestore';
import { toDirectImageUrl } from '../../utils/imageUrl';
import OptimizedImage from '../../components/common/OptimizedImage/OptimizedImage';
import HeroBanner from './components/HeroBanner';
import EditableSection from '../../components/admin/EditableSection';
import { useVisualEditor } from './contexts/VisualEditorContext';
import AppDownloadBanner from './components/AppDownloadBanner';
import styles from './TiendaPage.module.css';

const DEFAULT_STORE_TITLE = 'Nuestra Tienda';
const DEFAULT_STORE_SUBTITLE = 'Explora nuestros productos y personaliza el que más te guste.';

const SectionBackground = ({ config }) => {
  const { 
    backgroundColor, 
    backgroundGradient, 
    backgroundImageUrl, 
    backgroundBlur, 
    backgroundOverlay
  } = config;

  const hasImageOrGradient = backgroundImageUrl || backgroundGradient;
  const hasOverlay = backgroundOverlay;

  if (!hasImageOrGradient && (!backgroundColor || backgroundColor === 'transparent') && !hasOverlay) {
    return null;
  }

  return (
    <>
      {hasImageOrGradient && (
        <div style={{
          position: 'absolute',
          top: '-15px', left: '-15px', right: '-15px', bottom: '-15px',
          zIndex: -2,
          backgroundImage: backgroundImageUrl ? `url(${backgroundImageUrl})` : (backgroundGradient || 'none'),
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          filter: backgroundBlur ? `blur(${backgroundBlur}px)` : 'none',
          transform: backgroundBlur ? 'scale(1.05)' : 'none',
          pointerEvents: 'none'
        }} />
      )}
      {(!hasImageOrGradient && backgroundColor && backgroundColor !== 'transparent') && (
        <div style={{
          position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', zIndex: -2,
          backgroundColor: backgroundColor,
          pointerEvents: 'none'
        }} />
      )}
      {backgroundOverlay && (
        <div style={{
          position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', zIndex: -1,
          backgroundColor: backgroundOverlay,
          pointerEvents: 'none'
        }} />
      )}
    </>
  );
};

const TiendaPage = () => {
  const [searchParams] = useSearchParams();
  const location = useLocation();
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('name');
  const categoryId = searchParams.get('categoria');
  const isPreview = searchParams.has('t');

  // Determinar pageId basado en la URL
  const pageId = location.pathname === '/' || location.pathname === '/home' ? 'home' : 
                 location.pathname.replace(/^\/+/, '').split('/')[0] || 'home';

  const { storeConfigDraft, activePageId, setActivePageId } = useVisualEditor();

  // Actualizar el pageId activo en el contexto del editor para que guarde en el lugar correcto
  React.useEffect(() => {
    if (setActivePageId && activePageId !== pageId && activePageId !== 'footer') {
      setActivePageId(pageId);
    }
  }, [pageId, setActivePageId, activePageId]);

  // ── TODAS LAS QUERIES SE LANZAN EN PARALELO ──────────────────────

  const { data: storefrontConfig, isLoading: isConfigLoading } = useQuery({
    queryKey: ['storefront-config', pageId],
    queryFn: async () => {
      const { sections, error } = await getStorefrontConfig(pageId);
      if (error) throw new Error(error);
      return { sections: sections ?? [] };
    },
    staleTime: isPreview ? 0 : 10 * 60 * 1000,
    refetchOnMount: isPreview ? 'always' : false,
  });

  const { data: storeMessages } = useQuery({
    queryKey: ['store-messages'],
    queryFn: async () => {
      const [titleRes, subtitleRes, emptyRes] = await Promise.all([
        getMessage('store_title'),
        getMessage('store_subtitle'),
        getMessage('store_empty_message')
      ]);
      return {
        title: titleRes.data?.trim() || DEFAULT_STORE_TITLE,
        subtitle: subtitleRes.data?.trim() || DEFAULT_STORE_SUBTITLE,
        emptyMessage: emptyRes.data?.trim() || ''
      };
    },
    staleTime: 15 * 60 * 1000,
    gcTime: 30 * 60 * 1000,
  });

  const { data: storeConfig } = useQuery({
    queryKey: ['store-config-custom'],
    queryFn: async () => {
      const { data, error } = await getDocument('storeConfig', 'homePage');
      if (error) return null;
      return data;
    },
    staleTime: 5 * 60 * 1000,
  });

  const { data: categoriesData } = useQuery({
    queryKey: ['categories'],
    queryFn: async () => {
      const { data, error } = await getCategories();
      if (error) throw new Error(error);
      return data;
    },
    initialData: getCachedCategories()
  });

  const { data: featuredData } = useQuery({
    queryKey: ['featured-products'],
    queryFn: async () => {
      const { data, error } = await getFeaturedProducts();
      if (error) throw new Error(error);
      return data;
    },
    initialData: getCachedFeaturedProducts()
  });

  // ── QUERY PRINCIPAL DE PRODUCTOS ──────────────────────────────────
  const { data: productsData, isLoading: productsLoading, error: productsError } = useQuery({
    queryKey: ['products', categoryId, searchTerm, sortBy],
    queryFn: async () => {
      let result;
      if (searchTerm) {
        result = await searchProducts(searchTerm);
      } else if (categoryId) {
        result = await getProductsByCategory(categoryId);
      } else {
        result = await getProducts([], null, null);
      }
      if (result.error) throw new Error(result.error);

      let sorted = [...(result.data || [])];
      if (sortBy === 'price') {
        sorted.sort((a, b) => (a.price || 0) - (b.price || 0));
      } else if (sortBy === 'price-desc') {
        sorted.sort((a, b) => (b.price || 0) - (a.price || 0));
      } else {
        sorted.sort((a, b) => (a.name || '').localeCompare(b.name || ''));
      }
      return sorted;
    },
    placeholderData: keepPreviousData,
    initialData: (!searchTerm && !categoryId && sortBy === 'name') ? getCachedProducts() : undefined,
  });

  const handleSearch = (term) => setSearchTerm(term);

  // ── Valores con fallback inmediato — NUNCA esperar a que carguen ──
  const title = storeMessages?.title ?? DEFAULT_STORE_TITLE;
  const subtitle = storeMessages?.subtitle ?? DEFAULT_STORE_SUBTITLE;
  const emptyMessage = storeMessages?.emptyMessage ?? '';
  const featuredProducts = featuredData ?? [];
  const sections = storefrontConfig?.sections ?? [];

  // Usar el borrador en vivo si existe, si no usar el de Firestore
  let activeConfig = storeConfigDraft || storeConfig || {};

  // Configuración por defecto estilo Nude Project si está vacía
  if (!activeConfig.heroBanner || !activeConfig.heroBanner.mediaUrl) {
    activeConfig = {
      ...activeConfig,
      heroBanner: {
        mediaType: 'image',
        mediaUrl: 'https://images.unsplash.com/photo-1523381210434-271e8be1f52b?q=80&w=2070&auto=format&fit=crop',
        title: 'NUEVA COLECCIÓN',
        subtitle: 'Diseñada para destacar. Construida para durar.',
        buttonText: 'COMPRAR AHORA',
        buttonLink: '/tienda'
      }
    };
  }

  // ── MANEJO DEL ARRAY DE SECCIONES (DEFAULT FALLBACKS) ────────────────
  // La configuración de secciones ahora proviene 100% de la BD o del borrador,
  // y storefront.js se encarga de inyectar defaults si la BD está vacía.
  let displaySections = storeConfigDraft?.sections || storefrontConfig?.sections || [];

  // ── RENDERIZADO PROGRESIVO ────────────────────────────────────────

  let emptyMessageShown = false;

  const renderSection = (section) => {
    const s = section.settings || {};
    switch (section.type) {
      case 'header':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ padding: 0, overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <HeaderBlock config={s} />
          </section>
        );
      case 'categories_nav':
        // Esta sección estructural ahora se renderiza unificada en la cabecera principal.
        return null;
      case 'hero_banner':
        // Usa la configuración local de la sección o el fallback al config global
        const heroConfig = { ...activeConfig.heroBanner, ...s };
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <HeroBanner config={heroConfig} />
          </section>
        );
      case 'text':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ padding: 0, overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <TextBlock config={s} />
          </section>
        );
      case 'image':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ padding: 0, overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <ImageBlock config={s} isFirstSection={section.order === 0} />
          </section>
        );
      case 'video': {
        if (!s.url?.trim()) return null;
        let finalUrl = s.url;
        let isEmbed = false;

        // Auto-convertir links de YouTube a formato embed
        const ytMatch = finalUrl.match(/(?:youtube\.com\/(?:[^\/]+\/.+\/|(?:v|e(?:mbed)?)\/|.*[?&]v=)|youtu\.be\/)([^"&?\/\s]{11})/);
        if (ytMatch && ytMatch[1]) {
          finalUrl = `https://www.youtube.com/embed/${ytMatch[1]}`;
          isEmbed = true;
        } else if (/vimeo|embed/.test(finalUrl)) {
          isEmbed = true;
        }

        const aspect = s.aspectRatio || '16:9';
        let paddingBottom = '56.25%'; // 16:9
        if (aspect === '9:16') paddingBottom = '177.77%';
        else if (aspect === '1:1') paddingBottom = '100%';

        const forceRatio = isEmbed || aspect !== 'auto';

        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <div 
              className={styles.sectionVideo} 
              style={{ 
                position: 'relative', 
                paddingBottom: forceRatio ? paddingBottom : '0', 
                height: forceRatio ? '0' : 'auto', 
                overflow: 'hidden', 
                borderRadius: '12px',
                maxWidth: aspect === '9:16' ? '450px' : (aspect === '1:1' ? '600px' : '100%'),
                margin: '0 auto',
                background: '#000'
              }}
            >
              {isEmbed ? (
                <iframe 
                  title="Video" 
                  src={finalUrl} 
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                  allowFullScreen 
                  style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', border: 'none' }}
                />
              ) : (
                <video 
                  src={finalUrl} 
                  poster={s.poster || undefined} 
                  controls 
                  style={{ 
                    position: forceRatio ? 'absolute' : 'relative',
                    top: 0, left: 0, 
                    width: '100%', 
                    height: forceRatio ? '100%' : 'auto',
                    objectFit: 'cover',
                    borderRadius: '12px' 
                  }} 
                />
              )}
            </div>
          </section>
        );
      }
      case 'announcement_bar':
        return (
          <section key={section.id} style={{ position: 'relative', overflow: 'hidden' }}>
             <SectionBackground config={s} />
             <AnnouncementBar messages={s.messages} speed={s.speed} bgColor={s.bgColor} textColor={s.textColor} />
          </section>
        );
      case 'hero_carousel':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
             <SectionBackground config={s} />
             <HeroCarousel slides={s.slides} autoPlaySpeed={s.autoPlaySpeed} />
          </section>
        );
      case 'flash_sales':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <FlashSales
               title={s.title}
               collectionName={s.collection}
               endTime={s.endTime}
               categories={categoriesData}
            />
          </section>
        );
      case 'testimonials':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <Testimonials title={s.title} testimonials={s.testimonials} />
          </section>
        );
      case 'map_location':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <MapLocation config={s} />
          </section>
        );
      case 'trust_badges':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <TrustBadges badges={s.badges} />
          </section>
        );
      case 'marquee':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <BrandMarquee items={s.items} speed={s.speed} />
          </section>
        );
      case 'bestsellers_row':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <BestSellersRow cards={s.cards} />
          </section>
        );
      case 'featured_products': {
        const isEmpty = !featuredProducts || featuredProducts.length === 0;
        if (isEmpty) {
          if (emptyMessageShown) return null;
          emptyMessageShown = true;
        }
        return (
          <section key={section.id} className={styles.featuredSection} style={{ position: 'relative', paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            {(!isEmpty && s.title) && <h2 className={styles.featuredTitle}>{s.title}</h2>}
            <ProductGrid products={featuredProducts} loading={false} error={null} categories={categoriesData} emptyMessage={emptyMessage} />
          </section>
        );
      }
      case 'collection_carousel':
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <CollectionCarousel
              title={s.title}
              collectionName={s.collection}
              categories={categoriesData}
            />
          </section>
        );
      case 'product_grid': {
        const isEmpty = !productsLoading && (!productsData || productsData.length === 0);
        if (isEmpty) {
          if (emptyMessageShown) return null;
          emptyMessageShown = true;
        }
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            {(!isEmpty && s.title) && <h2 className={styles.featuredTitle}>{s.title}</h2>}
            <ProductGrid
              products={productsData || []}
              loading={productsLoading}
              error={productsError?.message}
              emptyMessage={emptyMessage}
              categories={categoriesData}
              layoutConfig={storeConfig?.layout}
            />
          </section>
        );
      }
      case 'sidebar_catalog': {
        const isEmpty = !productsLoading && (!productsData || productsData.length === 0);
        if (isEmpty) {
          if (emptyMessageShown) return null;
          emptyMessageShown = true;
        }
        return (
          <section key={section.id} className={styles.sectionBlock} style={{ paddingTop: s.paddingTop || '0rem', paddingBottom: s.paddingBottom || '0rem', overflow: 'hidden' }}>
            <SectionBackground config={s} />
            <SidebarCatalogLayout 
              productsData={productsData || []}
              productsLoading={productsLoading}
              productsError={productsError?.message}
              emptyMessage={emptyMessage}
              categories={categoriesData}
              layoutConfig={storeConfig?.layout}
              title={(!isEmpty && s.title) ? s.title : undefined}
            />
          </section>
        );
      }
      default:
        return null;
    }
  };

  // El header unificado ha sido movido a LegacyTiendaPage.
  // Esta vista ahora es puramente una Landing Page dinámica.

  const { isEditModeActive, updateSectionsDraft } = useVisualEditor();

  const ModuleInserter = ({ index }) => {
    const [isOpen, setIsOpen] = useState(false);
    if (!isEditModeActive) return null;

    const handleInsert = (type) => {
      const { SECTION_TYPES, getDefaultSettings } = require('./services/storefront');
      const newSections = [...displaySections];
      newSections.splice(index, 0, {
        id: `section_${Date.now()}`,
        type,
        order: index,
        settings: getDefaultSettings(type)
      });
      newSections.forEach((s, i) => s.order = i);
      updateSectionsDraft(newSections);
      setIsOpen(false);
    };

    return (
      <div className={styles.moduleInserterWrapper} onMouseLeave={() => setIsOpen(false)}>
        <div className={styles.inserterLine}></div>
        <div className={styles.inserterContent}>
          <button 
            className={`${styles.inserterBtn} ${isOpen ? styles.active : ''}`} 
            title="Añadir Módulo Aquí"
            onClick={() => setIsOpen(!isOpen)}
          >
            <Plus size={20} strokeWidth={1.5} />
          </button>
          {isOpen && (
            <div className={styles.inserterMenuVisible}>
              <p style={{fontSize: '0.8rem', color: '#64748b', margin: '0 0 10px 0', fontWeight: '600'}}>Añadir módulo nuevo:</p>
              <div className={styles.inserterOptions}>
                <button onClick={() => handleInsert('header')}>Encabezado (Título)</button>
                <button onClick={() => handleInsert('hero_banner')}>Banner Principal</button>
                <button onClick={() => handleInsert('bestsellers_row')}>Lo Más Vendido (Fila 5)</button>
                <button onClick={() => handleInsert('testimonials')}>Testimonios</button>
                <button onClick={() => handleInsert('map_location')}>Ubicación (Mapa)</button>
                <button onClick={() => handleInsert('product_grid')}>Grilla de Productos</button>
                <button onClick={() => handleInsert('sidebar_catalog')}>Catálogo (Filtros)</button>
                <button onClick={() => handleInsert('hero_carousel')}>Carrusel Imágenes</button>
                <button onClick={() => handleInsert('collection_carousel')}>Carrusel Colección</button>
                <button onClick={() => handleInsert('text')}>Texto Simple</button>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };

  const sorted = [...displaySections].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
  
  if (isConfigLoading && !storefrontConfig) {
    return (
      <div className={styles.container}>
        <div style={{ padding: '4rem', textAlign: 'center', color: 'var(--gris-texto-secundario)' }}>
          Cargando configuración...
        </div>
      </div>
    );
  }

  const { SECTION_TYPES } = require('./services/storefront');

  return (
    <div className={styles.container}>
      {!categoryId && !searchTerm && <AppDownloadBanner />}
      {sorted.map((section, index) => {
        const rendered = renderSection(section);
        if (!rendered) return null;
        const typeLabel = SECTION_TYPES?.find(t => t.id === section.type)?.label || section.type;
        
        return (
          <React.Fragment key={section.id}>
            <ModuleInserter index={index} />
            <EditableSection sectionId={section.id} currentConfig={activeConfig} label={typeLabel}>
              {rendered}
            </EditableSection>
          </React.Fragment>
        );
      })}
      <ModuleInserter index={sorted.length} />
    </div>
  );
};

export default TiendaPage;

import React, { useState, useEffect, useCallback } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getDailyWord, saveWordleResult, getWordleRanking, getWordleRankingToday } from '../../services/wordle';
import { VALID_GUESSES } from '../../data/wordleDictionary';
import { useAuth } from '../../contexts/AuthContext';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import styles from './WordlePage.module.css';

// Constantes
const MAX_ATTEMPTS = 6;
const LETTERS = 'QWERTYUIOPASDFGHJKLÑZXCVBNM'.split('');
const KEYS_ROWS = [
  ['Q', 'W', 'E', 'R', 'T', 'Y', 'U', 'I', 'O', 'P'],
  ['A', 'S', 'D', 'F', 'G', 'H', 'J', 'K', 'L', 'Ñ'],
  ['ENTER', 'Z', 'X', 'C', 'V', 'B', 'N', 'M', 'BACKSPACE']
];

const removeAccents = (str) => {
  return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toUpperCase();
};

const formatTime = (seconds) => {
  if (seconds == null) return '—';
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return m > 0 ? `${m}m ${s}s` : `${s}s`;
};

const WordlePage = () => {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const todayStr = format(new Date(), 'yyyy-MM-dd');
  const storageKey = `wala_wordle_${todayStr}`;

  // Estado del juego
  const [targetWord, setTargetWord] = useState('');
  const [wordLength, setWordLength] = useState(5);
  const [guesses, setGuesses] = useState([]);
  const [currentGuess, setCurrentGuess] = useState([]);
  const [activeIndex, setActiveIndex] = useState(0);
  const [gameStatus, setGameStatus] = useState('playing'); // 'playing', 'won', 'lost'
  const [userStats, setUserStats] = useState(null);
  const [startTime, setStartTime] = useState(null);
  const [showRanking, setShowRanking] = useState(false);
  const [rankingTab, setRankingTab] = useState('today'); // 'today' | 'global'
  const [showResultModal, setShowResultModal] = useState(false);

  // Obtener la palabra del día
  const { data: dailyWord, isLoading: isLoadingWord } = useQuery({
    queryKey: ['daily-word', todayStr],
    queryFn: () => getDailyWord(todayStr)
  });

  // Ranking del día (jugadores de hoy)
  const { data: rankingToday, isLoading: isLoadingToday } = useQuery({
    queryKey: ['wordle-ranking-today', todayStr],
    queryFn: getWordleRankingToday,
    staleTime: 0  // siempre fresco — el ranking cambia a medida que la gente juega
  });

  // Ranking global (rachas históricas)
  const { data: rankingGlobal, isLoading: isLoadingGlobal } = useQuery({
    queryKey: ['wordle-ranking-global'],
    queryFn: getWordleRanking,
    staleTime: 5 * 60 * 1000
  });

  const rankingData = rankingTab === 'today' ? rankingToday : rankingGlobal;
  const isLoadingRanking = rankingTab === 'today' ? isLoadingToday : isLoadingGlobal;

  // Mutación para guardar el resultado
  const saveResultMutation = useMutation({
    mutationFn: ({ won, attempts, timeSeconds, word, length }) => saveWordleResult(won, attempts, timeSeconds, word, length),
    onSuccess: (res) => {
      if (res.success && res.stats) {
        setUserStats(res.stats);
        queryClient.invalidateQueries({ queryKey: ['wordle-ranking-today', todayStr] });
        queryClient.invalidateQueries({ queryKey: ['wordle-ranking-global'] });
      }
    }
  });

  // Inicializar estado desde LocalStorage o nueva partida
  useEffect(() => {
    if (dailyWord) {
      const cleanTarget = removeAccents(dailyWord);
      setTargetWord(cleanTarget);
      setWordLength(cleanTarget.length);
      setCurrentGuess(Array(cleanTarget.length).fill(''));

      const savedState = localStorage.getItem(storageKey);
      if (savedState) {
        try {
          const parsed = JSON.parse(savedState);
          setGuesses(parsed.guesses || []);
          setGameStatus(parsed.gameStatus || 'playing');
          if (parsed.gameStatus && parsed.gameStatus !== 'playing') {
            setShowResultModal(true);
          }
          if (parsed.userStats) setUserStats(parsed.userStats);
          if (parsed.startTime) setStartTime(parsed.startTime);
        } catch (e) {
          console.error("Error parsing localstorage", e);
        }
      }
    }
  }, [dailyWord, storageKey]);

  // Guardar estado en LocalStorage en cada cambio
  useEffect(() => {
    if (targetWord) {
      localStorage.setItem(storageKey, JSON.stringify({
        guesses,
        gameStatus,
        userStats,
        startTime
      }));
    }
  }, [guesses, gameStatus, userStats, startTime, storageKey, targetWord]);

  // Evaluar letra
  const getLetterStatus = (letter, index, guessStr) => {
    if (targetWord[index] === letter) return 'correct';
    if (targetWord.includes(letter)) {
      // Manejar letras repetidas
      const targetCharCount = targetWord.split('').filter(c => c === letter).length;
      const currentGuessedCorrectCount = guessStr.split('').filter((c, i) => c === letter && targetWord[i] === letter).length;
      const previousOccurrencesInGuess = guessStr.substring(0, index).split('').filter(c => c === letter).length;
      
      if (previousOccurrencesInGuess < (targetCharCount - currentGuessedCorrectCount)) {
        return 'present';
      }
    }
    return 'absent';
  };

  const getKeyboardKeyStatus = (key) => {
    let status = 'default';
    for (const guess of guesses) {
      for (let i = 0; i < guess.length; i++) {
        if (guess[i] === key) {
          const charStatus = getLetterStatus(key, i, guess);
          if (charStatus === 'correct') return 'correct';
          if (charStatus === 'present' && status !== 'correct') status = 'present';
          if (charStatus === 'absent' && status === 'default') status = 'absent';
        }
      }
    }
    return status;
  };

  const onKeyPress = useCallback((key) => {
    if (gameStatus !== 'playing') return;

    if (!startTime) {
      setStartTime(Date.now());
    }

    if (key === 'BACKSPACE') {
      setCurrentGuess(prev => {
        const newArr = [...prev];
        if (newArr[activeIndex] !== '') {
          newArr[activeIndex] = '';
        } else if (activeIndex > 0) {
          newArr[activeIndex - 1] = '';
          setActiveIndex(activeIndex - 1);
        }
        return newArr;
      });
      return;
    }

    if (key === 'ENTER') {
      if (currentGuess.includes('')) {
        // Faltan letras
        return;
      }
      
      const guessStr = currentGuess.join('');
      
      // Validar si la palabra existe en el diccionario (si el diccionario está cargado)
      if (VALID_GUESSES.size > 10 && !VALID_GUESSES.has(guessStr)) {
        alert("La palabra no está en el diccionario.");
        return;
      }

      const newGuesses = [...guesses, guessStr];
      setGuesses(newGuesses);
      setCurrentGuess(Array(wordLength).fill(''));
      setActiveIndex(0);

      if (guessStr === targetWord) {
        setGameStatus('won');
        setShowResultModal(true);
        const timeSeconds = Math.floor((Date.now() - (startTime || Date.now())) / 1000);
        if (user) saveResultMutation.mutate({ won: true, attempts: newGuesses.length, timeSeconds, word: targetWord, length: wordLength });
      } else if (newGuesses.length >= MAX_ATTEMPTS) {
        setGameStatus('lost');
        setShowResultModal(true);
        const timeSeconds = Math.floor((Date.now() - (startTime || Date.now())) / 1000);
        if (user) saveResultMutation.mutate({ won: false, attempts: newGuesses.length, timeSeconds, word: targetWord, length: wordLength });
      }
      return;
    }

    if (LETTERS.includes(key)) {
      setCurrentGuess(prev => {
        const newArr = [...prev];
        newArr[activeIndex] = key;
        return newArr;
      });
      if (activeIndex < wordLength - 1) {
        setActiveIndex(activeIndex + 1);
      }
    }
  }, [currentGuess, gameStatus, guesses, wordLength, targetWord, user, saveResultMutation, activeIndex, startTime]);

  // Escuchar teclado físico
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.ctrlKey || e.metaKey || e.altKey) return;
      const key = e.key.toUpperCase();
      if (key === 'BACKSPACE') {
        e.preventDefault();
        onKeyPress('BACKSPACE');
      } else if (key === 'ENTER') {
        e.preventDefault();
        onKeyPress('ENTER');
      } else if (LETTERS.includes(key) || key === 'Ñ') {
        onKeyPress(key);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [onKeyPress]);


  if (isLoadingWord) {
    return <div className={styles.loading}>Cargando El Juego del Día...</div>;
  }

  return (
    <div className={styles.pageContainer}>
      <header className={styles.header}>
        <div className={styles.headerLeft}></div>
        <h1 className={styles.title}>La Palabra del Día</h1>
        <div className={styles.headerRight}>
          <button className={styles.iconBtn} onClick={() => setShowRanking(!showRanking)}>
            Ranking
          </button>
        </div>
      </header>

      {showRanking ? (
        <div className={styles.rankingContainer}>
          <h2>Ranking</h2>

          {/* Tabs */}
          <div className={styles.rankingTabs}>
            <button
              className={`${styles.rankingTab} ${rankingTab === 'today' ? styles.rankingTabActive : ''}`}
              onClick={() => setRankingTab('today')}
            >
              Hoy
            </button>
            <button
              className={`${styles.rankingTab} ${rankingTab === 'global' ? styles.rankingTabActive : ''}`}
              onClick={() => setRankingTab('global')}
            >
              Global
            </button>
          </div>

          {rankingTab === 'today' ? (
            <p className={styles.rankingDesc}>Jugadores que completaron el wordle de hoy, ordenados por intentos usados.</p>
          ) : (
            <p className={styles.rankingDesc}>Ordenado por la mayor racha de victorias seguidas (histórico).</p>
          )}
          
          {isLoadingRanking ? (
            <p>Cargando ranking...</p>
          ) : rankingData?.length === 0 ? (
            <p className={styles.rankingEmpty}>
              {rankingTab === 'today'
                ? 'Nadie ha completado el wordle de hoy todavía. ¡Sé el primero!'
                : 'No hay datos de ranking aún.'}
            </p>
          ) : (
            <table className={styles.rankingTable}>
              <thead>
                <tr>
                  <th>Pos</th>
                  <th>Jugador</th>
                  {rankingTab === 'today' ? (
                    <>
                      <th>Intentos</th>
                      <th>Tiempo</th>
                      <th>Racha Actual</th>
                    </>
                  ) : (
                    <>
                      <th>Mejor Racha</th>
                      <th>Victorias Totales</th>
                      <th>Intentos Acum.</th>
                    </>
                  )}
                </tr>
              </thead>
              <tbody>
                {rankingData?.map((p, index) => (
                  <tr key={p.id} className={user?.uid === p.id ? styles.currentUserRow : ''}>
                    <td>#{index + 1}</td>
                    <td>{p.displayName} {user?.uid === p.id && <strong>(Tú)</strong>}</td>
                    {rankingTab === 'today' ? (
                      <>
                        <td>{p.todayAttempts} / 6</td>
                        <td>{formatTime(p.timeSeconds)}</td>
                        <td><span className={styles.streakBadge}>{p.currentStreak}</span></td>
                      </>
                    ) : (
                      <>
                        <td><span className={styles.streakBadge}>{p.maxStreak}</span></td>
                        <td>{p.wins} / {p.played}</td>
                        <td>{p.totalAttempts || 0}</td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          )}
          <button className={styles.primaryBtn} onClick={() => setShowRanking(false)}>Volver al Juego</button>
        </div>
      ) : (
        <main className={styles.gameContainer}>
          {/* Rejilla */}
          <div className={styles.board} style={{ gridTemplateRows: `repeat(${MAX_ATTEMPTS}, 1fr)` }}>
            {Array.from({ length: MAX_ATTEMPTS }).map((_, rowIndex) => {
              const isCurrentRow = rowIndex === guesses.length;
              const isPastRow = rowIndex < guesses.length;

              return (
                <div key={rowIndex} className={styles.row} style={{ gridTemplateColumns: `repeat(${wordLength}, 1fr)` }}>
                  {Array.from({ length: wordLength }).map((_, colIndex) => {
                    const letter = isPastRow ? guesses[rowIndex][colIndex] : (isCurrentRow ? currentGuess[colIndex] : '');
                    let statusClass = styles.emptyCell;
                    
                    if (isPastRow) {
                      const status = getLetterStatus(letter, colIndex, guesses[rowIndex]);
                      statusClass = styles[status];
                    } else if (letter) {
                      statusClass = styles.filledCell;
                    }

                    const isFocused = isCurrentRow && activeIndex === colIndex;

                    return (
                      <div 
                        key={colIndex} 
                        className={`${styles.cell} ${statusClass} ${letter && isCurrentRow ? styles.pop : ''} ${isFocused ? styles.focusedCell : ''}`}
                        onClick={() => {
                          if (isCurrentRow) setActiveIndex(colIndex);
                        }}
                      >
                        {letter}
                      </div>
                    );
                  })}
                </div>
              );
            })}
          </div>

          {gameStatus !== 'playing' && !showResultModal && (
            <button className={styles.showResultBtn} onClick={() => setShowResultModal(true)}>
              Ver Resultados
            </button>
          )}

          {/* Modal de Resultado */}
          {showResultModal && (
            <div className={styles.resultOverlay} onClick={() => setShowResultModal(false)}>
              <div className={styles.resultCard} onClick={e => e.stopPropagation()}>
                <button className={styles.closeModalBtn} onClick={() => setShowResultModal(false)}>×</button>
                <h2>{gameStatus === 'won' ? '¡Felicidades!' : 'Fin del Juego'}</h2>
                {gameStatus === 'won' ? (
                  <p>Adivinaste la palabra en <strong>{guesses.length}</strong> intento{guesses.length !== 1 ? 's' : ''}.</p>
                ) : (
                  <p>La palabra era: <strong>{targetWord}</strong></p>
                )}
                
                {user ? (
                  <div className={styles.stats}>
                    <div className={styles.statBox}>
                      <span className={styles.statNumber}>{userStats?.wordlePlayed || 0}</span>
                      <span className={styles.statLabel}>Jugadas</span>
                    </div>
                    <div className={styles.statBox}>
                      <span className={styles.statNumber}>{userStats?.wordleWins || 0}</span>
                      <span className={styles.statLabel}>Victorias</span>
                    </div>
                    <div className={styles.statBox}>
                      <span className={styles.statNumber}>{userStats?.wordleCurrentStreak || 0}</span>
                      <span className={styles.statLabel}>Racha Actual</span>
                    </div>
                    <div className={styles.statBox}>
                      <span className={styles.statNumber}>{userStats?.wordleMaxStreak || 0}</span>
                      <span className={styles.statLabel}>Mejor Racha</span>
                    </div>
                  </div>
                ) : (
                  <p className={styles.loginPrompt}>Inicia sesión para guardar tus rachas y aparecer en el ranking.</p>
                )}
                
                <p style={{marginTop: '1.5rem', color: '#666'}}>Vuelve mañana para jugar una nueva palabra.</p>
              </div>
            </div>
          )}

          {/* Teclado */}
          <div className={styles.keyboard}>
            {KEYS_ROWS.map((row, rIdx) => (
              <div key={rIdx} className={styles.keyboardRow}>
                {row.map(key => {
                  const isAction = key === 'ENTER' || key === 'BACKSPACE';
                  const keyClass = isAction ? styles.actionKey : styles.key;
                  const statusClass = !isAction ? styles[`key_${getKeyboardKeyStatus(key)}`] : '';
                  
                  return (
                    <button 
                      key={key} 
                      className={`${keyClass} ${statusClass}`}
                      onClick={() => onKeyPress(key)}
                    >
                      {key === 'BACKSPACE' ? '⌫' : key}
                    </button>
                  );
                })}
              </div>
            ))}
          </div>
        </main>
      )}
    </div>
  );
};

export default WordlePage;

import React, { useState, useEffect, useRef } from 'react';
import { useQuery } from '@tanstack/react-query';
import { getProducts, updateProduct } from '../../../services/products';
import { getCategories } from '../../../services/categories';
import { getCollections } from '../../../services/collections';
import { getBrands } from '../../../services/brands';
import { getTags } from '../../../services/tags';
import { getCharacters } from '../../../services/characters';
import { getProductTypes } from '../../../services/productTypes';
import { logInventoryChange } from '../../../services/inventoryLogs';
import { useAuth } from '../../../contexts/AuthContext';
import { Search, Filter, Loader2, Save, PackageX, PackageSearch } from 'lucide-react';
import styles from './AdminInventario.module.css';

const AdminInventario = () => {
  const { user } = useAuth();
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCategory, setFilterCategory] = useState('');
  const [filterCollection, setFilterCollection] = useState('');
  const [filterBrand, setFilterBrand] = useState('');
  const [filterTag, setFilterTag] = useState('');
  const [filterCharacter, setFilterCharacter] = useState('');
  const [filterType, setFilterType] = useState('');
  
  const [products, setProducts] = useState([]);
  const [savingId, setSavingId] = useState(null);
  const [savedId, setSavedId] = useState(null);
  
  const timeoutRefs = useRef({});
  const initialStockRefs = useRef({});

  const { data: productsData, isLoading } = useQuery({
    queryKey: ['admin-inventory-products'],
    queryFn: async () => {
      const { data, error } = await getProducts([], null, null, { includeHidden: true });
      if (error) throw new Error(error);
      return data;
    }
  });

  const { data: categories } = useQuery({ queryKey: ['categories'], queryFn: async () => (await getCategories()).data });
  const { data: collections } = useQuery({ queryKey: ['collections'], queryFn: async () => (await getCollections()).data });
  const { data: brands } = useQuery({ queryKey: ['brands'], queryFn: async () => (await getBrands()).data });
  const { data: tags } = useQuery({ queryKey: ['tags'], queryFn: async () => (await getTags()).data });
  const { data: characters } = useQuery({ queryKey: ['characters'], queryFn: async () => (await getCharacters()).data });
  const { data: productTypes } = useQuery({ queryKey: ['productTypes'], queryFn: async () => (await getProductTypes()).data });

  useEffect(() => {
    if (productsData) {
      setProducts(productsData);
      productsData.forEach(p => {
        initialStockRefs.current[p.id] = p.inStock || 0;
      });
    }
  }, [productsData]);

  const handleStockChange = (id, newStockStr, productName) => {
    const newStock = parseInt(newStockStr, 10);
    if (isNaN(newStock) || newStock < 0) return;

    setProducts(prev => prev.map(p => p.id === id ? { ...p, inStock: newStock } : p));

    if (timeoutRefs.current[id]) {
      clearTimeout(timeoutRefs.current[id]);
    }

    setSavingId(id);
    
    timeoutRefs.current[id] = setTimeout(async () => {
      try {
        const oldStock = initialStockRefs.current[id] || 0;
        if (oldStock !== newStock) {
          await updateProduct(id, { inStock: newStock });
          await logInventoryChange(id, productName, oldStock, newStock, user?.email || 'Admin');
          initialStockRefs.current[id] = newStock;
        }
        setSavingId(null);
        setSavedId(id);
        setTimeout(() => setSavedId(null), 2000);
      } catch (error) {
        console.error("Error updating stock", error);
        setSavingId(null);
        alert('Error al guardar el inventario para ' + productName);
      }
    }, 1000);
  };

  const filteredProducts = products.filter(p => {
    const term = searchTerm.toLowerCase();
    const matchName = p.name?.toLowerCase().includes(term) || p.sku?.toLowerCase().includes(term);
    if (!matchName) return false;

    if (filterCategory && p.categoryId !== filterCategory && p.category !== filterCategory && !(p.categories || []).includes(filterCategory)) return false;
    if (filterCollection && !(p.collections || []).includes(filterCollection)) return false;
    if (filterBrand && p.brandId !== filterBrand) return false;
    if (filterTag && !(p.tags || []).includes(filterTag)) return false;
    if (filterCharacter && !(p.characters || []).includes(filterCharacter)) return false;
    if (filterType && p.productType !== filterType) return false;

    return true;
  });

  return (
    <div className={styles.wrapper}>
      <div className={styles.header}>
        <div>
          <h1 className={styles.title}>Inventario</h1>
          <p className={styles.subtitle}>Gestión rápida de cantidades, precios y disponibilidad</p>
        </div>
      </div>

      <div className={styles.filtersCard}>
        <div className={styles.searchRow}>
          <div className={styles.searchBox}>
            <Search size={20} className={styles.searchIcon} />
            <input 
              type="text" 
              placeholder="Buscar por nombre o SKU..." 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className={styles.searchInput}
            />
          </div>
        </div>
        
        <div className={styles.filtersGrid}>
          <div className={styles.filterGroup}>
            <Filter size={16} className={styles.filterIcon} />
            <select value={filterCategory} onChange={e => setFilterCategory(e.target.value)} className={styles.selectFilter}>
              <option value="">Todas las Categorías</option>
              {(categories || []).map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>

          <div className={styles.filterGroup}>
            <Filter size={16} className={styles.filterIcon} />
            <select value={filterCollection} onChange={e => setFilterCollection(e.target.value)} className={styles.selectFilter}>
              <option value="">Todas las Colecciones</option>
              {(collections || []).map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>

          <div className={styles.filterGroup}>
            <Filter size={16} className={styles.filterIcon} />
            <select value={filterBrand} onChange={e => setFilterBrand(e.target.value)} className={styles.selectFilter}>
              <option value="">Todas las Marcas</option>
              {(brands || []).map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
          </div>

          <div className={styles.filterGroup}>
            <Filter size={16} className={styles.filterIcon} />
            <select value={filterType} onChange={e => setFilterType(e.target.value)} className={styles.selectFilter}>
              <option value="">Todos los Tipos</option>
              {(productTypes || []).map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
            </select>
          </div>
        </div>
      </div>

      {isLoading ? (
        <div className={styles.loadingState}>
          <Loader2 className={styles.spinner} size={40} />
          <p>Cargando inventario completo...</p>
        </div>
      ) : (
        <div className={styles.tableCard}>
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Producto</th>
                  <th>Estado</th>
                  <th>Precio Venta</th>
                  <th>Stock Físico</th>
                </tr>
              </thead>
              <tbody>
                {filteredProducts.map(product => {
                  const stock = product.inStock || 0;
                  let statusClass = styles.inStock;
                  let statusText = 'Disponible';
                  if (stock === 0) {
                    statusClass = styles.outOfStock;
                    statusText = 'Agotado';
                  } else if (stock <= 3) {
                    statusClass = styles.lowStock;
                    statusText = 'Últimas uds';
                  }

                  const imgUrl = product.images?.[0] || product.thumbnailImageUrl || product.mainImage;

                  return (
                    <tr key={product.id}>
                      <td>
                        <div className={styles.productCell}>
                          {imgUrl ? (
                            <img src={imgUrl} alt={product.name} className={styles.productImage} />
                          ) : (
                            <div className={styles.productImageFallback}><PackageSearch size={20} /></div>
                          )}
                          <div className={styles.productInfo}>
                            <span className={styles.productName}>{product.name}</span>
                            <span className={styles.productSku}>{product.sku ? `SKU: ${product.sku}` : 'Sin SKU asignado'}</span>
                          </div>
                        </div>
                      </td>
                      <td>
                        <span className={`${styles.stockBadge} ${statusClass}`}>
                          {statusText}
                        </span>
                      </td>
                      <td>
                        <span className={styles.priceText}>S/ {Number(product.salePrice || product.price || 0).toFixed(2)}</span>
                      </td>
                      <td>
                        <div className={styles.stockEditor}>
                          <input 
                            type="number"
                            min="0"
                            value={stock}
                            onChange={(e) => handleStockChange(product.id, e.target.value, product.name)}
                            className={styles.stockInput}
                          />
                          <div className={styles.saveStatus}>
                            {savingId === product.id && <Loader2 size={16} className={styles.savingSpinner} />}
                            {savedId === product.id && <Save size={16} className={styles.savedIcon} />}
                          </div>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
            
            {filteredProducts.length === 0 && (
              <div className={styles.emptyState}>
                <PackageX size={48} className={styles.emptyIcon} />
                <h3>No se encontraron productos</h3>
                <p>Intenta ajustar los filtros o el término de búsqueda</p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminInventario;

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams, useLocation } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createProduct, updateProduct, getProduct, generateProductId } from '../../../services/products';
import { getMockups } from '../../../services/mockups';
import { getBrands, createBrand, updateBrand } from '../../../services/brands';
import { getCategories, createCategory } from '../../../services/categories';
import { getCollections, createCollection } from '../../../services/collections';
import { getTags, createTag } from '../../../services/tags';
import { getCharacters, createCharacter } from '../../../services/characters';
import { uploadFile, deleteFile } from '../../../services/firebase/storage';
import CreatableSelect from 'react-select/creatable';
import { ImagePlus, Save, ArrowLeft, Loader2, Shirt, Image as ImageIcon, Trash2, Camera, Star, X, Edit2 } from 'lucide-react';
import Button from '../../../components/common/Button';
import ProductImageContainer from '../components/ProductImageContainer/ProductImageContainer';
import AdminCustomizationViewsEditor from '../components/AdminCustomizationViewsEditor/AdminCustomizationViewsEditor';
import AdminComboEditor from '../components/AdminComboEditor/AdminComboEditor';
