              style={{width: '100%', padding: '6px'}}
            />
          </div>
        </div>
      ))}

      <Button variant="secondary" onClick={addBrand} style={{width: '100%', borderStyle: 'dashed'}}>
        <Plus size={16} strokeWidth={1.5} style={{marginRight: 6}} /> Añadir Marca / Botón
      </Button>
    </div>
  );
};

export default VisualEditorPanel;

import React, { useState, useEffect, useRef } from 'react';
import { fabric } from 'fabric';
import { Plus, Trash2, ImagePlus, Type, Frame, Image as ImageIcon, Loader2 } from 'lucide-react';
import styles from './AdminCustomizationViewsEditor.module.css';
import { uploadFile } from '../../../../services/firebase/storage';

const AdminCustomizationViewsEditor = ({ views, onChange, draftId }) => {
  const [activeViewIdx, setActiveViewIdx] = useState(0);
  const activeView = views[activeViewIdx];
  const [fabricCanvas, setFabricCanvas] = useState(null);
  const canvasElRef = useRef(null);
  const [uploading, setUploading] = useState(false);
  const [activeObjectInfo, setActiveObjectInfo] = useState({ isText: false, fontFamily: 'Arial' });

  const FONTS = ['Arial', 'Helvetica', 'Times New Roman', 'Courier New', 'Verdana', 'Georgia', 'Impact'];

  // Sync canvas instances
  useEffect(() => {
    if (activeView && canvasElRef.current) {
      if (fabricCanvas) {
        fabricCanvas.dispose();
      }
      const canvas = new fabric.Canvas(canvasElRef.current, {
        width: 400,
        height: 533,
        preserveObjectStacking: true,
      });

      const updateActiveInfo = () => {
        const activeObj = canvas.getActiveObject();
        if (activeObj) {
          setActiveObjectInfo({ 
            isText: activeObj.type === 'i-text' || activeObj.type === 'text', 
            fontFamily: activeObj.fontFamily || 'Arial' 
          });
        } else {
          setActiveObjectInfo({ isText: false, fontFamily: 'Arial' });
        }
      };

      canvas.on('selection:created', updateActiveInfo);
      canvas.on('selection:updated', updateActiveInfo);
      canvas.on('selection:cleared', updateActiveInfo);
      
      // Load background
      const baseImgUrl = activeView.imagesByColor?.default;
      if (baseImgUrl) {
        fabric.Image.fromURL(baseImgUrl, (img) => {
          const scale = Math.min(400 / img.width, 533 / img.height);
          img.set({ originX: 'center', originY: 'center', left: 200, top: 266.5, scaleX: scale, scaleY: scale, selectable: false, evented: false });
          canvas.setBackgroundImage(img, canvas.renderAll.bind(canvas));
        }, { crossOrigin: 'anonymous' });
      }

      // Load initial layers
      const layers = activeView.initialLayersByColor?.default || [];
      layers.forEach(layer => {
        if (layer.type === 'text') {
          const text = new fabric.IText(layer.text || 'Texto', {
            left: layer.left || 200, top: layer.top || 200,
            fill: layer.color || '#000', fontSize: layer.fontSize || 40,
            fontFamily: layer.fontFamily || 'sans-serif',
            originX: 'center', originY: 'center',
            scaleX: layer.scaleX || 1, scaleY: layer.scaleY || 1,
            angle: layer.angle || 0
          });
          canvas.add(text);
        } else if (layer.type === 'image' && layer.src) {
          fabric.Image.fromURL(layer.src, (img) => {
            img.set({
              left: layer.left || 200, top: layer.top || 200,
              originX: 'center', originY: 'center',
              scaleX: layer.scaleX || 1, scaleY: layer.scaleY || 1,
              angle: layer.angle || 0
            });
            canvas.add(img);
          }, { crossOrigin: 'anonymous' });
        }
      });

      canvas.on('object:modified', () => {
        // Use timeout to let fabric finish internal updates
        setTimeout(() => saveCanvasState(canvas), 50);
      });

      setFabricCanvas(canvas);
    }
  }, [activeViewIdx]);

  const saveCanvasState = (canvas = fabricCanvas) => {
    if (!canvas) return;
    const objects = canvas.getObjects().map(obj => {
      if (obj.type === 'i-text' || obj.type === 'text') {
        return {
          type: 'text', text: obj.text, color: obj.fill, fontSize: obj.fontSize, fontFamily: obj.fontFamily,
          left: obj.left, top: obj.top, scaleX: obj.scaleX, scaleY: obj.scaleY, angle: obj.angle
        };
      } else if (obj.type === 'image') {
        return {
          type: 'image', src: obj.getSrc(),
          left: obj.left, top: obj.top, scaleX: obj.scaleX, scaleY: obj.scaleY, angle: obj.angle
        };
      }
      return null;
    }).filter(Boolean);

    const updatedViews = [...views];
    updatedViews[activeViewIdx] = {
      ...updatedViews[activeViewIdx],
      initialLayersByColor: { default: objects }
    };
    onChange(updatedViews);
  };

  const updateActiveView = (updates) => {
    const updatedViews = [...views];
    updatedViews[activeViewIdx] = { ...updatedViews[activeViewIdx], ...updates };
    onChange(updatedViews);
  };

  const handleAddText = () => {
    if (!fabricCanvas) return;
    const text = new fabric.IText('Nuevo Texto', {
      left: 200, top: 200, fill: '#111', fontSize: 32, fontFamily: 'Arial', originX: 'center', originY: 'center'
    });
    fabricCanvas.add(text);
    fabricCanvas.setActiveObject(text);
    saveCanvasState(fabricCanvas);
  };

  const handleChangeFont = (e) => {
    const font = e.target.value;
    if (!fabricCanvas) return;
    const activeObj = fabricCanvas.getActiveObject();
    if (activeObj && (activeObj.type === 'i-text' || activeObj.type === 'text')) {
      activeObj.set({ fontFamily: font });
      fabricCanvas.renderAll();
      setActiveObjectInfo(prev => ({ ...prev, fontFamily: font }));
      saveCanvasState(fabricCanvas);
    }
  };

  const handleImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file || !fabricCanvas) return;
    setUploading(true);
    try {
      const path = `productos_v2/${draftId}/layer_${Date.now()}_${file.name}`;
      const { url } = await uploadFile(file, path);
      if (url) {
        fabric.Image.fromURL(url, (img) => {
          img.scaleToWidth(150);
          img.set({ left: 200, top: 200, originX: 'center', originY: 'center' });
          fabricCanvas.add(img);
          fabricCanvas.setActiveObject(img);
          saveCanvasState(fabricCanvas);
        }, { crossOrigin: 'anonymous' });
      }
    } finally {
      setUploading(false);
      e.target.value = '';
    }
  };

  const handleBaseImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setUploading(true);
    try {
      const path = `productos_v2/${draftId}/base_${Date.now()}_${file.name}`;
      const { url } = await uploadFile(file, path);
      if (url) {
        updateActiveView({ imagesByColor: { default: url } });
        if (fabricCanvas) {
          fabric.Image.fromURL(url, (img) => {
            const scale = Math.min(400 / img.width, 533 / img.height);
            img.set({ originX: 'center', originY: 'center', left: 200, top: 266.5, scaleX: scale, scaleY: scale, selectable: false, evented: false });
            fabricCanvas.setBackgroundImage(img, fabricCanvas.renderAll.bind(fabricCanvas));
          }, { crossOrigin: 'anonymous' });
        }
      }
    } finally {
      setUploading(false);
      e.target.value = '';
    }
  };

  const deleteActiveObject = () => {
    if (!fabricCanvas) return;
    const activeObjects = fabricCanvas.getActiveObjects();
    if (activeObjects.length) {
      activeObjects.forEach(obj => fabricCanvas.remove(obj));
      fabricCanvas.discardActiveObject();
      saveCanvasState(fabricCanvas);
    }
  };

  const addView = () => {
    const newView = {
      id: `view_${Date.now()}`,
      name: `Vista ${views.length + 1}`,
      imagesByColor: { default: '' },
      initialLayersByColor: { default: [] },
      printAreas: [{
        id: `zone_${Date.now()}_0`, shape: 'rectangle', x: 20, y: 20, width: 60, height: 60, rotation: 0, skewX: 0, skewY: 0
      }]
    };
    onChange([...views, newView]);
    setActiveViewIdx(views.length);
  };

  const removeView = () => {
    if (views.length <= 1) {
      alert('Debe existir al menos una vista.');
      return;
    }
    const nextViews = views.filter((_, i) => i !== activeViewIdx);
    onChange(nextViews);
    setActiveViewIdx(Math.max(0, activeViewIdx - 1));
  };

  if (!views || views.length === 0) return null;

  return (
    <div className={styles.wrapper}>
      <div className={styles.tabs}>
        {views.map((v, i) => (
          <button
            key={v.id}
            className={`${styles.tab} ${i === activeViewIdx ? styles.tabActive : ''}`}
            onClick={() => setActiveViewIdx(i)}
            type="button"
          >
            {v.name}
          </button>
        ))}
        <button type="button" onClick={addView} className={styles.addTabBtn} title="Añadir Vista">
          <Plus size={18} />
        </button>
      </div>

      <div className={styles.editorWorkspace}>
        {/* Tools */}
        <div className={styles.toolsPanel}>
          <div className={styles.toolSection}>
            <h4>Información de la Vista</h4>
            <input 
              className={styles.input}
              value={activeView.name}
              onChange={(e) => updateActiveView({ name: e.target.value })}
              placeholder="Ej. Frente"
            />
            <label className={styles.btn}>
              {uploading ? <Loader2 className="animate-spin" size={16} /> : <ImageIcon size={16} />}
              Subir Imagen Base
              <input type="file" hidden accept="image/*" onChange={handleBaseImageUpload} disabled={uploading} />
            </label>
            <button type="button" className={`${styles.btn} ${styles.btnDanger}`} onClick={removeView}>
              <Trash2 size={16} /> Eliminar Vista
            </button>
          </div>

          <div className={styles.toolSection}>
            <h4>Añadir Elementos Default</h4>
            <button type="button" className={styles.btn} onClick={handleAddText}>
              <Type size={16} /> Añadir Texto Libre
            </button>
            <label className={styles.btn}>
              {uploading ? <Loader2 className="animate-spin" size={16} /> : <ImagePlus size={16} />}
              Añadir Diseño / Mockup
              <input type="file" hidden accept="image/*" onChange={handleImageUpload} disabled={uploading} />
            </label>
            
            {activeObjectInfo.isText && (
              <div style={{ marginTop: '1rem', padding: '0.5rem', background: '#fff', borderRadius: '6px', border: '1px solid #ddd' }}>
                <label style={{ fontSize: '0.8rem', color: '#666', display: 'block', marginBottom: '0.25rem' }}>Tipo de Letra:</label>
                <select className={styles.input} value={activeObjectInfo.fontFamily} onChange={handleChangeFont} style={{ marginBottom: 0 }}>
                  {FONTS.map(f => <option key={f} value={f} style={{ fontFamily: f }}>{f}</option>)}
                </select>
              </div>
            )}
            
            {(activeObjectInfo.isText || fabricCanvas?.getActiveObject()) && (
              <button type="button" className={`${styles.btn} ${styles.btnDanger}`} onClick={deleteActiveObject} style={{marginTop: '1rem'}}>
                <Trash2 size={16} /> Quitar Capa
              </button>
            )}
          </div>
        </div>

        {/* Canvas */}
        <div className={styles.canvasContainer}>
          {!activeView.imagesByColor?.default && (
            <div style={{position:'absolute', top:0, left:0, width:'100%', height:'100%', display:'flex', alignItems:'center', justifyContent:'center', color:'#999'}}>
              Sube la imagen base de la prenda
            </div>
          )}
          <canvas ref={canvasElRef} className={styles.fabricCanvasEl} />
        </div>
      </div>
    </div>
  );
};

export default AdminCustomizationViewsEditor;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { getProduct } from '../../../../services/products';
import { toDirectImageUrl, toThumbnailImageUrl, ensureSingleImageUrl } from '../../../../utils/imageUrl';
import { getThumbnailVariant } from '../../../../utils/productThumbnailVariant';
import { recordThumbnailImpression } from '../../../../utils/productVariantBehavior';
import { useQueryClient } from '@tanstack/react-query';
import OptimizedImage, { useImagePreloader } from '../../../../components/common/OptimizedImage/OptimizedImage';
import ComboProductImageWithDesign, { comboHasDesignLayers } from './ComboProductImageWithDesign';
import styles from './ComboProductImage.module.css';

function getBestImageUrl(product, item, variantSelection = {}) {
  if (!product) return '';
  const displayColor = item?.variantMapping?.color || variantSelection?.color || '';
  const cleanedColor = displayColor ? displayColor.trim().toLowerCase() : '';

  let exactMatchUrl = '';
  let defaultFallbackUrl = '';

  // 1. Obtener la Customization View primero (fuente primaria de coordenadas)
  const view = product.customizationViews?.find((v) => v.id === item?.viewId)
    || product.customizationViews?.[0];

  if (view && view.imagesByColor) {
    const keys = Object.keys(view.imagesByColor);
    let matchedColorKey = null;

    if (cleanedColor) {
      matchedColorKey = keys.find(k => k.trim() === displayColor.trim()) ||
        keys.find(k => k.trim().toLowerCase() === cleanedColor);
    }

    if (matchedColorKey) {
      exactMatchUrl = ensureSingleImageUrl(view.imagesByColor[matchedColorKey]);
    }
    if (!defaultFallbackUrl) {
      defaultFallbackUrl = ensureSingleImageUrl(view.imagesByColor?.default);
    }
  }

  // 2. Si no hay match exacto en la vista, buscar en variants
  if (!exactMatchUrl && Array.isArray(product.variants) && product.variants.length > 0 && cleanedColor) {
    const matchingVariant = product.variants.find((v) => v.name && v.name.trim().toLowerCase() === cleanedColor);
    if (matchingVariant && matchingVariant.imageUrl) {
      exactMatchUrl = ensureSingleImageUrl(matchingVariant.imageUrl);
    }

    if (!defaultFallbackUrl) {
      const principalId = product.defaultVariantId;
      const principalVariant = principalId ? product.variants.find((v) => v.id === principalId) : null;
      defaultFallbackUrl = ensureSingleImageUrl(principalVariant?.imageUrl || product.variants[0]?.imageUrl);
    }
  }

  // Si encontró match exacto, usar ese
  if (exactMatchUrl) return exactMatchUrl;

  // 3. Fallbacks finales si no hay match exacto por color
  return defaultFallbackUrl || ensureSingleImageUrl(product.mainImage || (Array.isArray(product.images) && product.images[0]) || '');
}

/**
 * Muestra la imagen de un producto combo con soporte de diseños pre-configurados.
 * Prioridad:
 * 1. comboPreviewImage (URL subida a Firebase Storage desde admin)
 * 2. Rendering client-side con diseños (ComboProductImageWithDesign)
 * 3. Imágenes raw de los productos del combo lado a lado
 */
const ComboProductImage = ({
  comboProduct,
  variantSelections = {},
  className = '',
  isAboveFold = false,
  isThumbnail = false,
  renderSelector,
  onProductsFetched
}) => {
  const queryClient = useQueryClient();
  const [itemImageUrls, setItemImageUrls] = useState({});
  const [itemCropData, setItemCropData] = useState({});
  const [itemProducts, setItemProducts] = useState({});
  const [fetchDone, setFetchDone] = useState(false);
  const [designFailed, setDesignFailed] = useState(false);
  const containerRef = useRef(null);
  const comboImpressionRecorded = useRef(false);

  const comboItems = comboProduct?.comboItems || [];
  const comboLayout = comboProduct?.comboLayout || { orientation: 'horizontal', spacing: 20 };

  const savedPreview = comboProduct?.comboPreviewImage;
  const fallbackImage = comboProduct?.images?.[0];

  const isDefaultView = !variantSelections || Object.keys(variantSelections).length === 0;

  const effectiveVariantSelections = useMemo(() => {
    if (!isDefaultView || comboItems.length === 0) return variantSelections;
    return comboItems.reduce((acc, item, i) => {
      const color = item?.variantMapping?.color;
      if (color !== undefined && color !== null && color !== '') acc[i] = { color };
      else acc[i] = {};
      return acc;
    }, {});
  }, [isDefaultView, comboItems, variantSelections]);

  // Precargar todas las imágenes posibles asociadas a los sub-productos (colores, vistas)
  const allSubProductUrls = useMemo(() => {
    const urls = new Set();
    const extract = (obj) => {
      if (!obj) return;
      if (typeof obj === 'string') {
        if (obj.startsWith('http') && (obj.includes('cloudinary') || obj.match(/\.(jpeg|jpg|webp|png|gif)$/i))) {
          urls.add(obj);
        }
      } else if (Array.isArray(obj)) {
        obj.forEach(extract);
      } else if (typeof obj === 'object') {
        Object.values(obj).forEach(extract);
      }
    };
    Object.values(itemProducts).forEach(p => extract(p));
    return Array.from(urls);
  }, [itemProducts]);

  useImagePreloader(allSubProductUrls);

  // Intersection observer para registrar impresiones
  useEffect(() => {
    if (comboImpressionRecorded.current || comboItems.length === 0) return;
    const el = containerRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      (entries) => {
        if (comboImpressionRecorded.current) return;
        if (entries[0]?.isIntersecting) {
          comboImpressionRecorded.current = true;
          comboItems.forEach((item) => {
            if (item.productId) recordThumbnailImpression(item.productId);
          });
        }
      },
      { rootMargin: '50px', threshold: 0.1 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [comboItems]);

  const placeholderUrl = 'https://via.placeholder.com/400x400/eee/999?text=Combo';

  // Cargar imágenes de cada producto del combo según la variante elegida
  useEffect(() => {
    if (comboItems.length === 0) {
      setFetchDone(true);
      return;
    }
    let cancelled = false;

    const run = async () => {
      const results = await Promise.all(
        comboItems.map(async (item, i) => {
          try {
            let product = null;
            let cachedProduct = queryClient.getQueryData(['product', item.productId]);
            if (!cachedProduct) {
              const cachedProducts = queryClient.getQueryData(['products', null, '', 'name']);
              if (Array.isArray(cachedProducts)) {
                cachedProduct = cachedProducts.find(p => p.id === item.productId);
              }
            }
            product = cachedProduct;
            if (!product) {
              const { data } = await getProduct(item.productId);
              product = data;
            }
            if (!product) return null;
            const variantSelection = effectiveVariantSelections[i] || {};
            const imageUrl = getBestImageUrl(product, item, variantSelection);

            // Extract crop data from variant if available
            let cropData = null;
            if (variantSelection.id) {
              const variant = product.variants?.find(v => v.id === variantSelection.id);
              cropData = variant?.thumbnailCrop?.percentages || null;
            } else if (product.variants?.[0]?.thumbnailCrop?.percentages) {
              cropData = product.variants[0].thumbnailCrop.percentages;
            }

            return { index: i, imageUrl, cropData, product };
          } catch (err) {
            console.warn('Combo item image load:', item?.productId, err);
            return null;
          }
        })
      );

      if (cancelled) return;
      const nextUrls = {};
      const nextCrops = {};
      const nextProducts = {};
      results.forEach((r) => {
        if (r && r.imageUrl) {
          nextUrls[r.index] = r.imageUrl;
          if (r.cropData) nextCrops[r.index] = r.cropData;
        }
        if (r && r.product) {
          nextProducts[r.index] = r.product;
        }
      });
      setItemImageUrls(nextUrls);
      setItemCropData(nextCrops);
      setItemProducts(nextProducts);
      setFetchDone(true);
      if (onProductsFetched) {
        onProductsFetched(nextProducts);
      }
    };

    run();
    return () => { cancelled = true; };
  }, [comboItems, effectiveVariantSelections, queryClient]);

  const isHorizontal = comboLayout.orientation !== 'vertical';

  const previewUrl =
    savedPreview &&
      typeof savedPreview === 'string' &&
      savedPreview.trim().length > 0 &&
      !savedPreview.trim().toLowerCase().startsWith('data:')
      ? savedPreview.trim()
      : '';

  // Prioridad 1: previsualización del combo subida (tiene diseños como imagen combinada)
  // Usar la imagen pre-generada de alta prioridad solo para thumbnails (tarjetas, carrito) o cuando
  // no necesitamos renderizar interfaces interactivas por cada producto.
  const isUploadedUrlRaw = previewUrl &&
    previewUrl !== placeholderUrl &&
    !String(previewUrl).includes('placeholder');

  const hasDesignLayers = comboHasDesignLayers(comboProduct?.comboItemCustomization);

  if (isUploadedUrlRaw && (isThumbnail || !renderSelector)) {
    return (
      <div className={className}>
        <div ref={containerRef} className={styles.container}>
          <OptimizedImage
            src={toThumbnailImageUrl(previewUrl)}
            fallbackSrc={toDirectImageUrl(previewUrl)}
            alt={comboProduct?.name || 'Combo'}
            className={styles.image}
            loading={isAboveFold ? "eager" : "lazy"}
            fetchPriority={isAboveFold ? "high" : "auto"}
            showSkeleton={false}
            seamless={true}
            objectFit="contain"
          />
        </div>
      </div>
    );
  }

  // Prioridad 2: Renderizado en cliente (DOM overlay super rápido y a prueba de CORS)
  if (hasDesignLayers && comboItems.length > 0 && !designFailed) {
    return (
      <ComboProductImageWithDesign
        comboProduct={comboProduct}
        className={className}
        isAboveFold={isAboveFold}
        isThumbnail={isThumbnail}
        variantSelections={effectiveVariantSelections}
        renderSelector={renderSelector}
        onError={() => setDesignFailed(true)}
      />
    );
  }

  // Prioridad 3: Imágenes raw de los productos del combo (sin diseño)
  const manualImage = (comboProduct?.hasVariants && comboProduct?.variants?.[0]?.imageUrl) || fallbackImage;

  // Sin items: fallback
  if (comboItems.length === 0) {
    const displayUrl = manualImage || placeholderUrl;
    return (
      <div ref={containerRef} className={`${styles.container} ${className}`}>
        <OptimizedImage
          src={toDirectImageUrl(displayUrl)}
          alt={comboProduct?.name || 'Combo'}
          className={styles.image}
          loading={isAboveFold ? "eager" : "lazy"}
          fetchPriority={isAboveFold ? "high" : "auto"}
          showSkeleton={false}
        />
      </div>
    );
  }

  // Mientras no ha terminado el fetch: placeholder
  if (!fetchDone) {
    return (
      <div
        ref={containerRef}
        className={`${styles.container} ${styles.comboRow} ${className}`}
        style={{
          flexDirection: isHorizontal ? 'row' : 'column',
          gap: `${comboLayout.spacing ?? 20}px`,
          padding: '0.75rem'
        }}
      >
        {comboItems.map((item, index) => (
          <div key={`placeholder-${item.productId}-${index}`} className={styles.comboRowItem}>
            <div className={styles.comboRowPlaceholder} />
          </div>
        ))}
      </div>
    );
  }

  const hasAnyImage = comboItems.some((_, index) => itemImageUrls[index]);

  // Sin imágenes encontradas: fallback
  if (!hasAnyImage) {
    const displayUrl = manualImage || placeholderUrl;
    return (
      <div ref={containerRef} className={`${styles.container} ${className}`}>
        <OptimizedImage
          src={toDirectImageUrl(displayUrl)}
          alt={comboProduct?.name || 'Combo'}
          className={styles.image}
          loading={isAboveFold ? "eager" : "lazy"}
          fetchPriority={isAboveFold ? "high" : "auto"}
          showSkeleton={false}
          seamless={true}
        />
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      className={`${styles.container} ${styles.comboRow} ${className}`}
      style={{
        flexDirection: isHorizontal ? 'row' : 'column',
        gap: `${comboLayout.spacing ?? 20}px`,
        padding: '0.75rem'
      }}
    >

      {comboItems.map((item, index) => {
        const imageUrl = itemImageUrls[index];
        const reactKey = `${item.productId}-${index}`;
        const p = itemProducts[index];
        if (!imageUrl) {
          return (
            <div key={reactKey} className={styles.comboRowItem}>
              <div className={styles.comboRowPlaceholder} style={{ transform: `scale(${item.scale ?? 1})` }} />
            </div>
          );
        }
        return (
          <div key={reactKey} className={styles.comboRowItem}>
            {renderSelector && !isThumbnail && renderSelector(index, p, 'top')}
            <div style={{
              width: '100%',
              position: 'relative'
            }}>
              <div style={{
                width: '100%',
                height: '100%',
                transform: `scale(${item.scale ?? 1})`,
                transformOrigin: 'center center'
              }}>
                <OptimizedImage
                  src={toThumbnailImageUrl(imageUrl)}
                  alt={`${comboProduct?.name || 'Combo'} - producto ${index + 1}`}
                  className={styles.comboRowImage}
                  loading={isAboveFold ? "eager" : "lazy"}
                  fetchPriority={isAboveFold ? "high" : "auto"}
                  showSkeleton={false}
                  seamless={true}
                  fadeInDuration={200}
                  cropData={itemCropData[index]}
                />
              </div>
            </div>
            {renderSelector && !isThumbnail && renderSelector(index, p, 'bottom')}
          </div>
        );
      })}
    </div>
  );
};

export default ComboProductImage;

import React, { useState, useEffect } from 'react';
import { getProduct } from '../../../../services/products';
import { ensureSingleImageUrl } from '../../../../utils/imageUrl';
import { useQueryClient, useQuery } from '@tanstack/react-query';
import { generateThumbnailWithDesign } from '../../../../utils/thumbnailWithDesign';
import { getCloudinaryOptimized } from '../../../../components/common/OptimizedImage/OptimizedImage';
import { getFonts } from '../../../../services/fonts';
import styles from './ComboProductImage.module.css';

function getBestImageUrl(product, item, variantSelection = {}, comboCustom = null) {
    if (!product) return '';
    const displayColor = item?.variantMapping?.color || variantSelection?.color || '';
    const cleanedColor = displayColor ? displayColor.trim().toLowerCase() : '';

    let exactMatchUrl = '';
    let defaultFallbackUrl = '';

    if (comboCustom && comboCustom.imagesByColor) {
        const keys = Object.keys(comboCustom.imagesByColor);
        if (cleanedColor) {
            const matchKey = keys.find(k => k.trim() === displayColor.trim()) ||
                             keys.find(k => k.trim().toLowerCase() === cleanedColor);
            if (matchKey) exactMatchUrl = ensureSingleImageUrl(comboCustom.imagesByColor[matchKey]);
        }
        if (!defaultFallbackUrl) defaultFallbackUrl = ensureSingleImageUrl(comboCustom.imagesByColor?.default);
    }

    if (!exactMatchUrl) {
        const view = product.customizationViews?.find(v => v.id === item?.viewId) || product.customizationViews?.[0];
        if (view && view.imagesByColor) {
            const keys = Object.keys(view.imagesByColor);
            if (cleanedColor) {
                const matchedColorKey = keys.find(k => k.trim() === displayColor.trim()) ||
                                        keys.find(k => k.trim().toLowerCase() === cleanedColor);
                if (matchedColorKey) exactMatchUrl = ensureSingleImageUrl(view.imagesByColor[matchedColorKey]);
            }
            if (!defaultFallbackUrl) defaultFallbackUrl = ensureSingleImageUrl(view.imagesByColor?.default);
        }
    }

    if (!exactMatchUrl && Array.isArray(product.variants) && product.variants.length > 0 && cleanedColor) {
        let matchingVariant = product.variants.find(v => (v.name || '').trim() === displayColor.trim()) ||
                              product.variants.find(v => (v.name || '').trim().toLowerCase() === cleanedColor);
        if (matchingVariant && matchingVariant.imageUrl) exactMatchUrl = ensureSingleImageUrl(matchingVariant.imageUrl);
        
        if (!defaultFallbackUrl) {
            const principalVariant = product.defaultVariantId
                ? product.variants.find(v => v.id === product.defaultVariantId)
                : null;
            defaultFallbackUrl = ensureSingleImageUrl(principalVariant?.imageUrl || product.variants[0]?.imageUrl);
        }
    }

    if (exactMatchUrl) return getCloudinaryOptimized(exactMatchUrl);

    if (!defaultFallbackUrl) {
        defaultFallbackUrl = ensureSingleImageUrl(product.mainImage || (Array.isArray(product.images) && product.images[0]) || '');
    }

    return defaultFallbackUrl ? getCloudinaryOptimized(defaultFallbackUrl) : '';
}

function getDesignLayers(comboItemCustomization, itemIndex, color) {
    const cust = (comboItemCustomization || [])[itemIndex];
    if (!cust || !cust.initialLayersByColor) return [];

    if (color) {
        const cleanedColor = color.trim().toLowerCase();
        const keys = Object.keys(cust.initialLayersByColor);
        const exactMatch = keys.find(k => k.trim() === color.trim());
        if (exactMatch) return cust.initialLayersByColor[exactMatch];

        const loweredMatch = keys.find(k => k.trim().toLowerCase() === cleanedColor);
        if (loweredMatch) return cust.initialLayersByColor[loweredMatch];
    }

    const colorKey = color || 'default';
    return cust.initialLayersByColor[colorKey]
        || cust.initialLayersByColor.default
        || [];
}

export function comboHasDesignLayers(comboItemCustomization) {
    if (!Array.isArray(comboItemCustomization)) return false;
    return comboItemCustomization.some(cust => {
        if (!cust?.initialLayersByColor) return false;
        return Object.values(cust.initialLayersByColor).some(
            layers => Array.isArray(layers) && layers.length > 0
        );
    });
}

const SafeSvgImage = ({ layer, imageHref, transform, opacity }) => {
    const filterId = React.useMemo(() => 
        layer.id ? `tint-${layer.id}` : `tint-${Math.random().toString(36).substring(2, 9)}`, 
    [layer.id]);

    return (
        <g transform={transform} opacity={opacity}>
            {layer.tintColor && (
                <defs>
                    <filter id={filterId} colorInterpolationFilters="sRGB">
                        <feFlood floodColor={layer.tintColor} floodOpacity={layer.tintOpacity ?? 1} result="color" />
                        <feComposite in="color" in2="SourceAlpha" operator="in" />
                    </filter>
                </defs>
            )}
            <g transform={layer.flipX || layer.flipY ? `translate(${(layer.width || 200) / 2}, ${(layer.height || (layer.width || 200)) / 2}) scale(${layer.flipX ? -1 : 1}, ${layer.flipY ? -1 : 1}) translate(${-(layer.width || 200) / 2}, ${-(layer.height || (layer.width || 200)) / 2})` : undefined}>
                <image
                    href={imageHref}
                    xlinkHref={imageHref}
                    x="0"
                    y="0"
                    width={layer.width || 200}
                    height={layer.height || (layer.width || 200)}
                    preserveAspectRatio="none"
                    filter={layer.tintColor ? `url(#${filterId})` : undefined}
                />
            </g>
        </g>
    );
};

const thumbnailCache = new Map();
const MAX_CACHE_SIZE = 150;
const CACHE_VERSION = 'v20_forced_dims';

export const NativeOverlay = ({ baseImageUrl, layers, isThumbnail = false }) => {
    const [dataUrl, setDataUrl] = useState(null);
    const [isGenerating, setIsGenerating] = useState(true);
    const validLayers = Array.isArray(layers) ? layers.filter(l => l && l.type) : [];

    const { data: customFonts, isLoading: loadingFonts } = useQuery({
        queryKey: ['fonts'],
        queryFn: async () => {
            const { data, error } = await getFonts();
            return error ? [] : data;
        }
    });

    const displayUrl = getCloudinaryOptimized(ensureSingleImageUrl(baseImageUrl));

    useEffect(() => {
        if (loadingFonts) return;

        let cancelled = false;
        if (!baseImageUrl) {
            setDataUrl('error');
            setIsGenerating(false);
            return;
        }

        const cacheKey = `${CACHE_VERSION}-${baseImageUrl}-${JSON.stringify(validLayers.map(l => ({
            id: l.id, type: l.type, src: l.src, text: l.text, color: l.color, 
            x: l.x, y: l.y, scaleX: l.scaleX, scaleY: l.scaleY, baseW: l.baseW
        })))}`;
        
        if (thumbnailCache.has(cacheKey)) {
            setDataUrl(thumbnailCache.get(cacheKey));
            setIsGenerating(false);
            return;
        }

        setIsGenerating(true);

        const fontFamilies = new Set();
        validLayers.forEach(l => {
            if (l.type === 'text' && l.fontFamily) {
                const clean = String(l.fontFamily).replace(/['"]/g, '').trim();
                l.fontFamily = clean;
                fontFamilies.add(clean);
            }
        });

        const loadFonts = async () => {
            const promises = [];
            for (const ff of fontFamilies) {
                const cf = (customFonts || []).find(f => (f.family || f.name || '').replace(/['"]/g, '').trim() === ff);
                if (cf && cf.url) {
                    try {
                        const face = new FontFace(ff, `url("${cf.url}")`);
                        document.fonts.add(face);
                        promises.push(face.load().catch(() => document.fonts.load(`16px "${ff}"`)));
                    } catch { promises.push(document.fonts.load(`16px "${ff}"`).catch(() => null)); }
                } else {
                    promises.push(document.fonts.load(`16px "${ff}"`).catch(() => null));
                }
            }
            await Promise.all(promises);
            await document.fonts.ready;
        };

        loadFonts().then(async () => {
            if (cancelled) return;
            try {
                const imageUrl = getCloudinaryOptimized(ensureSingleImageUrl(baseImageUrl));
                const url = await generateThumbnailWithDesign(imageUrl, validLayers, { maxWidth: 900 });
                if (!cancelled && url) {
                    if (thumbnailCache.size >= MAX_CACHE_SIZE) {
                        thumbnailCache.delete(thumbnailCache.keys().next().value);
                    }
                    thumbnailCache.set(cacheKey, url);
                    setDataUrl(url);
                }
            } catch (err) {
                console.error('Fabric generation failed:', err);
            }
            setIsGenerating(false);
        });

        return () => { cancelled = true; };
    }, [baseImageUrl, layers, loadingFonts]);

    return (
        <div style={{ position: 'relative', width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <img
                src={displayUrl}
                alt="Producto"
                style={{
                    position: 'absolute',
                    top: 0,
                    left: 0,
                    width: '100%',
                    height: '100%',
                    display: 'block',
                    objectFit: 'contain',
                    opacity: dataUrl && dataUrl !== 'error' ? 0 : 1,
                    transition: 'opacity 0.3s ease'
                }}
                loading="eager"
                fetchpriority="high"
            />
            {dataUrl && dataUrl !== 'error' && (
                <img
                    src={dataUrl}
                    alt="Producto personalizado"
                    style={{
                        position: 'absolute',
                        top: 0,
                        left: 0,
                        width: '100%',
                        height: '100%',
                        display: 'block',
                        objectFit: 'contain',
                        opacity: 1,
                        transition: 'opacity 0.3s ease'
                    }}
                />
            )}
        </div>
    );
};

export const DomOverlay = ({ baseImageUrl, layers }) => {
    const validLayers = Array.isArray(layers) ? layers.filter(l => l && l.type) : [];
    const defaultBaseW = validLayers.find(l => l.baseW)?.baseW || 1200;
    const defaultBaseH = validLayers.find(l => l.baseH)?.baseH || 1200;

    return (
        <div style={{ position: 'relative', width: '100%', overflow: 'hidden', backgroundColor: 'transparent' }}>
            <img
                src={ensureSingleImageUrl(baseImageUrl)}
                alt="Product Container"
                style={{ width: '100%', height: 'auto', display: 'block', objectFit: 'contain', zIndex: 1 }}
            />
            <svg
                viewBox={`0 0 ${defaultBaseW} ${defaultBaseH}`}
                preserveAspectRatio="none"
                style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', zIndex: 2, pointerEvents: 'none', overflow: 'visible' }}
            >
                {validLayers.map((layer, idx) => {
                    const lBaseW = layer.baseW || defaultBaseW;
                    const lBaseH = layer.baseH || lBaseW;
                    const rX = defaultBaseW / lBaseW;
                    const rY = defaultBaseH / lBaseH;

                    const rawX = typeof layer.x === 'number' ? layer.x : 20;
                    const rawY = typeof layer.y === 'number' ? layer.y : 20;
                    const rawScaleX = layer.scaleX ?? 1;
                    const rawScaleY = layer.scaleY ?? 1;

                    const x = rawX * rX;
                    const y = rawY * rY;
                    const scaleX = rawScaleX * rX;
                    const scaleY = rawScaleY * rY;
                    const angle = layer.angle || 0;
                    const opacity = layer.opacity ?? 1;
                    const transform = `translate(${x}, ${y}) rotate(${angle}) scale(${scaleX}, ${scaleY})`;

                    const rawSrc = ensureSingleImageUrl(layer.src);
                    const imageHref = rawSrc.startsWith('blob:') ? rawSrc : rawSrc;

                    if (layer.type === 'image' && layer.src) {
                        return (
                            <SafeSvgImage
                                key={idx}
                                layer={layer}
                                imageHref={imageHref}
                                transform={transform}
                                opacity={opacity}
                            />
                        );
                    }

                    if (layer.type === 'text') {
                        const _fontSize = layer.fontSize || 40;
                        const lines = (layer.text || 'Texto').split('\n');
                        const lineHeight = layer.lineHeight || 1.16;
                        const textAlign = layer.textAlign || 'left';

                        const maxLineLen = lines.reduce((max, l) => Math.max(max, l.length), 0);
                        const w = layer.width || (maxLineLen * (_fontSize * 0.55));
                        const tAnchor = textAlign === 'center' ? 'middle' : textAlign === 'right' ? 'end' : 'start';
                        const xPos = textAlign === 'center' ? w / 2 : textAlign === 'right' ? w : 0;

                        return (
                            <g key={idx} transform={transform} opacity={opacity}>
                                <g transform={layer.flipX || layer.flipY ? `translate(${w / 2}, ${(_fontSize * lines.length) / 2}) scale(${layer.flipX ? -1 : 1}, ${layer.flipY ? -1 : 1}) translate(${-w / 2}, ${-(_fontSize * lines.length) / 2})` : undefined}>
                                    <text
                                        x={xPos}
                                        y={_fontSize * 0.8}
                                        fill={layer.color || '#000000'}
                                        fontSize={`${_fontSize}px`}
                                        fontFamily={layer.fontFamily || 'Arial'}
                                        fontWeight={layer.fontWeight || 'normal'}
                                        fontStyle={layer.fontStyle || 'normal'}
                                        textAnchor={tAnchor}
                                    >
                                        {lines.map((ln, i) => (
                                            <tspan x={xPos} dy={i === 0 ? 0 : `${lineHeight}em`} key={i}>{ln}</tspan>
                                        ))}
                                    </text>
                                </g>
                            </g>
                        );
                    }

                    if (layer.type === 'shape') {
                        const rawWidth = layer.width || 80;
                        const rawHeight = layer.height || 60;
                        const fill = layer.fill || '#000000';
                        const stroke = layer.stroke || 'none';
                        const strokeWidth = layer.strokeWidth || 0;

                        return (
                            <g key={idx} transform={transform} opacity={opacity}>
                                {layer.shapeType === 'circle' ? (
                                    <circle
                                        cx={layer.radius || 40}
                                        cy={layer.radius || 40}
                                        r={layer.radius || 40}
                                        fill={fill}
                                        stroke={stroke}
                                        strokeWidth={strokeWidth}
                                    />
                                ) : (
                                    <rect
                                        x="0"
                                        y="0"
                                        width={rawWidth}
                                        height={rawHeight}
                                        fill={fill}
                                        stroke={stroke}
                                        strokeWidth={strokeWidth}
                                    />
                                )}
                            </g>
                        );
                    }

                    return null;
                })}
            </svg>
        </div>
    );
};

const ComboProductImageWithDesign = ({
    comboProduct,
    className = '',
    isAboveFold = false,
    isThumbnail = false,
    variantSelections = {},
    renderSelector,
    onError
}) => {
    const queryClient = useQueryClient();
    const [itemsData, setItemsData] = useState([]);

    const { data: customFonts, isLoading: loadingFonts } = useQuery({
        queryKey: ['fonts'],
        queryFn: async () => {
            const { data, error } = await getFonts();
            return error ? [] : data;
        }
    });

    const comboItems = comboProduct?.comboItems || [];
    const comboLayout = comboProduct?.comboLayout || { orientation: 'horizontal', spacing: 20 };
    const comboItemCustomization = comboProduct?.comboItemCustomization || [];

    useEffect(() => {
        if (loadingFonts) return;

        if (comboItems.length === 0) {
            setItemsData([]);
            return;
        }

        let cancelled = false;

        const load = async () => {
            const data = [];
            for (let i = 0; i < comboItems.length; i++) {
                const item = comboItems[i];
                let product = queryClient.getQueryData(['product', item.productId]);
                if (!product) {
                    try {
                        const { data: p } = await getProduct(item.productId);
                        product = p;
                    } catch { }
                }

                if (!product) {
                    data.push(null);
                    continue;
                }

                const userSelectedColor = variantSelections[i]?.color;
                let defaultColor = item.variantMapping?.color || '';
                if (!defaultColor && Array.isArray(product.variants) && product.variants.length > 0 && product.variants[0]?.name) {
                    defaultColor = product.variants[0].name;
                }

                const effectiveItem = {
                    ...item,
                    variantMapping: {
                        ...(item.variantMapping || {}),
                        color: userSelectedColor || defaultColor || ''
                    }
                };

                const comboCustomForItem = (comboItemCustomization || [])[i] || null;
                const baseImageUrl = getBestImageUrl(product, effectiveItem, {}, comboCustomForItem);
                const color = effectiveItem.variantMapping.color;
                const layers = getDesignLayers(comboItemCustomization, i, color);

                data.push({ baseImageUrl, layers, product, itemIndex: i });
            }

            if (!cancelled) {
                setItemsData(data);
            }
        };

        load();
        return () => { cancelled = true; };
    }, [comboItems, comboItemCustomization, queryClient, variantSelections, loadingFonts]);

    const isHorizontal = comboLayout.orientation !== 'vertical';
    const computedGap = isThumbnail ? Math.min((comboLayout.spacing ?? 20) / 2, 8) : (comboLayout.spacing ?? 20);
    const computedPadding = isThumbnail ? '0.25rem' : '0.5rem';

    const isLoading = itemsData.length === 0 && comboItems.length > 0;

    return (
        <div
            className={`${styles.container} ${styles.comboRow} ${className}`}
            style={{
                flexDirection: isHorizontal ? 'row' : 'column',
                gap: `${computedGap}px`,
                padding: computedPadding,
                backgroundColor: 'transparent'
            }}
        >
            {comboItems.map((item, index) => {
                const data = itemsData[index];
                const comboScale = comboItems[index]?.scale || 1;
                const relativeScale = isThumbnail ? comboScale * 1.1 : Math.min(comboScale / Math.max(1, ...comboItems.map(i => i.scale || 1)), 1);

                if (isLoading) {
                    return (
                        <div key={`placeholder-${item.productId}-${index}`} className={styles.comboRowItem}>
                            <div className={styles.comboRowPlaceholder} />
                        </div>
                    );
                }

                if (!data) {
                    return <div key={index} className={styles.comboRowItem}>Error loading item</div>;
                }

                return (
                    <div key={index} className={styles.comboRowItem}>
                        {renderSelector && !isThumbnail && renderSelector(index, data.product, 'top')}
                        <div style={{
                            width: `${isThumbnail ? 100 : relativeScale * 100}%`,
                            position: 'relative',
                            margin: '0 auto',
                            aspectRatio: '4 / 5',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            transform: isThumbnail ? `scale(${relativeScale})` : 'none',
                            transformOrigin: 'center center'
                        }}>
                            <NativeOverlay baseImageUrl={data.baseImageUrl} layers={data.layers} />
                        </div>
                        {renderSelector && !isThumbnail && renderSelector(index, data.product, 'bottom')}
                    </div>
                );
            })}
        </div>
    );
};

