import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../../../contexts/AuthContext';
import { useGlobalToast } from '../../../../contexts/ToastContext';
import { getCuestionarioTemplate } from '../../../../services/cuestionarios';
import { createWebOrder } from '../../../../services/erp/firebase';
import { getMessage } from '../../../../services/messages';
import Button from '../../../../components/common/Button';
import styles from './ProductCuestionarioModal.module.css';

function ProductCuestionarioModal({
  isOpen,
  onClose,
  templateId,
  product,
  selectedVariant,
  selectedSize,
  quantity,
  comboVariantSelections
}) {
  const navigate = useNavigate();
  const toast = useGlobalToast();

  const [template, setTemplate] = useState(null);
  const [loading, setLoading] = useState(false);
  const [processing, setProcessing] = useState(false);

  const [customAnswers, setCustomAnswers] = useState({});

  useEffect(() => {
    if (isOpen && templateId) {
      setLoading(true);
      getCuestionarioTemplate(templateId).then(res => {
        if (res.data) setTemplate(res.data);
        else toast.error('Error al cargar plantilla de cuestionario');
        setLoading(false);
      });
    }
  }, [isOpen, templateId]);

  if (!isOpen) return null;

  const handleCustomAnswerChange = (fieldId, value) => {
    setCustomAnswers(prev => ({ ...prev, [fieldId]: value }));
  };

  // Helper to extract values by fuzzy matching the label
  const findAnswerByKeyword = (keywords) => {
    if (!template) return '';
    for (const field of template.fields) {
      const lowerLabel = field.label.toLowerCase();
      if (keywords.some(kw => lowerLabel.includes(kw))) {
        return customAnswers[field.id] || '';
      }
    }
    return '';
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (template?.fields) {
      for (const field of template.fields) {
        if (field.required && !customAnswers[field.id]) {
          toast.error(`El campo "${field.label}" es obligatorio`);
          return;
        }
      }
    }

    setProcessing(true);

    try {
      // Configurar WhatsApp number
      const tiendaNumRes = await getMessage('whatsapp_number_tienda');
      const fallbackNumRes = await getMessage('whatsapp_number');
      let waNum = tiendaNumRes.data?.trim() || fallbackNumRes.data?.trim() || '51999999999';
      waNum = waNum.replace(/[\s\-\(\)\+]/g, '');
      if (waNum && !waNum.startsWith('51') && waNum.length <= 9) waNum = `51${waNum}`;

      const pseudoOrderId = `PD-${Date.now().toString(36).toUpperCase()}`;

      // Extract core info for ERP
      const rawName = findAnswerByKeyword(['nombre', 'name', 'cliente', 'apellidos']) || 'Cliente Web';
      const nameParts = rawName.trim().split(/\s+/);
      const clienteNombre = nameParts[0];
      const clienteApellidos = nameParts.length > 1 ? nameParts.slice(1).join(' ') : '';

      const phone = findAnswerByKeyword(['celular', 'whatsapp', 'teléfono', 'fono', 'telefono']) || '000000000';
      const dni = findAnswerByKeyword(['dni', 'documento', 'identidad', 'carnet']) || '00000000';
      const address = findAnswerByKeyword(['dirección', 'direccion', 'calle', 'avenida', 'envío', 'domicilio']) || 'No especificada';
      const email = findAnswerByKeyword(['correo', 'email']) || '';
      const cityDistrict = findAnswerByKeyword(['ciudad', 'distrito', 'provincia', 'departamento']) || 'No especificado';

      const price = product.salePrice || product.price || 0;
      const subtotal = price * quantity;
      const shipping = subtotal > 100 ? 0 : 15;
      const total = subtotal + shipping;

      let talla = selectedSize || '';
      let color = selectedVariant?.name || '';

      const prendasStr = `${product.name}${color ? '/' + color : ''} ${talla ? '(' + talla + ')' : ''} x${quantity}`.trim();

      const productosMap = {
        item_0: {
          productoId: product.id || '',
          producto: product.name || '',
          cantidad: quantity || 1,
          talla: talla,
          color: color,
          precio: price,
          subtotal: subtotal,
          personalizado: false,
          textoPersonalizado: '',
          urlImagenPersonalizada: ''
        }
      };

      if (product.isComboProduct && comboVariantSelections) {
        productosMap.item_0.observacionesAdicionales = JSON.stringify(comboVariantSelections);
      }

      let notasCustom = 'RESPUESTAS CUESTIONARIO:\n' + template.fields.map(f => {
        return `- ${f.label}: ${customAnswers[f.id] || 'N/A'}`;
      }).join('\n');

      const webOrderPayload = {
        numeroPedido: pseudoOrderId,
        clienteNombre,
        clienteApellidos,
        clienteNombreCompleto: rawName,
        clienteNumeroDocumento: dni,
        clienteTipoDocumento: 'DNI',
        clienteContacto: phone,
        clienteCorreo: email,
        clienteDepartamento: cityDistrict,
        clienteDistrito: cityDistrict,
        clienteProvincia: cityDistrict.toLowerCase().includes('lima') ? 'No' : 'Sí',
        envioNombres: clienteNombre,
        envioApellidos: clienteApellidos,
        envioContacto: phone,
        envioNumeroDocumento: dni,
        envioTipoDocumento: 'DNI',
        envioDireccion: address,
        envioDistrito: cityDistrict,
        envioDepartamento: cityDistrict,
        canalVenta: 'Portal Web',
        web: true,
        activador: 'portal_web',
        vendedor: 'Portal Web',
        montoTotal: total,
        montoAdelanto: 0,
        montoPendiente: total,
        estadoGeneral: 'Nuevo',
        status: 'Nuevo',
        prendas: prendasStr,
        cantidad: quantity,
        productos: productosMap,
        observación: notasCustom,
        portalPseudoOrderId: pseudoOrderId,
      };

      let webOrderId = null;
      try {
        const { id, error: webErr } = await createWebOrder(webOrderPayload);
        if (!webErr) {
          webOrderId = id;
        }
      } catch (err) {
        console.warn('No se pudo guardar en pedidos_web:', err);
      }

      const cartItem = {
        id: `cart_${Date.now()}_${Math.random().toString(36).substring(7)}`,
        productId: product.id,
        productName: product.name,
        price,
        quantity,
        variant: { size: selectedSize, color: selectedVariant?.name },
        mainImage: product.mainImage,
        status: 'pending_confirmation',
        pseudoOrderId,
        ...(webOrderId && { webOrderId })
      };

      const currentCart = JSON.parse(localStorage.getItem('shopping_cart') || '[]');
      currentCart.push(cartItem);
      localStorage.setItem('shopping_cart', JSON.stringify(currentCart));

      let message = `SOLICITUD DE NUEVO PEDIDO (${pseudoOrderId})\n\n`;
      message += `Detalles del Formulario:\n`;
      if (template?.fields?.length > 0) {
        template.fields.forEach(f => {
          message += `${f.label}: ${customAnswers[f.id] || 'N/A'}\n`;
        });
        message += `\n`;
      }

      message += `Detalle de Compra:\n`;
      message += `1. ${product.name}\n`;
      message += `   Cantidad: ${quantity}\n`;
      if (talla) message += `   Talla/Modelo: ${talla}\n`;
      if (color) message += `   Color: ${color}\n`;
      message += `   Subtotal: S/ ${(price * quantity).toFixed(2)}\n`;
      message += `   Link: ${window.location.origin}/producto/${product.id}\n\n`;

      message += `Resumen de Pago:\n`;
      message += `Producto(s): S/ ${subtotal.toFixed(2)}\n`;
      message += `Envío: ${shipping === 0 ? 'Gratis' : `S/ ${shipping.toFixed(2)}`}\n`;
      message += `TOTAL A PAGAR: S/ ${total.toFixed(2)}\n`;

      message += `Solicitud de Pedido\nHola! Vengo de la tienda virtual y quiero confirmar mi pedido con código ${pseudoOrderId}.`;

      const waLink = `https://wa.me/${waNum}?text=${encodeURIComponent(message)}`;

      toast.success('¡Redirigiendo a WhatsApp para finalizar tu pedido!');
      window.open(waLink, '_blank');

      onClose();
      navigate('/carrito');

    } catch (err) {
      console.error(err);
      toast.error('Hubo un error al procesar tu pedido');
    } finally {
      setProcessing(false);
    }
  };

  return (
    <div className={styles.overlay}>
      <div className={styles.modal}>
        <div className={styles.header}>
          <h3 className={styles.title}>Completa tu pedido</h3>
          <button type="button" className={styles.closeBtn} onClick={onClose}>&times;</button>
        </div>

        {loading ? (
          <div className={styles.loading}>Cargando cuestionario...</div>
        ) : (
          <form onSubmit={handleSubmit} className={styles.formContainer}>
            {template && template.fields && template.fields.length > 0 ? (
              <div className={styles.section}>
                {template.fields.map(field => (
                  <div key={field.id} className={styles.field}>
                    <label>{field.label} {field.required && '*'}</label>
                    {field.type === 'textarea' ? (
                      <textarea
                        required={field.required}
                        value={customAnswers[field.id] || ''}
                        onChange={(e) => handleCustomAnswerChange(field.id, e.target.value)}
                        rows={3}
                      />
                    ) : (
                      <input
                        type={field.type === 'number' ? 'number' : 'text'}
                        required={field.required}
                        value={customAnswers[field.id] || ''}
                        onChange={(e) => handleCustomAnswerChange(field.id, e.target.value)}
                      />
                    )}
                  </div>
                ))}
              </div>
            ) : (
              <div className={styles.section}>
                <p>No se encontraron campos para este cuestionario.</p>
              </div>
            )}

            <div className={styles.footer}>
              <Button type="button" variant="outline" onClick={onClose} disabled={processing}>Cancelar</Button>
              <Button type="submit" variant="primary" disabled={processing}>
                {processing ? 'Procesando...' : 'Confirmar y Pagar en WhatsApp'}
              </Button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
}

export default ProductCuestionarioModal;

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { useAuth } from '../../../../contexts/AuthContext';
import { useGlobalToast } from '../../../../contexts/ToastContext';
import { useCart } from '../../../../contexts/CartContext';
import { createReferralShare } from '../../../../services/referrals';
import { toDirectImageUrl } from '../../../../utils/imageUrl';
import { isComboProduct } from '../../../../utils/comboProductUtils';
import { recordProductClick, recordVariantViewTime } from '../../../../utils/productVariantBehavior';
import { getFallbackHex } from '../../../../utils/colors';
import { getBrands } from '../../../../services/brands';
import { useImagePreloader } from '../../../../components/common/OptimizedImage/OptimizedImage';
import OptimizedImage from '../../../../components/common/OptimizedImage/OptimizedImage';
import ComboProductImage from '../ComboProductImage/ComboProductImage';
import DraggableContainer from '../../../../components/common/DraggableContainer/DraggableContainer';
import ProductCuestionarioModal from '../ProductCuestionarioModal/ProductCuestionarioModal';
import ProductReviews from '../ProductReviews';
import { Truck, RefreshCw, ShieldCheck, Share2 } from 'lucide-react';
import styles from './ProductDetail.module.css';

// ─── helpers ─────────────────────────────────────────────────────────────────
const getCategory = (product, cats) => {
  const ids = product?.categories ?? (product?.category ? [product.category] : []);
  const found = (cats || []).filter(c => ids.includes(c.id)).map(c => c.name).filter(Boolean);
  return found[0] || product?.category || '';
};

const buildImages = (product, variant, isCombo, comboSels, comboProd) => {
  const seen = new Set();
  const list = [];
  const push = (url, extra = {}) => {
    const u = toDirectImageUrl(url);
    if (u && !u.includes('undefined') && !seen.has(u)) { seen.add(u); list.push({ url: u, ...extra }); }
  };

  if (isCombo) {
    push(product?.comboPreviewImage || product?.mainImage || '', { isComboView: true });
    Object.keys(comboProd || {}).forEach(idx => {
      const sub = comboProd[idx];
      const sel = comboSels?.[idx];
      if (!sub) return;
      const cc = sel?.color?.trim().toLowerCase() || '';
      const mv = cc && sub.variants?.find(v => v.name?.trim().toLowerCase() === cc);
      if (mv) {
        (sub.customizationViews || []).forEach(view => {
          const k = Object.keys(view.imagesByColor || {}).find(k => k.trim().toLowerCase() === cc);
          if (k) push(view.imagesByColor[k]);
          if (view.hasBackSide) {
            const bk = Object.keys(view.backSide?.imagesByColor || {}).find(k => k.trim().toLowerCase() === cc);
            if (bk) push(view.backSide.imagesByColor[bk]);
          }
        });
        (mv.galleryImages || []).forEach(u => push(u));
        if (!mv.galleryImages?.length && mv.imageUrl) push(mv.imageUrl);
      } else {
        (sub.images || []).forEach(u => push(u));
        if (sub.mainImage) push(sub.mainImage);
      }
    });
    (product?.images || []).forEach(u => push(u));
  } else {
    const cc = variant?.name?.trim().toLowerCase() || '';
    if (variant) {
      (product?.customizationViews || []).forEach(view => {
        const k = Object.keys(view.imagesByColor || {}).find(k => k.trim().toLowerCase() === cc);
        if (k) push(view.imagesByColor[k]);
        if (view.hasBackSide) {
          const bk = Object.keys(view.backSide?.imagesByColor || {}).find(k => k.trim().toLowerCase() === cc);
          if (bk) push(view.backSide.imagesByColor[bk]);
        }
      });
      if (variant.imageUrl) push(variant.imageUrl);
      if (variant.galleryImages?.length) variant.galleryImages.forEach(u => push(u));
      else if (variant.images?.length) variant.images.forEach(u => push(u));
      else { (product?.images || []).forEach(u => push(u)); }
    } else {
      if (product?.mainImage) push(product.mainImage);
      (product?.images || []).forEach(u => push(u));
    }
  }
  if (!list.length) list.push({ url: 'https://via.placeholder.com/600x750', isComboView: false });
  return list;
};

// ─── Gallery ─────────────────────────────────────────────────────────────────
const Gallery = ({ images, activeIdx, setActiveIdx, showCombo, comboEl }) => {
  const [zoom, setZoom] = useState(false);
  const [pos, setPos] = useState({ x: 50, y: 50 });
  const active = images[activeIdx] || images[0];

  const onMove = e => {
    const r = e.currentTarget.getBoundingClientRect();
    setPos({ x: ((e.clientX - r.left) / r.width) * 100, y: ((e.clientY - r.top) / r.height) * 100 });
  };

  return (
    <div className={styles.gallery}>
      {images.length > 1 && (
        <div className={styles.thumbStrip}>
          {images.map((img, i) => (
            <button
              key={i}
              className={`${styles.thumb} ${activeIdx === i ? styles.thumbActive : ''}`}
              onClick={() => setActiveIdx(i)}
              onMouseEnter={() => setActiveIdx(i)}
            >
              <img src={img.url} alt="" loading="lazy" />
            </button>
          ))}
        </div>
      )}

      <div
        className={`${styles.mainFrame} ${showCombo ? styles.mainFrameCombo : ''}`}
        onMouseEnter={() => !showCombo && setZoom(true)}
        onMouseLeave={() => setZoom(false)}
        onMouseMove={onMove}
      >
        {showCombo ? (
          <div className={styles.comboWrap}>{comboEl}</div>
        ) : (
          <img
            src={active.url}
            alt="Producto"
            className={styles.mainImg}
            style={zoom ? { transform: 'scale(2.4)', transformOrigin: `${pos.x}% ${pos.y}%` } : {}}
            fetchpriority="high"
            loading="eager"
          />
        )}
        {!zoom && !showCombo && <span className={styles.zoomHint}>🔍 Hover para zoom</span>}
      </div>
    </div>
  );
};

// ─── Skeleton ─────────────────────────────────────────────────────────────────
const Skeleton = () => (
  <div className={styles.skeleton}>
    <div className={styles.skeletonGallery} />
    <div className={styles.skeletonInfo}>
      {[40, 85, 30, 100, 100].map((w, i) => (
        <div key={i} className={styles.skeletonLine} style={{ width: `${w}%` }} />
      ))}
    </div>
  </div>
);

// ─── ProductDetail ────────────────────────────────────────────────────────────
const ProductDetail = ({ product, loading, categories = [] }) => {
  const navigate = useNavigate();
  const { addToCart } = useCart();
  const { user, userProfile } = useAuth();
  const toast = useGlobalToast();

  const [variantIdx, setVariantIdx] = useState(0);
  const [selectedSize, setSelectedSize] = useState('');
  const [qty, setQty] = useState(1);
  const [comboSels, setComboSels] = useState({});
  const [comboProd, setComboProd] = useState({});
  const [imgIdx, setImgIdx] = useState(0);
  const [cuestionario, setCuestionario] = useState(null);
  const [sharing, setSharing] = useState(false);

  const secsRef = useRef(0);
  const lastVariantRef = useRef(null);

  const isCombo = isComboProduct(product);
  const hasVariants = Boolean(product?.hasVariants);
  const variants = hasVariants ? (Array.isArray(product?.variants) ? product.variants : []) : [];
  const selectedVariant = hasVariants && variants[variantIdx] ? variants[variantIdx] : null;
  const sizes = hasVariants ? (selectedVariant?.sizes || []) : (product?.mainSizes || []);
  const category = getCategory(product, categories);
  const displayPrice = product?.salePrice || product?.price || 0;
  const originalPrice = product?.salePrice ? product?.price : null;
  const discount = originalPrice ? Math.round(((originalPrice - displayPrice) / originalPrice) * 100) : 0;
  const referralCode = userProfile?.referralCode || (user?.uid ? `KS-${user.uid.substring(0, 6).toUpperCase()}` : '');

  const { data: brands } = useQuery({
    queryKey: ['brands'],
    queryFn: async () => (await getBrands()).data,
    staleTime: 300_000,
  });
  const brand = brands?.find(b => b.id === product?.brandId);

  const images = React.useMemo(
    () => product ? buildImages(product, selectedVariant, isCombo, comboSels, comboProd) : [],
    [product, selectedVariant, isCombo, comboSels, comboProd]
  );

  const allUrls = React.useMemo(() => {
    if (!product) return [];
    const s = new Set();
    const walk = v => {
      if (!v) return;
      if (typeof v === 'string' && v.startsWith('http')) s.add(v);
      else if (Array.isArray(v)) v.forEach(walk);
      else if (typeof v === 'object') Object.values(v).forEach(walk);
    };
    walk(product);
    return [...s];
  }, [product]);

  useImagePreloader(allUrls);

  useEffect(() => { setImgIdx(0); }, [selectedVariant?.id, selectedVariant?.name]);
  useEffect(() => { if (product?.id) recordProductClick(product.id); }, [product?.id]);

  useEffect(() => {
    if (!product?.id || !selectedVariant?.id) return;
    const flush = (id, s) => { if (id && s > 0) recordVariantViewTime(product.id, id, s); };
    if (lastVariantRef.current !== selectedVariant.id) {
      flush(lastVariantRef.current, secsRef.current);
      secsRef.current = 0;
      lastVariantRef.current = selectedVariant.id;
    }
    const iv = setInterval(() => secsRef.current++, 1000);
    return () => { clearInterval(iv); flush(selectedVariant.id, secsRef.current); };
  }, [product?.id, selectedVariant?.id]);

  useEffect(() => {
    if (!isCombo || !product?.comboItems?.length) return;
    const init = {};
    product.comboItems.forEach((item, i) => { if (item.variantMapping?.color) init[i] = { color: item.variantMapping.color }; });
    if (Object.keys(init).length) setComboSels(prev => ({ ...init, ...prev }));
  }, [product?.id, isCombo]);

  useEffect(() => { setSelectedSize(sizes[0] || ''); }, [selectedVariant?.id, JSON.stringify(sizes)]);

  // ── Handlers
  const handleAddToCart = () => {
    addToCart(
      product,
      { size: selectedSize, selectedVariant: selectedVariant ?? undefined },
      null,
      qty,
      isCombo ? { variantSelections: comboSels, customizations: {}, subProductsData: comboProd } : null
    );
    toast.success('¡Agregado al carrito!');
  };

  const handlePersonalize = () => {
    const p = new URLSearchParams();
    if (selectedSize) p.set('size', selectedSize);
    if (selectedVariant?.name) p.set('color', selectedVariant.name);
    if (isCombo && Object.keys(comboSels).length) p.set('comboSelections', JSON.stringify(comboSels));
    navigate(`/editor/${product.id}${p.toString() ? `?${p}` : ''}`);
  };

  const handleShare = async () => {
    if (!user) { toast.error('Inicia sesión para compartir y ganar monedas'); return; }
    setSharing(true);
    const { id, error } = await createReferralShare(referralCode);
    setSharing(false);
    if (error) { toast.error('Error al generar enlace'); return; }
    const url = `${window.location.origin}/producto/${product.id}?ref=${referralCode}&shareId=${id}`;
    navigator.clipboard.writeText(url)
      .then(() => toast.success('¡Enlace copiado! Compártelo y gana monedas.'))
      .catch(() => toast.error('Error al copiar'));
  };

  const handleDescClick = e => {
    const btn = e.target.closest('a.custom-quill-button');
    if (btn?.getAttribute('href')?.startsWith('cuestionario://')) {
      e.preventDefault();
      setCuestionario(btn.getAttribute('href').replace('cuestionario://', ''));
    }
  };

  // ── Combo selector renderer
  const renderComboSelector = (index, sub, position = 'all') => {
    if (!sub) return null;
    const sel = comboSels[index] || {};
    const cfg = product.comboItems?.[index] || {};
    const allowed = cfg.variantMapping?.allowedColors?.map(c => c.trim().toLowerCase()) || [];
    const allVars = Array.isArray(sub.variants) ? sub.variants : [];
    const vars = allowed.length ? allVars.filter(v => allowed.includes(v.name?.trim().toLowerCase())) : allVars;
    const hasColors = sub.hasVariants && vars.length > 0;
    const selVar = hasColors ? (vars.find(v => v.name === sel.color) || vars[0]) : null;
    const cSizes = hasColors ? (selVar?.sizes || []) : (sub.mainSizes || sub.sizes || []);

    const sizeUI = cSizes.length > 0 && (
      <div className={styles.selectorGroup}>
        <span className={styles.selectorLabel}>Talla</span>
        <DraggableContainer className={styles.pillRow}>
          {cSizes.map(s => (
            <button key={s} className={`${styles.sizePill} ${sel.size === s ? styles.sizePillActive : ''}`}
              onClick={() => setComboSels(p => ({ ...p, [index]: { ...p[index], size: s } }))}>
              {s}
            </button>
          ))}
        </DraggableContainer>
      </div>
    );

    const colorUI = hasColors && (
      <div className={styles.selectorGroup}>
        <span className={styles.selectorLabel}>Color: <em>{sel.color || vars[0]?.name}</em></span>
        <DraggableContainer className={styles.swatchRow}>
          {vars.map(v => {
            const hex = v.colorHex || getFallbackHex(v.name);
            return (
              <button key={v.id || v.name}
                className={`${styles.swatch} ${sel.color === v.name ? styles.swatchActive : ''}`}
                onClick={() => setComboSels(p => ({ ...p, [index]: { ...p[index], color: v.name } }))}
                title={v.name}>
                {v.imageUrl
                  ? <OptimizedImage src={toDirectImageUrl(v.imageUrl)} cropData={v.thumbnailCrop?.percentages} alt={v.name} className={styles.swatchImg} />
                  : <span className={styles.swatchColor} style={{ background: hex }} />}
              </button>
            );
          })}
        </DraggableContainer>
      </div>
    );

    if (position === 'top') return sizeUI;
    if (position === 'bottom') return colorUI;
    return <>{sizeUI}{colorUI}</>;
  };

  // ── Render
  if (loading) return <Skeleton />;
  if (!product) return <div className={styles.notFound}>Producto no encontrado.</div>;

  const activeImage = images[imgIdx] || images[0];
  const showCombo = isCombo && Boolean(activeImage?.isComboView);

  return (
    <>
      <div className={`${styles.pdp} ${isCombo ? styles.pdpCombo : ''}`}>

        {/* ── Gallery ── */}
        <div className={styles.galleryCol}>
          <Gallery
            images={images}
            activeIdx={imgIdx}
            setActiveIdx={setImgIdx}
            showCombo={showCombo}
            comboEl={
              isCombo ? (
                <ComboProductImage
                  comboProduct={product}
                  variantSelections={comboSels}
                  renderSelector={renderComboSelector}
                  onProductsFetched={setComboProd}
                />
              ) : null
            }
          />
        </div>

        {/* ── Info ── */}
        <div className={styles.infoCol}>

          {/* Breadcrumb */}
          <nav className={styles.breadcrumb}>
            <a href="/">Inicio</a>
            <span>/</span>
            {category && <><a href="/">{category}</a><span>/</span></>}
            <span>{product.name}</span>
          </nav>

          {/* Title + share */}
          <div className={styles.titleRow}>
            <h1 className={styles.pdpTitle}>{product.name}</h1>
            {user && (
              <button className={styles.shareIconBtn} onClick={handleShare} disabled={sharing} title="Compartir y ganar monedas">
                <Share2 size={16} strokeWidth={1.8} />
              </button>
            )}
          </div>

          {/* Brand */}
          {brand?.name && (
            <span className={styles.brandBadge} style={brand.bgColor ? { background: brand.bgColor } : {}}>
              {brand.name}
            </span>
          )}

          {/* Price */}
          <div className={styles.priceRow}>
            <span className={styles.price}>S/ {displayPrice.toFixed(2)}</span>
            {originalPrice && (
              <>
                <span className={styles.priceOriginal}>S/ {originalPrice.toFixed(2)}</span>
                <span className={styles.discountBadge}>−{discount}%</span>
              </>
            )}
          </div>

          <hr className={styles.divider} />

          {/* Color selector */}
          {hasVariants && variants.length > 0 && (
            <div className={styles.selectorGroup}>
              <span className={styles.selectorLabel}>Color: <em>{selectedVariant?.name}</em></span>
              <DraggableContainer className={styles.swatchRow}>
                {variants.map((v, i) => {
                  const hex = v.colorHex || getFallbackHex(v.name);
                  return (
                    <button key={v.id || i}
                      className={`${styles.swatch} ${variantIdx === i ? styles.swatchActive : ''}`}
                      onClick={() => setVariantIdx(i)} title={v.name}>
                      {v.imageUrl
                        ? <OptimizedImage src={toDirectImageUrl(v.imageUrl)} cropData={v.thumbnailCrop?.percentages} alt={v.name} className={styles.swatchImg} />
                        : <span className={styles.swatchColor} style={{ background: hex }} />}
                    </button>
                  );
                })}
              </DraggableContainer>
            </div>
          )}

          {/* Size selector */}
          {sizes.length > 0 && (
            <div className={styles.selectorGroup}>
              <span className={styles.selectorLabel}>Talla: <em>{selectedSize}</em></span>
              <DraggableContainer className={styles.pillRow}>
                {sizes.map(s => (
                  <button key={s}
                    className={`${styles.sizePill} ${selectedSize === s ? styles.sizePillActive : ''}`}
                    onClick={() => setSelectedSize(s)}>
                    {s}
                  </button>
                ))}
              </DraggableContainer>
            </div>
          )}

          {/* Quantity */}
          <div className={styles.qtyRow}>
            <span className={styles.selectorLabel}>Cantidad</span>
            <div className={styles.qtyControl}>
              <button className={styles.qtyBtn} onClick={() => setQty(q => Math.max(1, q - 1))}>−</button>
              <span className={styles.qtyValue}>{qty}</span>
              <button className={styles.qtyBtn} onClick={() => setQty(q => q + 1)}>+</button>
            </div>
          </div>

          {/* CTA Buttons */}
          <div className={styles.ctaStack}>
            {product.inStock ? (
              <button className={styles.btnPrimary} onClick={handleAddToCart}>
                Agregar al carrito
              </button>
            ) : (
              <button className={styles.btnPrimary} disabled>Agotado</button>
            )}
            {product.customizable && (
              <button className={styles.btnOutline} onClick={handlePersonalize}>
                Personalizar
              </button>
            )}
          </div>

          {/* Trust badges */}
          <div className={styles.trustRow}>
            <div className={styles.trustItem}><Truck size={14} /><span>Envío a todo el país</span></div>
            <div className={styles.trustItem}><RefreshCw size={14} /><span>Cambios y devoluciones</span></div>
            <div className={styles.trustItem}><ShieldCheck size={14} /><span>Pago seguro</span></div>
          </div>

          {/* Description */}
          {product.description && (
            <details className={styles.accordion} open>
              <summary className={styles.accordionSummary}>Descripción</summary>
              <div
                className={styles.richText}
                dangerouslySetInnerHTML={{ __html: product.description }}
                onClick={handleDescClick}
              />
            </details>
          )}

          {/* Reviews */}
          <ProductReviews productId={product.id} />

        </div>
      </div>

      <ProductCuestionarioModal
        isOpen={!!cuestionario}
        onClose={() => setCuestionario(null)}
        templateId={cuestionario}
        product={product}
        selectedVariant={selectedVariant}
        selectedSize={selectedSize}
        quantity={qty}
        comboVariantSelections={comboSels}
      />
    </>
  );
};

export default ProductDetail;

import React, { useEffect, useState, useRef, useMemo } from 'react';
import { Link } from 'react-router-dom';
import PremiumProductCard from '../PremiumProductCard/PremiumProductCard';
import { toDirectImageUrl } from '../../../../utils/imageUrl';
import styles from './ProductGrid.module.css';

const SKELETON_COUNT = 6;

const SkeletonCard = () => (
  <div className={styles.skeletonCard}>
    <div className={styles.skeletonImage} />
    <div className={styles.skeletonContent}>
      <div className={styles.skeletonLine} />
      <div className={styles.skeletonLineShort} />
      <div className={styles.skeletonPrice} />
    </div>
  </div>
);

const ProductGrid = React.memo(({ products, loading, error, emptyMessage, categories, layoutConfig }) => {

  const [visibleCount, setVisibleCount] = useState(12);
  const loadMoreRef = useRef(null);

  // Reiniciar la cuenta base cuando los productos o filtros cambian 
  useEffect(() => {
    setVisibleCount(12);
  }, [products]);

  // Observer para "infinite scroll" en RAM
  useEffect(() => {
    if (!products || visibleCount >= products.length) return;

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting) {
          setVisibleCount((prev) => Math.min(prev + 12, products.length));
        }
      },
      { rootMargin: '400px', threshold: 0.1 } // Anticipate scroll
    );

    if (loadMoreRef.current) observer.observe(loadMoreRef.current);
    return () => observer.disconnect();
  }, [visibleCount, products]);

  const visibleProducts = useMemo(() => {
    if (!products) return [];
    return products.slice(0, visibleCount);
  }, [products, visibleCount]);

  const gridStyle = useMemo(() => {
    // Si layoutConfig especifica 'auto', mapearlo a 'auto-fit'
    const desktopCols = layoutConfig?.productGridColumnsDesktop;
    const desktopVal = desktopCols === 'auto' || !desktopCols ? 'auto-fit' : desktopCols;
    
    return {
      '--grid-cols-desktop': desktopVal,
      '--grid-cols-mobile': layoutConfig?.productGridColumnsMobile || 2,
    };
  }, [layoutConfig]);

  if (loading) {
    return (
      <div className={styles.grid} style={gridStyle}>
        {Array.from({ length: SKELETON_COUNT }, (_, i) => (
          <SkeletonCard key={i} />
        ))}
      </div>
    );
  }

  if (error) {
    return (
      <div className={styles.errorContainer}>
        <p className={styles.errorTitle}>No pudimos cargar los productos</p>
        <p className={styles.errorText}>{error}</p>
      </div>
    );
  }

  if (!products || products.length === 0) {
    return (
      <div className={styles.emptyContainer}>
        <div className={styles.emptyIcon}>◇</div>
        <h3 className={styles.emptyTitle}>Próximamente más productos</h3>
        <p className={styles.emptyText}>
          {emptyMessage || 'Estamos preparando novedades. Revisa de nuevo en unos días.'}
        </p>
        <Link to="/" className={styles.emptyLink}>Volver al inicio</Link>
      </div>
    );
  }

  return (
    <>
      <div className={styles.grid} style={gridStyle}>
        {visibleProducts.map((product, index) => (
          <PremiumProductCard
            key={product.id}
            product={product}
            categories={categories}
            isAboveFold={index < 4}
            showHoverSecondaryMedia={layoutConfig?.showHoverSecondaryMedia ?? true}
          />
        ))}
      </div>
      {/* Elemento oculto para disparar la carga de la siguiente tanda iterativa en memoria */}
      {visibleCount < products.length && (
        <div ref={loadMoreRef} style={{ height: '20px', width: '100%', marginTop: '20px' }} />
      )}
    </>
  );
});

export default ProductGrid;

import React, { useState, useEffect } from 'react';
import { Filter, X } from 'lucide-react';
import ProductGrid from './ProductGrid';
import styles from './SidebarCatalogLayout.module.css';
import { toDirectImageUrl } from '../../../utils/imageUrl';
import { useQuery } from '@tanstack/react-query';
import { getCollections } from '../../../services/collections';
import { getBrands } from '../../../services/brands';
import { getTags } from '../../../services/tags';
import { getCharacters } from '../../../services/characters';
import { getProductTypes } from '../../../services/productTypes';

const SidebarCatalogLayout = ({ productsData, productsLoading, productsError, emptyMessage, categories, layoutConfig, title }) => {
  const [activeCategory, setActiveCategory] = useState(null);
  const [activeCollection, setActiveCollection] = useState(null);
  const [activeBrand, setActiveBrand] = useState(null);
  const [activeTag, setActiveTag] = useState(null);
  const [activeCharacter, setActiveCharacter] = useState(null);
  const [activeType, setActiveType] = useState(null);
  const [isMobileDrawerOpen, setIsMobileDrawerOpen] = useState(false);

  // Prevenir scroll en el body cuando el drawer esté abierto
  useEffect(() => {
    if (isMobileDrawerOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isMobileDrawerOpen]);

  const { data: collections } = useQuery({ queryKey: ['collections'], queryFn: async () => (await getCollections()).data });
  const { data: brands } = useQuery({ queryKey: ['brands'], queryFn: async () => (await getBrands()).data });
  const { data: tags } = useQuery({ queryKey: ['tags'], queryFn: async () => (await getTags()).data });
  const { data: characters } = useQuery({ queryKey: ['characters'], queryFn: async () => (await getCharacters()).data });
  const { data: productTypes } = useQuery({ queryKey: ['productTypes'], queryFn: async () => (await getProductTypes()).data });

  const handleCategoryClick = (catId) => {
    setActiveCategory(catId === activeCategory ? null : catId);
    setIsMobileDrawerOpen(false);
  };

  const handleFilterClick = (setter, id) => {
    setter(prev => prev === id ? null : id);
    setIsMobileDrawerOpen(false);
  };

  const filteredProducts = (productsData || []).filter(p => {
    if (activeCategory && p.categoryId !== activeCategory && p.category !== activeCategory && !(p.categories || []).includes(activeCategory)) return false;
    if (activeCollection && !(p.collections || []).includes(activeCollection)) return false;
    if (activeBrand && p.brandId !== activeBrand) return false;
    if (activeTag && !(p.tags || []).includes(activeTag)) return false;
    if (activeCharacter && !(p.characters || []).includes(activeCharacter)) return false;
    if (activeType && p.productType !== activeType) return false;
    return true;
  });

  return (
    <div className={styles.catalogWrapper}>
      {title && <h2 className={styles.catalogTitle}>{title}</h2>}
      
      <div className={styles.catalogLayout}>
        {/* BOTÓN MÓVIL (Visible solo en CSS) */}
        <div className={styles.mobileFilterControls}>
          <button 
            className={styles.mobileFilterBtn} 
            onClick={() => setIsMobileDrawerOpen(true)}
          >
            <Filter size={18} /> Filtrar y Categorías
          </button>
        </div>

        {/* OVERLAY FONDO OSCURO (Móvil) */}
        <div 
          className={`${styles.drawerOverlay} ${isMobileDrawerOpen ? styles.overlayVisible : ''}`} 
          onClick={() => setIsMobileDrawerOpen(false)}
        />

        {/* SIDEBAR Izquierdo / Drawer Móvil */}
        <aside className={`${styles.sidebar} ${isMobileDrawerOpen ? styles.sidebarOpen : ''}`}>
          
          <div className={styles.drawerHeader}>
            <h3 style={{ margin: 0 }}>Filtros</h3>
            <button className={styles.closeDrawerBtn} onClick={() => setIsMobileDrawerOpen(false)}>
              <X size={24} color="#666" />
            </button>
          </div>

          <div className={styles.sidebarSection}>
            <h3>Categorías</h3>
            <ul className={styles.categoryList}>
              <li 
                className={activeCategory === null ? styles.activeItem : ''}
                onClick={() => handleCategoryClick(null)}
              >
                Todas las categorías
              </li>
              {(categories || []).map(cat => (
                <li 
                  key={cat.id} 
                  className={activeCategory === cat.id ? styles.activeItem : ''}
                  onClick={() => handleCategoryClick(cat.id)}
                >
                  {cat.name}
                </li>
              ))}
            </ul>
          </div>

          {(collections || []).length > 0 && (
            <div className={styles.sidebarSection}>
              <h3>Colecciones</h3>
              <ul className={styles.categoryList}>
