import Button from '../../components/common/Button';
import styles from './AdminCliparts.module.css';

const AdminCliparts = () => {
  const queryClient = useQueryClient();
  const [editingId, setEditingId] = useState(null);
  const [form, setForm] = useState({ name: '', url: '', category: '' });
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef(null);

  const { data: clipartsData, isLoading, error } = useQuery({
    queryKey: ['admin-cliparts'],
    queryFn: async () => {
      const { data, error: err } = await getCliparts();
      if (err) throw new Error(err);
      return data;
    }
  });

  const createMutation = useMutation({
    mutationFn: (data) => createClipart(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-cliparts'] });
      queryClient.invalidateQueries({ queryKey: ['cliparts'] });
      setForm({ name: '', url: '', category: '' });
    }
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }) => updateClipart(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-cliparts'] });
      queryClient.invalidateQueries({ queryKey: ['cliparts'] });
      setEditingId(null);
      setForm({ name: '', url: '', category: '' });
    }
  });

  const deleteMutation = useMutation({
    mutationFn: (id) => deleteClipart(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-cliparts'] });
      queryClient.invalidateQueries({ queryKey: ['cliparts'] });
      setDeleteConfirm(null);
    }
  });

  const cliparts = clipartsData ?? [];

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.name.trim()) return;
    const url = form.url?.trim() ? toDirectImageUrl(form.url.trim()) : '';
    if (editingId) {
      updateMutation.mutate({
        id: editingId,
        data: { name: form.name.trim(), url, category: form.category.trim() }
      });
    } else {
      if (!form.url?.trim()) return;
      createMutation.mutate({
        name: form.name.trim(),
        url,
        category: form.category.trim()
      });
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleFileSelect = async (e) => {
    const file = e?.target?.files?.[0];
    if (!file || !file.type.startsWith('image/')) return;
    setUploading(true);
    try {
      const path = `cliparts/${Date.now()}_${file.name}`;
      const { url, error: err } = await uploadFile(file, path);
      if (url && !err) setForm((f) => ({ ...f, url }));
    } finally {
      setUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleEdit = (item) => {
    setEditingId(item.id);
    setForm({ name: item.name ?? '', url: item.url ?? '', category: item.category ?? '' });
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setForm({ name: '', url: '', category: '' });
  };

  return (
    <div className={styles.wrapper}>
      <div className={styles.header}>
        <div>
          <h1 className={styles.title}>Galería de Cliparts</h1>
          <p className={styles.subtitle}>Recursos gráficos que los clientes pueden usar al personalizar sus productos</p>
        </div>
      </div>

      <div className={styles.contentGrid}>
        {/* FORMULARIO */}
        <div className={styles.formSection}>
          <div className={styles.card}>
            <h2 className={styles.cardTitle}>
              {editingId ? 'Editar Clipart' : 'Nuevo Clipart'}
            </h2>
            <form className={styles.form} onSubmit={handleSubmit}>
              
              <div className={styles.fieldRow}>
                <div className={styles.field} style={{ flex: 2 }}>
                  <label className={styles.label}>Nombre del Clipart</label>
                  <input
                    type="text"
                    placeholder="Ej. Corazón Neon"
                    value={form.name}
                    onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))}
                    className={styles.input}
                    required
                  />
                </div>
                <div className={styles.field} style={{ flex: 1 }}>
                  <label className={styles.label}>Categoría</label>
                  <input
                    type="text"
                    placeholder="Ej. Amor, Deportes"
                    value={form.category}
                    onChange={(e) => setForm((f) => ({ ...f, category: e.target.value }))}
                    className={styles.input}
                  />
                </div>
              </div>

              <div className={styles.field}>
                <label className={styles.label}>Archivo del Clipart (PNG Transparente o SVG)</label>
                <div className={styles.imageUploadWrapper}>
                  {form.url ? (
                    <div className={styles.imagePreviewContainer}>
                      <img src={toDirectImageUrl(form.url)} alt="Clipart" className={styles.imagePreview} />
                      <button type="button" onClick={() => setForm(f => ({...f, url: ''}))} className={styles.removeBtn}><X size={16} /></button>
                    </div>
                  ) : (
                    <label className={styles.uploadImageLabel}>
                      <ImagePlus size={24} />
                      <span>Subir Imagen</span>
                      <input 
                        type="file" 
                        accept="image/png, image/svg+xml" 
                        onChange={handleFileSelect} 
                        disabled={uploading} 
                        hidden 
                      />
                    </label>
                  )}
                  {uploading && <div className={styles.uploadOverlay}><Loader2 className="animate-spin" /> Subiendo...</div>}
                </div>
              </div>

              <div className={styles.field}>
                <label className={styles.label}>O usa una URL Externa</label>
                <input
                  type="text"
                  placeholder="https://..."
                  value={form.url}
                  onChange={(e) => setForm((f) => ({ ...f, url: e.target.value }))}
                  className={styles.input}
                />
              </div>

              <div className={styles.formActions}>
                <Button type="submit" disabled={createMutation.isPending || updateMutation.isPending || uploading || (!form.url && !editingId)}>
                  {editingId ? 'Guardar Cambios' : 'Añadir Clipart'}
                </Button>
                {editingId && (
                  <Button type="button" variant="outline" onClick={handleCancelEdit}>
                    Cancelar
                  </Button>
                )}
              </div>
            </form>
          </div>
        </div>

        {/* LISTA DE CLIPARTS */}
        <div className={styles.listSection}>
          <div className={styles.card}>
            <h2 className={styles.cardTitle}>Biblioteca</h2>
            
            {isLoading && <p className={styles.loading}>Cargando cliparts...</p>}
            {error && <p className={styles.error}>{error.message}</p>}

            <div className={styles.clipartsGrid}>
              {cliparts.map((item) => (
                <div key={item.id} className={styles.clipartCard}>
                  <div className={styles.clipartVisual}>
                    <img 
                      src={toDirectImageUrl(item.url)} 
                      alt={item.name} 
                      className={styles.clipartImage} 
                      loading="lazy" 
                      onError={(e) => { e.target.style.display = 'none'; }} 
                    />
                  </div>
                  <div className={styles.clipartContent}>
                    <div className={styles.clipartInfo}>
                      <h3 className={styles.clipartName} title={item.name}>{item.name}</h3>
                      {item.category && <span className={styles.clipartBadge}>{item.category}</span>}
                    </div>
                    <div className={styles.clipartActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => handleEdit(item)} title="Editar">
                        <Edit2 size={16} />
                      </button>
                      <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDelete}`} onClick={() => setDeleteConfirm(item)} title="Eliminar">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {cliparts.length === 0 && !isLoading && (
              <div className={styles.emptyState}>
                <p>No hay cliparts en la biblioteca.</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {deleteConfirm && (
        <div className={styles.modalBackdrop} onClick={() => setDeleteConfirm(null)}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <h3 className={styles.modalTitle}>¿Eliminar clipart?</h3>
            <p className={styles.modalText}>Estás a punto de eliminar <strong>{deleteConfirm.name}</strong>. Esta acción no se puede deshacer.</p>
            <div className={styles.modalActions}>
              <Button variant="outline" onClick={() => setDeleteConfirm(null)}>
                Cancelar
              </Button>
              <Button
                variant="primary"
                onClick={() => deleteMutation.mutate(deleteConfirm.id)}
                disabled={deleteMutation.isPending}
                style={{ backgroundColor: '#ff4757', borderColor: '#ff4757' }}
              >
                Sí, eliminar
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminCliparts;

import React, { useState, useEffect } from 'react';
import { Save, Plus, Trash2, Edit2 } from 'lucide-react';
import { getSurveyConfig, saveSurveyConfig, DEFAULT_SURVEY_CONFIG } from '../../services/encuestaConfig';
import styles from './AdminEncuestas.module.css';

const AdminEncuestas = () => {
  const [config, setConfig] = useState(DEFAULT_SURVEY_CONFIG);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [activeTab, setActiveTab] = useState('intro'); // intro, basic, brands, completion, design

  useEffect(() => {
    const fetchConfig = async () => {
      const { data, error } = await getSurveyConfig();
      if (data) {
        // Hacemos un merge con default por si hay campos nuevos
        setConfig({
          ...DEFAULT_SURVEY_CONFIG,
          ...data
        });
      }
      setLoading(false);
    };
    fetchConfig();
  }, []);

  const handleSave = async () => {
    setSaving(true);
    const { error } = await saveSurveyConfig(config);
    if (!error) {
      alert('Configuración guardada correctamente.');
    } else {
      alert('Error al guardar: ' + error);
    }
    setSaving(false);
  };

  const handleIntroChange = (field, value) => {
    setConfig({ ...config, introPanel: { ...config.introPanel, [field]: value } });
  };

  const handleCompletionChange = (field, value) => {
    setConfig({ ...config, completionPanel: { ...config.completionPanel, [field]: value } });
  };

  const handleDesignChange = (field, value) => {
    setConfig({ ...config, design: { ...config.design, [field]: value } });
  };

  const handleBasicDataChange = (field, value) => {
    setConfig({ ...config, basicDataPanel: { ...config.basicDataPanel, [field]: value } });
  };

  const handleBrandsPanelChange = (field, value) => {
    setConfig({ ...config, brandsPanel: { ...config.brandsPanel, [field]: value } });
  };

  // --- Operaciones de Campos Básicos ---
  const addBasicField = () => {
    const newField = { id: `field_${Date.now()}`, label: 'Nueva Pregunta', type: 'text', required: false, options: [] };
    setConfig({
      ...config,
      basicDataPanel: { ...config.basicDataPanel, fields: [...config.basicDataPanel.fields, newField] }
    });
  };
  const removeBasicField = (index) => {
    const newFields = [...config.basicDataPanel.fields];
    newFields.splice(index, 1);
    setConfig({
      ...config,
      basicDataPanel: { ...config.basicDataPanel, fields: newFields }
    });
  };
  const updateBasicField = (index, key, value) => {
    const newFields = [...config.basicDataPanel.fields];
    newFields[index] = { ...newFields[index], [key]: value };
    setConfig({
      ...config,
      basicDataPanel: { ...config.basicDataPanel, fields: newFields }
    });
  };

  // --- Operaciones de Categorías (Brands) ---
  const addBrandCategory = () => {
    const newCategory = { id: `cat_${Date.now()}`, name: 'Nueva Categoría', fields: [] };
    setConfig({
      ...config,
      brandsPanel: { ...config.brandsPanel, categories: [...config.brandsPanel.categories, newCategory] }
    });
  };
  const updateBrandCategoryName = (catIndex, name) => {
    const newCats = [...config.brandsPanel.categories];
    newCats[catIndex].name = name;
    setConfig({
      ...config,
      brandsPanel: { ...config.brandsPanel, categories: newCats }
    });
  };
  const removeBrandCategory = (catIndex) => {
    const newCats = [...config.brandsPanel.categories];
    newCats.splice(catIndex, 1);
    setConfig({
      ...config,
      brandsPanel: { ...config.brandsPanel, categories: newCats }
    });
  };

  // --- Operaciones de Campos dentro de Categorías ---
  const addBrandField = (catIndex) => {
    const newField = { id: `brandField_${Date.now()}`, label: 'Nueva Pregunta de Categoría', type: 'text', required: false, options: [] };
    const newCats = [...config.brandsPanel.categories];
    newCats[catIndex].fields.push(newField);
    setConfig({
      ...config,
      brandsPanel: { ...config.brandsPanel, categories: newCats }
    });
  };
  const removeBrandField = (catIndex, fieldIndex) => {
    const newCats = [...config.brandsPanel.categories];
    newCats[catIndex].fields.splice(fieldIndex, 1);
    setConfig({
      ...config,
      brandsPanel: { ...config.brandsPanel, categories: newCats }
    });
  };
  const updateBrandField = (catIndex, fieldIndex, key, value) => {
    const newCats = [...config.brandsPanel.categories];
    newCats[catIndex].fields[fieldIndex] = { ...newCats[catIndex].fields[fieldIndex], [key]: value };
    setConfig({
      ...config,
      brandsPanel: { ...config.brandsPanel, categories: newCats }
    });
  };

  // --- Renderizador de Preguntas Genérico ---
  const renderFieldEditor = (field, index, onUpdate, onRemove) => (
    <div key={index} className={styles.fieldItem}>
      <div className={styles.fieldHeader}>
        <h3>Pregunta {index + 1}</h3>
        <button className={styles.removeBtn} onClick={() => onRemove(index)}>
          <Trash2 size={16} /> Eliminar
        </button>
      </div>
      <div className={styles.row}>
        <div className={styles.fieldGroup}>
          <label>Etiqueta de la pregunta</label>
          <input 
            type="text" 
            className={styles.input} 
            value={field.label} 
            onChange={e => onUpdate(index, 'label', e.target.value)}
          />
        </div>
        <div className={styles.fieldGroup}>
          <label>Tipo de respuesta</label>
          <select 
            className={styles.input} 
            value={field.type}
            onChange={e => onUpdate(index, 'type', e.target.value)}
          >
            <option value="text">Texto corto</option>
            <option value="textarea">Texto largo</option>
            <option value="select">Selección múltiple (Dropdown)</option>
          </select>
        </div>
        <div className={styles.fieldGroup}>
          <label>¿Es obligatorio?</label>
          <select 
            className={styles.input} 
            value={field.required ? 'yes' : 'no'}
            onChange={e => onUpdate(index, 'required', e.target.value === 'yes')}
          >
            <option value="yes">Sí</option>
            <option value="no">No</option>
          </select>
        </div>
      </div>
      {field.type === 'select' && (
        <div className={styles.fieldGroup}>
          <label>Opciones (separadas por comas)</label>
          <input 
            type="text" 
            className={styles.input} 
            value={field.options?.join(', ') || ''} 
            onChange={e => onUpdate(index, 'options', e.target.value.split(',').map(s => s.trim()).filter(s => s))}
            placeholder="Ej: Opción 1, Opción 2, Opción 3"
          />
        </div>
      )}
    </div>
  );

  if (loading) return <div>Cargando configuración...</div>;

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <h1>Configuración de Encuesta</h1>
        <button className={styles.saveBtn} onClick={handleSave} disabled={saving}>
          <Save size={18} /> {saving ? 'Guardando...' : 'Guardar Cambios'}
        </button>
      </div>

      <div className={styles.tabs}>
        <button className={`${styles.tabBtn} ${activeTab === 'intro' ? styles.active : ''}`} onClick={() => setActiveTab('intro')}>
          Hook Inicial
        </button>
        <button className={`${styles.tabBtn} ${activeTab === 'basic' ? styles.active : ''}`} onClick={() => setActiveTab('basic')}>
          Datos Básicos
        </button>
        <button className={`${styles.tabBtn} ${activeTab === 'brands' ? styles.active : ''}`} onClick={() => setActiveTab('brands')}>
          Intereses (Marcas)
        </button>
        <button className={`${styles.tabBtn} ${activeTab === 'completion' ? styles.active : ''}`} onClick={() => setActiveTab('completion')}>
          Finalización
        </button>
        <button className={`${styles.tabBtn} ${activeTab === 'design' ? styles.active : ''}`} onClick={() => setActiveTab('design')}>
          Diseño
        </button>
      </div>

      {activeTab === 'intro' && (
        <div className={styles.panel}>
          <h2>Configurar el "Hook" Inicial</h2>
          <div className={styles.fieldGroup}>
            <label>Título</label>
            <input type="text" className={styles.input} value={config.introPanel.title} onChange={e => handleIntroChange('title', e.target.value)} />
          </div>
          <div className={styles.fieldGroup}>
            <label>Subtítulo</label>
            <input type="text" className={styles.input} value={config.introPanel.subtitle} onChange={e => handleIntroChange('subtitle', e.target.value)} />
          </div>
          <div className={styles.fieldGroup}>
            <label>Descripción / Mensaje de enganche</label>
            <textarea className={styles.textarea} value={config.introPanel.description} onChange={e => handleIntroChange('description', e.target.value)} />
          </div>
          <div className={styles.row}>
            <div className={styles.fieldGroup}>
              <label>Texto Botón Continuar</label>
              <input type="text" className={styles.input} value={config.introPanel.continueButtonText} onChange={e => handleIntroChange('continueButtonText', e.target.value)} />
            </div>
            <div className={styles.fieldGroup}>
              <label>Texto Botón Descartar</label>
              <input type="text" className={styles.input} value={config.introPanel.skipButtonText} onChange={e => handleIntroChange('skipButtonText', e.target.value)} />
            </div>
          </div>
        </div>
      )}

      {activeTab === 'basic' && (
        <div className={styles.panel}>
          <h2>Campos de Datos Básicos</h2>
          <div className={styles.row}>
            <div className={styles.fieldGroup}>
              <label>Título del Panel</label>
              <input type="text" className={styles.input} value={config.basicDataPanel.title} onChange={e => handleBasicDataChange('title', e.target.value)} />
            </div>
            <div className={styles.fieldGroup}>
              <label>Subtítulo</label>
              <input type="text" className={styles.input} value={config.basicDataPanel.subtitle} onChange={e => handleBasicDataChange('subtitle', e.target.value)} />
            </div>
          </div>

          <h3>Preguntas Configurables</h3>
          <div className={styles.fieldsList}>
            {config.basicDataPanel.fields.map((field, index) => renderFieldEditor(field, index, updateBasicField, removeBasicField))}
          </div>
          <button className={styles.addBtn} onClick={addBasicField}>
            <Plus size={18} /> Añadir nueva pregunta general
          </button>
        </div>
      )}

      {activeTab === 'brands' && (
        <div className={styles.panel}>
          <h2>Configuración de Intereses (Marcas)</h2>
          <p style={{ color: '#64748b', marginBottom: '1.5rem', fontSize: '0.9rem' }}>
            Aquí puedes crear categorías independientes (ej. Deportes, Geek, Familia). El usuario podrá seleccionarlas como "Pills" y por cada una que seleccione, se le harán las preguntas que configures debajo.
          </p>

          <div className={styles.row}>
            <div className={styles.fieldGroup}>
              <label>Título del Panel Selector</label>
              <input type="text" className={styles.input} value={config.brandsPanel.title || ''} onChange={e => handleBrandsPanelChange('title', e.target.value)} />
            </div>
            <div className={styles.fieldGroup}>
              <label>Subtítulo</label>
              <input type="text" className={styles.input} value={config.brandsPanel.subtitle || ''} onChange={e => handleBrandsPanelChange('subtitle', e.target.value)} />
            </div>
          </div>

          <h3>Tus Categorías Creadas</h3>
          <div className={styles.fieldsList}>
            {config.brandsPanel.categories?.map((cat, catIndex) => (
              <div key={cat.id} className={styles.fieldItem} style={{ borderColor: config.design.primaryColor, borderLeftWidth: '4px' }}>
                <div className={styles.fieldHeader}>
                  <div style={{ display: 'flex', gap: '1rem', alignItems: 'center', width: '100%' }}>
                    <h3 style={{ margin: 0, minWidth: '120px' }}>Categoría:</h3>
                    <input 
                      type="text" 
                      className={styles.input} 
                      value={cat.name} 
                      onChange={e => updateBrandCategoryName(catIndex, e.target.value)}
                      style={{ padding: '0.5rem', fontWeight: 'bold' }}
                    />
                  </div>
                  <button className={styles.removeBtn} onClick={() => removeBrandCategory(catIndex)}>
                    <Trash2 size={16} /> Eliminar Categoría
                  </button>
                </div>

                <div style={{ padding: '1rem', background: 'white', borderRadius: '8px', border: '1px solid #e2e8f0', marginTop: '1rem' }}>
                  <h4 style={{ margin: '0 0 1rem 0', fontSize: '0.9rem', color: '#475569' }}>Preguntas para quien seleccione "{cat.name}"</h4>
                  <div className={styles.fieldsList}>
                    {cat.fields.map((field, fieldIndex) => 
                      renderFieldEditor(
                        field, 
                        fieldIndex, 
                        (i, k, v) => updateBrandField(catIndex, i, k, v), 
                        (i) => removeBrandField(catIndex, i)
                      )
                    )}
                  </div>
                  <button className={styles.addBtn} onClick={() => addBrandField(catIndex)} style={{ padding: '0.5rem', fontSize: '0.9rem', marginBottom: 0 }}>
                    <Plus size={16} /> Añadir pregunta para {cat.name}
                  </button>
                </div>
              </div>
            ))}
          </div>
          
          <button className={styles.addBtn} onClick={addBrandCategory}>
            <Plus size={18} /> Crear nueva categoría de interés
          </button>
        </div>
      )}

      {activeTab === 'completion' && (
        <div className={styles.panel}>
          <h2>Panel de Finalización</h2>
          <div className={styles.fieldGroup}>
            <label>Título</label>
            <input type="text" className={styles.input} value={config.completionPanel.title} onChange={e => handleCompletionChange('title', e.target.value)} />
          </div>
          <div className={styles.fieldGroup}>
            <label>Mensaje de agradecimiento</label>
            <textarea className={styles.textarea} value={config.completionPanel.message} onChange={e => handleCompletionChange('message', e.target.value)} />
          </div>
          <div className={styles.fieldGroup}>
            <label>Texto del Botón Final</label>
            <input type="text" className={styles.input} value={config.completionPanel.buttonText} onChange={e => handleCompletionChange('buttonText', e.target.value)} />
          </div>
        </div>
      )}

      {activeTab === 'design' && (
        <div className={styles.panel}>
          <h2>Diseño Visual</h2>
          <div className={styles.row}>
            <div className={styles.fieldGroup}>
              <label>Color Principal</label>
              <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                <input type="color" className={styles.colorPicker} value={config.design.primaryColor} onChange={e => handleDesignChange('primaryColor', e.target.value)} />
                <code>{config.design.primaryColor}</code>
              </div>
            </div>
            <div className={styles.fieldGroup}>
              <label>Color de Fondo</label>
              <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                <input type="color" className={styles.colorPicker} value={config.design.backgroundColor} onChange={e => handleDesignChange('backgroundColor', e.target.value)} />
                <code>{config.design.backgroundColor}</code>
              </div>
            </div>
            <div className={styles.fieldGroup}>
              <label>Color de Texto Principal</label>
              <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                <input type="color" className={styles.colorPicker} value={config.design.textColor} onChange={e => handleDesignChange('textColor', e.target.value)} />
                <code>{config.design.textColor}</code>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminEncuestas;

import React, { useState, useEffect } from 'react';
import { db } from '../../../services/firebase/config';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { getFunctions, httpsCallable } from 'firebase/functions';
import { useGlobalToast } from '../../../contexts/ToastContext';
import styles from './AdminNotifications.module.css';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer
} from 'recharts';

const defaultSettings = {
  categories: {
    cart_abandoned: true,
    retention: true,
    orders: true,
    promos: true
  },
  schedules: {
    cart_abandoned: { start: '09:00', end: '21:00' },
    retention: { start: '09:00', end: '21:00' },
    promos: { start: '10:00', end: '20:00' }
  },
  copys: {
    cart_1h: { a: { text: "Tu regalo te está esperando.", emoji: "📦", cta: "¿Terminamos?" }, b: null },
    cart_24h: { a: { text: "El box que elegiste sigue en tu carrito.", emoji: "🎁", cta: "¿Terminamos de armarlo?" }, b: null },
    cart_48h: { a: { text: "Última oportunidad. Tu carrito se vacía mañana.", emoji: "⏳", cta: "¿Lo completamos?" }, b: null },
    retention_7d: { a: { text: "Kapi te extraña mucho. Lleva varios días sin verte", emoji: "😢", cta: "Abre la app" }, b: null },
    retention_14d: { a: { text: "Tienes monedas que se van a perder. Y Kapi está triste...", emoji: "💔", cta: "Sálvalas" }, b: null }
  }
};

const AdminNotifications = () => {
  const [activeTab, setActiveTab] = useState('settings');
  const [settings, setSettings] = useState(defaultSettings);
  const [loading, setLoading] = useState(true);
  const [manualPromo, setManualPromo] = useState({ title: '', body: '', segment: 'all' });
  const [isSending, setIsSending] = useState(false);
  const toast = useGlobalToast();
  
  // Fake metrics for now, since we haven't tracked enough real data yet
  const [metricsData, setMetricsData] = useState([
    { name: 'Carrito 1h', openRate: 45, conversion: 15, optOut: 1 },
    { name: 'Carrito 24h', openRate: 35, conversion: 10, optOut: 2 },
    { name: 'Retención 7d', openRate: 60, conversion: 5, optOut: 0.5 },
  ]);

  useEffect(() => {
    const fetchSettings = async () => {
      try {
        const docRef = doc(db, 'notification_settings', 'global');
        const snap = await getDoc(docRef);
        if (snap.exists()) {
          setSettings({ ...defaultSettings, ...snap.data() });
        }
      } catch (err) {
        console.warn("Error cargando configuración:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchSettings();
  }, []);

  const handleSave = async () => {
    try {
      await setDoc(doc(db, 'notification_settings', 'global'), settings);
      toast.success('Configuración guardada exitosamente');
    } catch (err) {
      toast.error('Error al guardar configuración');
    }
  };

  const handleCategoryToggle = (cat) => {
    setSettings(prev => ({
      ...prev,
      categories: { ...prev.categories, [cat]: !prev.categories[cat] }
    }));
  };

  const handleScheduleChange = (cat, field, value) => {
    setSettings(prev => ({
      ...prev,
      schedules: {
        ...prev.schedules,
        [cat]: { ...(prev.schedules[cat] || { start: '09:00', end: '21:00' }), [field]: value }
      }
    }));
  };

  const handleCopyChange = (key, variant, field, value) => {
    setSettings(prev => {
      const newCopys = { ...prev.copys };
      if (!newCopys[key][variant]) {
        newCopys[key][variant] = { text: '', emoji: '', cta: '' };
      }
      newCopys[key][variant][field] = value;
      return { ...prev, copys: newCopys };
    });
  };

  const enableVariantB = (key) => {
    setSettings(prev => {
      const newCopys = { ...prev.copys };
      newCopys[key].b = { text: newCopys[key].a.text, emoji: newCopys[key].a.emoji, cta: newCopys[key].a.cta };
      return { ...prev, copys: newCopys };
    });
  };

  const disableVariantB = (key) => {
    setSettings(prev => {
      const newCopys = { ...prev.copys };
      newCopys[key].b = null;
      return { ...prev, copys: newCopys };
    });
  };

  const handleSendManualPromo = async () => {
    if (!manualPromo.title || !manualPromo.body) {
      return toast.error("El título y el mensaje son requeridos.");
    }
    setIsSending(true);
    try {
      const functions = getFunctions();
      const sendPromo = httpsCallable(functions, 'sendManualPromoNotification');
      const response = await sendPromo(manualPromo);
      if (response.data.success) {
        toast.success(`Campaña enviada a ${response.data.count} usuarios.`);
        setManualPromo({ title: '', body: '', segment: 'all' });
      } else {
        throw new Error(response.data.error || 'Error desconocido');
      }
    } catch (err) {
      console.error(err);
      toast.error('Ocurrió un error al enviar la campaña promocional.');
    } finally {
      setIsSending(false);
    }
  };

  if (loading) return <div>Cargando panel...</div>;

  return (
    <div className={styles.container}>
      <h2>Panel de Notificaciones</h2>
      
      <div className={styles.tabs}>
        <button className={activeTab === 'settings' ? styles.active : ''} onClick={() => setActiveTab('settings')}>Configuración & Copys</button>
        <button className={activeTab === 'manual' ? styles.active : ''} onClick={() => setActiveTab('manual')}>Envío Manual</button>
        <button className={activeTab === 'metrics' ? styles.active : ''} onClick={() => setActiveTab('metrics')}>Métricas</button>
      </div>

      {activeTab === 'settings' && (
        <div className={styles.tabContent}>
          <h3>Categorías y Horarios</h3>
          <div className={styles.switches}>
            {Object.keys(settings.categories).map(cat => (
              <div key={cat} className={styles.categoryRow}>
                <label className={styles.switchLabel}>
                  <input type="checkbox" checked={settings.categories[cat]} onChange={() => handleCategoryToggle(cat)} />
                  {cat.replace('_', ' ').toUpperCase()}
                </label>
                {settings.schedules[cat] && (
                  <div className={styles.scheduleInputs}>
                    <span>Desde: </span>
                    <input type="time" value={settings.schedules[cat].start} onChange={(e) => handleScheduleChange(cat, 'start', e.target.value)} />
                    <span> Hasta: </span>
                    <input type="time" value={settings.schedules[cat].end} onChange={(e) => handleScheduleChange(cat, 'end', e.target.value)} />
                  </div>
                )}
              </div>
            ))}
          </div>

          <h3>Copys y A/B Testing</h3>
          <p className={styles.helpText}>Edita el texto, emoji y call to action de cada notificación. Agrega una Variante B para medir cuál convierte más.</p>
          <div className={styles.copysList}>
            {Object.keys(settings.copys).map(key => (
              <div key={key} className={styles.copyBlock}>
                <div className={styles.copyHeader}>
                  <h4>{key.toUpperCase()}</h4>
                  {!settings.copys[key].b ? (
                    <button className={styles.textBtn} onClick={() => enableVariantB(key)}>+ Añadir Variante B (Test A/B)</button>
                  ) : (
                    <button className={styles.textBtnDanger} onClick={() => disableVariantB(key)}>- Quitar Variante B</button>
                  )}
                </div>
                
                {['a', 'b'].map(variant => {
                  if (variant === 'b' && !settings.copys[key].b) return null;
                  return (
                    <div key={variant} className={styles.variantContainer}>
                      <span className={styles.variantLabel}>Variante {variant.toUpperCase()}</span>
                      <div className={styles.copyFields}>
                        <div className={styles.fieldGroup}>
                          <label>Texto Principal</label>
                          <input type="text" value={settings.copys[key][variant].text} onChange={(e) => handleCopyChange(key, variant, 'text', e.target.value)} className={styles.copyInput} />
                        </div>
                        <div className={styles.fieldGroupSmall}>
                          <label>Emoji</label>
                          <input type="text" value={settings.copys[key][variant].emoji} onChange={(e) => handleCopyChange(key, variant, 'emoji', e.target.value)} className={styles.copyInput} />
                        </div>
                        <div className={styles.fieldGroup}>
                          <label>Call to Action (Botón)</label>
                          <input type="text" value={settings.copys[key][variant].cta} onChange={(e) => handleCopyChange(key, variant, 'cta', e.target.value)} className={styles.copyInput} />
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            ))}
          </div>

          <button className={styles.saveBtn} onClick={handleSave}>Guardar Cambios</button>
        </div>
      )}

      {activeTab === 'manual' && (
        <div className={styles.tabContent}>
          <h3>Envío Promocional Manual</h3>
          <p className={styles.helpText}>Esta herramienta enviará una notificación Push Inmediata a la audiencia segmentada.</p>
          <div className={styles.manualForm}>
            <label>Título:</label>
            <input type="text" value={manualPromo.title} onChange={e => setManualPromo({...manualPromo, title: e.target.value})} placeholder="Ej. ¡Nueva Colección de Cajas de Regalo!" />
            
            <label>Mensaje:</label>
            <textarea value={manualPromo.body} onChange={e => setManualPromo({...manualPromo, body: e.target.value})} placeholder="Ingresa el cuerpo de la notificación..."></textarea>
            
            <label>Segmentación:</label>
            <select value={manualPromo.segment} onChange={e => setManualPromo({...manualPromo, segment: e.target.value})}>
              <option value="all">Todos los usuarios con app instalada</option>
              <option value="vip">Usuarios VIP (con más de 50 monedas)</option>
              <option value="inactive">Inactivos (sin abrir en 30+ días)</option>
            </select>
            
            <button className={styles.saveBtn} onClick={handleSendManualPromo} disabled={isSending}>
              {isSending ? 'Enviando...' : 'Enviar Ahora'}
            </button>
          </div>
        </div>
      )}

      {activeTab === 'metrics' && (
        <div className={styles.tabContent}>
          <h3>Rendimiento por Categoría (Últimos 30 días)</h3>
          <p className={styles.helpText}>Mide la efectividad de los copys y determina a los ganadores del Test A/B.</p>
          <div className={styles.chartContainer}>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={metricsData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="openRate" name="Tasa de Apertura (%)" fill="#4f46e5" />
                <Bar dataKey="conversion" name="Tasa de Conversión (%)" fill="#10b981" />
                <Bar dataKey="optOut" name="Tasa de Desactivación (%)" fill="#ef4444" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}

    </div>
  );
};

export default AdminNotifications;

import React, { useState, useMemo, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getProducts, getCategories, deleteProduct, updateProduct, createProduct } from '../../services/products';
import { createReferenceProducts } from '../../scripts/createReferenceProducts';
import { exportProducts } from '../../utils/exportProducts';
import { useToast } from '../../hooks/useToast';
import Button from '../../components/common/Button';
import Toggle from '../../components/common/Toggle/Toggle';
import ProductTable from '../../components/admin/ProductTable/ProductTable';
import BulkActions from '../../components/admin/BulkActions/BulkActions';
import ToastContainer from '../../components/common/Toast/ToastContainer';
import { EyeIcon, EyeOffIcon, EditIcon, TrashIcon, GridIcon, TableIcon, CopyIcon } from '../../components/common/Icons/Icons';
import { toDirectImageUrl, toThumbnailImageUrl } from '../../utils/imageUrl';
import ComboProductImage from '../Tienda/components/ComboProductImage/ComboProductImage';
import OptimizedImage from '../../components/common/OptimizedImage/OptimizedImage';
import styles from './AdminProductos.module.css';

const AdminProductos = () => {
  const queryClient = useQueryClient();
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [creatingReference, setCreatingReference] = useState(false);
  const [createResult, setCreateResult] = useState(null);
  const [optimisticVisibility, setOptimisticVisibility] = useState({});
  const [viewMode, setViewMode] = useState(() => {
    const saved = localStorage.getItem('admin-products-view-mode');
    return saved === 'table' ? 'table' : 'cards';
  });
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProductIds, setSelectedProductIds] = useState([]);
  const [bulkProcessing, setBulkProcessing] = useState(false);
  const { toasts, removeToast, success, error: showError } = useToast();

  const { data: productsData, isLoading, error } = useQuery({
    queryKey: ['admin-products'],
    queryFn: async () => {
      const { data, error: err } = await getProducts([], null, null, { includeHidden: true });
      if (err) throw new Error(err);
      return data;
    }
  });

  const { data: categoriesData = [] } = useQuery({
    queryKey: ['admin-categories'],
    queryFn: async () => {
      const { data, error: err } = await getCategories();
      if (err) throw new Error(err);
      return data;
    }
  });

  const deleteMutation = useMutation({
    mutationFn: (id) => deleteProduct(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-products'] });
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['featured-products'] });
      queryClient.invalidateQueries({ queryKey: ['collection-products'] });
      setDeleteConfirm(null);
      success('Producto eliminado exitosamente');
    },
    onError: () => {
      showError('Error al eliminar el producto');
    }
  });

  const toggleVisibleMutation = useMutation({
    mutationFn: ({ id, product, visible }) => updateProduct(id, { ...product, visible }),
    onMutate: async ({ id, visible }) => {
      // Cancelar queries en curso
      await queryClient.cancelQueries({ queryKey: ['admin-products'] });

      // Snapshot del valor anterior
      const previousProducts = queryClient.getQueryData(['admin-products']);

      // Optimistic update
      queryClient.setQueryData(['admin-products'], (old) => {
        if (!old) return old;
        return old.map((p) => (p.id === id ? { ...p, visible } : p));
      });

      // Guardar estado optimista
      setOptimisticVisibility((prev) => ({ ...prev, [id]: visible }));

      return { previousProducts };
    },
    onError: (err, variables, context) => {
      // Revertir en caso de error
      if (context?.previousProducts) {
        queryClient.setQueryData(['admin-products'], context.previousProducts);
      }
      setOptimisticVisibility((prev) => {
        const newState = { ...prev };
        delete newState[variables.id];
        return newState;
      });
      showError('Error al cambiar visibilidad del producto');
    },
    onSuccess: (data, variables) => {
      queryClient.invalidateQueries({ queryKey: ['admin-products'] });
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['featured-products'] });
      queryClient.invalidateQueries({ queryKey: ['collection-products'] });
      // Limpiar estado optimista después de éxito
      setOptimisticVisibility({});
      success(variables.visible ? 'Producto mostrado exitosamente' : 'Producto ocultado exitosamente');
    },
    onSettled: () => {
      // Limpiar estado optimista después de completar
      setTimeout(() => {
        setOptimisticVisibility({});
      }, 500);
    }
  });

  // Guardar preferencia de vista
  useEffect(() => {
    localStorage.setItem('admin-products-view-mode', viewMode);
  }, [viewMode]);

  const products = useMemo(() => {
    if (!productsData) return [];
    let filtered = productsData.map((p) => {
      // Aplicar estado optimista si existe
      if (optimisticVisibility[p.id] !== undefined) {
        return { ...p, visible: optimisticVisibility[p.id] };
      }
      return p;
    });

    // Filtrar por búsqueda
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase().trim();
      filtered = filtered.filter((p) => {
        const nameMatch = p.name?.toLowerCase().includes(query);
        const categoryMatch = categoryName(p).toLowerCase().includes(query);
        const priceMatch = String(p.price || '').includes(query);
        return nameMatch || categoryMatch || priceMatch;
      });
    }

    return filtered;
  }, [productsData, optimisticVisibility, searchQuery]);

  const categoryName = (p) => {
    const ids = p.categories ?? (p.category ? [p.category] : []);
    if (!ids.length) return '—';
    return ids.map((id) => categoriesData.find((c) => c.id === id)?.name || id).join(', ');
  };

  const handleToggleVisibility = (product) => {
    const newVisible = !(product.visible !== false);
    toggleVisibleMutation.mutate({
      id: product.id,
      product,
      visible: newVisible
    });
  };

  const handleDelete = (product) => {
    setDeleteConfirm(product);
  };

  const handleBulkShow = async () => {
    if (selectedProductIds.length === 0) return;
    if (!window.confirm(`¿Mostrar ${selectedProductIds.length} producto(s) seleccionado(s)?`)) return;

    setBulkProcessing(true);
    try {
      const updates = products
        .filter(p => selectedProductIds.includes(p.id))
        .map(p => ({
          id: p.id,
          product: p,
          visible: true
        }));

      await Promise.all(updates.map(update =>
        updateProduct(update.id, { ...update.product, visible: true })
      ));

      queryClient.invalidateQueries({ queryKey: ['admin-products'] });
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['featured-products'] });
      queryClient.invalidateQueries({ queryKey: ['collection-products'] });
      setSelectedProductIds([]);
      success(`${selectedProductIds.length} producto(s) mostrado(s) exitosamente`);
    } catch (error) {
      console.error('Error al mostrar productos:', error);
      showError('Error al mostrar algunos productos');
    } finally {
      setBulkProcessing(false);
    }
  };

  const handleBulkHide = async () => {
    if (selectedProductIds.length === 0) return;
    if (!window.confirm(`¿Ocultar ${selectedProductIds.length} producto(s) seleccionado(s)?`)) return;

    setBulkProcessing(true);
    try {
      const updates = products
        .filter(p => selectedProductIds.includes(p.id))
        .map(p => ({
          id: p.id,
          product: p,
          visible: false
        }));

      await Promise.all(updates.map(update =>
        updateProduct(update.id, { ...update.product, visible: false })
      ));

      queryClient.invalidateQueries({ queryKey: ['admin-products'] });
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['featured-products'] });
      queryClient.invalidateQueries({ queryKey: ['collection-products'] });
      setSelectedProductIds([]);
      success(`${selectedProductIds.length} producto(s) ocultado(s) exitosamente`);
    } catch (error) {
      console.error('Error al ocultar productos:', error);
      showError('Error al ocultar algunos productos');
    } finally {
      setBulkProcessing(false);
    }
  };

  const handleBulkDelete = async () => {
    if (selectedProductIds.length === 0) return;
    if (!window.confirm(`¿Eliminar ${selectedProductIds.length} producto(s) seleccionado(s)? Esta acción no se puede deshacer.`)) return;

    setBulkProcessing(true);
    try {
      await Promise.all(selectedProductIds.map(id => deleteProduct(id)));

      queryClient.invalidateQueries({ queryKey: ['admin-products'] });
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['featured-products'] });
      queryClient.invalidateQueries({ queryKey: ['collection-products'] });
      const count = selectedProductIds.length;
      setSelectedProductIds([]);
      success(`${count} producto(s) eliminado(s) exitosamente`);
    } catch (error) {
      console.error('Error al eliminar productos:', error);
      showError('Error al eliminar algunos productos');
    } finally {
      setBulkProcessing(false);
    }
  };

  const handleExport = () => {
    try {
      const count = exportProducts(products, categoriesData, selectedProductIds.length > 0 ? selectedProductIds : null);
      success(`Se exportaron ${count} producto(s) exitosamente`);
    } catch (err) {
      console.error('Error al exportar:', err);
      showError('Error al exportar productos: ' + err.message);
    }
  };

  const handleDuplicate = async (product) => {
    try {
      // Crear copia del producto sin el ID
      const { id, createdAt, ...productData } = product;
      const duplicateData = {
        ...productData,
        name: `${productData.name} (Copia)`,
        visible: false, // Oculto por defecto para que el admin lo revise
      };

      const result = await createProduct(duplicateData);

      if (result.error) {
        throw new Error(result.error);
      }

      queryClient.invalidateQueries({ queryKey: ['admin-products'] });
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['featured-products'] });
      queryClient.invalidateQueries({ queryKey: ['collection-products'] });
      success('Producto duplicado exitosamente');

      // Navegar al producto duplicado para editarlo
      if (result.data?.id) {
        setTimeout(() => {
          window.location.href = `/admin/productos/${result.data.id}`;
        }, 1000);
      }
    } catch (err) {
      console.error('Error al duplicar producto:', err);
      showError('Error al duplicar producto: ' + (err.message || 'Error desconocido'));
    }
  };

  const handleCreateReferenceProducts = async () => {
    if (!window.confirm('¿Crear 5 productos de referencia (Poleras, Polos, Joggers, Gorros, Joyas)?\n\nEsto creará productos con datos de ejemplo.')) {
      return;
    }

    setCreatingReference(true);
    setCreateResult(null);

    try {
      const result = await createReferenceProducts();
      setCreateResult(result);

      // Invalidar queries para refrescar la lista
      queryClient.invalidateQueries({ queryKey: ['admin-products'] });
      queryClient.invalidateQueries({ queryKey: ['products'] });
      queryClient.invalidateQueries({ queryKey: ['admin-categories'] });
      queryClient.invalidateQueries({ queryKey: ['categories'] });
    } catch (error) {
      console.error('Error al crear productos de referencia:', error);
      setCreateResult({
        success: false,
        error: error.message || 'Error desconocido'
      });
    } finally {
      setCreatingReference(false);
    }
  };

  return (
    <div className={styles.wrapper}>
      <div className={styles.header}>
        <h1 className={styles.title}>Productos</h1>
        <div style={{ display: 'flex', gap: '10px', alignItems: 'center', flexWrap: 'wrap' }}>
          <Button
            variant="secondary"
            onClick={handleCreateReferenceProducts}
            disabled={creatingReference}
            title="Crear productos de referencia: Poleras, Polos, Joggers, Gorros y Joyas"
          >
            {creatingReference ? 'Creando...' : 'Crear productos de referencia'}
          </Button>
          <Button
            variant="secondary"
            onClick={handleExport}
            disabled={products.length === 0}
            title="Exportar productos a CSV"
          >
            Exportar CSV
          </Button>
          <Link to="/admin/productos/nuevo">
            <Button>Nuevo producto</Button>
          </Link>
        </div>
      </div>

      {createResult && (
        <div style={{
          padding: '12px',
          marginBottom: '20px',
          borderRadius: '4px',
          backgroundColor: createResult.success ? '#d4edda' : '#f8d7da',
          color: createResult.success ? '#155724' : '#721c24',
          border: `1px solid ${createResult.success ? '#c3e6cb' : '#f5c6cb'}`
        }}>
          {createResult.success ? (
            <div>
              <strong>✅ Productos creados exitosamente!</strong>
              <p style={{ margin: '8px 0 0 0', fontSize: '14px' }}>
                Se crearon {createResult.successful} de {createResult.total} productos de referencia.
              </p>
            </div>
          ) : (
            <div>
              <strong>❌ Error al crear productos</strong>
              <p style={{ margin: '8px 0 0 0', fontSize: '14px' }}>
                {createResult.error || 'Error desconocido'}
              </p>
            </div>
          )}
        </div>
      )}

      {/* Barra de búsqueda y vista */}
      <div className={styles.toolbar}>
        <div className={styles.searchContainer}>
          <input
            type="text"
            placeholder="Buscar productos por nombre, categoría o precio..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className={styles.searchInput}
          />
          {searchQuery && (
            <button
              type="button"
              onClick={() => setSearchQuery('')}
              className={styles.clearSearch}
              aria-label="Limpiar búsqueda"
            >
              ×
            </button>
          )}
        </div>
        <div className={styles.viewToggle}>
          <button
            type="button"
            className={`${styles.viewToggleBtn} ${viewMode === 'cards' ? styles.active : ''}`}
            onClick={() => setViewMode('cards')}
            title="Vista de tarjetas"
            aria-label="Vista de tarjetas"
          >
            <GridIcon size={18} />
          </button>
          <button
            type="button"
            className={`${styles.viewToggleBtn} ${viewMode === 'table' ? styles.active : ''}`}
            onClick={() => setViewMode('table')}
            title="Vista de tabla"
            aria-label="Vista de tabla"
          >
            <TableIcon size={18} />
          </button>
        </div>
      </div>

      {isLoading && <p className={styles.loading}>Cargando productos...</p>}
      {error && <p className={styles.error}>{error.message}</p>}

      {/* Barra de acciones en masa */}
      {viewMode === 'table' && selectedProductIds.length > 0 && (
        <BulkActions
          selectedCount={selectedProductIds.length}
          onShowAll={handleBulkShow}
          onHideAll={handleBulkHide}
          onDeleteAll={handleBulkDelete}
          onExport={() => {
            try {
              const count = exportProducts(products, categoriesData, selectedProductIds);
              success(`Se exportaron ${count} producto(s) exitosamente`);
            } catch (err) {
              showError('Error al exportar: ' + err.message);
            }
          }}
          onClearSelection={() => setSelectedProductIds([])}
          isProcessing={bulkProcessing}
        />
      )}

      {viewMode === 'table' ? (
        <ProductTable
          products={products}
          categories={categoriesData}
          onToggleVisibility={handleToggleVisibility}
          onDelete={handleDelete}
          onDuplicate={handleDuplicate}
          optimisticVisibility={optimisticVisibility}
          isToggling={toggleVisibleMutation.isPending}
          isLoading={isLoading}
          selectedIds={selectedProductIds}
          onSelectProduct={setSelectedProductIds}
          onSelectAll={setSelectedProductIds}
        />
      ) : (
        <div className={styles.grid}>
          {products.map((p) => {
            const isVisible = p.visible !== false;
            const isToggling = optimisticVisibility[p.id] !== undefined;

            return (
              <div key={p.id} className={styles.card}>
                {/* Toggle de visibilidad en esquina superior derecha */}
                <div className={styles.cardToggle}>
                  <Toggle
                    checked={isVisible}
                    onChange={() => handleToggleVisibility(p)}
                    disabled={toggleVisibleMutation.isPending && !isToggling}
                    size="small"
                    aria-label={isVisible ? 'Producto visible - Click para ocultar' : 'Producto oculto - Click para mostrar'}
                  />
                  <span className={styles.toggleIcon}>
                    {isVisible ? <EyeIcon size={14} /> : <EyeOffIcon size={14} />}
                  </span>
                </div>

                <div className={styles.cardImage}>
                  {p.isComboProduct ? (
                    <ComboProductImage
                      comboProduct={p}
                      variantSelections={{}}
                      className={styles.cardImageCombo}
                    />
                  ) : (() => {
                    const principalVariant = p.variants?.find(v => v.id === p.defaultVariantId) || p.variants?.[0];
                    const adminImageStr = p.thumbnailImageUrl || principalVariant?.imageUrl || p.mainImage || p.images?.[0] || '';
                    const displayUrl = adminImageStr || 'https://via.placeholder.com/400x400/eee/999?text=Producto';
                    const adminCrop = principalVariant?.thumbnailCrop?.percentages;

                    return (
                      <OptimizedImage
                        src={toThumbnailImageUrl(displayUrl)}
                        fallbackSrc={toDirectImageUrl(displayUrl)}
                        alt={p.name}
                        containerClassName={styles.cardImageContainer}
                        cropData={adminCrop}
                        showSkeleton={true}
                      />
                    );
                  })()}
                </div>
                <div className={styles.cardBody}>
                  <h3 className={styles.cardName}>{p.name}</h3>
                  <p className={styles.cardMeta}>
                    {categoryName(p)} · S/ {Number(p.price || 0).toFixed(2)} · Stock: {p.inStock ?? 0}
                  </p>
                  <div className={styles.badges}>
                    {p.featured && <span className={styles.badge}>Destacado</span>}
                    {!isVisible && <span className={styles.badgeOculto}>Oculto</span>}
                  </div>
                </div>
                <div className={styles.cardActions}>
                  <Link
                    to={`/admin/productos/${p.id}`}
                    className={styles.btnEdit}
                    title="Editar producto"
                  >
                    <EditIcon size={16} />
                    <span>Editar</span>
                  </Link>
                  <button
                    type="button"
                    className={styles.btnDuplicate}
                    onClick={() => handleDuplicate(p)}
                    title="Duplicar producto"
                  >
                    <CopyIcon size={16} />
                    <span>Duplicar</span>
                  </button>
                  <button
                    type="button"
                    className={styles.btnDelete}
                    onClick={() => setDeleteConfirm(p)}
                    title="Eliminar producto"
                  >
                    <TrashIcon size={16} />
                    <span>Eliminar</span>
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {products.length === 0 && !isLoading && (
        <p className={styles.empty}>No hay productos. <Link to="/admin/productos/nuevo">Crear uno</Link>.</p>
      )}

      {deleteConfirm && (
        <div className={styles.modalBackdrop} onClick={() => setDeleteConfirm(null)}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <p>¿Eliminar el producto &quot;{deleteConfirm.name}&quot;?</p>
            <div className={styles.modalActions}>
              <Button variant="secondary" onClick={() => setDeleteConfirm(null)}>
                Cancelar
              </Button>
              <Button
                variant="primary"
                onClick={() => deleteMutation.mutate(deleteConfirm.id)}
                disabled={deleteMutation.isPending}
              >
                Eliminar
              </Button>
            </div>
          </div>
        </div>
      )}

      <ToastContainer toasts={toasts} onRemove={removeToast} />
    </div>
  );
};

export default AdminProductos;

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { collection, query, getDocs, updateDoc, doc, serverTimestamp, orderBy } from 'firebase/firestore';
import { db } from '../../services/firebase/config';
import { useGlobalToast } from '../../contexts/ToastContext';
import styles from './AdminReferidos.module.css';

const AdminReferidos = () => {
  const toast = useGlobalToast();
  const queryClient = useQueryClient();
  const [procesandoId, setProcesandoId] = useState(null);

  const { data: referidos, isLoading } = useQuery({
    queryKey: ['adminReferrals'],
    queryFn: async () => {
      const q = query(collection(db, 'referrals'), orderBy('createdAt', 'desc'));
      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    }
  });

  const aprobarRestriccion = async (referidoId, totalGanancia) => {
    if (!window.confirm(`¿Confirmas que este pedido ya se entregó y el referido puede reclamar S/ ${totalGanancia} monedas?`)) return;
    
    setProcesandoId(referidoId);
    try {
      const docRef = doc(db, 'referrals', referidoId);
      await updateDoc(docRef, {
        status: 'completed',
        earnedCoins: totalGanancia,
        completedAt: serverTimestamp(),
        updatedAt: serverTimestamp()
      });
      toast.success('Referido aprobado exitosamente');
      queryClient.invalidateQueries(['adminReferrals']);
    } catch (error) {
      toast.error('Error al aprobar');
    } finally {
      setProcesandoId(null);
    }
  };

  const rechazarRestriccion = async (referidoId) => {
    if (!window.confirm('¿Confirmas que esta venta fue cancelada o no califica?')) return;
    
    setProcesandoId(referidoId);
    try {
      const docRef = doc(db, 'referrals', referidoId);
      await updateDoc(docRef, {
        status: 'ineligible',
        earnedCoins: 0,
        completedAt: serverTimestamp(),
        updatedAt: serverTimestamp()
      });
      toast.success('Referido marcado como no elegible');
      queryClient.invalidateQueries(['adminReferrals']);
    } catch (error) {
      toast.error('Error al rechazar');
    } finally {
      setProcesandoId(null);
    }
  };

  if (isLoading) return <div style={{ padding: '2rem' }}>Cargando panel de referidos...</div>;

  return (
    <div className="admin-container">
      <h2>Gestión de Referidos (Ventas por WhatsApp)</h2>
      <p style={{ marginBottom: '2rem', color: '#666' }}>
        Como las ventas finalizan por WhatsApp y tu ERP externo, el sistema no sabe automáticamente cuándo se completa el envío. 
        Aquí verás las ventas iniciadas con código de referido. Cuando confirmes que el pedido se entregó, haz clic en "Aprobar" para que el usuario pueda reclamar sus monedas.
      </p>

      <div className={styles.tableWrapper}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th>Fecha</th>
              <th>Código Referente</th>
              <th>Cód. Pedido WA</th>
              <th>Monto Venta</th>
              <th>Monedas a Ganar</th>
              <th>Estado Actual</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {referidos?.length === 0 && (
              <tr><td colSpan="7" style={{ textAlign: 'center' }}>No hay referidos registrados aún.</td></tr>
            )}
            {referidos?.map(ref => {
              const d = ref.createdAt?.toDate()?.toLocaleDateString() || 'N/A';
              const monedasCalculadas = Math.floor((ref.orderTotal || 0) / 100) * 5;
              
              let statusLabel = 'Etapa 2 (Solo Clic)';
              if (ref.status === 'purchased') statusLabel = 'Etapa 3 (Compró por WA)';
              if (ref.status === 'completed') statusLabel = 'Etapa 4 (Aprobado/Esperando Reclamo)';
              if (ref.status === 'claimed') statusLabel = 'Finalizado (Monedas Reclamadas)';
              if (ref.status === 'ineligible') statusLabel = 'No califica / Cancelado';

              const isPending = ref.status === 'purchased';

              return (
                <tr key={ref.id}>
                  <td>{d}</td>
                  <td><strong>{ref.referrerCode}</strong></td>
                  <td>{ref.orderId || '-'}</td>
                  <td>{ref.orderTotal ? `S/ ${ref.orderTotal}` : '-'}</td>
                  <td style={{ color: '#d35400', fontWeight: 'bold' }}>{monedasCalculadas > 0 ? monedasCalculadas : 0}</td>
                  <td>{statusLabel}</td>
                  <td>
                    {isPending && (
                      <div style={{ display: 'flex', gap: '0.5rem' }}>
                        <button 
                          className={styles.btnApprove}
                          onClick={() => aprobarRestriccion(ref.id, monedasCalculadas)}
                          disabled={procesandoId === ref.id}
                        >
                          Aprobar
                        </button>
                        <button 
                          className={styles.btnReject}
                          onClick={() => rechazarRestriccion(ref.id)}
                          disabled={procesandoId === ref.id}
                        >
                          Rechazar
                        </button>
                      </div>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminReferidos;

import React, { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getMessage, setMessage } from '../../services/messages';
import Button from '../../components/common/Button';
import styles from './AdminTiendaTextos.module.css';

const AdminWhatsApp = () => {
  const queryClient = useQueryClient();
  const [numbers, setNumbers] = useState({
    tienda: '',
    crear: '',
    cuenta: '',
    text_tienda: '',
    text_crear: '',
    text_cuenta: '',
  });

  const { data: savedNumbers, isLoading } = useQuery({
    queryKey: ['admin-whatsapp-numbers'],
    queryFn: async () => {
      const [tienda, crear, cuenta, textTienda, textCrear, textCuenta] = await Promise.all([
        getMessage('whatsapp_number_tienda'),
        getMessage('whatsapp_number_crear'),
        getMessage('whatsapp_number_cuenta'),
        getMessage('whatsapp_text_tienda'),
        getMessage('whatsapp_text_crear'),
        getMessage('whatsapp_text_cuenta')
      ]);

      // Fallback a whatsapp_number si las específicas están vacías (retrocompatibilidad)
      const fallback = await getMessage('whatsapp_number');

      return {
        tienda: tienda.data?.trim() || fallback.data?.trim() || '',
        crear: crear.data?.trim() || fallback.data?.trim() || '',
        cuenta: cuenta.data?.trim() || fallback.data?.trim() || '',
        text_tienda: textTienda.data || 'Solicitud de Pedido\n\nHola! Vengo de la tienda virtual y quiero confirmar mi pedido con código {id}.',
        text_crear: textCrear.data || '*Mi Creación Libre*\n\nHola! Diseñé esto con el Creador Libre, ayúdame a cotizar.',
        text_cuenta: textCuenta.data || 'Hola, necesito ayuda con mi cuenta / mi pedido.'
      };
    }
  });

  useEffect(() => {
    if (savedNumbers) {
      setNumbers(savedNumbers);
    }
  }, [savedNumbers]);

  const saveMutation = useMutation({
    mutationFn: async (updatedNumbers) => {
      await Promise.all([
        setMessage('whatsapp_number_tienda', updatedNumbers.tienda?.trim() || ''),
        setMessage('whatsapp_number_crear', updatedNumbers.crear?.trim() || ''),
        setMessage('whatsapp_number_cuenta', updatedNumbers.cuenta?.trim() || ''),
        // Textos
        setMessage('whatsapp_text_tienda', updatedNumbers.text_tienda || ''),
        setMessage('whatsapp_text_crear', updatedNumbers.text_crear || ''),
        setMessage('whatsapp_text_cuenta', updatedNumbers.text_cuenta || ''),
        // Mantener whatsapp_number como fallback general
        setMessage('whatsapp_number', updatedNumbers.tienda?.trim() || '')
      ]);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-whatsapp-numbers'] });
      queryClient.invalidateQueries({ queryKey: ['whatsapp-numbers-config'] });
    }
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    saveMutation.mutate(numbers);
  };

  const formatNumber = (value) => {
    return value.replace(/[^\d\s\-\(\)\+]/g, '');
  };

  const handleChange = (key, value) => {
    // Si es una key de texto no formateamos a numero
    if (key.startsWith('text_')) {
      setNumbers(prev => ({
        ...prev,
        [key]: value
      }));
    } else {
      setNumbers(prev => ({
        ...prev,
        [key]: formatNumber(value)
      }));
    }
  };

  const renderPreview = (num) => {
    if (!num) return null;
    const clean = num.replace(/[\s\-\(\)]/g, '');
    const formatted = clean.startsWith('+') ? clean : `+51${clean}`;
    return `https://wa.me/${formatted.replace(/\+/g, '')}`;
  };

  if (isLoading) {
    return <p className={styles.loading}>Cargando...</p>;
  }

  return (
    <div className={styles.wrapper}>
      <h1 className={styles.title}>Configuración de WhatsApp</h1>
      <p className={styles.subtitle}>
        Personaliza a qué número de WhatsApp se redirigirá al cliente según la pestaña donde se encuentre.
      </p>

      <form onSubmit={handleSubmit} className={styles.form}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '2.5rem' }}>

          <div className={styles.configBlock} style={{ background: 'var(--gris-fondo)', padding: '1.5rem', borderRadius: '8px', border: '1px solid var(--gris-borde)' }}>
            <h3 style={{ margin: '0 0 1rem 0' }}>1. Configuración de Tienda (Checkout)</h3>
            <div className={styles.field}>
              <label htmlFor="whatsapp_tienda">Número de WhatsApp</label>
              <input
                id="whatsapp_tienda"
                type="text"
                value={numbers.tienda}
                onChange={(e) => handleChange('tienda', e.target.value)}
                placeholder="Ej: +51 987 654 321"
                className={styles.input}
              />
              {numbers.tienda && <p className={styles.sectionHint}>{renderPreview(numbers.tienda)}</p>}
            </div>
            <div className={styles.field} style={{ marginTop: '1rem' }}>
              <label htmlFor="whatsapp_text_tienda">Mensaje Principal (Usa {'{id}'} para el N° de Pedido)</label>
              <textarea
                id="whatsapp_text_tienda"
                value={numbers.text_tienda}
                onChange={(e) => handleChange('text_tienda', e.target.value)}
                rows={3}
                className={styles.input}
                style={{ resize: 'vertical' }}
              />
            </div>
          </div>

          <div className={styles.configBlock} style={{ background: 'var(--gris-fondo)', padding: '1.5rem', borderRadius: '8px', border: '1px solid var(--gris-borde)' }}>
            <h3 style={{ margin: '0 0 1rem 0' }}>2. Configuración de Creador (Diseño Libre)</h3>
            <div className={styles.field}>
              <label htmlFor="whatsapp_crear">Número de WhatsApp</label>
              <input
                id="whatsapp_crear"
                type="text"
                value={numbers.crear}
                onChange={(e) => handleChange('crear', e.target.value)}
                placeholder="Ej: +51 987 654 321"
                className={styles.input}
              />
              {numbers.crear && <p className={styles.sectionHint}>{renderPreview(numbers.crear)}</p>}
            </div>
            <div className={styles.field} style={{ marginTop: '1rem' }}>
              <label htmlFor="whatsapp_text_crear">Mensaje de Cotización</label>
              <textarea
                id="whatsapp_text_crear"
                value={numbers.text_crear}
                onChange={(e) => handleChange('text_crear', e.target.value)}
                rows={3}
                className={styles.input}
                style={{ resize: 'vertical' }}
              />
            </div>
          </div>

          <div className={styles.configBlock} style={{ background: 'var(--gris-fondo)', padding: '1.5rem', borderRadius: '8px', border: '1px solid var(--gris-borde)' }}>
            <h3 style={{ margin: '0 0 1rem 0' }}>3. Configuración para Mi Cuenta (Soporte)</h3>
            <div className={styles.field}>
              <label htmlFor="whatsapp_cuenta">Número de WhatsApp</label>
              <input
                id="whatsapp_cuenta"
                type="text"
                value={numbers.cuenta}
                onChange={(e) => handleChange('cuenta', e.target.value)}
                placeholder="Ej: +51 987 654 321"
                className={styles.input}
              />
              {numbers.cuenta && <p className={styles.sectionHint}>{renderPreview(numbers.cuenta)}</p>}
            </div>
            <div className={styles.field} style={{ marginTop: '1rem' }}>
              <label htmlFor="whatsapp_text_cuenta">Mensaje de Ayuda General</label>
              <textarea
                id="whatsapp_text_cuenta"
                value={numbers.text_cuenta}
                onChange={(e) => handleChange('text_cuenta', e.target.value)}
                rows={3}
                className={styles.input}
                style={{ resize: 'vertical' }}
              />
            </div>
          </div>

        </div>

        <p className={styles.sectionHint} style={{ marginTop: '1rem', fontSize: '0.8125rem', color: '#666' }}>
          * Si dejas un número vacío, el botón no aparecerá en esa sección específica. El código +51 se agrega automáticamente si no incluyes código de país.
        </p>

        <div className={styles.actions} style={{ marginTop: '2rem' }}>
          <Button type="submit" disabled={saveMutation.isPending}>
            {saveMutation.isPending ? 'Guardando...' : 'Guardar todas las configuraciones'}
          </Button>
        </div>
      </form>

      {saveMutation.isSuccess && (
        <div style={{ marginTop: '1rem', padding: '0.75rem', background: '#d4edda', color: '#155724', borderRadius: '6px', fontSize: '0.875rem' }}>
          ✓ Configuraciones guardadas exitosamente. El botón de WhatsApp se actualizará en las pestañas correspondientes.
        </div>
      )}

      {saveMutation.isError && (
        <div style={{ marginTop: '1rem', padding: '0.75rem', background: '#f8d7da', color: '#721c24', borderRadius: '6px', fontSize: '0.875rem' }}>
          ✗ Error al guardar: {saveMutation.error?.message || 'Error desconocido'}
        </div>
      )}
    </div>
  );
};

export default AdminWhatsApp;

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { Gift, Calendar, Plus, Edit2, Trash2, X, Heart, Users, UserPlus, UserCircle, Globe } from 'lucide-react';
import styles from './CuentaFechasImportantesPage.module.css';

const EVENT_TYPES = [
  { id: 'cumpleanos', label: 'Cumpleaños', needsDate: true },
  { id: 'aniversario', label: 'Aniversario', needsDate: true },
  { id: 'otro', label: 'Fecha Especial', needsDate: true }
];

const ROLES_MAP = {
  pareja: { label: 'Pareja', singular: 'Pareja' },
  hijos: { label: 'Hijos', singular: 'Hijo/a' },
  padres: { label: 'Padres', singular: 'Padre/Madre' },
  hermanos: { label: 'Hermanos', singular: 'Hermano/a' },
  sobrinos: { label: 'Sobrinos', singular: 'Sobrino/a' },
  primos: { label: 'Primos', singular: 'Primo/a' },
  amigos: { label: 'Amigos', singular: 'Amigo/a' },
  otros: { label: 'Otros', singular: 'Otra persona' }
};

const getGlobalDates = (roleKey, gender) => {
  const dates = [];
  if (gender === 'Femenino') dates.push('Día de la Mujer');
  if (gender === 'Masculino') dates.push('Día del Hombre');
  
  if (roleKey === 'pareja') dates.push('San Valentín');
  if (roleKey === 'padres' && gender === 'Femenino') dates.push('Día de la Madre');
  if (roleKey === 'padres' && gender === 'Masculino') dates.push('Día del Padre');
  if (roleKey === 'hijos') dates.push('Día del Niño');
  if (roleKey === 'amigos') dates.push('Día de la Amistad');
  
  return dates;
};

const CuentaFechasImportantesPage = () => {
  const { userProfile, updateUserProfile } = useAuth();
  const navigate = useNavigate();
  
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [tempRecipient, setTempRecipient] = useState(null);
  const [saving, setSaving] = useState(false);

  const recipients = userProfile?.giftRecipients || [];
  const hasCompletedSurvey = userProfile?.hasCompletedSurvey;

  if (!hasCompletedSurvey) {
    return (
      <div className={styles.container}>
        <div className={styles.emptyState}>
          <Gift size={64} className={styles.emptyStateIcon} />
          <h2>¡Gana recompensas diciéndonos qué te gusta!</h2>
          <p>
            Al completar nuestro perfil de regalos, ganarás Kapicoins que puedes canjear
            por descuentos, y te recordaremos las fechas más importantes de tus seres queridos.
          </p>
          <Link to="/encuesta-suscripcion" className={styles.primaryButton}>
            Completa la encuesta ahora
          </Link>
        </div>
      </div>
    );
  }

  const handleAddNew = () => {
    setTempRecipient({
      id: Math.random().toString(36).substring(2, 9),
      roleKey: 'otros',
      roleDisplay: 'Otra persona',
      name: '',
      gender: '',
      events: [{ id: Math.random().toString(36).substring(2, 9), type: 'Cumpleaños', date: '' }],
    });
    setIsModalOpen(true);
  };

  const handleEdit = (rec) => {
    setTempRecipient(JSON.parse(JSON.stringify(rec)));
    setIsModalOpen(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('¿Seguro que deseas eliminar a esta persona de tus fechas importantes?')) return;
    
    const newList = recipients.filter(r => r.id !== id);
    try {
      await updateUserProfile({ giftRecipients: newList });
    } catch (e) {
      alert('Error al eliminar la persona.');
    }
  };

  const handleTempChange = (field, value) => {
    setTempRecipient(prev => {
      const updated = { ...prev, [field]: value };
      if (field === 'roleKey') {
        updated.roleDisplay = ROLES_MAP[value]?.singular || 'Otra persona';
      }
      return updated;
    });
  };

  const addEvent = () => {
    setTempRecipient(prev => ({
      ...prev,
      events: [...prev.events, { id: Math.random().toString(36).substring(2, 9), type: 'Fecha Especial', date: '', customName: '' }]
    }));
  };

  const updateEvent = (index, field, value) => {
    setTempRecipient(prev => {
      const newEvents = [...prev.events];
      newEvents[index][field] = value;
      return { ...prev, events: newEvents };
    });
  };

  const removeEvent = (index) => {
    setTempRecipient(prev => {
      const newEvents = [...prev.events];
      newEvents.splice(index, 1);
      return { ...prev, events: newEvents };
    });
  };

  const saveRecipient = async () => {
    if (!tempRecipient.name || tempRecipient.name.trim() === '') {
       return alert('El nombre es obligatorio.');
    }
    if (!tempRecipient.gender || tempRecipient.gender.trim() === '') {
       return alert('El género es obligatorio.');
    }

    for (const ev of tempRecipient.events) {
      const evTypeConfig = EVENT_TYPES.find(e => e.label === ev.type) || EVENT_TYPES.find(e => e.id === 'otro');
      if (evTypeConfig.needsDate && (!ev.date || ev.date.trim() === '')) {
        return alert(`La fecha es obligatoria para el evento: ${ev.type}.`);
      }
      if (ev.type === 'Fecha Especial' && (!ev.customName || ev.customName.trim() === '')) {
        return alert('Por favor, indica qué se celebra en la Fecha Especial.');
      }
    }

    setSaving(true);
    try {
      const copy = [...recipients];
      const existingIdx = copy.findIndex(r => r.id === tempRecipient.id);
      if (existingIdx >= 0) {
        copy[existingIdx] = tempRecipient;
      } else {
        copy.push(tempRecipient);
      }
      await updateUserProfile({ giftRecipients: copy });
      setIsModalOpen(false);
    } catch (e) {
      alert('Error al guardar los datos.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.header}>
        <h1>Fechas Importantes</h1>
        <button onClick={handleAddNew} className={styles.primaryButton}>
          <Plus size={20} /> Añadir Persona
        </button>
      </div>

      <div className={styles.grid}>
        {recipients.length === 0 ? (
          <p style={{ color: '#64748b' }}>Aún no has agregado personas a tu lista.</p>
        ) : (
          recipients.map(rec => (
            <div key={rec.id} className={styles.card}>
              <div className={styles.cardHeader}>
                <div>
                  <h3 className={styles.cardTitle}>{rec.name}</h3>
                  <span className={styles.cardRole}>{rec.roleDisplay}</span>
                  {getGlobalDates(rec.roleKey, rec.gender).length > 0 && (
                    <div className={styles.globalDatesContainer}>
                      {getGlobalDates(rec.roleKey, rec.gender).map((gDate, i) => (
                        <span key={i} className={styles.globalDateBadge}>
                          <Globe size={12} /> {gDate}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
                <div className={styles.cardActions}>
                  <button onClick={() => handleEdit(rec)} className={styles.iconBtn} title="Editar">
                    <Edit2 size={18} />
                  </button>
                  <button onClick={() => handleDelete(rec.id)} className={`${styles.iconBtn} ${styles.deleteBtn}`} title="Eliminar">
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>
              
              <div className={styles.eventsList}>
                {rec.events.map(ev => (
                  <div key={ev.id} className={styles.eventItem}>
                    <Calendar size={16} />
                    <span>
                      <strong>{ev.type === 'Fecha Especial' ? ev.customName : ev.type}:</strong>{' '}
                      {ev.date ? new Date(ev.date + 'T00:00:00').toLocaleDateString('es-ES', { day: 'numeric', month: 'long' }) : 'Sin fecha'}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          ))
        )}
      </div>

      {isModalOpen && tempRecipient && (
        <div className={styles.modalOverlay}>
          <div className={styles.modalContent}>
            <div className={styles.modalHeader}>
              <h2>{tempRecipient.name ? `Editar a ${tempRecipient.name}` : 'Añadir Nueva Persona'}</h2>
              <button onClick={() => setIsModalOpen(false)} className={styles.closeBtn}>
                <X size={24} />
              </button>
            </div>
            
            <div className={styles.formBody}>
              <div style={{ display: 'flex', gap: '1rem' }}>
                <div className={styles.fieldGroup} style={{ flex: 2 }}>
                  <label>Nombre de la persona *</label>
                  <input 
                    type="text" 
                    className={styles.input} 
                    placeholder="Ej. Carlos" 
                    value={tempRecipient.name} 
                    onChange={e => handleTempChange('name', e.target.value)} 
                  />
                </div>
                <div className={styles.fieldGroup} style={{ flex: 1 }}>
                  <label>Género *</label>
                  <select 
                    className={styles.input} 
                    value={tempRecipient.gender || ''} 
                    onChange={e => handleTempChange('gender', e.target.value)}
                  >
                    <option value="">Seleccionar...</option>
                    <option value="Masculino">Masculino</option>
                    <option value="Femenino">Femenino</option>
                    <option value="Otro">Otro</option>
                  </select>
                </div>
              </div>

              <div className={styles.fieldGroup}>
                <label>Relación / Parentesco *</label>
                <select 
                  className={styles.input} 
                  value={tempRecipient.roleKey || 'otros'} 
                  onChange={e => handleTempChange('roleKey', e.target.value)}
                >
                  {Object.keys(ROLES_MAP).map(key => (
                    <option key={key} value={key}>{ROLES_MAP[key].label}</option>
                  ))}
                </select>
              </div>
              
              <div className={styles.breakdownSection}>
                <h3 style={{ fontSize: '1rem', marginTop: 0, marginBottom: '1rem' }}>Fechas Importantes</h3>
                
                {tempRecipient.events.map((event, eventIdx) => {
                  const evTypeConfig = EVENT_TYPES.find(e => e.label === event.type) || EVENT_TYPES.find(e => e.id === 'otro');
                  
                  return (
                    <div key={event.id} style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem', alignItems: 'flex-start', background: eventIdx === 0 ? '#ffffff' : 'transparent', padding: eventIdx === 0 ? '1rem' : '0', borderRadius: '8px', border: eventIdx === 0 ? '1px solid #e2e8f0' : 'none' }}>
                      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                        
                        {eventIdx === 0 ? (
                          <div style={{ fontWeight: 'bold', color: '#0f172a', padding: '0.5rem 0' }}>
                            Cumpleaños *
                          </div>
                        ) : (
                          <select 
                            className={styles.input} 
                            value={event.type}
                            onChange={e => updateEvent(eventIdx, 'type', e.target.value)}
                          >
                            {EVENT_TYPES.filter(et => et.id !== 'cumpleanos').map(et => (
                              <option key={et.id} value={et.label}>{et.label}</option>
                            ))}
                          </select>
                        )}
                        
                        {event.type === 'Fecha Especial' && eventIdx > 0 && (
                          <input 
                            type="text" 
                            className={styles.input} 
                            placeholder="¿Qué se celebra? (Ej. Bautizo)" 
                            value={event.customName || ''} 
                            onChange={e => updateEvent(eventIdx, 'customName', e.target.value)}
                          />
                        )}

                        {evTypeConfig.needsDate && (
                          <input 
                            type="date" 
                            className={styles.input} 
                            value={event.date} 
                            onChange={e => updateEvent(eventIdx, 'date', e.target.value)} 
                          />
                        )}
                      </div>
                      
                      {eventIdx > 0 && (
                        <button type="button" onClick={() => removeEvent(eventIdx)} className={styles.removeBtn} style={{ marginTop: '0.2rem' }}>
                          <Trash2 size={20} />
                        </button>
                      )}
                    </div>
                  );
                })}
                
                <button type="button" onClick={addEvent} className={styles.addBtn}>
                  <Plus size={18} /> Agregar otra fecha importante
                </button>
              </div>

            </div>
            
            <div className={styles.modalFooter}>
              <button onClick={() => setIsModalOpen(false)} className={styles.cancelBtn}>Cancelar</button>
              <button onClick={saveRecipient} className={styles.primaryButton} disabled={saving}>
                {saving ? 'Guardando...' : 'Guardar Cambios'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CuentaFechasImportantesPage;

import React, { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useAuth } from '../../contexts/AuthContext';
import { useGlobalToast } from '../../contexts/ToastContext';
import { getReferralsByReferrer, createReferralShare, claimReferralCoins, updateReferralCode } from '../../services/referrals';
import ReferralRanking from '../../components/analytics/ReferralRanking';
import styles from './CuentaReferidosPage.module.css';

const STAGES = {
  sent: 1,
  clicked: 2,
  purchased: 3,
  completed: 4,
  claimed: 4,
  ineligible: 3,
};

const CuentaReferidosPage = () => {
  const { user, userProfile, updateUserProfile } = useAuth();
  const toast = useGlobalToast();
  const queryClient = useQueryClient();
  const [generating, setGenerating] = useState(false);
  
  // States para edición de código
  const [isEditingCode, setIsEditingCode] = useState(false);
  const [newCodeInput, setNewCodeInput] = useState('');
  const [savingCode, setSavingCode] = useState(false);

  const referralCode = userProfile?.referralCode || '';

  const { data: referrals, isLoading } = useQuery({
    queryKey: ['myReferrals', referralCode],
    queryFn: async () => {
      const res = await getReferralsByReferrer(referralCode);
      if (res.error) throw new Error(res.error);
      return res.data;
    },
    enabled: !!referralCode,
  });

  // Notificaciones al cargar la página (música figurativa)
  useEffect(() => {
    if (referrals && referrals.length > 0) {
      // Mostrar notificaciones de las actividades más recientes (últimos 3 días)
      const now = new Date();
      const recent = referrals.filter(r => {
        const d = r.updatedAt?.toDate() || r.createdAt?.toDate();
        if (!d) return false;
        return (now - d) / (1000 * 60 * 60 * 24) <= 3;
      });
      
      const unnotifiedKey = 'notified_referrals_' + referralCode;
      const notifiedStr = localStorage.getItem(unnotifiedKey) || '[]';
      const notified = JSON.parse(notifiedStr);
      let newNotified = [...notified];

      recent.forEach(r => {
        if (!notified.includes(r.id + '_' + r.status)) {
          if (r.status === 'clicked') {
            toast.info('👀 Alguien acaba de ver un producto desde tu enlace.');
          } else if (r.status === 'purchased' || r.status === 'completed') {
            toast.success('🎉 ¡Vendiste! Alguien compró por tu enlace.');
          }
          newNotified.push(r.id + '_' + r.status);
        }
      });
      
      if (newNotified.length > notified.length) {
        localStorage.setItem(unnotifiedKey, JSON.stringify(newNotified));
      }
    }
  }, [referrals, referralCode, toast]);

  const generateLink = async () => {
    if (!referralCode) return;
    setGenerating(true);
    const { id, error } = await createReferralShare(referralCode);
    if (error) {
      toast.error('Error al generar enlace');
      setGenerating(false);
      return;
    }
    
    // Invalidate queries so it shows in the list as "Etapa 1"
    queryClient.invalidateQueries(['myReferrals', referralCode]);

    const url = `${window.location.origin}?ref=${referralCode}&shareId=${id}`;
    navigator.clipboard.writeText(url)
      .then(() => toast.success('¡Enlace general copiado al portapapeles!'))
      .catch(() => toast.error('Error copiando al portapapeles'));
    
    setGenerating(false);
  };

  const handleClaim = async (referralDoc) => {
    if (referralDoc.status !== 'completed' || !referralDoc.earnedCoins) return;
    
    const { error } = await claimReferralCoins(
      referralDoc.id, 
      referralDoc.earnedCoins, 
      user.uid, 
      userProfile?.monedas || 0
    );

    if (error) {
      toast.error('Error al reclamar monedas');
    } else {
      toast.success(`¡Has reclamado ${referralDoc.earnedCoins} monedas con éxito!`);
      queryClient.invalidateQueries(['myReferrals', referralCode]);
      // También se actualiza el userProfile globalmente a través del effect en AuthContext 
      // Si quieres forzar actualización inmediata de UI sin refrescar:
      // updateUserProfile({ monedas: currentMonedas + ... }) pero ya Firebase snapshot hará el update.
    }
  };

  const copyCodeOnly = () => {
    navigator.clipboard.writeText(referralCode)
      .then(() => toast.success('Código copiado'))
      .catch(() => toast.error('Error al copiar'));
  };

  const handleSaveNewCode = async () => {
    if (!newCodeInput || newCodeInput.trim().length < 4) {
      toast.error('El código debe tener al menos 4 caracteres');
      return;
    }
    setSavingCode(true);
    const { error } = await updateReferralCode(user.uid, newCodeInput);
    if (error) {
      toast.error(error);
      setSavingCode(false);
    } else {
      toast.success('Código actualizado exitosamente');
      await updateUserProfile({ referralCode: newCodeInput.trim().toUpperCase(), referralCodeEdited: true });
      setIsEditingCode(false);
      setSavingCode(false);
    }
  };

  if (isLoading) {
    return <div className={styles.loading}>Cargando panel de referidos...</div>;
  }

  // Cálculos de estadísticas
  const totalVisitas = referrals?.filter(r => STAGES[r.status] >= 2).length || 0;
  const totalCompras = referrals?.filter(r => STAGES[r.status] >= 3 && r.status !== 'ineligible').length || 0;
  const totalMonedas = referrals?.reduce((acc, r) => acc + (r.earnedCoins || 0), 0) || 0;

  // Progreso Multiplicador (mes actual)
  const now = new Date();
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const comprasMesActual = referrals?.filter(r => {
    const isCompleted = r.status === 'completed' || r.status === 'claimed';
    const d = r.completedAt?.toDate();
    return isCompleted && d && d >= startOfMonth;
  }).length || 0;

  const nextPurchaseMultiplier = comprasMesActual >= 2;

  return (
    <div className={styles.container}>
      <div className={styles.headerCard}>
        <div className={styles.recompensaTitle}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 12 20 22 4 22 4 12"></polyline><rect x="2" y="7" width="20" height="5"></rect><line x1="12" y1="22" x2="12" y2="7"></line><path d="M12 7H7.5a2.5 2.5 0 0 1 0-5C11 2 12 7 12 7z"></path><path d="M12 7h4.5a2.5 2.5 0 0 0 0-5C13 2 12 7 12 7z"></path></svg>
          RECOMPENSAS
        </div>
        <div className={styles.balance}>
          <div className={styles.coinIcon}>🪙</div>
          <span className={styles.balanceNumber}>{userProfile?.monedas || 0}</span>
          <span className={styles.balanceCurrency}>Monedas</span>
        </div>
        
        <div className={styles.statsRow}>
          <div className={styles.statBox}>
            <span className={styles.statValue}>{totalVisitas}</span>
            <span className={styles.statLabel}>Visitas</span>
          </div>
          <div className={styles.statBox}>
            <span className={styles.statValue}>{totalCompras}</span>
            <span className={styles.statLabel}>Compras</span>
          </div>
          <div className={styles.statBox}>
            <span className={styles.statValue}>{totalMonedas}</span>
            <span className={styles.statLabel}>Monedas Ganadas</span>
          </div>
        </div>

        <div className={styles.codeRow}>
          <div className={styles.codeBox}>
            {isEditingCode ? (
              <div style={{ display: 'flex', gap: '0.5rem', width: '100%' }}>
                <input 
                  type="text" 
                  value={newCodeInput} 
                  onChange={e => setNewCodeInput(e.target.value)} 
                  style={{ padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc', textTransform: 'uppercase', flex: 1, minWidth: '120px' }}
                  maxLength={15}
                  placeholder="NUEVO_CODIGO"
                />
                <button onClick={handleSaveNewCode} disabled={savingCode} style={{ background: '#28a745', color: 'white', border: 'none', padding: '0.5rem', borderRadius: '4px', cursor: 'pointer' }}>✓</button>
                <button onClick={() => setIsEditingCode(false)} style={{ background: '#dc3545', color: 'white', border: 'none', padding: '0.5rem', borderRadius: '4px', cursor: 'pointer' }}>✕</button>
              </div>
            ) : (
              <>
                {referralCode}
                {!userProfile?.referralCodeEdited && (
                  <button onClick={() => { setIsEditingCode(true); setNewCodeInput(referralCode); }} title="Editar código (solo se puede 1 vez)" style={{ background: 'transparent', border: 'none', cursor: 'pointer', fontSize: '1rem' }}>✏️</button>
                )}
                <button className={styles.copyBtn} onClick={copyCodeOnly} title="Copiar código">Copiar</button>
              </>
            )}
          </div>
          <button className={styles.generateBtn} onClick={generateLink} disabled={generating}>
            {generating ? 'Generando...' : 'Generar Link de Referido'}
          </button>
        </div>
        
        <div className={styles.infoText}>
          Genera un enlace y compártelo. Ganarás <strong>10 monedas</strong> por cada venta finalizada.
          {nextPurchaseMultiplier ? (
            <div style={{ color: '#ffd700', fontWeight: 'bold', marginTop: '0.5rem' }}>
              ¡Multiplicador activado! Tu próxima venta este mes te dará x2 monedas (20).
            </div>
          ) : (
            <div style={{ color: '#a0aec0', marginTop: '0.5rem' }}>
              Llevas {comprasMesActual}/3 compras completadas este mes. ¡En la 3ra venta el premio se duplica!
            </div>
          )}
        </div>
      </div>

      <h3 className={styles.listTitle}>Historial de Referidos</h3>
      
      {!referrals || referrals.length === 0 ? (
        <div className={styles.empty}>
          Aún no tienes referidos. ¡Comienza a compartir tu enlace!
        </div>
      ) : (
        <div className={styles.list}>
          {referrals.map((ref) => {
            const currentStage = STAGES[ref.status] || 1;
            const isCompleted = ref.status === 'completed';
            const isClaimed = ref.status === 'claimed';
            const isIneligible = ref.status === 'ineligible';

            const d = ref.clickedAt?.toDate() || ref.createdAt?.toDate();
            const dateStr = d ? d.toLocaleDateString() : 'N/A';

            return (
              <div key={ref.id} className={`${styles.referralCard} ${isClaimed ? styles.cardClaimed : ''}`}>
                <div className={styles.cardHeader}>
                  <span className={styles.dateText}>{dateStr}</span>
                  {ref.orderId && <span className={styles.orderLabel}>Pedido #{ref.orderId}</span>}
                </div>

                <div className={styles.stepperContainer}>
                  {/* Etapa 1 */}
                  <div className={`${styles.step} ${currentStage >= 1 ? styles.activeStep : ''}`}>
                    <div className={styles.stepCircle}>1</div>
                    <div className={styles.stepLabel}>Enviado</div>
                  </div>
                  <div className={`${styles.stepLine} ${currentStage >= 2 ? styles.activeLine : ''}`} />
                  
                  {/* Etapa 2 */}
                  <div className={`${styles.step} ${currentStage >= 2 ? styles.activeStep : ''}`}>
                    <div className={styles.stepCircle}>2</div>
                    <div className={styles.stepLabel}>Clic</div>
                  </div>
                  <div className={`${styles.stepLine} ${currentStage >= 3 ? styles.activeLine : ''}`} />
                  
                  {/* Etapa 3 */}
                  <div className={`${styles.step} ${currentStage >= 3 ? styles.activeStep : ''}`}>
                    <div className={styles.stepCircle}>3</div>
                    <div className={styles.stepLabel}>Compra</div>
                  </div>
                  <div className={`${styles.stepLine} ${currentStage >= 4 && !isIneligible ? styles.activeLine : ''}`} />
                  
                  {/* Etapa 4 */}
                  <div className={`${styles.step} ${currentStage >= 4 ? styles.activeStep : ''}`}>
                    <div className={styles.stepCircle}>4</div>
                    <div className={styles.stepLabel}>Reclamar</div>
                  </div>
                </div>

                {isIneligible && (
                  <div className={styles.statusBox}>
                    <p className={styles.errorText}>Esta compra no califica (Monto S/{ref.orderTotal}). Se requieren tramos completos de S/100.</p>
                  </div>
                )}

                {(isCompleted || isClaimed) && (
                  <div className={styles.actionBox}>
                    <div className={styles.earnedStats}>
                      Venta Total: <strong>S/ {ref.orderTotal?.toFixed(2) || '0.00'}</strong> <br/>
                      Ganancia: <strong className={styles.highlightCoins}>{ref.earnedCoins} Monedas</strong>
                    </div>
                    {isCompleted && (
                      <button className={styles.claimActionBtn} onClick={() => handleClaim(ref)}>
                        🪙 Reclamar Monedas
                      </button>
                    )}
                    {isClaimed && (
                      <span className={styles.claimedBadge}>✔️ Reclamado</span>
                    )}
                  </div>
                )}

              </div>
            );
          })}
        </div>
      )}

      {/* Nuevo componente de Ranking Mensual */}
      <ReferralRanking />
    </div>
  );
};

export default CuentaReferidosPage;

import React, { useState, useEffect, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { getDesignsByUser } from '../../services/designs';
import { usePedidos } from '../../hooks/usePedidos';
import MiCreacionCard from './components/MiCreacionCard';
import styles from './MisCreacionesPage.module.css';

const formatDate = (timestamp) => {
  if (!timestamp) return '—';
  try {
    const date = typeof timestamp.toDate === 'function'
      ? timestamp.toDate()
      : timestamp.seconds
        ? new Date(timestamp.seconds * 1000)
        : null;
    if (!date || isNaN(date.getTime())) return '—';
    return date.toLocaleDateString('es-PE', {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
    });
  } catch {
    return '—';
  }
};

const MisCreacionesPage = () => {
  const { user, userProfile } = useAuth();
  const [designs, setDesigns] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const dni = userProfile?.dni ? String(userProfile.dni).trim() : '';
  const { data: pedidosData, buscar: buscarPedidos } = usePedidos(dni);

  useEffect(() => {
    if (dni) {
      buscarPedidos(dni);
    }
  }, [dni, buscarPedidos]);

  useEffect(() => {
    if (!user?.uid) return;
    let cancelled = false;
    (async () => {
      const { data, error: err } = await getDesignsByUser(user.uid);
      if (!cancelled) {
        setDesigns(Array.isArray(data) ? data : []);
        setError(err || null);
      }
      if (!cancelled) setLoading(false);
    })();
    return () => { cancelled = true; };
  }, [user?.uid]);

  const purchasedDesignIds = useMemo(() => {
    const ids = new Set();
    const pedidos = pedidosData?.pedidos || [];
    pedidos.forEach(pedido => {
      const items = pedido.productos || {};
      Object.values(items).forEach(item => {
        if (item.designId) ids.add(item.designId);
      });
    });
    return ids;
  }, [pedidosData]);

  if (!user) return null;
  if (loading) {
    return (
      <div className={styles.wrapper}>
        <h2 className={styles.title}>Mis Creaciones</h2>
        <ul className={styles.grid}>
          {[1, 2, 3, 4, 5, 6].map((i) => (
            <li key={i} className={`${styles.cardItem} ${styles.skeletonCard}`}>
              <div className={styles.skeletonThumb} />
              <div className={styles.cardBody}>
