import { db } from './config';
import { doc, getDoc, updateDoc, setDoc, collection, getDocs, addDoc, deleteDoc, query, orderBy, runTransaction } from 'firebase/firestore';

// --- UTILIDADES DE FECHA ---
export const getStartOfWeek = (date = new Date()) => {
  const d = new Date(date);
  const day = d.getDay();
  const diff = d.getDate() - day + (day === 0 ? -6 : 1); // Adjust when day is Sunday
  d.setDate(diff);
  d.setHours(0, 0, 0, 0);
  return d;
};

export const formatIsoDate = (date) => date.toISOString().split('T')[0];

export const isSameWeek = (date1, date2) => {
  return getStartOfWeek(date1).getTime() === getStartOfWeek(date2).getTime();
};

export const getRuletaEligibility = (userProfile) => {
  if (!userProfile) return { isUnlocked: false, days: 0, lost: false };

  const currentWeekStart = getStartOfWeek();
  
  // Analizamos los claims guardados en userProfile.weeklyClaimsData
  // Estructura: { weekStart: '2026-05-18', daysClaimed: ['2026-05-18', '2026-05-19'] }
  const data = userProfile.weeklyClaimsData || { weekStart: formatIsoDate(currentWeekStart), daysClaimed: [] };
  
  if (data.weekStart !== formatIsoDate(currentWeekStart)) {
    // Si la semana guardada no es la actual, entonces tiene 0 días esta semana
    return { isUnlocked: false, days: 0, lost: false };
  }

  const daysCount = data.daysClaimed.length;
  const today = new Date();
  const currentDayOfWeek = today.getDay(); // 0 (Domingo) - 6 (Sábado)
  
  // Para perder, debe haber pasado al menos un día en la semana sin que lo haya reclamado
  // Ej: Es miércoles (3). Debería tener 3 daysClaimed. Si tiene menos de 2, ya perdió la semana.
  // Lógica exacta de pérdida:
  let adjustedDay = currentDayOfWeek === 0 ? 7 : currentDayOfWeek;
  const missedDays = adjustedDay - daysCount;
  
  // Si hoy no ha reclamado, missedDays puede ser 1, pero aún puede reclamar hoy.
  // Si la diferencia entre el día actual de la semana y los reclamados es >= 2, seguro perdió.
  // O si ya terminó el día ayer y le faltaba 1.
  // Simplificación de pérdida: Si estamos a Domingo (7) y tiene < 6 reclamados, ya perdió seguro.
  const hasLost = (adjustedDay > daysCount + 1);

  const isUnlocked = daysCount >= 7;

  return { isUnlocked, days: daysCount, hasLost };
};

// --- PREMIOS ---
const PRIZES_COLLECTION = 'ruletaPrizes';
const CONFIG_DOC = 'ruletaConfig/settings';

export const getRuletaPrizes = async () => {
  try {
    const q = query(collection(db, PRIZES_COLLECTION), orderBy('probability', 'desc'));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
  } catch (error) {
    console.error('Error fetching ruleta prizes:', error);
    return [];
  }
};

export const saveRuletaPrize = async (prizeData, id = null) => {
  try {
    if (id) {
      await updateDoc(doc(db, PRIZES_COLLECTION, id), prizeData);
    } else {
      await addDoc(collection(db, PRIZES_COLLECTION), prizeData);
    }
    return { success: true };
  } catch (error) {
    console.error('Error saving ruleta prize:', error);
    return { success: false, error };
  }
};

export const deleteRuletaPrize = async (id) => {
  try {
    await deleteDoc(doc(db, PRIZES_COLLECTION, id));
    return { success: true };
  } catch (error) {
    console.error('Error deleting ruleta prize:', error);
    return { success: false, error };
  }
};

// --- SPIN ---
export const spinRuleta = async (userId, userProfile) => {
  const eligibility = getRuletaEligibility(userProfile);
  if (!eligibility.isUnlocked) {
    return { success: false, error: 'Ruleta no desbloqueada' };
  }

  // Comprobar si ya giró esta semana
  const currentWeekStart = formatIsoDate(getStartOfWeek());
  if (userProfile.lastRuletaSpinWeek === currentWeekStart) {
    return { success: false, error: 'Ya giraste la ruleta esta semana' };
  }

  try {
    const prizes = await getRuletaPrizes();
    if (prizes.length === 0) throw new Error("No hay premios configurados");

    // Sorteo basado en probabilidades
    const rand = Math.random() * 100;
    let accumulated = 0;
    let selectedPrize = prizes[prizes.length - 1]; // Fallback

    for (const prize of prizes) {
      accumulated += Number(prize.probability);
      if (rand <= accumulated) {
        selectedPrize = prize;
        break;
      }
    }

    // Usar transacción para asignar premio y marcar que ya giró
    const userRef = doc(db, 'users', userId);
    
    await runTransaction(db, async (transaction) => {
      const userDoc = await transaction.get(userRef);
      if (!userDoc.exists()) throw new Error("User does not exist");
      const data = userDoc.data();

      const updateData = {
        lastRuletaSpinWeek: currentWeekStart
      };

      // Si es de tipo Monedas
      if (selectedPrize.type === 'Monedas') {
        updateData.monedas = (data.monedas || 0) + Number(selectedPrize.amount || 0);
      }
      
      // Aquí se pueden agregar lógicas para otros tipos de premios
      // Ej. Accesorio (agregarlo a la mochila), Descuento (crear código y agregarlo al perfil), etc.

      transaction.update(userRef, updateData);
    });

    return { success: true, prize: selectedPrize };
  } catch (error) {
    console.error('Error spinning ruleta:', error);
    return { success: false, error: error.message };
  }
};

import { 
  collection, 
  addDoc, 
  updateDoc, 
  doc, 
  query, 
  where, 
  getDocs, 
  serverTimestamp, 
  orderBy,
  Timestamp
} from 'firebase/firestore';
import { db } from './firebase/config';
import { getDocument, setDocument } from './firebase/firestore';

const REFERRALS_COLLECTION = 'referrals';

/**
 * Registra un clic en el enlace de referido.
 * Crea un documento de seguimiento (tracker) para esta sesión.
 */
export async function createReferralShare(referrerCode) {
  try {
    const code = referrerCode.trim().toUpperCase();
    
    // Validar límite mensual (50 referidos compartidos)
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    const qLimit = query(
      collection(db, REFERRALS_COLLECTION),
      where('referrerCode', '==', code),
      where('createdAt', '>=', Timestamp.fromDate(startOfMonth))
    );
    const limitSnap = await getDocs(qLimit);
    if (limitSnap.size >= 50) {
      return { id: null, error: 'Has alcanzado el límite mensual de referidos compartidos.' };
    }

    const docRef = await addDoc(collection(db, REFERRALS_COLLECTION), {
      referrerCode: code,
      status: 'sent', // Etapa 1
      createdAt: serverTimestamp(),
    });
    return { id: docRef.id, error: null };
  } catch (error) {
    return { id: null, error: error.message };
  }
}

/**
 * Registra un clic en el enlace de referido.
 * Si recibe un shareId (Etapa 1 existente), lo actualiza a Etapa 2.
 * Si no, crea un documento de seguimiento (tracker) nuevo desde Etapa 2.
 */
export async function recordReferralClick(referrerCode, shareId = null) {
  try {
    if (shareId) {
      // Actualizar doc existente
      const docRef = doc(db, REFERRALS_COLLECTION, shareId);
      await updateDoc(docRef, {
        status: 'clicked', // Etapa 2
        clickedAt: serverTimestamp(),
        updatedAt: serverTimestamp()
      });
      return { id: shareId, error: null };
    }

    const docRef = await addDoc(collection(db, REFERRALS_COLLECTION), {
      referrerCode: referrerCode.trim().toUpperCase(),
      status: 'clicked', // Etapa 2
      clickedAt: serverTimestamp(),
      createdAt: serverTimestamp(),
    });
    return { id: docRef.id, error: null };
  } catch (error) {
    return { id: null, error: error.message };
  }
}

/**
 * Vincula una compra finalizada con el flujo del referido
 */
export async function linkPurchaseToReferral(referralId, orderId, orderTotal) {
  try {
    const docRef = doc(db, REFERRALS_COLLECTION, referralId);
    await updateDoc(docRef, {
      status: 'purchased', // Etapa 3
      orderId,
      orderTotal,
      purchasedAt: serverTimestamp(),
      updatedAt: serverTimestamp()
    });
    return { error: null };
  } catch (error) {
    return { error: error.message };
  }
}

/**
 * Actualiza el referido a Completado cuando el Admin finaliza el pedido.
 * Calcula las monedas ganadas (5 por cada 100).
 */
export async function updateReferralToCompletedByOrder(orderId, orderTotal) {
  try {
    const q = query(collection(db, REFERRALS_COLLECTION), where('orderId', '==', orderId));
    const snapshot = await getDocs(q);
    if (snapshot.empty) return { error: null, found: false };

    const referralDoc = snapshot.docs[0];
    const data = referralDoc.data();
    
    // Contar compras completadas en este mes
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    
    const countQ = query(
      collection(db, REFERRALS_COLLECTION),
      where('referrerCode', '==', data.referrerCode),
      where('status', 'in', ['completed', 'claimed']),
      where('completedAt', '>=', Timestamp.fromDate(startOfMonth))
    );
    const countSnapshot = await getDocs(countQ);
    const completedThisMonth = countSnapshot.size;
    
    // A partir de la 3ra compra del mes se duplica (20 monedas), caso contrario 10
    const earnedCoins = completedThisMonth >= 2 ? 20 : 10;

    await updateDoc(referralDoc.ref, {
      status: 'completed', // Etapa 4 lista para reclamar
      earnedCoins,
      completedAt: serverTimestamp(),
      updatedAt: serverTimestamp()
    });

    return { error: null, found: true };
  } catch (error) {
    return { error: error.message };
  }
}

/**
 * Obtiene todos los referidos para el panel del usuario
 */
export async function getReferralsByReferrer(referrerCode) {
  try {
    if (!referrerCode) return { data: [], error: null };
    
    const q = query(
      collection(db, REFERRALS_COLLECTION), 
      where('referrerCode', '==', referrerCode)
    );
    const snapshot = await getDocs(q);
    
    const data = snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    }))
    // Ordenar manualmente porque orderBy requiere index en Firestore si combinamos con where
    .sort((a, b) => {
      const aTime = a.clickedAt?.toMillis() || a.createdAt?.toMillis() || 0;
      const bTime = b.clickedAt?.toMillis() || b.createdAt?.toMillis() || 0;
      return bTime - aTime;
    });

    return { data, error: null };
  } catch (error) {
    return { data: [], error: error.message };
  }
}

/**
 * Reclama las monedas de un referido (Etapa 4 -> Finalizado/Reclamado)
 */
export async function claimReferralCoins(referralId, earnedCoins, uid, currentMonedas = 0) {
  try {
    // 1. Actualizar el doc del referido a 'claimed'
    const docRef = doc(db, REFERRALS_COLLECTION, referralId);
    await updateDoc(docRef, {
      status: 'claimed',
      claimedAt: serverTimestamp(),
      updatedAt: serverTimestamp()
    });

    // 2. Sumar monedas al perfil
    await setDocument('portal_users', uid, {
      monedas: currentMonedas + earnedCoins,
      updatedAt: serverTimestamp()
    });

    return { error: null };
  } catch (error) {
    return { error: error.message };
  }
}

/**
 * Permite editar el código de referido por única vez.
 */
export async function updateReferralCode(uid, newCode) {
  try {
    const cleanCode = newCode.trim().toUpperCase();
    
    // Verificar que no esté en uso
    const q = query(collection(db, 'portal_users'), where('referralCode', '==', cleanCode));
    const snap = await getDocs(q);
    if (!snap.empty) {
      return { error: 'El código ya está en uso' };
    }
    
    await setDocument('portal_users', uid, {
      referralCode: cleanCode,
      referralCodeEdited: true,
      updatedAt: serverTimestamp()
    });
    
    return { error: null };
  } catch (error) {
    return { error: error.message };
  }
}

/**
 * Obtiene el ranking Top 10 del mes actual
 */
export async function getTopReferrersOfMonth() {
  try {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    
    const q = query(
      collection(db, REFERRALS_COLLECTION),
      where('status', 'in', ['completed', 'claimed']),
      where('completedAt', '>=', Timestamp.fromDate(startOfMonth))
    );
    
    const snapshot = await getDocs(q);
    
    // Agrupar por código de referido
    const userStats = {};
    snapshot.docs.forEach(doc => {
      const data = doc.data();
      const code = data.referrerCode;
      if (!userStats[code]) {
        userStats[code] = { referrerCode: code, count: 0, coins: 0 };
      }
      userStats[code].count += 1;
      userStats[code].coins += data.earnedCoins || 0;
    });
    
    // Ordenar y tomar Top 10
    const top10 = Object.values(userStats)
      .sort((a, b) => b.count - a.count)
      .slice(0, 10);
      
    return { data: top10, error: null };
  } catch (error) {
    return { data: [], error: error.message };
  }
}

import { getCloudinaryOptimized } from '../components/common/OptimizedImage/OptimizedImage';
import { toDirectImageUrl, toCanvasImageUrl, isGoogleDriveUrl, isFirebaseStorageUrl, ensureSingleImageUrl } from './imageUrl';
import html2canvas from 'html2canvas';
import { generateThumbnailWithDesign } from './thumbnailWithDesign';

/**
 * Crea un canvas nativo de placeholder cuando una imagen no puede cargarse (p. ej. CORS).
 * Así el editor combo puede mostrarse igual y el usuario no pierde el diseño.
 */
function createPlaceholderCanvas(width = 400, height = 400) {
  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
  if (ctx) {
    ctx.fillStyle = '#f0f0f0';
    ctx.fillRect(0, 0, width, height);
    ctx.fillStyle = '#999';
    ctx.font = '14px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('Imagen no disponible', width / 2, height / 2);
  }
  return canvas;
}

/**
 * Carga una imagen desde URL y la devuelve como canvas nativo (para componer).
 * Usa crossOrigin 'anonymous' para poder exportar; si la imagen viene de otro dominio
 * sin CORS, fallará.
 * @param {string} imageUrl - URL de la imagen (puede ser Google Drive; se convierte con toDirectImageUrl)
 * @param {number} scale - Escala a aplicar (1 = tamaño original)
 * @returns {Promise<{ canvas: HTMLCanvasElement, scale: number }>}
 */
const loadImageElement = (url) => new Promise((resolve, reject) => {
  const img = new Image();
  img.crossOrigin = 'anonymous';
  img.onload = () => resolve(img);
  img.onerror = () => reject(new Error(`Error al cargar imagen: ${url}`));
  img.src = url;
});

export const loadImageAsFabricCanvas = async (imageUrl, scale = 1) => {
  const optimized = getCloudinaryOptimized(imageUrl);
  const single = ensureSingleImageUrl(optimized);
  if (!single) throw new Error('URL de imagen no válida');
  const directUrl = toDirectImageUrl(single);
  const canvasUrl = toCanvasImageUrl(single);
  const isDriveOrFirebase =
    isGoogleDriveUrl(single) || isFirebaseStorageUrl(single) ||
    isGoogleDriveUrl(directUrl) || isFirebaseStorageUrl(directUrl);

  const addCacheBuster = (url) => {
    if (!url || url.startsWith('data:')) return url;
    try {
      const u = new URL(url);
      u.searchParams.set('_cb', Date.now() + '_' + Math.random().toString(36).substr(2, 5));
      return u.toString();
    } catch {
      return url + (url.includes('?') ? '&' : '?') + '_cb=' + Date.now() + '_' + Math.random().toString(36).substr(2, 5);
    }
  };

  const baseUrls = [];
  if (isDriveOrFirebase) {
    baseUrls.push(canvasUrl, directUrl, single);
  } else {
    baseUrls.push(directUrl, single);
  }
  
  const urlsWithCb = [];
  baseUrls.filter(Boolean).forEach(u => {
    urlsWithCb.push(u);
    urlsWithCb.push(addCacheBuster(u));
    if (u.startsWith('http')) {
      urlsWithCb.push(`https://api.allorigins.win/raw?url=${encodeURIComponent(u)}`);
    }
  });

  const tried = new Set();
  let lastError = null;

  for (const url of urlsWithCb) {
    const clean = typeof url === 'string' ? url.trim() : '';
    if (!clean || tried.has(clean)) continue;
    tried.add(clean);
    try {
      let objectUrlToCleanup = null;
      let finalUrlToLoad = clean;
      
      // Intentar fetch primero si es firebase para saltar caché envenenada de Chrome
      if (clean.includes('firebasestorage') && !clean.includes('allorigins')) {
          try {
              const res = await fetch(clean, { mode: 'cors', cache: 'reload' });
              if (res.ok) {
                  const blob = await res.blob();
                  finalUrlToLoad = URL.createObjectURL(blob);
                  objectUrlToCleanup = finalUrlToLoad;
              }
          } catch(e) {
             // Ignorar y seguir con carga normal
          }
      }

      const img = await loadImageElement(finalUrlToLoad);
      if (objectUrlToCleanup) URL.revokeObjectURL(objectUrlToCleanup);
      const canvas = document.createElement('canvas');
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext('2d');
      if (!ctx) {
        throw new Error('No se pudo obtener contexto 2D para componer la imagen');
      }
      ctx.drawImage(img, 0, 0);
      return { canvas, scale };
    } catch (err) {
      lastError = err;
    }
  }

  throw lastError || new Error('Error al cargar la imagen');
};

/**
 * Genera la imagen compuesta del combo como data URL (para usar en admin: generar y subir).
 * @param {Array<Object>} comboItems - Items del combo ({ productId, viewId, scale, variantMapping, ... })
 * @param {Object} comboLayout - { orientation: 'horizontal' | 'vertical', spacing: number }
 * @param {Function} getImageUrlForItem - Async (item, index) => Promise<{ imageUrl: string, scale: number } | null>
 * @returns {Promise<string>} Data URL PNG de la imagen compuesta
 */
export const generateComboPreviewDataUrl = async (comboItems, comboLayout, getImageUrlForItem) => {
  if (!comboItems || comboItems.length === 0) {
    throw new Error('El combo no tiene productos');
  }

  const canvasInstances = [];

  for (let i = 0; i < comboItems.length; i++) {
    const item = comboItems[i];
    try {
      const resolved = await getImageUrlForItem(item, i);
      if (!resolved || !resolved.imageUrl) continue;

      const { canvas, scale } = await loadImageAsFabricCanvas(
        resolved.imageUrl,
        typeof resolved.scale === 'number' && resolved.scale > 0 ? resolved.scale : 1
      );
      canvasInstances.push({ canvas, scale });
    } catch (err) {
      console.error(`Error loading image for combo item ${i}:`, err);
    }
  }

  if (canvasInstances.length === 0) {
    throw new Error('No se pudieron cargar las imágenes de los productos del combo');
  }

  return composeComboImage(canvasInstances, comboLayout);
};

/**
 * Compone múltiples canvases de Fabric.js en una sola imagen
 * @param {Array<Object>} canvasInstances - Array de objetos { canvas: Fabric.Canvas, scale?: number }
 * @param {Object} layout - { orientation: 'horizontal' | 'vertical', spacing: number }
 * @returns {Promise<string>} Data URL de la imagen compuesta
 */
export const composeComboImage = async (canvasInstances, layout) => {
  if (!canvasInstances || canvasInstances.length === 0) {
    throw new Error('Se requiere al menos un canvas');
  }

  const { orientation = 'horizontal', spacing = 20 } = layout || {};
  const isHorizontal = orientation === 'vertical' ? false : true;

  // Calcular dimensiones totales
  let totalWidth = 0;
  let totalHeight = 0;
  const canvasData = [];

  const getCanvasWidth = (canvas) => {
    if (!canvas) return 0;
    if (typeof canvas.getWidth === 'function') return canvas.getWidth();
    return Number(canvas.width) || 0;
  };

  const getCanvasHeight = (canvas) => {
    if (!canvas) return 0;
    if (typeof canvas.getHeight === 'function') return canvas.getHeight();
    return Number(canvas.height) || 0;
  };

  const canvasToDataUrl = (canvas) => {
    if (!canvas || typeof canvas.toDataURL !== 'function') {
      throw new Error('Canvas inválido para exportar imagen');
    }
    try {
      // Soporte para Fabric.js
      return canvas.toDataURL({ format: 'png', quality: 1, multiplier: 1 });
    } catch (_) {
      // Soporte para canvas nativo
      return canvas.toDataURL('image/png', 1.0);
    }
  };

  for (let i = 0; i < canvasInstances.length; i++) {
    const item = canvasInstances[i];
    const canvas = item.canvas;
    if (!canvas) continue;

    const scale = item.scale || 1;
    const width = getCanvasWidth(canvas) * scale;
    const height = getCanvasHeight(canvas) * scale;

    canvasData.push({
      canvas,
      scale,
      width,
      height
    });

    if (isHorizontal) {
      totalWidth += width + (i < canvasInstances.length - 1 ? spacing : 0);
      totalHeight = Math.max(totalHeight, height);
    } else {
      totalWidth = Math.max(totalWidth, width);
      totalHeight += height + (i < canvasInstances.length - 1 ? spacing : 0);
    }
  }

  if (totalWidth === 0 || totalHeight === 0) {
    throw new Error('No se pudieron calcular las dimensiones del combo');
  }

  // Hacer que el canvas final sea siempre un CUADRADO PERFECTO (1:1) para evitar estiramiento en ProductCard
  // o aplastamiento en ProductDetail.
  const finalSize = Math.max(totalWidth, totalHeight);

  // Crear canvas temporal para la composición
  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = finalSize;
  tempCanvas.height = finalSize;
  const ctx = tempCanvas.getContext('2d');

  // Fondo transparente o blanco (prioriza blanco para mantener consistencia)
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, finalSize, finalSize);

  // Calcular offsets para centrar el combo en el lienzo cuadrado
  const offsetX = (finalSize - totalWidth) / 2;
  const offsetY = (finalSize - totalHeight) / 2;

  // Renderizar cada canvas en su posición central
  let currentX = offsetX;
  let currentY = offsetY;

  for (const item of canvasData) {
    const { canvas, width, height } = item;

    // Exportar canvas a imagen
    const canvasDataUrl = canvasToDataUrl(canvas);

    // Crear imagen desde data URL
    const img = await new Promise((resolve, reject) => {
      const image = new Image();
      image.onload = () => resolve(image);
      image.onerror = reject;
      image.src = canvasDataUrl;
    });

    // Dibujar imagen escalada en posición
    ctx.save();
    ctx.drawImage(img, currentX, currentY, width, height);
    ctx.restore();

    // Actualizar posición para el siguiente canvas
    if (isHorizontal) {
      currentX += width + spacing;
    } else {
      currentY += height + spacing;
    }
  }

  // Convertir a data URL (Usar webp para reducir drásticamente el peso y no romper Firestore)
  return tempCanvas.toDataURL('image/webp', 0.85);
};

/**
 * Compone múltiples canvases y devuelve data URL + bounds de cada ítem (posición en px en la imagen compuesta).
 * @param {Array<Object>} canvasInstances - Array de { canvas, scale? }
 * @param {Object} layout - { orientation, spacing }
 * @returns {Promise<{ dataUrl: string, totalWidth: number, totalHeight: number, itemBounds: Array<{ x: number, y: number, width: number, height: number }> }>}
 */
export const composeComboImageWithBounds = async (canvasInstances, layout) => {
  if (!canvasInstances || canvasInstances.length === 0) {
    throw new Error('Se requiere al menos un canvas');
  }

  const { orientation = 'horizontal', spacing = 20 } = layout || {};
  const isHorizontal = orientation === 'vertical' ? false : true;

  let totalWidth = 0;
  let totalHeight = 0;
  const canvasData = [];

  const getCanvasWidth = (canvas) => {
    if (!canvas) return 0;
    if (typeof canvas.getWidth === 'function') return canvas.getWidth();
    return Number(canvas.width) || 0;
  };

  const getCanvasHeight = (canvas) => {
    if (!canvas) return 0;
    if (typeof canvas.getHeight === 'function') return canvas.getHeight();
    return Number(canvas.height) || 0;
  };

  const canvasToDataUrl = (canvas) => {
    if (!canvas || typeof canvas.toDataURL !== 'function') {
      throw new Error('Canvas inválido para exportar imagen');
    }
    try {
      return canvas.toDataURL({ format: 'png', quality: 1, multiplier: 1 });
    } catch (_) {
      return canvas.toDataURL('image/png', 1.0);
    }
  };

  for (let i = 0; i < canvasInstances.length; i++) {
    const item = canvasInstances[i];
    const canvas = item.canvas;
    if (!canvas) continue;

    const scale = item.scale || 1;
    const width = getCanvasWidth(canvas) * scale;
    const height = getCanvasHeight(canvas) * scale;

    canvasData.push({ canvas, scale, width, height });

    if (isHorizontal) {
      totalWidth += width + (i < canvasInstances.length - 1 ? spacing : 0);
      totalHeight = Math.max(totalHeight, height);
    } else {
      totalWidth = Math.max(totalWidth, width);
      totalHeight += height + (i < canvasInstances.length - 1 ? spacing : 0);
    }
  }

  const itemBounds = [];
  if (isHorizontal) {
    let currentX = 0;
    for (let i = 0; i < canvasData.length; i++) {
      itemBounds.push({
        x: currentX,
        y: 0,
        width: canvasData[i].width,
        height: canvasData[i].height
      });
      currentX += canvasData[i].width + (i < canvasData.length - 1 ? spacing : 0);
    }
  } else {
    let currentY = 0;
    for (let i = 0; i < canvasData.length; i++) {
      itemBounds.push({
        x: 0,
        y: currentY,
        width: canvasData[i].width,
        height: canvasData[i].height
      });
      currentY += canvasData[i].height + (i < canvasData.length - 1 ? spacing : 0);
    }
  }

  const finalSize = Math.max(totalWidth, totalHeight);
  const offsetX = (finalSize - totalWidth) / 2;
  const offsetY = (finalSize - totalHeight) / 2;

  // Actualizar los bounds para que reflejen el nuevo padding
  const centeredBounds = itemBounds.map(b => ({
    ...b,
    x: b.x + offsetX,
    y: b.y + offsetY
  }));

  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = finalSize;
  tempCanvas.height = finalSize;
  const ctx = tempCanvas.getContext('2d');
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, finalSize, finalSize);

  let currentX = offsetX;
  let currentY = offsetY;

  for (const item of canvasData) {
    const { canvas, width, height } = item;
    const canvasDataUrl = canvasToDataUrl(canvas);
    const img = await new Promise((resolve, reject) => {
      const image = new Image();
      image.onload = () => resolve(image);
      image.onerror = reject;
      image.src = canvasDataUrl;
    });
    ctx.drawImage(img, currentX, currentY, width, height);
    if (isHorizontal) {
      currentX += width + spacing;
    } else {
      currentY += height + spacing;
    }
  }

  const dataUrl = tempCanvas.toDataURL('image/webp', 0.85);
  return { dataUrl, totalWidth: finalSize, totalHeight: finalSize, itemBounds: centeredBounds };
};

/**
 * Genera la imagen compuesta del combo con bounds (para editor unificado).
 * @param {Array<Object>} comboItems
 * @param {Object} comboLayout
 * @param {Function} getImageUrlForItem - Async (item, index) => Promise<{ imageUrl: string, scale: number } | null>
 * @returns {Promise<{ dataUrl: string, totalWidth: number, totalHeight: number, itemBounds: Array }>}
 */
export const generateComboPreviewDataUrlWithBounds = async (comboItems, comboLayout, getImageUrlForItem) => {
  if (!comboItems || comboItems.length === 0) {
    throw new Error('El combo no tiene productos');
  }

  const canvasInstances = [];

  for (let i = 0; i < comboItems.length; i++) {
    const item = comboItems[i];
    try {
      const resolved = await getImageUrlForItem(item, i);
      if (!resolved || !resolved.imageUrl) {
        canvasInstances.push({ canvas: createPlaceholderCanvas(400, 400), scale: 1 });
        continue;
      }

      const { canvas, scale } = await loadImageAsFabricCanvas(
        resolved.imageUrl,
        typeof resolved.scale === 'number' && resolved.scale > 0 ? resolved.scale : 1
      );
      canvasInstances.push({ canvas, scale });
    } catch (err) {
      if (typeof console !== 'undefined' && console.debug) {
        console.debug('Combo: imagen no cargada (CORS/URL inválida). Abortando composición para usar Fallback.', err?.message || err);
      }
      throw err;
    }
  }

  return composeComboImageWithBounds(canvasInstances, comboLayout);
};

